window.HADITH_CACHE["ahmad_4"] = {"2001":{"ar":"حَدَّثَنَا قُرَّانُ بْنُ تَمَّامٍ عَنْ سَعِيدِ بْنِ عُبَيْدٍ الطَّائِيِّ عَنْ عَلِيِّ بْنِ رَبِيعَةَ الْأَسَدِيِّ قَالَمَاتَ رَجُلٌ مِنْ الْأَنْصَارِ يُقَالُ لَهُ قَرَظَةُ بْنُ كَعْبٍ فَنِيحَ عَلَيْهِ فَخَرَجَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَصَعِدَ الْمِنْبَرَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ قَالَ مَا بَالُ النَّوْحِ فِي الْإِسْلَامِ أَمَا إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ كَذِبًا عَلَيَّ لَيْسَ كَكَذِبٍ عَلَى أَحَدٍ أَلَا وَمَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Qurran bin Tamam] dari [Sa'id bin Ubaid Ath Tha`i] dari [Ali bin Rabi'ah Al Asadi] ia berkata, \"Seorang laki-laki Anshar yang bernama Qarazhah bin Ka'ab meninggal dunia hingga orang-orang pun meratapinya. Maka [Al Mughirah bin Syu'bah] keluar dan langsung menaiki mimbar. Ia lantas memuji Allah dan membaca pujian-pujian atas-Nya. Kemudian ia berkata, \"Apakah dalam Islam ada ratapan (untuk mayit)? Sungguh, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mendustaiku tidak sebaqaimana berbuat dusta kepada selain aku. Ketahuilah, barangsiapa dengan sengaja berdusta atas namaku, maka hendaklah ia mempersiapkan tempat duduknya di dalam neraka.'\""},"2002":{"ar":"حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ أَبُو مُحَمَّدٍ الْكِلَابِيُّ حَدَّثَنَا مُجَالِدٌ عَنِ الشَّعْبِيِّ عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَوَضَّأْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَغَسَلَ وَجْهَهُ وَذِرَاعَيْهِ وَمَسَحَ بِرَأْسِهِ وَمَسَحَ عَلَى خُفَّيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا أَنْزِعُ خُفَّيْكَ قَالَ لَا إِنِّي أَدْخَلْتُهُمَا وَهُمَا طَاهِرَتَانِ ثُمَّ لَمْ أَمْشِ حَافِيًا بَعْدُ ثُمَّ صَلَّى صَلَاةَ الصُّبْحِ","id":"Telah menceritakan kepada kami [Abdah bin Sulaiman Abu Muhammad Al Kilabi] Telah menceritakan kepada kami [Mujalid] dari [Sya'bi] dari [Al Mughirah bin Syu'bah] ia berkata, \"Saya memberikan air wudlu kepada Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Kemudian beliau pun mencuci wajah dan kedua tangannya (dari siku hingga ujung jari), kemudian beliau membasuh kepalanya dan juga membasuh kedua sepatunya. Lalu saya pun berkata, \"Wahai Rasulullah, lepaskanlah kedua sepatumu.\" Beliau menjawab: \"Tidak. Sesungguhnya saya memasukkan keduanya dalam keadaan suci, setelah itu saya belum berjalan tanpa mengenakan sepatu.\" Setelah itu beliau menunaikan shalat Subuh.\""},"2003":{"ar":"حَدَّثَنِي عَبْدُ الْمُتَعَالِ بْنُ عَبْدِ الْوَهَّابِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْأُمَوِيُّ حَدَّثَنَا الْمُجَالِدُ عَنْ عَامِرٍ قَالَكَسَفَتْ الشَّمْسُ ضَحْوَةً حَتَّى اشْتَدَّتْ ظُلْمَتُهَا فَقَامَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَصَلَّى بِالنَّاسِ فَقَامَ قَدْرَ مَا يَقْرَأُ سُورَةً مِنْ الْمَثَانِي ثُمَّ رَكَعَ مِثْلَ ذَلِكَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ رَكَعَ مِثْلَ ذَلِكَ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ مِثْلَ ذَلِكَ ثُمَّ رَكَعَ الثَّانِيَةَ مِثْلَ ذَلِكَ ثُمَّ إِنَّ الشَّمْسَ تَجَلَّتْ فَسَجَدَ ثُمَّ قَامَ قَدْرَ مَا يَقْرَأُ سُورَةً ثُمَّ رَكَعَ وَسَجَدَ ثُمَّ انْصَرَفَ فَصَعِدَ الْمِنْبَرَ فَقَالَ إِنَّ الشَّمْسَ كَسَفَتْ يَوْمَ تُوُفِّيَ إِبْرَاهِيمُ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَإِنَّمَا هُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ فَإِذَا انْكَسَفَ وَاحِدٌ مِنْهُمَا فَافْزَعُوا إِلَى الصَّلَاةِ ثُمَّ نَزَلَ فَحَدَّثَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ فِي الصَّلَاةِ فَجَعَلَ يَنْفُخُ بَيْنَ يَدَيْهِ ثُمَّ إِنَّهُ مَدَّ يَدَهُ كَأَنَّهُ يَتَنَاوَلُ شَيْئًا فَلَمَّا انْصَرَفَ قَالَ إِنَّ النَّارَ أُدْنِيَتْ مِنِّي حَتَّى نَفَخْتُ حَرَّهَا عَنْ وَجْهِي فَرَأَيْتُ فِيهَا صَاحِبَ الْمِحْجَنِ وَالَّذِي بَحَرَ الْبَحِيرَةَ وَصَاحِبَةَ حِمْيَرَ صَاحِبَةَ الْهِرَّةِحَدَّثَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ قَالَ حَدَّثَنِي أَبِي حَدَّثَنَا الْمُجَالِدُ عَنْ عَامِرٍ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abdul Mu'tal bin Abdul Wahab] Telah menceritakan kepada kami [Yahya bin Sa'id Al Umawi] Telah menceritakan kepada kami [Al Mujalid] dari [Amir] ia berkata, \"Tepat pada waktu dluha terjadi generhana matahari hingga kegelapannya pun semakin tebal. Kemudian [Al Mughirah bin Syu'bah] bangkit dan shalat bersama kaum muslimin. Syu'bah berdiri selama bacaan surat Al Matsani (surat yang bacaannya selalu diulang-ulang dalam shalat), kemudian ia rukuk selama itu juga, lalu mengangkat kepalanya, kemudian rukuk lagi seperti tadi lalu mengangkat kepalanya dan berdiri seperti berdirinya yang pertama. Kemudian ia melakukan rukuk yang kedua sebagaimana rukuk yang pertama. Pada saat itu, tersingkaplah matahari. Syu'bah kemudian sujud, lalu berdiri selama bacaan satu surat kemudian rukuk lagi dan sujud. Setelah itu, ia beranjak naik ke atas mimbar dan berkata, \"Pernah terjadi gerhana matahari tepat pada hari wafatnya Ibrahim putera Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam pun berdiri seraya bersabda: 'Sesungguhnya tidaklah terjadi gerhana matahari dan bulan karena kematian seseorang. Akan tetapi, keduanya merupakan dua ayat dari ayat-ayat Allah 'azza wajalla. Bila terjadi gerhana pada salah satu dari keduanya, maka bersegeralah kalian untuk menunaikan shalat.'\" Kemudian Syu'bah turun dari mimbar, dan ia menceritakan bahwa Rasulullah shallallahu 'alaihi wasallam suatu saat pernah shalat, lalu beliau meniup kedua tangannya, kemudian merenggangkan tanganya lagi seperti sedang mengambil sesuatu. Setelah shalat beliau bersabda: \"Sesungguhnya neraka telah didekatkan dariku hingga aku berusaha meniup hawa panasnya dari wajahku. Dan di dalam neraka itu, aku melihat pemilik tongkat yang berkeluk kepalanya dan orang yang membelah telinga Unta, kemudian Shahibatul Himyar yaitu pemilik kucing.\" Telah menceritakan kepada kami [Sa'id bin Sa'id Al Amawi] ia berkata, telah menceritakan kepadaku [bapakku] telah menceritakan kepada kami [Al Mujalid] dari [Amir] semisalnya.\""},"2004":{"ar":"حَدَّثَنِي أَبُو النَّضْرِ الْحَارِثُ بْنُ النُّعْمَانِ عَنْ شَيْبَانَ عَنْ جَابِرٍ عَنْ عَامِرٍ عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْهُذَلِيَّتَيْنِ أَنَّ الْعَقْلَ عَلَى الْعَصَبَةِ وَأَنَّ الْمِيرَاثَ لِلْوَرَثَةِ وَأَنَّ فِي الْجَنِينِ غُرَّةً","id":"Telah menceritakan kepadaku [Abu An Nadlr Al Harits bin Nu'man] dari [Syaiban] dari [Jabir] dari [Amir] dari [Al Mughirah bin Syu'bah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam telah memberi putusan untuk dua orang dari suku Hudzail, bahwa tebusan itu harus dibayar oleh Ashabah, bayar harta warisan hanya dibagikan kepada para ahli warits, dan dalam (pembunuhan) janin maka dendanya adalah membayar Ghurrah.\" "},"2005":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ وَقَدْ كُنْتُ حَفِظْتُ مِنْ كَثِيرٍ مِنْ عُلَمَائِنَا بِالْمَدِينَةِ أَنَّ مُحَمَّدَ بْنَ عَمْرِو بْنِ حَزْمٍ كَانَ يَرْوِي عَنِ الْمُغِيرَةِ أَحَادِيثَ مِنْهَا أَنَّهُ حَدَّثَهُأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ غَسَّلَ مَيِّتًا فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [Bapakku] dari [Ibnu Ishaq] ia berkata; saya telah menghafal dari [sekian banyak ulama kita di Madinah], bahwa [Muhammad bin Amru bin Hazm] meriwayatkan dari [Al Mughirah] beberapa hadits. Di antaranya adalah, bahwa telah menceritakan kepadanya, bahwaq ia pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangisapa memandikan mayit, maka hendaklah ia mandi.\""},"2006":{"ar":"حَدَّثَنَا حُسَيْنٌ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنِ الشَّعْبِيِّ عَنْ وَرَّادٍ عَنِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ كَرِهَ لَكُمْ ثَلَاثًا قِيلَ وَقَالَ وَكَثْرَةَ السُّؤَالِ وَإِضَاعَةَ الْمَالِ وَحَرَّمَ عَلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأْدَ الْبَنَاتِ وَعُقُوقَ الْأُمَّهَاتِ وَمَنَعَ وَهَاتِ","id":"Telah menceritakan kepada kami [Husain] Telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Asy Sya'bi] dari [Warrad] dari [Al Mughirah bin Syu'bah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla membenci tiga hal bagi kalian.\" Lalu ditanyakanlah ketiga hal itu kepada beliau, maka beliau menjawab: \"Banyak bertanya dan menyia-nyiakan harta, Rasulullah shallallahu 'alaihi wasallam telah mengharamkan atas kalian untuk membunuh anak-anak perempuan, durhaka kepada ibu, dan menahan hak orang lain.\""},"2007":{"ar":"حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي سِمَاكٌ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى خَيْرًا مِنْهَا فَلْيَأْتِ بِالَّذِي هُوَ خَيْرٌ","id":"Telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Simak] dari [Tamim bin Tharaqah] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa bersumpah lalu melihat sesuatu yang lebih baik darinya, maka hendaklah ia mengutamakan yang lebih baik.\""},"2008":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَوَكِيعٌ عَنْ زَكَرِيَّا قَالَ وَكِيعٌ عَنْ عَامِرٍ وَقَالَ يَحْيَى فِي حَدِيثِهِ قَالَ حَدَّثَنِي عَامِرٌ قَالَ حَدَّثَنَا عَدِيُّ بْنُ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَبْتَ بِحَدِّهِ فَكُلْهُ وَمَا أَصَبْتَ بِعَرْضِهِ فَهُوَ وَقِيذٌ وَسَأَلْتُهُ عَنْ صَيْدِ الْكَلْبِ قَالَ وَكِيعٌ إِذَا أَرْسَلْتَ كَلْبَكَ وَذَكَرْتَ اسْمَ اللَّهِ فَكُلْ فَقَالَ وَمَا أَمْسَكَ عَلَيْكَ وَلَمْ يَأْكُلْ فَكُلْهُ فَإِنَّ أَخْذَهُ ذَكَاتُهُ وَإِنْ وَجَدْتَ مَعَ كَلْبِكَ كَلْبًا آخَرَ فَخَشِيتَ أَنْ يَكُونَ أَخَذَهُ مَعَهُ وَقَدْ قَتَلَهُ فَلَا تَأْكُلْ فَإِنَّكَ إِنَّمَا ذَكَرْتَ اسْمَ اللَّهِ عَلَى كَلْبِكَ وَلَمْ تَذْكُرْهُ عَلَى غَيْرِهِ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dan [Waki'] dari [Zakaria], [Waki'] berkata dari [Amir], [Yahya] menyebutkan dalam haditsnya, ia berkata; telah menceritakan kepadaku [Amir] ia berkata, Telah menceritakan kepada kami [Adi bin Hatim] ia berkata, \"Aku bertanya Rasulullah shallallahu 'alaihi wasallam tentang hewan buruan yang terkena bagian tumpul tombak (bukan mata tombaknya). Beliau bersabda: \"Hewan yang terkena oleh mata tombak maka makanlah, namun hewan buruan terkena bagian tumpulnya maka ia seperti waqidz (hewan yang sakit dan hampir mati).\" Kemudian aku bertanya tentang hewan hasil buruan anjing.\" Waki' berkata, \"Jika kamu melepas anjingmu dan menyebut nama Allah, maka makanlah.\" Kemudian Rasulullah bersabda lagi: \"Jika anjing tersebut menangkap buruan untukmu dan ia tidak memakannya maka makanlah, karena pemburuannya termasuk penyembelihan. Jika kamu mendapatkan anjing lain bersama anjingmu, lalu kamu khawatir jika anjing tersebut ikut berburu bersama anjingmu hingga membunuhnya, maka janganlah kamu makan. Sebab engkau hanya menyebut nama Allah atas anjingmu, bukan untuk anjing yang lain.\""},"2009":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ يَعْنِي ابْنَ رُفَيْعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ رَجُلًا خَطَبَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَقَدْ غَوَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ الْخَطِيبُ أَنْتَ قُلْ وَمَنْ يَعْصِ اللَّهَ وَرَسُولَهُ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdul Aziz] -yakni Ibnu Rufai'- dari [Tamim bin Tharaqah] dari [Adi bin Hatim], bahwa seorang laki-laki berkhutbah di sisi Rasulullah shallallahu 'alaihi wasallam seraya berkata, \"Barangsiapa mentaati Allah dan Rasul-Nya maka sesungguhnya ia telah mendapat petunjuk. Dan barangsiapa bermaksiat kepada keduanya sesungguhnya ia telah sesat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seburuk-buruk Khatib adalah kamu. Katakanlah, 'Dan barangsiapa mendurhakai Allah dan Rasul-Nya.'\""},"2010":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سَعْدَانُ الْجُهَنِيُّ عَنِ ابْنِ خَلِيفَةَ الطَّائِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَتَّقِيَ النَّارَ فَلْيَتَصَدَّقْ وَلَوْ بِشِقِّ تَمْرَةٍ فَمَنْ لَمْ يَجِدْ فَبِكَلِمَةٍ طَيِّبَةٍ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sa'dan Al Juhani] dari [Ibnu Khalifah Ath Tha`i] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa di antara kalian bisa menjaga diri dari api neraka, hendaklah ia bersedekah meskipun dengan setengah biji kurma. Dan barangsiapa tidak mendapatkan, hendaklah ia mengucapkan kalimat thayyibah.\""},"2011":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سِمَاكٍ عَنْ مُرَيِّ بْنِ قَطَرِيٍّ عَنْ عَدِيِّ بْنِ حَاتِمٍ الطَّائِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا نَصِيدُ الصَّيْدَ فَلَا نَجِدُ سِكِّينًا إِلَّا الظِّرَارَ وَشِقَّةَ الْعَصَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَّ الدَّمَ بِمَا شِئْتَ وَاذْكُرْ اسْمَ اللَّهِ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Simak] dari [Mura bin Qathari] dari [Adi bin Hatim Ath Tha`i] ia berkata, \"Aku berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Kami berburu hewan buruan, namun kami tidak mendapatkan pisau kecuali batu dan pecahan tongkat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Alirkanlah darah dengan menggunakan alat sekehendakmu, lalu sebutlah nama Allah.\""},"2012":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ يُحَدِّثُ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] ia berkata, aku mendengar [Abdullah bin Amru] budak Al Hasan bin Ali menceritakan dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah kemudian melihat sesuatu yang lebih baik darinya, maka hendaklah ia mengutamakan yang lebih baik kemudian membayar kafarah sumpahnya.\""},"2013":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَتَّقِيَ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abdullah bin Ma'qil] dari [Adi bin Hatim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian dapat membebaskan dirinya dari neraka meski dengan setengah biji kurma, maka lakukanlah.\""},"2014":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ وَابْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مُحِلِّ بْنِ خَلِيفَةَ قَالَ عَبْدُ الرَّحْمَنِ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ تَجِدُوا فَبِكَلِمَةٍ طَيِّبَةٍ وَقَالَ ابْنُ جَعْفَرٍ فَبِكَلِمَةٍ","id":"Telah menceritakan kepada kami [Abdurrahman] dan [Ibnu Ja'far] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Muhil bin Khalifah] ia berkata, [Abdurrahman] berkata, aku mendengar [Adi bin Hatim] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: Hendaklah kalian menghindari neraka meski hanya dengan setengah biji kurma. Jika kalian tidak mampu, maka ucapkanlah kalimat thayyibah.\" Ibnu Ja'far menyebutkan, \"Hendaklah dengan kalimat.\""},"2015":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ قَالَ حَدَّثَنَا الشَّعْبِيُّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ وَكَانَ لَنَا جَارًا أَوْ دَخِيلًا وَرَبِيطًا بِالنَّهْرَيْنِأَنَّهُ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أُرْسِلُ كَلْبِي فَأَجِدُ مَعَ كَلْبِي كَلْبًا قَدْ أَخَذَ لَا أَدْرِي أَيُّهُمَا أَخَذَ قَالَ فَلَا تَأْكُلْ فَإِنَّمَا سَمَّيْتَ عَلَى كَلْبِكَ وَلَمْ تُسَمِّ عَلَى غَيْرِهِحَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ عَنِ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ ذَلِكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Masruq] ia berkata, Telah menceritakan kepada kami [Asy Sya'bi] ia berkata, aku mendengar [Adi bin Hatim] -kami mempunyai seorang tetangga berada di Nahrain- bahwa ia bertanya kepada Nabi shallallahu 'alaihi wasallam seraya berkata, \"Aku melepas anjingku, lalu aku mendapati anjing lain bersama anjingku menangkap hewan buruan, namun aku tidak tahu di antara keduanya mana yang telah menangkap.\" Beliau bersabda: \"Janganlah kamu makan, karena kamu membacakan nama Allah untuk anjingmu, bukan anjing selain milikmu.\" Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Asy Sya'bi] dari [Adi bin Hatim] dari Nabi shallallahu 'alaihi wasallam.\""},"2016":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا مُجَالِدٌ عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَلَّمَنِي الْإِسْلَامَ وَنَعَتَ لِي الصَّلَاةَ وَكَيْفَ أُصَلِّي كُلَّ صَلَاةٍ لِوَقْتِهَا ثُمَّ قَالَ لِي كَيْفَ أَنْتَ يَا ابْنَ حَاتِمٍ إِذَا رَكِبْتَ مِنْ قُصُورِ الْيَمَنِ لَا تَخَافُ إِلَّا اللَّهَ حَتَّى تَنْزِلَ قُصُورَ الْحِيرَةِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ فَأَيْنَ مَقَانِبُ طَيِّئٍ وَرِجَالُهَا قَالَ يَكْفِيكَ اللَّهُ طَيِّئًا وَمَنْ سِوَاهَا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَتَصَيَّدُ بِهَذِهِ الْكِلَابِ وَالْبَزَاةِ فَمَا يَحِلُّ لَنَا مِنْهَا قَالَ يَحِلُّ لَكُمْ{ مَا عَلَّمْتُمْ مِنْ الْجَوَارِحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمْ اللَّهُ فَكُلُوا مِمَّا أَمْسَكْنَ عَلَيْكُمْ وَاذْكُرُوا اسْمَ اللَّهِ عَلَيْهِ }فَمَا عَلَّمْتَ مِنْ كَلْبٍ أَوْ بَازٍ ثُمَّ أَرْسَلْتَ وَذَكَرْتَ اسْمَ اللَّهِ عَلَيْهِ فَكُلْ مِمَّا أَمْسَكَ عَلَيْكَ قُلْتُ وَإِنْ قَتَلَ قَالَ وَإِنْ قَتَلَ وَلَمْ يَأْكُلْ مِنْهُ شَيْئًا فَإِنَّمَا أَمْسَكَهُ عَلَيْكَ قُلْتُ أَفَرَأَيْتَ إِنْ خَالَطَ كِلَابَنَا كِلَابٌ أُخْرَى حِينَ نُرْسِلُهَا قَالَ لَا تَأْكُلْ حَتَّى تَعْلَمَ أَنَّ كَلْبَكَ هُوَ الَّذِي أَمْسَكَ عَلَيْكَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا قَوْمٌ نَرْمِي بِالْمِعْرَاضِ فَمَا يَحِلُّ لَنَا قَالَ لَا تَأْكُلْ مَا أَصَبْتَ بِالْمِعْرَاضِ إِلَّا مَا ذَكَّيْتَ","id":"Telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Mujalid] dari [Amir] dari [Adi bin Hatim] ia berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau mengajariku tentang Islam, menjelaskan sifat shalat dan bagaimana agar aku shalat tepat pada waktunya. Kemudian beliau bertanya kepadaku: \"Bagaimana denganmu wahai Ibnu Hatim, jika kamu berkendaraan dari istana Yaman, apakah kamu tidak takut selain kepada Allah hingga kamu sampai di istana Hirah?\" aku menjawab, \"Wahai Rasulullah, lalu dimanakah posisi tentara suku Thayyi?\" beliau bersabda: \"Cukuplah Allah sebagai penjagamu dari orang-orang Thayyi dan selainnya.\" Aku berkata lagi, \"Wahai Rasulullah, kami adalah kaum yang suka berburu dengan anjing-anjing ini dan burung ini. Lalu apa yang halal bagi kami dari hasil buruannya?\" Beliau menjawab: \"Dihalalkan bagimu yang baik-baik dan (buruan yang ditangkap) oleh binatang buas yang Telah kamu ajar dengan melatih nya untuk berburu; kamu mengajarnya menurut apa yang Telah diajarkan Allah kepadamu. Maka makanlah dari apa yang ditangkapnya untukmu, dan sebutlah nama Allah atas binatang buas itu (waktu melepaskannya) '. (Qs. Al Maidah: 4) Maka anjing atau burung buas yang telah kamu latih, kemudian kamu melepasnya dan menyebut nama Allah, maka makanlah hasil buruan yang ditangkapnya untukmu.\" Aku bertanya, \"Kalau ia membunuhnya?\" beliau menjawab: \"Kalau ia membunuhnya namun tidak memakan secuil pun darinya, maka sesungguhnya ia hanya berburu untukmu.\" Aku bertanya lagi, \"Bagaimanakah menurut anda, jika anjing-anjing kami berbaur dengan anjing-anjing yang lain saat kami melepaskannya?\" beliau menjawab: \"Jangan kamu makan hingga kamu memastikan bahwa anjing milikmulah yang telah menangkapnya.\" Aku berkata, \"Wahai Rasulullah, kami kadang melempar (buruan) dengan mi'rdl (bagian tombak yang tumpul), lalu mana yang halal bagi kami?\" beliau bersabda: \"Jangan kamu makan, kecuali buruan yang sempat kamu sembelih.\""},"2017":{"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ أَبِي الْجُوَيْرِيَةِ عَنْ مَعْنِ بْنِ يَزِيدَ السُّلَمِيِّ سَمِعْتُهُ يَقُولُبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَأَبِي وَجَدِّي وَخَاصَمْتُ إِلَيْهِ فَأَفْلَجَنِي وَخَطَبَ عَلَيَّ فَأَنْكَحَنِي","id":"Telah menceritakan kepada kami [Hisyam bin Sa'id] telah mengabarkan kepada kami [Abu Awanah] dari [Abu Al Juwairiyah] dari [Ma'n bin Yazid As Sulami] aku mendengarnya berkata, \"Aku beserta bapak dan kakekku berbai'at kepada Rasulullah shallallahu 'alaihi wasallam, kemudian aku mengadu kepadanya dan beliau pun menolongku, lalu beliau menawarkan untuk menikah (lalu aku menerimanya) hingga beliau pun menikahkanku.\""},"2018":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَتَنَاوَلْتُ قِدْرًا لِأُمِّي فَاحْتَرَقَتْ يَدِي فَذَهَبَتْ بِي أُمِّي إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ يَدِي وَلَا أَدْرِي مَا يَقُولُ أَنَا أَصْغَرُ مِنْ ذَاكَ فَسَأَلْتُ أُمِّي فَقَالَتْ كَانَ يَقُولُ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ وَاشْفِ أَنْتَ الشَّافِي لَا شِفَاءَ إِلَّا شِفَاؤُكَ","id":"Telah menceritakan kepada kami [Abu Ahmad] telah menceritakan kepada kami [Isma'il] dari [Simak] dari [Muhammad bin Hathib] ia berkata, \"Aku mengambil periuk untuk ibuku, lalu tanganku terbakar. [Ibuku] kemudian membawaku menemui Nabi shallallahu 'alaihi wasallam, beliau lantas mengusap tanganku namun aku tidak tahu apa yang beliau baca, sebab waktu itu aku masih kecil. Setelah itu aku menanyakannya kepada ibuku, ia berkata, \"Beliau membaca: 'ADZHIBIL BAASA RABBAN NAASI WASYFI ANTASY SYAAFI LAA SYIFAA`A ILAA SYIFAA`UK (Hilangkanlah kepedihannya wahai Rabb-nya manusia, sembuhkanlah, Engkaulah Yang Maha Menyembuhkan, tiada kesembuhan selain kesembuhan dari-Mu).'\""},"2019":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ وَإِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ قَالَا حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَدَنَوْتُ إِلَى قِدْرٍ لَنَا فَاحْتَرَقَتْ يَدِي قَالَ إِبْرَاهِيمُ أَوْ قَالَ فَوَرِمَتْ قَالَ فَذَهَبَتْ بِي أُمِّي إِلَى رَجُلٍ فَجَعَلَ يَتَكَلَّمُ بِكَلَامٍ لَا أَدْرِي مَا هُوَ وَجَعَلَ يَنْفُثُ فَسَأَلْتُ أُمِّي فِي خِلَافَةِ عُثْمَانَ مَنْ الرَّجُلُ فَقَالَتْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Aswad bin Amir] dan [Ibrahim bin Abul Abbas] keduanya berkata, Telah menceritakan kepada kami [Syarik] dari [Simak] dari [Muhammad bin Hathib] ia berkata, \"Aku mendekati bejana hingga tanganku terbakar. Ibrahim menyebutkan, \"Hingga tangannya bengkak.\" Muhammad bin Hathib berkata, \"Kemudian Ibuku membawaku kepada seorang laki-laki, lalu laki-laki itu membaca sesuatu yang aku tidak pahami, kemudian ia meniup (tanganku). Saat pemerintahan Utsman aku bertanya kepada [ibuku], siapakah laki-laki tersebut. Ibuku lalu menjawab, \"(Dia itu) Rasulullah shallallahu 'alaihi wasallam.\""},"2020":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ قَالَكُنْتُ جَالِسًا مَعَ مُحَمَّدِ بْنِ حَاطِبٍ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي قَدْ رَأَيْتُ أَرْضًا ذَاتَ نَخْلٍ فَاخْرُجُوا فَخَرَجَ حَاطِبٌ وَجَعْفَرٌ فِي الْبَحْرِ قِبَلَ النَّجَاشِيِّ قَالَ فَوُلِدْتُ أَنَا فِي تِلْكَ السَّفِينَةِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Amru] telah menceritakan kepada kami [Abu Ishaq] dari [Abu Malik Al Asyja'i] ia berkata; aku pernah duduk bersama [Muhammad bin Hathib] lalu ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya aku telah melihat lahan yang memiliki pohon kurma, karena itu keluarlah kalian.\" Maka berangkatlah Hathib dan Ja'far dengan berlayar di laut menuju An Najasyi. Muhammad berkata, \"Maka aku dilahirkan di dalam perahu itu.\""},"2021":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ حَدَّثَنَا أَبُو بَلْجٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصْلُ مَا بَيْنَ الْحَلَالِ وَالْحَرَامِ الصَّوْتُ وَضَرْبُ الدُّفِّ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Abu Awanah] telah menceritakan kepada kami [Abu Balj] dari [Muhammad bin Hathib] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pembatas antara yang halal dan yang haram adalah bunyi suara dan pukulan rebana.\""},"2022":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَلْجٍ قَالَقُلْتُ لِمُحَمَّدِ بْنِ حَاطِبٍ إِنِّي قَدْ تَزَوَّجْتُ امْرَأَتَيْنِ لَمْ يُضْرَبْ عَلَيَّ بِدُفٍّ قَالَ بِئْسَمَا صَنَعْتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فَصْلَ مَا بَيْنَ الْحَلَالِ وَالْحَرَامِ الصَّوْتُ يَعْنِي الضَّرْبَ بِالدُّفِّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Balj] ia berkata; Aku berkata kepada [Muhammad bin Hathib], \"Sesungguhnya aku telah menikah dengan dua orang wanita, namun pernikahanku belum (dimeriahkan dengan) pukulan rebana.\" Ia lalu berkata, \"Alangkah buruk apa yang kamu lakukan. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pembatas antara halal dan haram adalah suara, yakni bunyi pukulan rebana.\""},"2023":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَوَقَعَتْ الْقِدْرُ عَلَى يَدِي فَاحْتَرَقَتْ يَدِي فَانْطَلَقَ بِي أَبِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يَتْفُلُ فِيهَا وَيَقُولُ أَذْهِبْ الْبَاسَ رَبَّ النَّاسِ وَأَحْسِبُهُ قَالَ وَاشْفِهِ إِنَّكَ أَنْتَ الشَّافِي","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Muhammad bin Hathib] ia berkata, \"Suatu saat ada periuk yang terjatuh mengenai tanganku, hingga tanganku pun terbakar. Bapakku lantas membawaku kepada Rasulullah shallallahu 'alaihi wasallam, beliau pun meniupnya dan membacakan, \"ADZHIBIL BAAS RABBAN NAASI, -dan aku menduga beliau membaca- WASYFI INNAKA ANTASY SYAAFI (Hilangkanlah kepedihannya wahai Rabb-nya manusia, sembuhkanlah, sesungguhnya Engkaulah Yang Maha Menyembuhkan).'\""},"2024":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ حَكِيمِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَمَّنْسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ دَعُوا النَّاسَ فَلْيُصِبْ بَعْضُهُمْ مِنْ بَعْضٍ فَإِذَا اسْتَنْصَحَ رَجُلٌ أَخَاهُ فَلْيَنْصَحْ لَهُ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Abu Awanah] dari [Atha` bin Sa`ib] dari [Hakim bin Abu Yazid] dari [Bapaknya] dari [seorang] yang mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tinggalkanlah manusia, sehingga sebagian mereka mendapat hak dari sebagian yang lain. Jika seorang laki-laki meminta nasihat kepada saudaranya, maka hendaknya ia menasihatinya.\""},"2025":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ قَالَكَانَ أَوَّلُ يَوْمٍ عَرَفْتُ فِيهِ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى رَأَيْتُ شَيْخًا أَبْيَضَ الرَّأْسِ وَاللِّحْيَةِ عَلَى حِمَارٍ وَهُوَ يَتْبَعُ جِنَازَةً فَسَمِعْتُهُ يَقُولُ حَدَّثَنِي فُلَانُ بْنُ فُلَانٍ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَحَبَّ لِقَاءَ اللَّهِ أَحَبَّ اللَّهُ لِقَاءَهُ وَمَنْ كَرِهَ لِقَاءَ اللَّهِ كَرِهَ اللَّهُ لِقَاءَهُ قَالَ فَأَكَبَّ الْقَوْمُ يَبْكُونَ فَقَالَ مَا يُبْكِيكُمْ فَقَالُوا إِنَّا نَكْرَهُ الْمَوْتَ قَالَ لَيْسَ ذَلِكَ وَلَكِنَّهُ إِذَا حَضَرَ{ فَأَمَّا إِنْ كَانَ مِنْ الْمُقَرَّبِينَ فَرَوْحٌ وَرَيْحَانٌ وَجَنَّةُ نَعِيمٍ }فَإِذَا بُشِّرَ بِذَلِكَ أَحَبَّ لِقَاءَ اللَّهِ وَاللَّهُ لِلِقَائِهِ أَحَبُّ{ وَأَمَّا إِنْ كَانَ مِنْ الْمُكَذِّبِينَ الضَّالِّينَ فَنُزُلٌ مِنْ حَمِيمٍ }قَالَ عَطَاءٌ وَفِي قِرَاءَةِ ابْنِ مَسْعُودٍ ثُمَّ تَصْلِيَةُ جَحِيمٍ فَإِذَا بُشِّرَ بِذَلِكَ يَكْرَهُ لِقَاءَ اللَّهِ وَاللَّهُ لِلِقَائِهِ أَكْرَهُ","id":"Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Atha` bin As Sa`ib] ia berkata, \"Pertaka kali aku mengetahui [Abdurrahman bin Abu Laila] adalah ketika aku melihat seorang laki-laki tuan yang telah memutih rambut dan jenggotnya mengendarai seekor Himar sedang mengikuti jenazah. Aku mendengar [laki-laki tua itu] berkata, \"Fulan bin Fulan menceritakan kepadaku, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mencintai untuk berjumpa dengan Allah, maka Allah mencintai perjumpaan dengannya. Dan barangsiapa membenci untuk berjumpa dengan Allah, maka Allah akan membenci perjumpaan-Nya dengannya.\" Lalu orang-orang pun menelungkup dan menangis. Maka beliau bertanya: \"Apa yang menyebabkan kalian menangis?\" mereka menjawab, \"Sesungguhnya kami membenci kematian.\" Beliau bersabda: \"Bukan itu maksudnya, akan tetapi saat kematian itu datang. '(Adapun jika dia (orang yang mati) termasuk orang-orang yang didekatkan (kepada Allah), maka ia akan memperoleh ketenteraman dan rezki serta jannah kenikmatan) ' (Qs. Al Waaqi'ah: seorang laki-laki-89). Maka saat ia diberi kabar gembira tentangnya, ia akan mencintai perjumpaannya dengan Allah, dan Allah mencintai perjumpaan dengannya. '(Dan adapun jika dia termasuk golongan yang mendustakan lagi sesat. Maka dia mendapat hidangan air yang mendidih) ' (Qs. Al Waaqi'ah: 92-92). Atha` berkata, \"Dalam qira`ah Ibnu Mas'ud; \"Kemudian Tashliayatu Jahim (api yang bergejolak). Maka jika ia diberi kabar tentangnya, ia akan membenci perjumpaan Allah, dan Allah pun lebih membenci perjumpaan dengannya.\""},"2026":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شَيْبَانُ حَدَّثَنَا مَنْصُورٌ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ سَلَمَةَ بْنِ نُعَيْمٍ قَالَ وَكَانَ مِنْ أَصْحَابِ الرَّسُولِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لَقِيَ اللَّهَ لَا يُشْرِكُ بِهِ شَيْئًا دَخَلَ الْجَنَّةَ وَإِنْ زَنَى وَإِنْ سَرَقَ","id":"Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepada kami [Syaiban] telah menceritakan kepada kami [Manshur] dari [Salim bin Abul Ja'd] dari [Salamah bin Nu'aim] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menjumpai Allah dalam keadaan tidak menyekutukan-Nya dengan sesuatu apa pun maka ia akan masuk surga, meskipun ia berzina atau mencuri.\""},"2027":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ مُجَالِدٍ عَنِ الشَّعْبِيِّ قَالَ حَدَّثَنَا عَامِرُ بْنُ شَهْرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خُذُوا مِنْ قَوْلِ قُرَيْشٍ وَدَعُوا فِعْلَهُمْ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ibnu Uyainah] dari [Mujalid] dari [Asy Sya'bi] ia berkata, Telah menceritakan kepada kami [Amir bin Syahr] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah perkataan orang-orang Quraisy dan tinggalkanlah perbuatan mereka.\""},"2028":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ إِسْمَاعِيلَ عَنْ عَطَاءٍ عَنْ عَامِرِ بْنِ شَهْرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ خُذُوا بِقَوْلِ قُرَيْشٍ وَدَعُوا فِعْلَهُمْ","id":"Telah menceritakan kepada kami [Aswad bin Amir] telah menceritakan kepada kami [Syarik] dari [Isma'il] dari [Atha`] dari [Amir bin Syahr] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ambillah perkataan orang-orang Quraisy dan tinggalkanlah perbuatan mereka.\""},"2029":{"ar":"حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ أَخْبَرَنَا شُعْبَةُ أَخْبَرَنَا أَبُو إِسْحَاقَ الْهَمْدَانِيُّ عَنْ جُرَيٍّ النَّهْدِيِّ عَنْ رَجُلٍ مِنْ بَنِي سُلَيْمٍ قَالَعَقَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَدِهِ أَوْ فِي يَدِي فَقَالَ سُبْحَانَ اللَّهِ نِصْفُ الْمِيزَانِ وَالْحَمْدُ لِلَّهِ تَمْلَأُ الْمِيزَانَ وَاللَّهُ أَكْبَرُ تَمْلَأُ مَا بَيْنَ السَّمَاءِ وَالْأَرْضِ وَالطُّهُورُ نِصْفُ الْإِيمَانِ وَالصَّوْمُ نِصْفُ الصَّبْرِ","id":"Telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah mengabarkan kepada kami [Syu'bah] telah mengabarkan kepada kami [Abu Ishaq Al Hamdani] dari [Jurai An Nahdi] dari [seorang laki-laki Bani Sulaim] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menghitung di tangannya atau di tanganku seraya bersabda: \"SUBHANALLAH (Maha Suci Allah) adalah setengah mizan, WAL HAMDULILLAH (Dan Segala puji bagi Allah) akan memenuhi timbangan, WAALLAHU AKBAR (Dan Allah Maha Besar) akan memenuhi antara langit dan bumi. Bersuci adalah setengah dari iman. Sedangkan puasa adalah setengah dari kesabaran.\""},"2030":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنِ الشَّعْبِيِّ قَالَ حَدَّثَنِي أَبُو جَبِيرَةَ بْنُ الضَّحَّاكِ قَالَفِينَا نَزَلَتْ فِي بَنِي سَلِمَةَ{ وَلَا تَنَابَزُوا بِالْأَلْقَابِ }قَالَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَلَيْسَ مِنَّا رَجُلٌ إِلَّا وَلَهُ اسْمَانِ أَوْ ثَلَاثَةٌ فَكَانَ إِذَا دُعِيَ أَحَدٌ مِنْهُمْ بِاسْمٍ مِنْ تِلْكَ الْأَسْمَاءِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ يَغْضَبُ مِنْ هَذَا قَالَ فَنَزَلَتْ{ وَلَا تَنَابَزُوا بِالْأَلْقَابِ }","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Asy Sya'bi] ia berkata, telah menceritakan kepadaku [Abu Jabirah bin Adl Dlahak] ia berkata, \"Telah turun ayat berkenaan dengan kami, yakni Bani Salamah: '(Dan jangan memanggil dengan gelaran yang mengandung ejekan..) ' (Qs. Al Hujuraat: 11). Abu Jabirah berkata, \"Saat Rasulullah shallallahu 'alaihi wasallam tiba di kota Madinah, tidak seorang laki-laki dari kami yang mempunyai nama kecuali memiliki nama lebih dari dua atau tiga. Dan jika salah seorang dari mereka dipanggil dengan salah satu nama tersebut mereka berkata, \"Wahai Rasulullah, sesungguhnya ia marah karena panggilan itu.\" Maka turunlah ayat: '(Dan jangan memanggil dengan gelaran yang mengandung ejekan) '."},"2031":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ الطَّائِيِّ قَالَ أَخْبَرَنِي مَنْ سَمِعَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَلَنْ يَهْلِكَ النَّاسُ حَتَّى يُعْذِرُوا مِنْ أَنْفُسِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Abu Al Bakhtari Ath Tha`i] ia berkata, telah mengabarkan kepadaku [seorang] yang mendengar dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Manusia tidak akan binasa sehingga mereka mencari-cari alasan dari dosa-dosa mereka.\""},"2032":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ رَجُلٍ مِنَّا مِنْ أَشْجَعَ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ خَاتَمًا مِنْ ذَهَبٍ فَأَمَرَنِي أَنْ أَطْرَحَهُ فَطَرَحْتُهُ إِلَى يَوْمِي هَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Hushain] dari [Salim bin Abul Ja'd] dari [seorang laki-laki kami] yang berasal dari Asyja', ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melihat cincin emas yang aku kenakan, lalu beliau memerintahkanku untuk menanggalkannya, maka aku pun menanggalkannya hingga hariku ini.\""},"2033":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَبِي بُرْدَةَ عَنِ الْأَغَرِّ الْمُزَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ لَيُغَانُ عَلَى قَلْبِي وَإِنِّي لَأَسْتَغْفِرُ اللَّهَ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Abu Kamil] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit Al Bunani] dari [Abu Burdah] dari [Al Aghar Al Muzani] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hatiku benar-benar diliputi sesuatu, dan sungguh dalam sehari aku minta ampun kepada Allah sebanyak seratus kali.\""},"2034":{"ar":"حَدَّثَنَا وَهْبٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي بُرْدَةَ أَنَّهُ سَمِعَ الْأَغَرَّ الْمُزَنِيَّ يُحَدِّثُ ابْنَ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى رَبِّكُمْ فَإِنِّي أَتُوبُ إِلَى اللَّهِ عَزَّ وَجَلَّ كُلَّ يَوْمٍ مِائَةَ مَرَّةٍ","id":"Telah menceritakan kepada kami [Wahb] telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Abu Burdah] bahwa ia mendengar [Al Aghar Al Muzani] menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Wahai sekalian manusia, bertaubatlah kepada Rabb kalian. Sesungguhnya aku bertaubat kepada Allah 'azza wajalla setiap hari seratus kali.\""},"2035":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا يُونُسُ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى اللَّهِ وَاسْتَغْفِرُوهُ فَإِنِّي أَتُوبُ إِلَى اللَّهِ وَأَسْتَغْفِرُهُ فِي كُلِّ يَوْمٍ مِائَةَ مَرَّةٍ فَقُلْتُ لَهُ اللَّهُمَّ إِنِّي أَسْتَغْفِرُكَ اللَّهُمَّ إِنِّي أَتُوبُ إِلَيْكَ اثْنَتَانِ أَمْ وَاحِدَةٌ فَقَالَ هُوَ ذَاكَ أَ��ْ نَحْوَ هَذَا","id":"Telah menceritakan kepada kami [Isma'il] telah menceritakan kepada kami [Yunus] dari [Humaid bin Hilal] dari [Abu Burdah] dari [seorang laki-laki] sahabat Nabi shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai sekalian manusia, bertaubatlah dan beristighfarlah kepada Allah, sesungguhnya aku bertaubat dan beristighfar kepada-Nya seratus kali setiap hari.\" Aku berkata, \"ALLAHUMMA INNII ASTAGHFIRUKA (Ya Allah aku meminta ampun pada-Mu), ALLAHUMMA INNII ATUUBU ILAIK (Ya Allah, aku bertaubat pada-Mu). Kedua-duanya atau hanya satu?\" beliau bersabda: \"Begitulah, atau yang semisalnya.\""},"2036":{"ar":"حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ أَيُّوبَ قَالَ وَحَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ الطُّفَاوِيُّ قَالَ حَدَّثَنَا أَيُّوبُ الْمَعْنَي عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ أَبِي بُرْدَةَ عَنْ رَجُلٍ مِنْ الْمُهَاجِرِينَ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا أَيُّهَا النَّاسُ تُوبُوا إِلَى اللَّهِ وَاسْتَغْفِرُوهُ فَإِنِّي أَتُوبُ إِلَى اللَّهِ وَأَسْتَغْفِرُهُ فِي كُلِّ يَوْمٍ مِائَةَ مَرَّةٍ أَوْ أَكْثَرَ مِنْ مِائَةِ مَرَّةٍ","id":"Telah menceritakan kepada kami [Mu'tamir] ia berkata, aku mendengar [Ayyub] berkata, dan Telah menceritakan kepada kami [Muhammad bin Abdurrahman Ath Thufawi] ia berkata, Telah menceritakan kepada kami [Ayyub Al Ma'na] dari [Humaid bin Hilal] dari [Abu Burdah] dari [seorang laki-laki Muhajirin] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai sekalian manusia, bertaubatlah dan beristighfarlah kepada Allah. Sesungguhnya aku bertaubat dan beristighfar kepada-Nya seratus kali setiap hari, atau lebih dari itu.\""},"2037":{"ar":"حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ حَدَّثَنِي زِيَادُ بْنُ عِلَاقَةَ عَنْ عَرْفَجَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَكُونُ هَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ الْمُسْلِمِينَ وَهُمْ جَمِيعٌ فَاضْرِبُوهُ بِالسَّيْفِ كَائِنًا مَنْ كَانَحَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ الْأَشْجَعِيِّ أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ وَقَالَ شَيْبَانُ ابْنِ شُرَيْحٍ الْأَسْلَمِيِّ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yahya] dari [Syu'bah] telah menceritakan kepadaku [Ziyad bin Ilaqah] dari [Arfajah] ia berkata, aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Akan terjadi fitnah dan perkara yang diada-adakan. Akan terjadi fitnah dan perkara yang diada-adakan. Maka barangsiapa ingin memecah belah urusan kaum muslimin yang telah bersatu, maka bunuhlah siapa pun orangnya.\" Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin Alaqah] dari [Arfajah Al Asyja'i], bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda -Syaiban bin Syuraih Al Aslami berkata-, lalu ia pun menyebutkan hadits tersebut.\""},"2038":{"ar":"حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا أَبُو بَكْرِ بْنُ عُمَارَةَ بْنِ رُوَيْبَةَ عَنْ أَبِيهِ قَالَسَأَلَهُ رَجُلٌ مِنْ أَهْلِ الْبَصْرَةِ قَالَ أَخْبِرْنِي مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَلِجُ النَّارَ أَحَدٌ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ أَنْ تَغْرُبَقَالَ آنْتَ سَمِعْتَهُ مِنْهُ قَالَ سَمِعَتْ أُذُنَايَ وَوَعَاهُ قَلْبِي فَقَالَ الرَّجُلُ وَاللَّهِ لَقَدْ سَمِعْتُهُ يَقُولُ ذَلِكَ","id":"Telah menceritakan kepada kami [Yahya] dari [Isma'il] Telah menceritakan kepada kami [Abu Bakr bin Umarah bin Ruwaibah] dari [Bapaknya] ia berkata, \"Aku bertanya kepada seorang laki-laki penduduk Bashrah, \"Kabarkanlah kepadaku apa yang telah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam.\" Ia pun berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk neraka seorang yang shalat sebelum terbitnya matahari dan sebelum terbenamnya.\" Ibnu Ruwaibah berkata, \"Apakah kamu mendengarnya dari beliau?\" Laki-laki itu menjawab, \"Kedua telingaku mendengarnya dan hatiku memahami dan menghafalnya.\" Kemudian laki-laki itu berkata lagi, \"Demi Allah, aku telah mendengar beliau mengatakan hal itu.\""},"2039":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ قَالَ وَحَدَّثَنَا مِسْعَرٌ قَالَ وَحَدَّثَنَا الْبَخْتَرِيُّ بْنُ الْمُخْتَارِ عَنْ أَبِي بَكْرِ بْنِ عُمَارَةَ بْنِ رُوَيْبَةَ الثَّقَفِيِّ سَمِعُوهُ عَنْ أَبِيهِ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَنْ يَلِجَ النَّارَ رَجُلٌ صَلَّى قَبْلَ طُلُوعِ الشَّمْسِ وَقَبْلَ غُرُوبِهَافَقَالَ رَجُلٌ مِنْ أَهْلِ الْبَصْرَةِ آنْتَ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قَالَ أَشْهَدُ لَسَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ibnu Abu Khalid] ia berkata, dan Telah menceritakan kepada kami [Mis'ar] ia berkata, Telah menceritakan kepada kami [Al Bakhtari bin Al Mukhtar] dari [Abu Bakr bin Umarah bin Ruwaibah Ats Tsaqafi] mereka mendengarnya dari [Bapaknya] ia berkata, \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan masuk neraka seorang laki-laki yang shalat sebelum terbitnya matahari dan sebelum terbenamnya.\" Seorang laki-laki dari penduduk Bashrah lantas berkata, \"Apakah kamu mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" Ia berkata, \"Benar. Sungguh aku bersaksi bahwa kedua telingaku telah mendengarnya dan hatiku menghafalnya.\""},"2040":{"ar":"حَدَّثَنَا ابْنُ فُضَيْلٍ حَدَّثَنَا حُصَيْنٌ عَنْ عُمَارَةَ بْنِ رُوَيْبَةَ أَنَّهُرَأَى بِشْرَ بْنَ مَرْوَانَ عَلَى الْمِنْبَرِ رَافِعًا يَدَيْهِ يُشِيرُ بِإِصْبَعَيْهِ يَدْعُو فَقَالَ لَعَنَ اللَّهُ هَاتَيْنِ الْيُدَيَّتَيْنِ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَدْعُو وَهُوَ يُشِيرُ بِإِصْبَعٍ","id":"Telah menceritakan kepada kami [Ibnu Fudlail] telah menceritakan kepada kami [Hushain] dari [Umarah bin Ruwaibah], bahwa ia melihat Bisyr bin Marwan berada di atas mimbar mengangkat kedua tangannya berdoa seraya berisyarat dengan dua jarinya. Maka Umarah pun berkata, \"Semoga Allah melaknati dua tangan ini, aku melihat Rasulullah shallallahu 'alaihi wasallam berada di atas mimbar berdo'a berisyarat dengan menggunakan satu jarinya.\""},"2041":{"ar":"حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا عَامِرٌ قَالَ حَدَّثَنِي أَوْ أَخْبَرَنِي عُرْوَةُ بْنُ مُضَرِّسٍ الطَّائِيُّ قَالَجِئْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَوْقِفِ فَقُلْتُ جِئْتُ يَا رَسُولَ اللَّهِ مِنْ جَبَلَيْ طَيِّئٍ أَكْلَلْتُ مَطِيَّتِي وَأَتْعَبْتُ نَفْسِي وَاللَّهِ مَا تَرَكْتُ مِنْ جَبَلٍ إِلَّا وَقَفْتُ عَلَيْهِ هَلْ لِي مِنْ حَجٍّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَدْرَكَ مَعَنَا هَذِهِ الصَّلَاةَ وَأَتَى عَرَفَاتٍ قَبْلَ ذَلِكَ لَيْلًا أَوْ نَهَارًا تَمَّ حَجُّهُ وَقَضَى تَفَثَهُ","id":"Telah menceritakan kepada kami [Yahya] dari [Isma'il] telah menceritakan kepada kami [Amir] ia berkata, telah menceritakan kepadaku, atau telah mengabarkan kepadaku [Urwah bin Mudlarris Ath Tha`i] ia berkata, \"Aku mendatangi Rasulullah shallallahu 'alaihi wasallam di tempat wukuf, lalu aku berkata, \"Wahai Rasulullah, aku datang dari pegunungan Thayyi`, lalu hewan tungganganku kelelahan dan aku pun merasa letih. Demi Allah, aku tidak pernah meninggalkan satu pegunungan pun kecuali aku berhenti dan istirahat. Apakah aku mendapatkan pahala haji.?\" Beliau menjawab: \"Barangsiapa mendapati shalat (subuh) ini bersama kami, lalu sebelum itu ia telah datang ke Arafah baik pada malam atau pun siang hari, maka hajinya telah sempurnya dan boleh untuk bertahallul.\""},"2042":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ عُرْوَةَ بْنِ مُضَرِّسِ بْنِ حَارِثَةَ بْنِ لَامٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِجَمْعٍ فَقُلْتُ لَهُ هَلْ لِي مِنْ حَجٍّ فَقَالَ مَنْ صَلَّى مَعَنَا هَذِهِ الصَّلَاةَ فِي هَذَا الْمَكَانِ ثُمَّ وَقَفَ مَعَنَا هَذَا الْمَوْقِفَ حَتَّى يُفِيضَ الْإِمَامُ أَفَاضَ قَبْلَ ذَلِكَ مِنْ عَرَفَاتٍ لَيْلًا أَوْ نَهَارًا فَقَدْ تَمَّ حَجُّهُ وَقَضَى تَفَثَهُحَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ يُحَدِّثُ عَنْ عُرْوَةَ بْنِ مُضَرِّسِ بْنِ أَوْسِ بْنِ حَارِثَةَ بْنِ لَامٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَهُ حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ عَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ حَدَّثَنِي قَالَ سَمِعْتُ الشَّعْبِيَّ عَنْ عُرْوَةَ بْنِ الْمُضَرِّسِ بْنِ أَوْسِ بْنِ حَارِثَةَ بْنِ لَامٍ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِجَمْعٍ فَذَكَرَ مِثْلَ حَدِيثِ رَوْحٍ","id":"Telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Syu'bah] ia berkata, aku mendengar [Abdullah bin Abu As Safar] ia berkata, aku mendengar [Asy Sya'bi] dari [Urwah bin Mudlarris bin Haritsah bin Lam] ia berkata, \"Aku datang menemui Rasulullah shallallahu 'alaihi wasallam saat beliau berada dalam sekerumunan orang. Aku lalu bertanya kepada beliau, \"Apakah aku mendapatkan pahala haji?\" Beliau bersabda: \"Barangsiapa menunaikan shalat (subuh) ini bersama kami di tempat ini, lalu melakukan wukuf bersama kami di tempat wukuf ini hingga Imam keluar, dan sebelumnya ia telah keluar dari Arafah pada malam hari atau siang hari, maka hajinya telah sempurna dan boleh bertahallul.\" Telah menceritakan kepada kami [Abu An Nadlr] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] ia berkata, aku mendengar [Asy Sya'bi] menceritakan dari [Urwah bin Mudlarris bin Aus bin Haritsah bin Lam] ia berkata, \"Aku mendatangi Nabi shallallahu 'alaihi wasallam…lalu ia menyebutkan hadits itu.\" Telah menceritakan kepada kami [Affan] telah menceritakan kepada kami [Syu'bah] berkata, [Abdullah bin Abu As Safar] menceritakan kepadaku, ia berkata; aku mendengar [Asy Sya'bi] dari [Urwah bin Al Mudlarris bin Aus bin Haritsah bin Lam] ia berkata, \"Aku datang menemui Nabi shallallahu 'alaihi wasallam saat beliau berada dalam suatu kerumunan orang…lalu ia menyebutkan seperti hadits Rauh.\""},"2043":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَ حَدَّثَنَا عُرْوَةُ بْنُ مُضَرِّسٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِجَمْعٍ فَقُلْتُ يَا رَسُولَ اللَّهِ هَلْ لِي مِنْ حَجٍّ فَقَالَ مَنْ صَلَّى مَعَنَا هَذِهِ الصَّلَاةَ فِي هَذَا الْمَكَانِ وَوَقَفَ مَعَنَا هَذَا الْمَوْقِفَ حَتَّى يُفِيضَ أَفَاضَ قَبْلَ ذَلِكَ مِنْ عَرَفَاتٍ لَيْلًا أَوْ نَهَارًا فَقَدْ تَمَّ حَجُّهُ وَقَضَى تَفَثَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata, Telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu Safar] ia berkata, aku mendengar [Asy Sya'bi] berkata, Telah menceritakan kepada kami [Urwah bin Mudlarris] ia berkata, \"Aku datang menemui Rasulullah shallallahu 'alaihi wasallam saat beliau berada dalam suatu kerumunan orang, aku lantas bertanya, \"Wahai Rasulullah, apakah aku mendapat pahala haji?\" beliau bersabda: \"Barangsiapa menunaikan shalat (subuh) ini bersama kami di tempat ini, lalu melakukan wukuf bersama kami di tempat wukuf ini hingga ia keluar, dan sebelumnya ia telah keluar dari Arafah pada malam hari atau siang hari, maka hajinya telah sempurnya dan boleh untuk bertahallul.\""},"2044":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِيهِ قَالَرَآنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ وَأَنَا فِي الشَّمْسِ فَأَمَرَنِي فَحَوَّلْتُ إِلَى الظِّلِّ","id":"Telah menceritakan kepada kami [Waki'] ia berkata, Telah menceritakan kepada kami [Ibnu Abu Khalid] dari [Qais bin Abu Hazim] dari [Bapaknya] ia berkata, \"Saat Nabi shallallahu 'alaihi wasallam sedang berkhutbah beliau melihatku berada di bawah terik matahari, beliau lalu menyuruhku untuk bernaung.\""},"2045":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ بَشِيرِ بْنِ سَلْمَانَ عَنِ الْقَاسِمِ بْنِ صَفْوَانَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبْرِدُوا بِالظُّهْرِ فَإِنَّ شِدَّةَ الْحَرِّ مِنْ فَيْحِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Waki'] dari [Basyir bin Salman] dari [Al Qasim bin Shafwan] dari [Bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Akhirkanlah shalat zhuhur hingga udara menjadi dingin, sebab teriknya matahari adalah hembusan dari neraka jahannam.\""},"2046":{"ar":"حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا أَبُو إِسْمَاعِيلَ يَعْنِي بَشِيرًا عَنِ الْقَاسِمِ بْنِ صَفْوَانَ الزُّهْرِيِّ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَبْرِدُوا بِصَلَاةِ الظُّهْرِ فَإِنَّ الْحَرَّ مِنْ فَوْرِ جَهَنَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Ubaid] telah menceritakan kepada kami [Abu Isma'il] -yakni Basyir- dari [Al Qasim bin Shafwan Az Zuhri] dari [Bapaknya] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: Akhirkanlah shalat zhuhur hingga udara menjadi dingin, sebab teriknya matahari adalah hembusan dari neraka jahannam.\""},"2047":{"ar":"حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي أَبُو إِسْحَاقَ قَالَ سَمِعْتُ سُلَيْمَانَ بْنَ صُرَدٍ يَقُولُ قَالَ وَحَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ قَالَ يَحْيَى يَعْنِي يَوْمَ الْخَنْدَقِ الْآنَ نَغْزُوهُمْ وَلَا يَغْزُونَا","id":"Telah menceritakan kepada kami [Yahya] dari [Sufyan] ia berkata, telah menceritakan kepadaku [Abu Ishaq] ia berkata, aku mendengar [Sulaiman bin Shurad] berkata, (Abdullah bin Ahmad) berkata, Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Sulaiman bin Shurad] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda pada hari Ahzab -Yahya menyebutkan pada perang Khandaq-: \"Pada hari ini kita akan memerangi mereka, dan mereka tidak akan memerangi kita lagi.\""},"2048":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَاقَ عَنْ سُلَيْمَانَ بْنِ صُرَدٍ قَالَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَحْزَابِ قَالَ الْآنَ نَغْزُوهُمْ وَلَا يَغْزُونَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] ia berkata, aku mendengar [Abu Ishaq] dari [Sulaiman bin Shurad] ia berkata, \"Ketika Rasulullah shallallahu 'alaihi wasallam berangkat pada hari terjadinya perang Ahzab, beliau bersabda: \"Pada hari ini kita akan memerangi mereka, dan mereka tidak akan memerangi kita lagi.\""},"2049":{"ar":"وَمِمَّا اجْتَمَعَ فِيهِ سُلَيْمَانُ بْنُ صُرَدٍ وَخَالِدُ بْنُ عُرْفُطَةَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَامِعِ بْنِ شَدَّادٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ قَالَكُنْتُ جَالِسًا مَعَ سُلَيْمَانَ بْنِ صُرَدٍ وَخَالِدِ بْنِ عُرْفُطَةَ وَهُمَا يُرِيدَانِ أَنْ يَتْبَعَا جِنَازَةَ مَبْطُونٍ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ أَلَمْ يَقُلْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَقْتُلُهُ بَطْنُهُ فَلَنْ يُعَذَّبَ فِي قَبْرِهِ فَقَالَ بَلَى","id":"Dan di antara hadits yang sama-sama diriwayatkan oleh Sulaiman bin Shurad dan Khalid bin Urfuthah; Telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Jami' bin Syaddad] dari [Abdullah bin Yasar] ia berkata, aku pernah duduk bersama [Sulaiman bin Shurad] dan [Khalid bin Urfuthah] sedangkan keduanya ingin mengikuti jenazah orang yang mati lantaran sakit perut. Kemudian salah seorang dari keduanya berkata kepada temannya, \"Bukankah Rasulullah shallallahu 'alaihi wasallam pernah bersabda: 'Barangsiapa dibunuh oleh perutnya (mati lantaran sakit perut), maka di dalam kubur ia tidak akan disiksa?.\" Maka temannya menjawab, \"Benar.\""},"2050":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي جَامِعُ بْنُ شَدَّادٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَسَارٍ قَالَكَانَ سُلَيْمَانُ بْنُ صُرَدٍ وَخَالِدُ بْنُ عُرْفُطَةَ قَاعِدَيْنِ قَالَ فَذُكِرَ أَنَّ رَجُلًا مَاتَ بِالْبَطْنِ فَقَالَ أَحَدُهُمَا لِصَاحِبِهِ أَمَا سَمِعْتَ أَوَمَا بَلَغَكَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَهُ بَطْنُهُ فَلَنْ يُعَذَّبَ فِي قَبْرِهِ قَالَ الْآخَرُ بَلَى","id":"Telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Jami' bin Syaddad] ia berkata, aku mendengar [Abdullah bin Yasar] berkata; [Sulaiman bin Shurad] dan [Khalid bin Urfuthah] pernah duduk-duduk bersama, lalu disebutkanlah bahwa ada seorang laki-laki yang meninggal karena sakit perut. Maka salah satu dari keduanya berkata kepada temannya, \"Tidakkah kamu pernah mendengar, atau ia mengatakan, \"Tidakkah telah sampai berita kepadamu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dibunuh oleh perutnya (mati karena sakit perut), maka ia tidak akan disiksa di dalam kuburnya.\" Maka yang lainnya menjawab, \"Benar.\""},"2051":{"ar":"حَدَّثَنَا قُرَانٌ حَدَّثَنَا سَعِيدٌ الشَّيْبَانِيُّ أَبُو سِنَانٍ عَنْ أَبِي إِسْحَاقَ قَالَمَاتَ رَجُلٌ صَالِحٌ فَأُخْرِجَ بِجِنَازَتِهِ فَلَمَّا رَجَعْنَا تَلَقَّانَا خَالِدُ بْنُ عُرْفُطَةَ وَسُلَيْمَانُ بْنُ صُرَدٍ وَكِلَاهُمَا قَدْ كَانَتْ لَهُ صُحْبَةٌ فَقَالَا سَبَقْتُمُونَا بِهَذَا الرَّجُلِ الصَّالِحِ فَذَكَرُوا أَنَّهُ كَانَ بِهِ بَطْنٌ وَأَنَّهُمْ خَشُوا عَلَيْهِ الْحَرَّ قَالَ فَنَظَرَ أَحَدُهُمَا إِلَى صَاحِبِهِ فَقَالَ أَمَا سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ قَتَلَهُ بَطْنُهُ لَمْ يُعَذَّبْ فِي قَبْرِهِ","id":"Telah menceritakan kepada kami [Qurran] telah menceritakan kepada kami [Sa'id Asy Syaibani Abu Sinan] dari [Abu Ishaq] ia berkata, \"Seorang laki-laki shalih meninggal dunia, lalu jenazahnya diberangkatkan. Ketika pulang kami berjumpa dengan [Khalid bin Urfuthah] dan [Sulaiman bin Shurad] -keduanya termasuk sahabat Nabi shallallahu 'alaihi wasallam-, maka kedua berkata, \"Kalian telah mendahului kami mengantar jenazah laki-laki shalih ini.\" Lalu orang-orang menuturkan bahwa laki-laki itu meninggal lantaran sakit perut, dan mereka khawatir laki-laki itu akan ditimpa panasnya (siksa kubur). Maka salah satu dari keduanya memandang ke arah temannya seraya bertanya, \"Tidakkah kamu telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa dibunuh oleh perutnya (mati lantaran sakit perut), maka ia tidak akan disiksa di dalam kuburnya.'\""},"2052":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي نَضْرَةَ عَنْ قَيْسِ بْنِ عَبَّادٍ قَالَقُلْتُ لِعَمَّارِ بْنِ يَاسِرٍ يَا أَبَا الْيَقْظَانِ أَرَأَيْتَ هَذَا الْأَمْرَ الَّذِي أَتَيْتُمُوهُ بِرَأْيِكُمْ أَوْ شَيْءٌ عَهِدَهُ إِلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ","id":"Telah menceritakan kepada kami [Abdush Shamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Abu An Nadlrah] dari [Qais bin Abbad] ia berkata, aku berkata kepada [Ammar bin Yasir], \"Wahai Abu Yaqzhan, bagaimana pendapatmu tentang perkara yang kalian telah lakukan ini, apakah ia muncul dari pendapat kalian atau sesuatu yang telah dipesankan Rasulullah shallallahu 'alaihi wasallam kepada kalian?\" maka ia pun menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah berpesan kepada kami tentang sesuatu pun yang belum beliau pesankan kepada umat.\""},"2053":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ عَيَّاشٍ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ نَاجِيَةَ الْعَنَزِيِّ قَالَتَدَارَأَ عَمَّارٌ وَعَبْدُ اللَّهِ بْنُ مَسْعُودٍ فِي التَّيَمُّمِ فَقَالَ عَبْدُ اللَّهِ لَوْ مَكَثْتُ شَهْرًا لَا أَجِدُ فِيهِ الْمَاءَ لَمَا صَلَّيْتُ فَقَالَ لَهُ عَمَّارٌ أَمَا تَذْكُرُ إِذْ كُنْتُ أَنَا وَأَنْتَ فِي الْإِبِلِ فَأَجْنَبْتُ فَتَمَعَّكْتُ تَمَعُّكَ الدَّابَّةِ فَلَمَّا رَجَعْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِالَّذِي صَنَعْتُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ التَّيَمُّمُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Ayyasy] telah menceritakan kepada kami [Abu Ishaq] dari [Najiyah Al Anazi] ia berkata, [Ammar] dan Abdullah bin Mas'ud saling berdebat tentang tayammum. Abdullah berkata, \"Sekiranya aku tinggal selama sebulan dan tidak mendapat air, niscaya aku tidak akan shalat.\" Ammar lalu berkata kepadanya, \"Tidakkah kamu ingat saat aku dan kamu dalam perang jamal, aku junub kemudian aku berguling-guling di atas debu sebagaimana binatang yang berguling-guling. Saat kembali kepada Rasulullah shallallahu 'alaihi wasallam, aku lalu mengabarkan apa yang telah aku lakukan, dan beliau pun bersabda: \"Sesungguhnya kamu cukup melakukan tayammum.\""},"2054":{"ar":"حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الْمَلِكِ بْنِ أَبِي غَنِيَّةَ قَالَ حَدَّثَنَا عُقْبَةُ بْنُ الْمُغِيرَةِ عَنْ جَدِّ أَبِيهِ الْمُخَارِقِ قَالَلَقِيتُ عَمَّارًا يَوْمَ الْجَمَلِ وَهُوَ يَبُولُ فِي قَرْنٍ فَقُلْتُ أُقَاتِلُ مَعَكَ فَأَكُونُ مَعَكَ قَالَ قَاتِلْ تَحْتَ رَايَةِ قَوْمِكَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَسْتَحِبُّ لِلرَّجُلِ أَنْ يُقَاتِلَ تَحْتَ رَايَةِ قَوْمِهِ","id":"Telah menceritakan kepada kami [Yahya bin Abdul Malik bin Abu Ghaniyyah] ia berkata, Telah menceritakan kepada kami [Uqbah bin Al Mughirah] dari kakek bapaknya [Al Mukhariq] ia berkata, \"Aku berjumpa [Ammar] saat terjadi perang Jamal, saat itu ia sedang kencing di Qarn. Aku berkata kepadanya, \"Aku ingin berperang bersamamu sehingga aku selalu bersamamu.\" Ia lalu berkata, \"Berperanglah di bawah bendera kaummu. Karena Rasulullah shallallahu 'alaihi wasallam menyukai seorang laki-laki yang berperang di bawah bendera kaumnya.\""},"2055":{"ar":"حَدَّثَنَا قُرَيْشُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبْجَرَ عَنْ أَبِيهِ عَنْ وَاصِلِ بْنِ حَيَّانَ قَالَ قَالَ أَبُو وَائِلٍخَطَبَنَا عَمَّارٌ فَأَبْلَغَ وَأَوْجَزَ فَلَمَّا نَزَلَ قُلْنَا يَا أَبَا الْيَقْظَانِ لَقَدْ أَبْلَغْتَ وَأَوْجَزْتَ فَلَوْ كُنْتَ تَنَفَّسْتَ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ طُولَ صَلَاةِ الرَّجُلِ وَقِصَرَ خُطْبَتِهِ مَئِنَّةٌ مِنْ فِقْهِهِ فَأَطِيلُوا الصَّلَاةَ وَأَقْصِرُوا الْخُطْبَةَ فَإِنَّ مِنْ الْبَيَانِ لَسِحْرًا","id":"Telah menceritakan kepada kami [Quraisy bin Ibrahim] telah menceritakan kepada kami [Abdurrahman bin Abdul Malik bin Abjar] dari [Bapaknya] dari [Washil bin Hayyan] ia berkata, [Abu Wa`il] berkata, \"Ammar pernah berkhutbah di hadapan kami dengan khutbah yang singkat menyentuh hati. Saat ia turun, maka kami berkata, \"Wahai Abu Yaqzhan, sungguh kamu telah menyampaikan khutbah yang menyentuh namun ringkas, sekiranya kamu mau memangjangkan (khutbah).\" Ammar lalu berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, panjangnya shalat dan ringkasnya khutbah yang disampaikan oleh seseorang adalah tanda kefakihannya. Maka panjangkanlah shalat dan ringkaskanlah khutbah. Dan sungguh di antara indahnya penjelasan adalah bagian dari sihir.\""},"2056":{"ar":"حَدَّثَنَا عَفَّانُ وَيُونُسُ قَالَا حَدَّثَنَا أَبَانُ حَدَّثَنَا قَتَادَةُ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يُونُسُ إِنَّهُ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّيَمُّمِ فَقَالَ ضَرْبَةٌ لِلْكَفَّيْنِ وَالْوَجْهِ وَقَالَ عَفَّانُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي التَّيَمُّمِ ضَرْبَةٌ لِلْوَجْهِ وَالْكَفَّيْنِ","id":"Telah menceritakan kepada kami [Affan] dan [Yunus] kedua berkata, Telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Qatadah] dari [Azrah] dari [Sa'id bin Abdurrahman bin Abza] dari [Bapaknya] dari [Ammar bin Yasir] bahwa Nabi shallallahu 'alaihi wasallam, [Yunus] menyebutkan bahwa Ammar bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang tayammum. Maka beliau bersabda: \"Satu tepukan untuk dua telapak tangan dan wajah.\" [Affan] menyebutkan, \"Nabi shallallahu 'alaihi wasallam bersabda tentang tayammum: \"Satu tepukan untuk wajah dan dua telapak tangan.\""},"2057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ حَدَّثَنَا إِسْرَائِيلُ عَنْ سِمَاكٍ عَنْ ثَرْوَانَ بْنِ مِلْحَانَ قَالَكُنَّا جُلُوسًا فِي الْمَسْجِدِ فَمَرَّ عَلَيْنَا عَمَّارُ بْنُ يَاسِرٍ فَقُلْنَا لَهُ حَدِّثْنَا مَا سَمِعْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي الْفِتْنَةِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَكُونُ بَعْدِي قَوْمٌ يَأْخُذُونَ الْمُلْكَ يَقْتُلُ عَلَيْهِ بَعْضُهُمْ بَعْضًاقَالَ قُلْنَا لَهُ لَوْ حَدَّثَنَا غَيْرُكَ مَا صَدَّقْنَاهُ قَالَ فَإِنَّهُ سَيَكُونُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Zubair] Telah menceritakan kepada kami [Isra`il] dari [Simak] dari [Tsarwan bin Milhan] ia berkata, \"Saat kami duduk-duduk di Masjid, lewatlah [Ammar bin Yasir]. Maka kami berkata, \"Ceritakanlah kepada kami apa yang telah kamu dengar dari Rasulullah shallallahu 'alaihi wasallam tentang fitnah.\" Ammar berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan ada setelahku suatu kaum yang merampas kekuasaan dengan saling membunuh satu sama lain.\" Tsarwan berkata, \"Kami lalu berkata kepadanya, \"Sekiranya yang menceritakan kepadaku bukan engkau maka kami tidak akan mempercayainya.\" Ammar berkata, \"Itu benar-benar akan terjadi.\""},"2058":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ قَالَ ابْنُ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ عَنِ ابْنِ عَبَّاسٍ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَّسَ بِأُوَلَاتِ الْجَيْشِ وَمَعَهُ عَائِشَةُ زَوْجَتُهُ فَانْقَطَعَ عِقْدٌ لَهَا مِنْ جَزْعِ ظَفَارِ فَحُبِسَ النَّاسُ ابْتِغَاءَ عِقْدِهَا وَذَلِكَ حَتَّى أَضَاءَ الْفَجْرُ وَلَيْسَ مَعَ النَّاسِ مَاءٌ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ عَلَى رَسُولِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُخْصَةَ التَّطَهُّرِ بِالصَّعِيدِ الطَّيِّبِ فَقَامَ الْمُسْلِمُونَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَرَبُوا بِأَيْدِيهِمْ الْأَرْضَ ثُمَّ رَفَعُوا أَيْدِيَهُمْ وَلَمْ يَقْبِضُوا مِنْ التُّرَابِ شَيْئًا فَمَسَحُوا بِهَا وُجُوهَهُمْ وَأَيْدِيَهُمْ إِلَى الْمَنَاكِبِ وَمِنْ بُطُونِ أَيْدِيهِمْ إِلَى الْآبَاطِ وَلَا يَغْتَرُّ بِهَذَا النَّاسُوَبَلَغَنَا أَنَّ أَبَا بَكْرٍ قَالَ لِعَائِشَةَ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا وَاللَّهِ مَا عَلِمْتُ إِنَّكِ لَمُبَارَكَةٌ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [Bapakku] dari [Shalih] ia berkata, [Ibnu Syihab] berkata, telah menceritakan kepadaku [Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Ammar bin Yasir], bahwa Rasulullah shallallahu 'alaihi wasallam mengistirahatkan pasukan pada akhir malam. Dan saat itu beliau bersama isterinya, Aisyah radliallahu 'anha. Kemudian kalung milik Aisyah terputus karena kesedihan mendalam (yang terjadi di) Zhafar, maka para sahabat pun berusaha mencari kalungnya hingga cahaya subuh memancar. Sementara mereka tidak memiliki persediaan air. Maka Allah 'azza wajalla menurunkan kepada Rasul-Nya shallallahu 'alaihi wasallam keringanan untuk bersuci dengan debu yang suci. Akhirnya kaum muslimin melaksanakan shalat bersama Rasulullah shallallahu 'alaihi wasallam, mereka menepukkan kedua tangannya ke atas tanah dan mengangkat keduanya tanpa menggenggam sesuatu pun dari tanah, lalu mengusapkannya pada wajah dan kedua tangannya hingga ke pundak, kemudian dari tangan bagian hingga hingga ketiak. Kaum muslimin pun tidak tertipu dengan ini, telah sampai (berita) pada kami, bahwa Abu Bakar berkata kepada Aisyah radliallahu 'anha, \"Demi Allah, aku tidak tahu jika kami akan membawa berkah.\""},"2059":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ حَدَّثَنِي مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ الْحَارِثِ التَّيْمِيُّ عَنْ عُمَرَ بْنِ الْحَكَمِ بْنِ ثَوْبَانَ عَنِ ابْنِ لَاسٍ الْخُزَاعِيِّ قَالَ دَخَلَ عَمَّارُ بْنُ يَاسِرٍ الْمَسْجِدَ فَرَكَعَ فِيهِ رَكْعَتَيْنِ أَخَفَّهُمَا وَأَتَمَّهُمَا قَالَ ثُمَّ جَلَسَ فَقُمْنَا إِلَيْهِ فَجَلَسْنَا عِنْدَهُ ثُمَّ قُلْنَا لَهُ لَقَدْ خَفَّفْتَ رَكْعَتَيْكَ هَاتَيْنِ جِدًّا يَا أَبَا الْيَقْظَانِ فَقَالَ إِنِّي بَادَرْتُ بِهِمَا الشَّيْطَانَ أَنْ يَدْخُلَ عَلَيَّ فِيهِمَا قَالَ فَذَكَرَ الْحَدِيثَ حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ قَالَصَلَّى عَمَّارٌ صَلَاةً فَجَوَّزَ فِيهَا فَسُئِلَ أَوْ فَقِيلَ لَهُ فَقَالَ مَا خَرَمْتُ مِنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [Bapakku] dari [Muhammad bin Ishaq] telah menceritakan kepadaku [Muhammad bin Ibrahim bin Harits At Taimi] dari [Umar bin Al Hakam bin Tsauban] dari [Ibnu Las Al Khuza'i] ia berkata, \" [Ammar bin Yasir] masuk masjid lalu shalat dua rakaat, ia kerjakan dengan ringan dan sempurna.\" Ibnu Las Al Khuza'I melanjutkan, \"Ammar kemudian duduk, maka kami pun beranjak dan duduk di sisinya, lalu kami berkata kepadanya, \"Sungguh, kamu telah menunaikan dua rakaat ini dengan ringan sekali wahai Abu Yaqzhan.\" Ammar menjawab, \"Aku bergegas menunaikannya hingga mendahului masuknya setan pada dua rakaat itu.\" Al Khuza'i berkata, \"Ammar kemudian menyebutkan hadits.\" Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Syarik] dari [Abu Hasyim] dari [Abu Mijlaz] ia berkata, \" [Ammar] pernah menunaikan shalat dan meringankannya, maka ia pun ditanya -atau- dikatakanlah kepadanya. Maka ia menjawab, \"Aku tidak mengurangi sedikitpun dari shalat Rasulullah shallallahu 'alaihi wasallam.\""},"2060":{"ar":"حَدَّثَنَا إِسْحَاقُ الْأَزْرَقُ عَنْ شَرِيكٍ عَنْ أَبِي هَاشِمٍ عَنْ أَبِي مِجْلَزٍ قَالَصَلَّى بِنَا عَمَّارٌ صَلَاةً فَأَوْجَزَ فِيهَا فَأَنْكَرُوا ذَلِكَ فَقَالَ أَلَمْ أُتِمَّ الرُّكُوعَ وَالسُّجُودَ قَالُوا بَلَى قَالَ أَمَا إِنِّي قَدْ دَعَوْتُ فِيهِمَا بِدُعَاءٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ اللَّهُمَّ بِعِلْمِكَ الْغَيْبَ وَقُدْرَتِكَ عَلَى الْخَلْقِ أَحْيِنِي مَا عَلِمْتَ الْحَيَاةَ خَيْرًا لِي وَتَوَفَّنِي إِذَا كَانَتْ الْوَفَاةُ خَيْرًا لِي أَسْأَلُكَ خَشْيَتَكَ فِي الْغَيْبِ وَالشَّهَادَةِ وَكَلِمَةَ الْحَقِّ فِي الْغَضَبِ وَالرِّضَا وَالْقَصْدَ فِي الْفَقْرِ وَالْغِنَى وَلَذَّةَ النَّظَرِ إِلَى وَجْهِكَ وَالشَّوْقَ إِلَى لِقَائِكَ وَأَعُوذُ بِكَ مِنْ ضَرَّاءَ مُضِرَّةٍ وَمِنْ فِتْنَةٍ مُضِلَّةٍ اللَّهُمَّ زَيِّنَّا بِزِينَةِ الْإِيمَانِ وَاجْعَلْنَا هُدَاةً مَهْدِيِّينَحَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ إِسْحَاقَ عَنْ يَزِيدِ بْنِ مُحَمَّدِ بْنِ خُثَيْمٍ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ حَدَّثَنِي مُحَمَّدُ بْنُ خُثَيْمٍ أَبُو يَزِيدَ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَ كُنْتُ أَنَا وَعَلِيُّ بْنُ أَبِي طَالِبٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ رَفِيقَيْنِ فِي غَزْوَةِ الْعُشَيْرَةِ فَمَرَرْنَا بِرِجَالٍ مِنْ بَنِي مُدْلِجٍ يَعْمَلُونَ فِي نَخْلٍ لَهُمْ فَذَكَرَ مَعْنَى حَدِيثِ عِيسَى بْنِ يُونُسَ","id":"Telah menceritakan kepada kami [Ishaq Al Azraq] dari [Syarik] dari [Abu Hasyim] dari [Abu Mijlaz] ia berkata, \" [Ammar] pernah shalat bersama kami dan ia menunaikannya denan ringgkas, lalu orang-orang pun mengingkarinya. Maka Ammar bertanya, \"Bukankah aku telah menyempurnakan rukuk dan sujud?\" mereka menjawab, \"Benar.\" Ammar berkata, \"Sesungguhnya dalam dua rakaat itu, aku telah berdo'a dengan do'a yang Rasulullah shallallahu 'alaihi wasallam pernah berdo'a dengannya, 'ALLAHUMMA BI'ILMIKAL GHAIBA WA QUDRATIKA 'ALAL KHALQI AHYINII MAA 'ALIMTAL HAYAATA KHAIRAN LII, WATAWAFFANII IDZAA KAANATIL WAFAATU KHAIRAN LII. AS`ALUKA KHASYYATAKA FIL GHAIB, WASY SYAHAADATI WAKALIMATAL HAQQI FIL GHADLABI WAR RIDLAA WAL QASHDA FIL FAQRI WAL GHINAA WA LADZDZATAN NAZHARI ILAA WAJHIKA WASY SYAUQI ILAA LIQAAI`IKA WA A'UUDZU BIKA MIN DLARRAA`A MUDLIRRATIN WA MIN FITNATIN MUDLILLATIN, ALLAHUMMA ZAYYINAA BIZIINATIL IIMAAN, WAJ'ALNAA HUDAATAN MAHDIYYIIN (Ya Allah, dengan ilmu-Mu atas yang ghaib, dan dengan kemahakuasaan-Mu atas seluruh makhluk, hidupkanlah aku jika Engkau mengetahui bahwa hidup lebih baik bagiku, dan matikanlah aku jika Engkau mengetahui bahwa kematian itu lebih baik bagiku. Ya Allah, sesungguhnya aku memohon pada-Mu agar aku takut pada-Mu dalam keadaan sembunyi atau ramai. Aku memohon pada-Mu agar dapat berkata dengan benar diwaktu ridla atau marah. Aku minta kepada-Mu agar dapat melaksanakan kesederhanaan dalam keadaan kaya atau fakir serta kenikmatan memandang wajah-Mu (di surga), rindu bertemu dengan-Mu. Aku berlindung kepada-Mu dari penderitaan yang membahayakan dan fitnah yang menyesatkan. Ya Allah, hiasilah kami dengan iman, dan jadikanlah kami sebagai penunjuk (jalan) yang lurus yang memperoleh bimbingan dari-Mu).'\" Telah menceritakan kepada kami Ahmad bin Abdul Malik Telah menceritakan kepada kami Muhammad bin Salamah dari Muhammad bin Ishaq dari Yazid bin Muhammad bin Khutsaim dari Muhammad bin Ka'ab Al Qurazhi telah menceritakan kepadaku Muhammad bin Khutsaim Abu Yazid dari Ammar bin Yasir ia berkata, \"Aku dan Ali bin Abu Thalib radliallahu 'anhu adalah dua orang yang berteman pada saat perang Al Usyairah. Kemudian kami melewati sekelompok laki-laki dari Bani Mudlij yang sedang bekerja pada kebun kurma milik mereka…lalu ia menyebutkan makna hadits Isa bin Yunus.\""},"2061":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَكُنْتُ جَالِسًا مَعَ أَبِي مُوسَى وَعَبْدِ اللَّهِ قَالَ فَقَالَ أَبُو مُوسَى يَا أَبَا عَبْدِ الرَّحْمَنِ أَرَأَيْتَ لَوْ أَنَّ رَجُلًا لَمْ يَجِدْ الْمَاءَ وَقَدْ أَجْنَبَ شَهْرًا مَا كَانَ يَتَيَمَّمُ قَالَ لَا وَلَوْ لَمْ يَجِدْ الْمَاءَ شَهْرًا قَالَ فَقَالَ لَهُ أَبُو مُوسَى فَكَيْفَ تَصْنَعُونَ بِهَذِهِ الْآيَةِ فِي سُورَةِ الْمَائِدَةِ{ فَلَمْ تَجِدُوا مَاءً فَتَيَمَّمُوا صَعِيدًا طَيِّبًا }قَالَ فَقَالَ عَبْدُ اللَّهِ لَوْ رُخِّصَ لَهُمْ فِي هَذَا لَأَوْشَكُوا إِذَا بَرَدَ عَلَيْهِمْ الْمَاءُ أَنْ يَتَيَمَّمُوا الصَّعِيدَ ثُمَّ يُصَلُّوا قَالَ فَقَالَ لَهُ أَبُو مُوسَى إِنَّمَا كَرِهْتُمْ ذَا لِهَذَا قَالَ نَعَمْ قَالَ لَهُ أَبُو مُوسَى أَلَمْ تَسْمَعْ لِقَوْلِ عَمَّارٍ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَأَجْنَبْتُ فَلَمْ أَجِدْ الْمَاءَ فَتَمَرَّغْتُ فِي الصَّعِيدِ كَمَا تَمَرَّغُ الدَّابَّةُ ثُمَّ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ إِنَّمَا كَانَ يَكْفِيكَ أَنْ تَقُولَ وَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ مَسَحَ كُلَّ وَاحِدَةٍ مِنْهُمَا بِصَاحِبَتِهَا ثُمَّ مَسَحَ بِهَا وَجْهَهُ لَمْ يُجِزْ الْأَعْمَشُ الْكَفَّيْنِ قَالَ فَقَالَ لَهُ عَبْدُ اللَّهِ أَلَمْ تَزْعُمُوا لَمْ يَقْنَعْ بِقَوْلِ عَمَّارٍ وَقَالَ أَبُو مُعَاوِيَةَ مَرَّةً قَالَ فَضَرَبَ بِيَدِهِ عَلَى الْأَرْضِ ثُمَّ نَفَضَهَا ثُمَّ ضَرَبَ بِشِمَالِهِ عَلَى يَمِينِهِ وَبِيَمِينِهِ عَلَى شِمَالِهِ عَلَى الْكَفَّيْنِ ثُمَّ مَسَحَ وَجْهَهُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] ia berkata, aku pernah duduk bersama [Abu Musa] dan Abdullah. Kemudian Abu Musa berkata, \"Wahai Abu Abdurrahman, bagaimana menurutmu jika ada seorang laki-laki yang tidak mendapatkan air, sementara ia telah junub selama satu bulan, bolehkah ia betayammum?\" Ia menjawab, \"Tidak, meskipun ia tidak mendapatkan air.\" Syaqiq berkata, \"Maka Abu Musa bertanya, \"Lalu apa yang kalian perbuat berkenaan dengan ayat yang terdapat dalam surat Al Maidah (ayat: 6): '(Jika kamu tidak memperoleh air, maka bertayammumlah dengan tanah yang baik (bersih)?\" Maka Abdullah berkata, \"Sekiranya mereka diberi keringanan dalam masalah ini, niscaya mereka akan segera bertayammum dan shalat disaat air sangat dingin.\" Kemudian Abu Musa bertanya kepadanya, \"Apakah hanya karena ini kalian tidak menyukainya?\" Abdullah menjawab, \"Ya.\" Abu Musa berkata lagi kepadanya, \"Tidakkah kamu mendengar ungkapan [Ammar], \"Rasulullah shallallahu 'alaihi wasallam pernah mengutusku untuk suatu keperluan. Lalu aku junub dan tidak mendapatkan air, maka aku pun berguling-guling di hamparan tanah sebagaimana bergulingnya binatang. Kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan menuturkan hal itu. Beliau bersabda: 'Cukup bagimu mengatakan, kemudian beliau menepukkan tangannya di atas tanah dan mengusapkannya pada kedua tangan dan wajahnya.\" -Al A'masy tidak membatasi pada kedua telapak tangan.- Maka Abdullah pun berkata, \"Tidakkah kalian mengira bahwa beliau belum merasa puas dengan ungkapannya Ammar?\" Sekali waktu Abu Mu'awiyah menyebutkan, \"Kemudian beliau menepukkan kedua tangannya di atas tanah lalu mengibaskannya dan mengusapkan telapak tangan kirinya ke telapak tangan kanan, kemudian telapak tangan kanannya ke atas telapak tangan kiri. Setelah itu, beliau mengusap wajahnya.\""},"2062":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ جَابِرٍ عَنِ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَابِتٍ قَالَجَاءَ عُمَرُ بْنُ الْخَطَّابِ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي مَرَرْتُ بِأَخٍ لِي مِنْ بَنِي قُرَيْظَةَ فَكَتَبَ لِي جَوَامِعَ مِنْ التَّوْرَاةِ أَلَا أَعْرِضُهَا عَلَيْكَ قَالَ فَتَغَيَّرَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ اللَّهِ يَعْنِي ابْنَ ثَابِتٍ فَقُلْتُ لَهُ أَلَا تَرَى مَا بِوَجْهِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ رَضِينَا بِاللَّهِ تَعَالَى رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا قَالَ فَسُرِّيَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَوْ أَصْبَحَ فِيكُمْ مُوسَى ثُمَّ اتَّبَعْتُمُوهُ وَتَرَكْتُمُونِي لَضَلَلْتُمْ إِنَّكُمْ حَظِّي مِنْ الْأُمَمِ وَأَنَا حَظُّكُمْ مِنْ النَّبِيِّينَ","id":"Telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Sufyan] dari [Jabir] dari [Asy Sya'bi] dari [Abdullah bin Tsabit] ia berkata, \"Umar bin Al Khathab datang menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya aku melewati saudaraku dari Bani Quraizhah, ia lalu menulis untukku beberapa kalimat yang singkat dari kitab Taurat, maka bolehkah aku memperlihatkannya padamu?\" Wajah Rasulullah shallallahu 'alaihi wasallam seketika itu berubah. Abdullah -Ibnu Tsabit- berkata, \"Aku lalu berkata kepadanya, \"Tidakkah kamu lihat perubahan pada wajah Rasulullah shallallahu 'alaihi wasallam?\" kemudian Umar berkata, \"Kami rela Allah sebagai Rabb kami, Islam sebagai agama kami, dan Muhammad shallallahu 'alaihi wasallam sebagai Rasul.\" Lalu meredalah kemarahan Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Demi Dzat yang jiwa Muhammad berada di tangan-Nya, sekiranya Musa berada di tengah-tengah kalian, lalu kalian mengikutinya dan meninggalkanku, niscaya kalian akan tersesat. Kalian adalah bagianku dari ummat manusia dan aku adalah bagian kalian dari para Nabi.\""},"2063":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا خَالِدٌ عَنْ أَبِي الْعَلَاءِ بْنِ الشِّخِّيرِ عَنْ أَخِيهِ مُطَرِّفٍ عَنْ عِيَاضِ بْنِ حِمَارٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ الْتَقَطَ لُقَطَةً فَلْيُشْهِدْ ذَا عَدْلٍ أَوْ ذَوَيْ عَدْلٍ ثُمَّ لَا يَكْتُمْ وَلَا يُغَيِّبْ فَإِنْ جَاءَ رَبُّهَا فَهُوَ أَحَقُّ بِهَا وَإِلَّا فَإِنَّمَا هُوَ مَالُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Khalid] dari [Abu Ala bin Syikhkhir] dari saudaranya [Mutharrif] dari [Iyadl bin Himar] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mendapati barang temuan, maka hendaklah ia menyaksikannya kepada orang yang adil dan janganlah menyembunyikannya. Jika pemiliknya datang maka dia (pemiliknya itulah) yang lebih berhak, tetapi jika tidak datang maka temuan itu adalah harta Allah yang Dia berikan kepada siapa saja yang Dia kehendaki.\""},"2064":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ قَالَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عِيَاضِ بْنِ حِمَارٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِثْمُ الْمُسْتَبَّيْنِ مَا قَالَا عَلَى الْبَادِئِ مَا لَمْ يَعْتَدْ الْمَظْلُومُ وَالْمُسْتَبَّانِ شَيْطَانَانِ يَتَكَاذَبَانِ وَيَتَهَاتَرَانِ","id":"Telah menceritakan kepada kami [Abdush Shamad] ia berkata, Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] dari [Yazid bin Abdullah] dari [Iyadl bin Himar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dosa dua orang yang saling mencaci akan ditimpakan kepada orang yang memulai, selama orang yang terzhalimi tidak membalas. Dua orang yang saling mencaci adalah dua setan yang saling berkata dusta dan saling meremehkan.\""},"2065":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍ الْمُجَاشِعِيِّرَفَعَ الْحَدِيثَ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَنِي أَنْ أُعَلِّمَكُمْ مَا جَهِلْتُمْ مِمَّا عَلَّمَنِي يَوْمِي هَذَا وَإِنَّهُ قَالَ إِنَّ كُلَّ مَالٍ نَحَلْتُهُ عِبَادِي فَهُوَ لَهُمْ حَلَالٌ فَذَكَرَ نَحْوَ حَدِيثِ هِشَامٍ عَنْ قَتَادَةَ وَقَالَ وَأَهْلُ النَّارِ خَمْسَةٌ الضَّعِيفُ الَّذِي لَا زَبْرَ لَهُ الَّذِينَ هُمْ فِيكُمْ تَبَعٌ لَا يَبْتَغُونَ أَهْلًا وَلَا مَالًا","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Qatadah] dari [Mutharrif bin Abdullah bin Asy Syikhkhir] dari [Iyadl bin Himar Al Mujasyi'i] ia memarfu'kan hadits, ia berkata, \"Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla memerintahkan kepadaku untuk mengajari kalian apa yang belum kalian ketahui dari apa-apa yang telah diajarkan kepadaku pada hari ini. Allah berfirman: 'Sesungguhnya harta yang Aku berikan kepada hamba-Ku, maka itu halal bagi mereka'.\" Lalu ia menyebutkan semisal hadits Hisyam dari Qatadah. Dan beliau bersabda: \"Penghuni neraka itu ada lima; orang lemah yang tidak memiliki akal untuk mencegahkan dari perbuatan yang tidak selayaknya dilakukan. Mereka mempunyai pengikut di antara kalian, dan mereka tidak mencari banyaknya pengikut dan harta.\""},"2066":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عَوْفٌ عَنْ حَكِيمٍ الْأَثْرَمِ عَنِ الْحَسَنِ قَالَ حَدَّثَنِي مُطَرِّفُ بْنُ عَبْدِ اللَّهِ حَدَّثَنِي عِيَاضُ بْنُ حِمَارٍ الْمُجَاشِعِيُّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خُطْبَةٍ خَطَبَهَا قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَنِي أَنْ أُعَلِّمَكُمْ مَا جَهِلْتُمْ مِمَّا عَلَّمَنِي يَوْمِي هَذَا قَالَ وَإِنَّ كُلَّ مَالٍ نَحَلْتُهُ عِبَادِي فَهُوَ لَهُمْ حَلَالٌ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Auf] dari [Hakim Al Atsram] dari [Al Hasan] ia berkata, telah menceritakan kepadaku [Mutharrif bin Abdullah] telah menceritakan kepadaku [Iyadl bin Himar Al Mujasyi'i] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda di dalam khutbahnya: \"Sesungguhnya Allah 'azza wajalla telah memerintahkan kepadaku untuk mengajari kalian apa yang telah diajarkan-Nya padaku di hari ini, sesuatu yang belum kalian ketahui. Dia berfirman: 'Sesungguhnya setiap harta yang Aku karuniakan kepada hamba-Ku, maka harta itu bagi mereka adalah halal.'\" Lalu ia pun menyebutkan hadits."},"2067":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ حَدَّثَنَا الْعَلَاءُ بْنُ زِيَادٍ الْعَدَوِيُّ وَحَدَّثَنِي يَزِيدُ أَخُو مُطَرِّفٍ قَالَ وَحَدَّثَنِي عُقْبَةُ كُلُّ هَؤُلَاءِ يَقُولُ حَدَّثَنِي مُطَرِّفٌ أَنَّ عِيَاضَ بْنَ حِمَارٍ حَدَّثَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي خُطْبَتِهِ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَمَرَنِي أَنْ أُعَلِّمَكُمْ مَا جَهِلْتُمْ فَذَكَرَ الْحَدِيثَ وَقَالَ الضَّعِيفُ الَّذِي لَا زَبْرَ لَهُ الَّذِينَ هُمْ فِيكُمْ تَبَعٌ لَا يَبْتَغُونَ أَهْلًا وَلَا مَالًا قَالَ قَالَ رَجُلٌ لِمُطَرِّفٍ يَا أَبَا عَبْدِ اللَّهِ أَمِنَ الْمَوَالِي هُوَ أَوْ مِنْ الْعَرَبِ قَالَ هُوَ التَّابِعَةُ يَكُونُ لِلرَّجُلِ يُصِيبُ مِنْ خَدَمِهِ سِفَاحًا غَيْرَ نِكَاحٍ وَقَالَ أَهْلُ الْجَنَّةِ ثَلَاثَةٌ ذُو سُلْطَانٍ مُقْسِطٌ مُصَدِّقٌ مُوقِنٌ وَرَجُلٌ رَحِيمٌ رَقِيقُ الْقَلْبِ بِكُلِّ ذِي قُرْبَى وَمُسْلِمٍ وَرَجُلٌ عَفِيفٌ فَقِيرٌ مُتَصَدِّقٌقَالَ هَمَّامٌ قَالَ بَعْضُ أَصْحَابِ قَتَادَةَ وَلَا أَعْلَمُهُ إِلَّا قَالَ يُونُسُ الْإِسْكَافُ قَالَ لِي إِنَّ قَتَادَةَ لَمْ يَسْمَعْ حَدِيثَ عِيَاضِ بْنِ حِمَارٍ مِنْ مُطَرِّفٍ قُلْتُ هُوَ حَدَّثَنَا عَنْ مُطَرِّفٍ وَتَقُولُ أَنْتَ لَمْ يَسْمَعْهُ مِنْ مُطَرِّفٍ قَالَ فَجَاءَ أَعْرَابِيٌّ فَجَعَلَ يَسْأَلُهُ وَاجْتَرَأَ عَلَيْهِ قَالَ فَقُلْنَا لِلْأَعْرَابِيِّ سَلْهُ هَلْ سَمِعَ حَدِيثَ عِيَاضِ بْنِ حِمَارٍ عَنْ مُطَرِّفٍ فَسَأَلَهُ فَقَالَ لَا حَدَّثَنِي أَرْبَعَةٌ عَنْ مُطَرِّفٍ فَسَمَّى ثَلَاثَةً الَّذِي قُلْتُ لَكُمْ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] Telah menceritakan kepada kami [Al 'Ala` bin Ziyad Al Adawi], dan telah menceritakan kepadaku [Yazid] -saudaranya Mutharrif- ia berkata, [Uqbah] menceritakan kepadaku -setiap mereka- berkata, telah menceritakan kepadaku [Mutharrif] bahwa [Iyadl bin Himar] menceritakan kepadanya, bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda dalam khutbahnya: \"Sesungguhnya Allah 'azza wajalla telah memerintahkanku untuk mengajari kalian apa yang tidak kalian ketahui… lalu ia menyebutkan hadits tersebut.\" Dan beliau bersabda: \"Orang lemah yang tidak memiliki akal untuk mencegahkan dari perbuatan yang tidak selayaknya dilakukan. Mereka mempunyai pengikut di antara kalian, dan mereka tidak mencari banyaknya pengikut dan harta.\" Seorang laki-laki bertanya kepada Mutharrif, \"Wahai Abu Abdullah apakah dari kalangan Mawaali ataukah dari Arab.\""},"2068":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ يَزِيدَ أَخِي مُطَرِّفٍ عَنْ عِيَاضِ بْنِ حِمَارٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِثْمُ الْمُسْتَبَّيْنِ مَا قَالَا عَلَى الْبَادِئِ حَتَّى يَفْتَدِيَ الْمَظْلُومُ أَوْ مَا لَمْ يَفْتَدِ الْمَظْلُومُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] dari [Yazid] saudaranya Mutharrif, dari [Iyadl bin Himar], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Dosa dua orang yang saling mencaci akan ditimpakan kepada orang yang memulai, hingga orang terzhalimi membalas. Atau, selama orang yang terzhalimi tidak membalas.\""},"2069":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ بِهَذَا الْإِسْنَادِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُسْتَبَّانِ شَيْطَانَانِ يَتَكَاذَبَانِ وَيَتَهَاتَرَانِ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam] dengan isnad ini (jalur periwayatan yang sama dengan hadits sebelumnya), ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua orang yang saling mencaci adalah dua setan yang saling berkata dusta dan saling meremehkan.\""},"2070":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ خَالِدًا يُحَدِّثُ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ مُطَرِّفِ بْنِ الشِّخِّيرِ عَنْ عِيَاضِ بْنِ حِمَارٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ الْتَقَطَ لُقَطَةً فَلْيُشْهِدْ ذَوَيْ عَدْلٍ أَوْ ذَا عَدْلٍ خَالِدٌ الشَّاكُّ وَلَا يَكْتُمْ وَلَا يُغَيِّبْ فَإِنْ جَاءَ صَاحِبُهَا فَهُوَ أَحَقُّ بِهَا وَإِلَّا فَهُوَ مَالُ اللَّهِ يُؤْتِيهِ مَنْ يَشَاءُقَالَ سَمِعْت يَحْيَى بْنَ سَعِيدٍ يَقُولُ مُطَرِّفٌ أَكْبَرُ مِنْ الْحَسَنِ بِعِشْرِينَ سَنَةً وَأَبُو الْعَلَاءِ أَكْبَرُ مِنْ الْحَسَنِ بِعَشْرِ سِنِينَ حَدَّثَنِيهِ أَخٌّ لِأَبِي بَكْرِ بْنِ الْأَسْوَدِ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي عَقِيلٍ الدَّوْرَقِيِّ بِهَذَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] berkata, aku mendengar [Khalid] menceritakan dari [Yazid bin Abdullah bin Asy Syikhkhir] dari [Mutharrif bin Asy Syikhkhir] dari [Iyadl bin Himar] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa menemukan barang temuan, maka hendaklah ia mempersaksikannya kepada orang yang adil, dan janganlah ia sembunyikan atau menghilangkannya. Jika pemiliknya datang maka dialah yang lebih berhak, namun jika tidak datang, maka itu adalah harta Allah yang Dia berikan kepada orang yang dikehendaki-Nya.\" (Abdullah bin Ahmad) berkata, \"Aku mendengar Yahya bin Said berkata, \"Mutharrif lebih tua dua puluh tahun dari Hasan. Dan Abul Ala` lebih tua sepuluh tahun dari Hasan.\" Telah menceritakan kepadaku Saudara Abu Bakr bin Al Aswad dari Yahya bin Sa'id dari Abu Aqil Ad Dauraqi dengan hadits ini.\""},"2071":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ حَنْظَلَةَ الْكَاتِبِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَافَظَ عَلَى الصَّلَوَاتِ الْخَمْسِ رُكُوعِهِنَّ وَسُجُودِهِنَّ وَوُضُوئِهِنَّ وَمَوَاقِيتِهِنَّ وَعَلِمَ أَنَّهُنَّ حَقٌّ مِنْ عِنْدِ اللَّهِ دَخَلَ الْجَنَّةَ أَوْ قَالَ وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah menceritakan kepada kami [Abdush Shamad] dan ['Affan] keduanya berkata, Telah menceritakan kepada kami [Hammam] Telah menceritakan kepada kami [Qatadah] dari [Hanzhalah Al Katib] ia berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa selalu menjaga shalat wajib yang lima, baik rukuk, sujud, wudlu atau waktu-waktunya. Dan ia mengetahui bahwa semua itu merupakan kewajiban dari sisi Allah, maka ia akan masuk surga.\" Atau beliau mengatakan; \"Wajib baginya surga.\""},"2072":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ حَنْظَلَةَ الْأُسَيْدِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَافَظَ عَلَى الصَّلَوَاتِ الْخَمْسِ عَلَى وُضُوئِهَا وَمَوَاقِيتِهَا وَرُكُوعِهَا وَسُجُودِهَا يَرَاهَا حَقًّا لِلَّهِ عَلَيْهِ حُرِّمَ عَلَى النَّارِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Hanzhalah Al Usaidi], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: Barangsiapa selalu menjaga shalat wajib yang lima, baik wudlu, waktu-waktunya, rukuk dan sujudnya. Dan ia melihat bahwa itu semuan adalah hak Allah, maka haram baginya masuk neraka.\""},"2073":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ خَيْثَمَةَ وَالشَّعْبِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَلَالٌ بَيِّنٌ وَحَرَامٌ بَيِّنٌ وَشُبُهَاتٌ بَيْنَ ذَلِكَ مَنْ تَرَكَ الشُّبُهَاتِ فَهُوَ لِلْحَرَامِ أَتْرَكُ وَمَحَارِمُ اللَّهِ حِمًى فَمَنْ أَرْتَعَ حَوْلَ الْحِمَى كَانَ قَمِنًا أَنْ يَرْتَعَ فِيهِ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim] Telah menceritakan kepada kami [Syaiban] dari [Ashim] dari [Khaitsamah] dan [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang halal sudah jelas dan yang haram juga sudah jelas, sedangkan syubhat berada di antara keduanya. Barangsiapa meninggalkan syubhat, berarti terhadap yang haram ia akan lebin menjauh. Dan hal-hal yang diharamkan Allah adalah daerah terlarang, maka siapa yang mengembalakan ternak di sekitar daerah terlarang, sangat mungkin ia akan memasukinya.\""},"2074":{"ar":"حَدَّثَنَا هَاشِمٌ قَالَ حَدَّثَنَا شَيْبَانُ عَنْ عَاصِمٍ عَنْ خَيْثَمَةَ وَالشَّعْبِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ النَّاسِ قَرْنِي ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ يَأْتِي قَوْمٌ تَسْبِقُ أَيْمَانُهُمْ شَهَادَتَهُمْ وَشَهَادَتُهُمْ أَيْمَانَهُمْ","id":"Telah menceritakan kepada kami [Hasyim] ia berkata, Telah menceritakan kepada kami [Syaiban] dari [Ashim] dari [Khaitsamah] dan [Asy Sya'bi] dari [Nu'man bin Basyir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik manusia adalah generasiku, kemudian orang-orang yang datang setelah mereka, kemudian orang-orang yang datang setelah mereka, kemudian generasi yang datang setelah mereka. Setelah itu, akan datang suatu kaum yang sumpahnya mendahului persaksian dan persaksian mereka mendahului sumpah-sumpah mereka.\""},"2075":{"ar":"حَدَّثَنَا حَسَنٌ وَيُونُسُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَاصِمِ بْنِ بَهْدَلَةَ عَنْ خَيْثَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنِ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ هَذِهِ الْأُمَّةِ الْقَرْنُ الَّذِينَ بُعِثْتُ فِيهِمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَهُمْ ثُمَّ الَّذِينَ يَلُونَ الَّذِينَ يَلُونَهُمْ قَالَ حَسَنٌ ثُمَّ يَنْشَأُ أَقْوَامٌ تَسْبِقُ أَيْمَانُهُمْ شَهَادَتَهُمْ وَشَهَادَتُهُمْ أَيْمَانَهُمْ","id":"Telah menceritakan kepada kami [Hasan] dan [Yunus] keduanya berkata, Telah menceritakan kepada kami [Hammad bin Salamah] dari [Ashim bin Bahdalah] dari [Khaitsamah bin Abdurrahman] dari [An Nu'man bin Basyir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik ummat ini adalah generasi yang aku diutus kepada mereka (yakni para sabahat), kemudian generasi yang datang setelah mereka, kemudian generasi yang datang setelah mereka, kemudian generasi yang datang setelahnya.\" Hasan menyebutkan, \"Kemudian muncullah suatu kaum yang sumpah-sumpah mereka mendahului persaksian mereka dan persaksian mereka mendahului sumpah-sumpahnya mereka.\""},"2076":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا أَيُّوبُ فَذَكَرَ حَدِيثًا قَالَ وَحَدَّثَ عَنْ أَبِي قِلَابَةَ عَنْ رَجُلٍ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ يُصَلِّي رَكْعَتَيْنِ ثُمَّ يَسْأَلُ ثُمَّ يُصَلِّي رَكْعَتَيْنِ ثُمَّ يَسْأَلُ حَتَّى انْجَلَتْ الشَّمْسُ قَالَ فَقَالَ إِنَّ نَاسًا مِنْ أَهْلِ الْجَاهِلِيَّةِ يَقُولُونَ أَوْ يَزْعُمُونَ أَنَّ الشَّمْسَ وَالْقَمَرَ إِذَا انْكَسَفَ وَاحِدٌ مِنْهُمَا فَإِنَّمَا يَنْكَسِفُ لِمَوْتِ عَظِيمٍ مِنْ عُظَمَاءِ أَهْلِ الْأَرْضِ وَإِنَّ ذَاكَ لَيْسَ كَذَلِكَ وَلَكِنَّهُمَا خَلْقَانِ مِنْ خَلْقِ اللَّهِ فَإِذَا تَجَلَّى اللَّهُ عَزَّ وَجَلَّ لِشَيْءٍ مِنْ خَلْقِهِ خَشَعَ لَهُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Abdul Warits] Telah menceritakan kepada kami [Ayyub] lalu ia menyebutkan hadits. Dan ia berkata; dan ia menceritakan dari [Abu Qilabah] dari [seorang laki-laki] dari [Nu'man bin Basyir] ia berkata, \"Telah rerjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam. Beliau shalat dua rakaat kemudian bertanya (apakah matahari telah terang kembali), kemudian beliau shalat dua rakaat lagi dan bertanya, sehingga matahari pun tampak kembali. Beliau bersabda: \"Sesungguhnya orang-orang pada masa jahiliyah berkata, atau mereka menyangka bahwa terjadinya gerhana matahari dan bulan karena kematiannya pemuka (orang besar) penduduk bumi. Padahal bukan demikian, tetapi keduanya adalah dua makluk di antara makhluk-makhluk Allah. Jika Allah 'azza wajalla menampakkan diri untuk makhluk-Nya, maka makhluk itu akan tersungkur khusyuk pada-Nya.\""},"2077":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنِ الْأَعْمَشِ وَمَنْصُورٍ عَنْ ذَرٍّ عَنْ يُسَيْعٍ الْكِنْدِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدُّعَاءَ هُوَ الْعِبَادَةُ ثُمَّ قَرَأَ{ ادْعُونِي أَسْتَجِبْ لَكُمْ إِنَّ الَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِي }","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Sufyan] dari [Al A'masy] dan [Manshur] dari [Dzar] dari [Yusba' Al Kindi] dari [Nu'man bin Basyir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya do'a itu adalah ibadah.\" Kemudian beliau membaca ayat: '(Berdo'alah kalian kepada-Ku, niscaya akan Aku kabulkan untuk kalian. Sesungguhnya orang-orang yang menyombongkan diri dari beribadah kepada-Ku..) ' (Qs. Ghaafir: 60)."},"2078":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنِ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ أَبَاهُ نَحَلَهُ نُحْلًا فَقَالَتْ لَهُ أُمُّ النُّعْمَانِ أَشْهِدْ لِابْنِي عَلَى هَذَا النُّحْلِ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ لَهُ أَوَكُلَّ وَلَدِكَ أَعْطَيْتَ مَا أَعْطَيْتَ هَذَا قَالَ لَا قَالَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَشْهَدَ لَهُ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [Bapaknya] dari [Nu'man bin Basyir], bahwa bapaknya memberikan kepadanya suatu pemberian, lalu ibunya berkata kepada bapaknya, \"Persaksikanlah untuk anakku atas pemberian ini.\" Maka bapaknya pun mendatangi Nabi shallallahu 'alaihi wasallam dan menuturkan hal itu pada beliau. Beliau lantas bertanya: \"Apakah setiap anakmu kamu berikan seperti apa yang kamu berikan pada anak ini?\" Ia menjawab, \"Tidak.\" Maka Rasulullah shallallahu 'alaihi wasallam tidak mau untuk menjadi saksinya.\""},"2079":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنِ الْأَعْمَشِ عَنِ الشَّعْبِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ كَمَثَلِ الْجَسَدِ إِذَا اشْتَكَى الرَّجُلُ رَأْسَهُ تَدَاعَى لَهُ سَائِرُ جَسَدِهِ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpaan orang Mukmin itu seperti satu jasad, jika seorang laki-laki merasakan sakit pada kepalanya, maka seluruh jasadnya akan ikut merasakannya.\""},"2080":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكُ بْنُ حَرْبٍ حَدَّثَنَا النُّعْمَانُ بْنُ بَشِيرٍ يَقُولُعَلَى مِنْبَرِ الْكُوفَةِ وَاللَّهِ مَا كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ نَبِيُّكُمْ عَلَيْهِ السَّلَام يَشْبَعُ مِنْ الدَّقَلِ وَمَا تَرْضَوْنَ دُونَ أَلْوَانِ التَّمْرِ وَالزُّبْدِ","id":"Telah menceritakan kepada kami [Abu Kamil] Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Simak bin Harb] Telah menceritakan kepada kami [An Nu'man bin Basyir], bahwa ia pernah berkata di atas mimbar di daerah Kufah, \"Nabi Shallallahu 'alaihi Wasallam -atau ia berkata- Nabi kalian 'alaihis salam tidak pernah kekenyangan karena makan Daqal (kurma jelek yang basah) atau apa yang kalian senangi selain kurma dan keju.\""},"2081":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي مُحَمَّدُ بْنُ النُّعْمَانِ بْنِ بَشِيرٍ وَحُمَيْدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَذَهَبَ أَبِي بَشِيرُ بْنُ سَعْدٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُشْهِدَهُ عَلَى نُحْلٍ نَحَلَنِيهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكُلَّ بَنِيكَ نَحَلْتَ مِثْلَ هَذَا قَالَ لَا قَالَ فَأَرْجِعْهَا","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Zuhri] telah mengabarkan kepadaku [Muhammad bin Nu'man bin Basyir] dan [Humaid bin Abdurrahman bin Auf] dari [An Nu'man bin Basyir] ia berkata, \"Bapakku, Basyir bin Sa'd, pergi menemui Rasulullah shallallahu 'alaihi wasallam untuk mempersaksikan pemberian yang diberikannya kepadaku. Maka Nabi shallallahu 'alaihi wasallam bertanya: \"Apakah setiap anakmu kamu berikan seperti ini?\" Ia menjawab, \"Tidak.\" Beliau bersabda: \"Kalau begitu kembalikanlah pemberian itu.\""},"2082":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا فِطْرٌ حَدَّثَنَا أَبُو الضُّحَى قَالَ سَمِعْتُ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُانْطَلَقَ بِي أَبِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي يُشْهِدُهُ عَلَى عَطِيَّةٍ يُعْطِينِيهَا فَقَالَ هَلْ لَكَ وَلَدٌ غَيْرُهُ قَالَ نَعَمْ قَالَ فَسَوِّ بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Abu Ahmad] Telah menceritakan kepada kami [Fithr] Telah menceritakan kepada kami [Abu Adl Dluha] ia berkata, aku mendengar [An Nu'man bin Basyir] berkata, \"Bapakku membawaku pergi menemui Rasulullah shallallahu 'alaihi wasallam untuk mempersaksikan pemberian yang diberikannya padaku. Maka beliau bertanya: \"Apakah kamu mempunyai anak selainnya?\" Ia menjawab, \"Ya.\" Beliau bersabda: \"Kalau begitu, sama ratakan pemberian di antara mereka.\""},"2083":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا أَصْحَابُهُ كَأَنَّمَا عَلَى رُءُوسِهِمْ الطَّيْرُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al Mas'udi] dari [Ziyad bin Ilaqah] dari [Usamah bin Syarik] ia berkata; Aku mendatangi Nabi shallallahu 'alaihi wasallam dan saat itu, para sahabatnya seakan-akan diatas kepala mereka terdapat burung."},"2084":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ عِنْدَهُ كَأَنَّمَا عَلَى رُءُوسِهِمْ الطَّيْرُ قَالَ فَسَلَّمْتُ عَلَيْهِ وَقَعَدْتُ قَالَ فَجَاءَتْ الْأَعْرَابُ فَسَأَلُوهُ فَقَالُوا يَا رَسُولَ اللَّهِ نَتَدَاوَى قَالَ نَعَمْ تَدَاوَوْا فَإِنَّ اللَّهَ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ لَهُ دَوَاءً غَيْرَ دَاءٍ وَاحِدٍ الْهَرَمُ قَالَ وَكَانَ أُسَامَةُ حِينَ كَبِرَ يَقُولُ هَلْ تَرَوْنَ لِي مِنْ دَوَاءٍ الْآنَ قَالَ وَسَأَلُوهُ عَنْ أَشْيَاءَ هَلْ عَلَيْنَا حَرَجٌ فِي كَذَا وَكَذَا قَالَ عِبَادَ اللَّهِ وَضَعَ اللَّهُ الْحَرَجَ إِلَّا امْرَأً اقْتَضَى امْرَأً مُسْلِمًا ظُلْمًا فَذَلِكَ حَرَجٌ وَهُلْكٌ قَالُوا مَا خَيْرُ مَا أُعْطِيَ النَّاسُ يَا رَسُولَ اللَّهِ قَالَ خُلُقٌ حَسَنٌ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Zaid bin Ilaqah] dari [Usamah bin Syarik] ia berkata; Saya mendatangi Nabi shallallahu 'alaihi wasallam sementara para sahabatnya berada di sisi beliau, sepertinya di atas kepala-kepala mereka terdapat burung. Kemudian saya mengucapkan salam atasnya dan duduk. Setelah itu, datanglah orang-orang A'rab dan bertanya kepada beliau, \"Wahai Rasulullah, haruskah kami berobat?\" beliau menjawab, \"Ya, karena Allah tidak pernah menurunkan penyakit, kecuali Dia juga menurunkan obatnya, kecuali untuk satu penyakit, yaitu kepikunan.\" Dan Usamah, ketika usianya telah lanjut ia berkata, \"Apakah sekarang kalian mendapati obat untukku?\" kemudian orang-orang pun bertanya kepada beliau mengenai berbagai hal, \"Apakah kami berdosa jika berobat dengan ini dan itu?\" maka beliau pun menjawab: \"Wahai para hamba Allah, sesungguhnya Allah telah menghilangkan dosa, kecuali seorang yang menuntut seorang muslim dengan zhalim, itulah dosa dan kehancuran.\" Mereka bertanya lagi, \"Sesuatu apakah yang paling baik yang diberikan kepada manusia?\" beliau menjawab: \"Yaitu akhlak yang baik.\""},"2085":{"ar":"حَدَّثَنَا ابْنُ زِيَادٍ يَعْنِي الْمُطَّلِبَ بْنَ زِيَادٍ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَدَاوَوْا عِبَادَ اللَّهِ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ لَمْ يُنَزِّلْ دَاءً إِلَّا أَنْزَلَ مَعَهُ شِفَاءً إِلَّا الْمَوْتَ وَالْهَرَمَ","id":"Telah menceritakan kepada kami [Ibnu Ziyad yakni Al Muthallib bin Ziyad] Telah menceritakan kepada kami [Ziyad bin Ilaqah] dari [Usamah bin Syarik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berobatlah kalian wahai hamba Allah, karena Allah 'azza wajalla tidak pernah menurunkan penyakit, kecuali juga menurunkan obatnya, kecuali kematian dan kepikunan.\""},"2086":{"ar":"حَدَّثَنَا مُصْعَبُ بْنُ سَلَّامٍ حَدَّثَنَا الْأَجْلَحُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ أُسَامَةَ بْنِ شَرِيكٍ رَجُلٌ مِنْ قَوْمِهِ قَالَجَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ النَّاسِ خَيْرٌ قَالَ أَحْسَنُهُمْ خُلُقًا ثُمَّ قَالَ يَا رَسُولَ اللَّهِ أَنَتَدَاوَى قَالَ تَدَاوَوْا فَإِنَّ اللَّهَ لَمْ يُنْزِلْ دَاءً إِلَّا أَنْزَلَ لَهُ شِفَاءً عَلِمَهُ مَنْ عَلِمَهُ وَجَهِلَهُ مَنْ جَهِلَهُ","id":"Telah menceritakan kepada kami [Mush'ab bin Sallam] Telah menceritakan kepada kami [Al Ajlah] dari [Ziyad bin Ilaqah] dari [Usamah bin Syarik] bahwa seorang laki-laki dari kaumnya berkata; Seorang A'rabi datang menemui Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, manusia manakah yang paling baik?\" Beliau menjawab: \"Yaitu, yang paling baik akhlaknya diantara mereka.\" kemudian ia bertanya lagi, \"Wahai Rasulullah, haruskah kami berobat?\" beliau menjawab: \"Berobatlah kalian, karena Allah tidak pernah menurunkan penyakit, melainkan Allah juga menurunkan obatnya, orang yang mengetahuinya akan tahu dan orang yang tidak mengetahuinya bakalan tidak tahu.\""},"2087":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عِيسَى بْنُ دِينَارٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ الْحَارِثِ بْنِ الْمُصْطَلِقِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَحَبَّ أَنْ يَقْرَأَ الْقُرْآنَ غَضًّا كَمَا أُنْزِلَ فَلْيَقْرَأْهُ عَلَى قِرَاءَةِ ابْنِ أُمِّ عَبْدٍ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Isa bin Dinar] dari [bapaknya] dari [Amru bin Harits bin Musthaliq] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang senang untuk membaca Al Qur'an sebagaimana ketika ia diturunkan, maka hendaklah dia membaca sebagaimana bacaan Ibnu Ummi Abdi (Abdullah bin mas'ud).\""},"2088":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ وَإِسْحَاقَ يَعْنِي الْأَزْرَقَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ عَمْرَو بْنَ الْحَارِثِ قَالَ إِسْحَاقُ بْنُ الْمُصْطَلِقِ يَقُولُمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا سِلَاحَهُ وَبَغْلَةً بَيْضَاءَ وَأَرْضًا جَعَلَهَا صَدَقَةً","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Syufyan] dan [Ishaq yakni Al Azraq], ia berkata, Telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] ia berkata, saya mendengar [Amru bin Harits] telah berkata Ishaq bin Al Musthaliq berkata; Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan (harta) kecuali senjatanya dan keledai putih serta tanah (pekarangan) yang beliau jadikan sedekah."},"2089":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ سَابِقٍ حَدَّثَنَا عِيسَى بْنُ دِينَارٍ حَدَّثَنَا أَبِي أَنَّهُ سَمِعَ الْحَارِثَ بْنَ أَبِي ضِرَارٍ الْخُزَاعِيِّ قَالَقَدِمْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَانِي إِلَى الْإِسْلَامِ فَدَخَلْتُ فِيهِ وَأَقْرَرْتُ بِهِ فَدَعَانِي إِلَى الزَّكَاةِ فَأَقْرَرْتُ بِهَا وَقُلْتُ يَا رَسُولَ اللَّهِ أَرْجِعُ إِلَى قَوْمِي فَأَدْعُوهُمْ إِلَى الْإِسْلَامِ وَأَدَاءِ الزَّكَاةِ فَمَنْ اسْتَجَابَ لِي جَمَعْتُ زَكَاتَهُ فَيُرْسِلُ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَسُولًا لِإِبَّانِ كَذَا وَكَذَا لِيَأْتِيَكَ مَا جَمَعْتُ مِنْ الزَّكَاةِ فَلَمَّا جَمَعَ الْحَارِثُ الزَّكَاةَ مِمَّنْ اسْتَجَابَ لَهُ وَبَلَغَ الْإِبَّانَ الَّذِي أَرَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُبْعَثَ إِلَيْهِ احْتَبَسَ عَلَيْهِ الرَّسُولُ فَلَمْ يَأْتِهِ فَظَنَّ الْحَارِثُ أَنَّهُ قَدْ حَدَثَ فِيهِ سَخْطَةٌ مِنْ اللَّهِ عَزَّ وَجَلَّ وَرَسُولِهِ فَدَعَا بِسَرَوَاتِ قَوْمِهِ فَقَالَ لَهُمْ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ وَقَّتَ لِي وَقْتًا يُرْسِلُ إِلَيَّ رَسُولَهُ لِيَقْبِضَ مَا كَانَ عِنْدِي مِنْ الزَّكَاةِ وَلَيْسَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخُلْفُ وَلَا أَرَى حَبْسَ رَسُولِهِ إِلَّا مِنْ سَخْطَةٍ كَانَتْ فَانْطَلِقُوا فَنَأْتِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلِيدَ بْنَ عُقْبَةَ إِلَى الْحَارِثِ لِيَقْبِضَ مَا كَانَ عِنْدَهُ مِمَّا جَمَعَ مِنْ الزَّكَاةِ فَلَمَّا أَنْ سَارَ الْوَلِيدُ حَتَّى بَلَغَ بَعْضَ الطَّرِيقِ فَرِقَ فَرَجَعَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ يَا رَسُولَ اللَّهِ إِنَّ الْحَارِثَ مَنَعَنِي الزَّكَاةَ وَأَرَادَ قَتْلِي فَضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَعْثَ إِلَى الْحَارِثِ فَأَقْبَلَ الْحَارِثُ بِأَصْحَابِهِ إِذْ اسْتَقْبَلَ الْبَعْثَ وَفَصَلَ مِنْ الْمَدِينَةِ لَقِيَهُمْ الْحَارِثُ فَقَالُوا هَذَا الْحَارِثُ فَلَمَّا غَشِيَهُمْ قَالَ لَهُمْ إِلَى مَنْ بُعِثْتُمْ قَالُوا إِلَيْكَ قَالَ وَلِمَ قَالُوا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ بَعَثَ إِلَيْكَ الْوَلِيدَ بْنَ عُقْبَةَ فَزَعَمَ أَنَّكَ مَنَعْتَهُ الزَّكَاةَ وَأَرَدْتَ قَتْلَهُ قَالَ لَا وَالَّذِي بَعَثَ مُحَمَّدًا بِالْحَقِّ مَا رَأَيْتُهُ بَتَّةً وَلَا أَتَانِي فَلَمَّا دَخَلَ الْحَارِثُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنَعْتَ الزَّكَاةَ وَأَرَدْتَ قَتْلَ رَسُولِي قَالَ لَا وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا رَأَيْتُهُ وَلَا أَتَانِي وَمَا أَقْبَلْتُ إِلَّا حِينَ احْتَبَسَ عَلَيَّ رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَشِيتُ أَنْ تَكُونَ كَانَتْ سَخْطَةً مِنْ اللَّهِ عَزَّ وَجَلَّ وَرَسُولِهِ قَالَ فَنَزَلَتْ الْحُجُرَاتُ{ يَا أَيُّهَا الَّذِينَ آمَنُوا إِنْ جَاءَكُمْ فَاسِقٌ بِنَبَإٍ فَتَبَيَّنُوا أَنْ تُصِيبُوا قَوْمًا بِجَهَالَةٍ فَتُصْبِحُوا عَلَى مَا فَعَلْتُمْ نَادِمِينَ }إِلَى هَذَا الْمَكَانِ{ فَضْلًا مِنْ اللَّهِ وَنِعْمَةً وَاللَّهُ عَلِيمٌ حَكِيمٌ }","id":"Telah menceritakan kepada kami [Muhammad bin Sabiq] Telah menceritakan kepada kami [Isa bin Dinar] Telah menceritakan kepada kami [bapakku] bahwa ia mendengar [Al Harits bin Abu Dlirar Al Khuza'i] ia berkata; Saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan beliau mengajakku untuk masuk Islam, maka aku pun masuk Islam dan mengikrarkannya. Kemudian beliau menyuruhku untuk mengeluarkan zakat, maka aku pun mengikrarkannya. Dan saya pun berkata, \"Wahai Rasulullah, saya akan pulang ke kaumku untuk mengajak mereka masuk Islam dan menunaikan zakat. Barangsiapa yang menyambut panggilan dakwahku, maka akan aku kumpulkan zakat yang dikeluarkannya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus seorang utusan untuk waktu yang telah ditetapkan dengan tujuan untuk mengambil zakat yang kamu kumpulkan. Ketika Al Harits telah mengumpulkan zakat dari orang yang memenuhi panggilan dakwahnya, bertepatan waktu yang disepakatinya dengan Rasulullah untuk mengutus utusannya, ternyata utusannya tertahan oleh suatu hal sehingga tidak dapat datang, sehingga Al Harits menduga bahwa ketidak datangan utusan Rasulullah adalah pertanda dari murka beliau, maka Al Harits-pun memanggil para pembesar kaumnya seraya berkata: \" Rasulullah sebenarnya telah menentukan suatu waktu mengirim utusan kepadaku untuk menerima kumpulan zakat yang telah aku kumpulkan, tetapi aku melihat tertahannya/ketidak datangan utusan beliau adalah pertanda dari murka beliau, maka mereka lalu berangkat dan mendatangi Rasulullah. Bersamaan itu pula Rasulullah telah mengirim Walid bin Uqbah ke Harits untuk mengumpulkan zakat yang telah dikumpulkan oleh Al Harits. Ketika telah sampai setengah perjalanan, Walid bin Uqbah kembali lagi dan mendatangi Rasulullah dan berkata: \"Wahai Rasulullah sesungguhnya Al Harits telah mencegahku untuk mengambil zakat dan malah berniat untuk membunuhku\", maka Rasulullah lalu mengirim rombongan untuk menemui Al Harits dan para sahabatnya. Ketika sampai di luar Madinah, Al Harits menemui mereka dan mereka berkata: \"Inikah Al Harits?? Maka ketika Al Harits mendatangi mereka, dia berkata: \"Kepada siapakah kalian diutus\"?? mereka lalu menjawab: \"Kepadamu\" lalu Al Harits bertanya: \"Kenapa?? Mereka menjawab: \"Bahwa Rasulullah telah mengirim untukmu utusan, lalu dia menduga bahwa engkau telah menahan zakat serta berkeinginan untuk membunuhnya\". Maka Al Harits berkata: \"Demi dzat yang mengutus Muhammad, sesungguhnya kita tidak seperti yang kalian tuduhkan, bahkan kami belum pernah melihat utusan Rasulullah sama sekali dan dia tidak mendatangiku\". Ketika Alharits menemui Rasulullah, berkatalah beliau kepada Al Harits: \"Wahai Al Harits sungguh kalian telah menahan zakat dan berniat untuk membunuh utusanku\", lalu Al Harits menjawab: \"Demi Dzat yang mengirim engkau sebagai utusan-Nya, aku tidak seperti itu, utusanmu tidak pernah datang dan menemuiku. Bahkan kami menduga bahwa ketika utusanmu tidak datang pada waktu yang telah ditentukan, kami menduga bahwa itu adalah pertanda dari kemurkaan Allah dan Rasul-Nya kepada kami-kami ini\", spontan turunlah ayat: \"Wahai Orang-orang beriman apabila datang kepada kalian orang fasiq membawa suatu berita…..(QS. Al hujurat, 6) \""},"2090":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ خِلَاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عُتْبَةَ قَالَأَتَى ابْنُ مَسْعُودٍ فِي رَجُلٍ تَزَوَّجَ امْرَأَةً فَمَاتَ عَنْهَا وَلَمْ يَفْرِضْ لَهَا وَلَمْ يَدْخُلْ بِهَا فَسُئِلَ عَنْهَا شَهْرًا فَلَمْ يَقُلْ فِيهَا شَيْئًا ثُمَّ سَأَلُوهُ فَقَالَ أَقُولُ فِيهَا بِرَأْيِي فَإِنْ يَكُ خَطَأً فَمِنِّي وَمِنْ الشَّيْطَانِ وَإِنْ يَكُ صَوَابًا فَمِنْ اللَّهِ لَهَا صَدَقَةُ إِحْدَى نِسَائِهَا وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَقَامَ رَجُلٌ مِنْ أَشْجَعَ فَقَالَ أَشْهَدُ لَقَضَيْتَ فِيهَا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بِرْوَعَ ابْنَةِ وَاشِقٍ قَالَ فَقَالَ هَلُمَّ شَاهِدَاكَ فَشَهِدَ لَهُ الْجَرَّاحُ وَأَبُو سِنَانٍ رَجُلَانِ مِنْ أَشْجَعَ","id":"Telah menceritakan kepada kami [Abu Dawud] Telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Khilas] dari [Abdullah bin Utbah] ia berkata; Ibnu Masud mendatangi seorang laki-laki yang telah menikahi seorang wanita, kemudian meninggal dunia dan belum sempat memberikan maharnya serta belum pernah mencampurinya. [Ibnu Mas'ud] ditanya tentang perkara hukum perempuan tersebut, dan selama kurun waktu satu bulan belum memberikan jawaban. kemudian mereka kembali bertanya kepadanya, akhirnya beliau pun berkata, \"Aku akan menjawab dengan pendapatku sendiri. Jika pendapatku salah, maka itu adalah dari kelemahan diriku dan datangnya dari syaithan, tapi apabila pendapatku benar, maka hal itu datangnya dari Allah. Wanita itu berhak mendapatkan mahar sebagaimana isteri yang lain, ia juga berhak mendapatkan bagian harta warisan. Dan baginya ada keharusan menunggu masa iddah.\" Kemudian berdirilah seorang laki-laki dari Bani Asyja' seraya berkata, \"Aku bersumpah bahwa Anda telah memutuskan perkara wanita tersebut sebagaimana Rasulullah memutuskan perkaranya Birwa' binti Wasiq.\" Lalu Ibnu Masud berkata, \"Datangkanlah padaku saksimu!\" Maka bersaksilah [Jarrah] dan [Abu Sinan] serta dua orang laki-laki dari bani Asyja'.\""},"2091":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَأَتَى قَوْمٌ عَبْد�� اللَّهِ يَعْنِي ابْنَ مَسْعُودٍ فَقَالُوا مَا تَرَى فِي رَجُلٍ تَزَوَّجَ امْرَأَةً فَذَكَرَ الْحَدِيثَ قَالَ فَقَالَ رَجُلٌ مِنْ أَشْجَعَ قَالَ مَنْصُورٌ أُرَاهُ سَلَمَةَ بْنَ يَزِيدَ فَقَالَ فِي مِثْلِ هَذَا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ رَجُلٌ مِنَّا امْرَأَةً مِنْ بَنِي رُؤَاسٍ يُقَالُ لَهَا بِرْوَعُ بِنْتُ وَاشِقٍ فَخَرَجَ مَخْرَجًا فَدَخَلَ فِي بِئْرٍ فَأَسِنَ فَمَاتَ وَلَمْ يَفْرِضْ لَهَا صَدَاقًا فَأَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَمَهْرِ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ","id":"Telah menceritakan kepada kami [Abu Sa'id] Telah menceritakan kepada kami [Za`idah] Telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Alqamah] dan [Al Aswad] ia berkata; Orang-orang mendatangi [Abdullah yakni Ibnu Mas'ud] dan mereka pun bertanya, \"Bagaimana pendapatmu, mengenai seorang laki-laki yang menikahi seorang wanita?\" Lalu ia pun menyebutkan hadits. Al Qamah berkata; Kemudian seorang laki-laki dari Asyja' -Manshur berkata; Menurutku ia adalah [Salamah bin Zaid] - dan berkata, \"Dalam persoalan ini, Rasulullah shallallahu 'alaihi wasallam telah memutuskan. Pernah seorang laki-laki dari kami menikahi wanita dari Bani Ru`as yang biasa dipanggil Birwa' bintu Wasiq. Suatu hari, laki-laki itu keluar kemudian memasuki kawasan sumur lalu ia pingsan dan mati. Sedangkan ia belum memberikan mahar kepada wanita yang dikahinya. Kemudian orang-orang pun mendatangi Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Ia berhak mendapatkan mahar sebagaimana isteri-isteri yang lain, tidak ada tipu daya dan ketidakadilan. Ia juga mendapat bagian dari harta warisan dan baginya keharusan menunggu masa iddah.\""},"2092":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ دَاوُدَ عَنِ الشَّعْبِيِّ عَنْ عَلْقَمَةَأَنَّ رَجُلًا تَزَوَّجَ امْرَأَةً فَتُوُفِّيَ عَنْهَا زَوْجُهَا قَبْلَ أَنْ يَدْخُلَ بِهَا وَلَمْ يُسَمِّ لَهَا صَدَاقًا فَسُئِلَ عَنْهَا عَبْدُ اللَّهِ فَقَالَ لَهَا صَدَاقُ إِحْدَى نِسَائِهَا وَلَا وَكْسَ وَلَا شَطَطَ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَقَامَ أَبُو سِنَانٍ الْأَشْجَعِيُّ فِي رَهْطٍ مِنْ أَشْجَعَ فَقَالُوا نَشْهَدُ لَقَدْ قَضَيْتَ فِيهَا بِقَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بِرْوَعَ بِنْتِ وَاشِقٍحَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وَحَدَّثَنَا ابْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ عَنْ دَاوُدَ عَنِ الشَّعْبِيِّ عَنْ عَلْقَمَةَ بِهَذَا و حَدَّثَنَا عَبْد اللَّهِ قَالَ حَدَّثَنَاه ابْنُ أَبِي شَيْبَةَ عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Hammnad bin Salamah] dari [Dawud] dari [Asy Sya'bi] dari [Al Qamah] bahwa pernah seorang laki-laki menikahi seorang wanita. Kemudian sang suami itu meninggal dan belum sempat menggaulinya dan belum juga menentukan maharnya. Lalu ditanyakanlah hal itu kepada [Abdullah], maka ia menjawab, \"Ia berhak mendapatkan mahar sebagaimana isteri yang lain, tidak ada tipu daya dan kezhaliman. Ia juga berhak mendapatkan harta warisan, dan baginya ada keharusan menunggu masa iddah.\" Kemudian berdirilah [Abu Sinan Al Asyja'i] yang berada dalam suatu rombongan, dan mereka berkata, \"Kami bersaksi bahwa Anda telah memutuskannya dengan ketetapan yang pernah Rasulullah shallallahu 'alaihi wasallam pada Birwa' binti Wasiq.\" Telah menceritakan kepada kami Abdullah bin Muhammad bin Abu Syaibah telah berkata Abdullah dan Telah menceritakan kepada kami [Ibnu Abu Syaibah] ia berkata, Telah menceritakan kepada kami [Ibnu Abu Za`idah] dari [Dawud] dari [Asy Sya'bi] dari [Al Qamah] dengan hadits ini. Dan Telah menceritakan kepada kami Abdullah ia berkata, Telah menceritakannya kepada kami Ibnu Abu Syaibah Abdullah bin Muhammad dan ia pun menyebutkan hadits."},"2093":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ فِرَاسٍ عَنِ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِفِي رَجُلٍ تَزَوَّجَ امْرَأَةً فَمَاتَ عَنْهَا وَلَمْ يَدْخُلْ بِهَا وَلَمْ يَفْرِضْ لَهَا قَالَ لَهَا الصَّدَاقُ وَعَلَيْهَا الْعِدَّةُ وَلَهَا الْمِيرَاثُ فَقَالَ مَعْقِلُ بْنُ سِنَانٍ شَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِهِ فِي بِرْوَعَ بِنْتِ وَاشِقٍحَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ مِثْلَ حَدِيثِ فِرَاسٍ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Firas] dari [Asy Sya'bi] dari [Masruq] dari [Abdullah] mengenai permasalah; Seorang laki-laki menikahi seorang wanita, lalu laki-laki itu meninggal, dan ia belum sempat menggaulinya dan juga belum memberinya mahar. Abdullah berkata, \"Baginya mahar dan keharusan menunggu masa iddah, serta ia juga mendapat bagian dari harta warisan.\" Kemudian [Ma'qil bin Sinan] berkata; \"Saya telah menyaksikan Nabi shallallahu 'alaihi wasallam menghakimi dengan putusan ini, berkenaan dengan Birwa' binti Wasiq.\" Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Qamah] dari [Abdullah] semisal hadits Firas."},"2094":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَأُتِيَ عَبْدُ اللَّهِ فِي امْرَأَةٍ تَزَوَّجَهَا رَجُلٌ فَتُوُفِّيَ وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يَكُنْ دَخَلَ بِهَا قَالَ فَاخْتَلَفُوا إِلَيْهِ فَقَالَ أَرَى لَهَا مِثْلُ صَدَاقِ نِسَائِهَا وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَشَهِدَ مَعْقِلُ بْنُ سِنَانٍ الْأَشْجَعِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي بِرْوَعَ بِنْتِ وَاشِقٍ بِمِثْلِ هَذَا","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Qamah] ia berkata; Pernah dihadapkan kepada Abdullah suatu persoalan mengenai seorang wanita yang telah dinikahi oleh seorang laki-laki. Kemudian laki-laki itu meninggal, sementara ia belum memberikan wanita itu mahar dan juga belum menggaulinya. Maka orang-orang pun berselisih. [Abdullah] berkata, \"Menurutku, ia berhak mendapatkan mahar sebagaimana isteri-isteri yang lain, ia juga mendapat bagian warisan, dan baginya ada keharusan menunggu masa iddah.\" Kemudian [Ma'qil bin Sinan Al Asyja'i] bersaksi, bahwa Rasulullah shallallahu 'alaihi wasallam telah memutuskan perkara Birwa' binti Wasyiq seperti ini."},"2095":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي وَائِلٍ عَنْ قَيْسِ بْنِ أَبِي غَرَزَةَ قَالَكُنَّا نَبْتَاعُ الْأَوْسَاقَ بِالْمَدِينَةِ وَكُنَّا نُسَمِّي أَنْفُسَنَا السَّمَاسِرَةَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمَّانَا بِاسْمٍ أَحْسَنَ مِمَّا كُنَّا نُسَمِّي أَنْفُسَنَا بِهِ فَقَالَ يَا مَعْشَرَ التُّجَّارِ إِنَّ هَذَا الْبَيْعَ يَحْضُرُهُ اللَّغْوُ وَالْحَلِفُ فَشُوبُوهُ بِالصَّدَقَةِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al A'masy] dari [Abu Wa`il] dari [Qais bin Abu Gharazah] ia berkata; Kami berjual beli beberapa wasaq di Madinah. Dan kami menamakan diri dengan panggilan, \"As Samasirah (tukang makelar).\" Kemudian datanglah Rasulullah shallallahu 'alaihi wasallam dan beliau pun menamai kami dengan panggilan yang lebih baik, beliau berseru: \"YA MA'SYARAT TUJJAAR (Wahai pedagang), sesungguhnya jual beli ini terasuki kelalaian dan sumpah, maka hapuskanlah dengan mengeluarkan sedekah.\" "},"2096":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبِي وَإِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنِ الْبَرَاءِ بْنِ عَازِبٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ حُنَيْنٍ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [bapakku] dan [Isra`il] dari [Abu Ishaq] dari [Al Barra' bin Azib] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat perang Hunain: \"Aku adalah Nabi yang tidak akan berbohong, Aku adalah putranya Abdul Muthalib.\""},"2097":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ قَالَ فَحَدَّثَنِي بِهِ ابْنُ أَبِي لَيْلَى قَالَ فَحَدَّثَ أَنَّ الْبَرَاءَ بْنَ عَازِبٍ قَالَكَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى فَرَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَبَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata, telah menceritakannya kepadaku [Ibnu Abu Laila] ia berkata dan menceritakan bahwa [Al Barra` bin Azib] berkata; Bahwa sifat shalat Rasulullah adalah, lama beliau ruku', mengangkat kepalanya dari ruku', sujud, dan mengangkat kepalanya dari sujud, serta diantara dua sujud, lama kesemuanya hampir-hampir sama (mendekati).\""},"2098":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَاقَ الْهَمْدَانِيَّ يَقُولُ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُلَمَّا أَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ قَالَ فَتَبِعَهُ سُرَاقَةُ بْنُ مَالِكِ بْنِ جُعْشُمٍ فَدَعَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاخَتْ بِهِ فَرَسُهُ فَقَالَ ادْعُ اللَّهَ لِي وَلَا أَضُرُّكَ قَالَ فَدَعَا اللَّهَ لَهُ قَالَ فَعَطِشَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَرُّوا بِرَاعِي غَنَمٍ فَقَالَ أَبُو بَكْرٍ الصِّدِّيقُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَأَخَذْتُ قَدَحًا فَحَلَبْتُ فِيهِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُثْبَةً مِنْ لَبَنٍ فَأَتَيْتُهُ بِهِ فَشَرِبَ حَتَّى رَضِيتُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Abu Ishaq Al Hamdani] berkata, saya mendengar [Al Barra` bin 'Azib] berkata; Ketika Rasulullah shallallahu 'alaihi wasallam berangkat dari Makkah ke Madinah, Suraqah bin Malik bin Ju'tsum mengikutinya. Maka Rasulullah shallallahu 'alaihi wasallam mendo'akan keburukan untuknya, hingga kuda tunggangannya pun tersungkur jatuh. Setelah itu, ia berkata, \"Bedo'alah kebaikan untukku, dan aku tidak akan mencelakaimu.\" Maka Rasulullah shallallahu 'alaihi wasallam pun mendoakan kebaikan untuknya. kemudian Rasulullah shallallahu 'alaihi wasallam kehausan, lalu mereka melewati seorang penggembala kambing, hingga berkatalah [Abu Bakar], \"Maka aku mengambil gelas dan memeras susu untuk Rasulullah shallallahu 'alaihi wasallam, kemudian kudatangi beliau dan beliau pun meminumnya hingga akupun merasa puas.\""},"2099":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي عُبَيْدَةَ وَرَجُلٍ آخَرَ عَنِ الْبَرَاءِ بْنِ عَازِبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَنَامَ تَوَسَّدَ يَمِينَهُ وَيَقُولُ اللَّهُمَّ قِنِي عَذَابَكَ يَوْمَ تَجْمَعُ عِبَادَكَ قَالَ فَقَالَ أَبُو إِسْحَاقَ وَقَالَ الْآخَرُ يَوْمَ تَبْعَثُ عِبَادَكَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata, Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Abu Ubaidah] dan [laki-laki lain] dari [Al Barra` bin 'Azib] ia berkata; Jika Rasulullah shallallahu 'alaihi wasallam hendak tidur, maka beliau menjadikan bagian kanan tubuhnya sebagai sandaran, kemudian berdo'a: \"ALLAHUMMA QINI ADZABAKA YAUMA TAJMA'U IBAADAKA (Ya Allah, jagalah diriku dari adzab-Mu pada hari berkumpulnya semua hamba-MU).\" Abu Ishaq dan yang lain berkata; \"Yaitu pada hari Engkau membangkitkan seluruh hamba-Mu.\""},"2100":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُقَرَأَ رَجُلٌ الْكَهْفَ وَفِي الدَّارِ دَابَّةٌ فَجَعَلَتْ تَنْفِرُ فَنَظَرَ فَإِذَا ضَبَابَةٌ أَوْ سَحَابَةٌ قَدْ غَشِيَتْهُ قَالَا فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْرَأْ فُلَانُ فَإِنَّهَا السَّكِينَةُ تَنَزَّلَتْ عِنْدَ الْقُرْآنِ أَوْ تَنَزَّلَتْ لِلْقُرْآنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Al Baraa`] berkata; Seorang laki-laki membaca surat Al Kahfi, sementara di dalam rumahnya terdapat binatang melata yang seketika itu langsung kabur. Kemudian ia melihat, ternyata awan tipis telah menaunginya. Maka mereka berdua menuturkan hal itu kepada Nabi shallallahu 'alaihi wasallam. beliau bersabda: \"Bacalah wahai Fulan! Itu adalah As sakinah (ketenangan) yang turun saat Al Qur`an dibaca atau atau As Sakinah itu memang turun untuk Al Qur`an.\""},"2101":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَسَمِعْتُ الْبَرَاءَ وَسَأَلَهُ رَجُلٌ مِنْ قَيْسٍ فَقَالَ أَفَرَرْتُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ فَقَالَ الْبَرَاءُ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَفِرَّ كَانَتْ هَوَازِنُ نَاسًا رُمَاةً وَإِنَّا لَمَّا حَمَلْنَا عَلَيْهِمْ انْكَشَفُوا فَأَكْبَبْنَا عَلَى الْغَنَائِمِ فَاسْتَقْبَلُونَا بِالسِّهَامِ وَلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى بَغْلَتِهِ الْبَيْضَاءِ وَإِنَّ أَبَا سُفْيَانَ بْنَ الْحَارِثِ آخِذٌ بِلِجَامِهَا وَهُوَ يَقُولُ أَنَا النَّبِيُّ لَا كَذِبْأَنَا ابْنُ عَبْدِ الْمُطَّلِبْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Al Baraa`] saat itu, seorang laki-laki dari Qais bertanya kepadanya, \"Apakah kalian melihat Rasulullah shallallahu 'alaihi wasallam pada saat perang Hunain?\" Al Baraa` menjawab, \"Akan tetapi, Rasulullah shallallahu 'alaihi wasallam tidak lari dari medan peperangan. Saat itu, kaum Hawazin mempunyai pasukan pemanah. Dan ketika kami memukul mundur dan menjadikan mereka terpecah belah, kami segera melahap ghanimah hingga mereka pun balik menghujani kami dengan anak panah. Dan sungguh, saya melihat Rasulullah shallallahu 'alaihi wasallam berada di atas Bighal putihnya, sementara Sufyan bin Al Harits memegang tali kekangnya. Dan saat itu, beliau bersabda: \"Aku adalah seorang Nabi yang tidak pernah berdusta. Aku adalah putra Abdul Muthallib.\""},"2102":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ قَالَ سَمِعْتُ رَبِيعَ بْنَ الْبَرَاءِ يُحَدِّثُ عَنِ الْبَرَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَقْبَلَ مِنْ سَفَرٍ قَالَ آيِبُونَ تَائِبُونَ عَابِدُونَ لِرَبِّنَا حَامِدُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Ar Rabi' bin Al Baraa`] menceritakan dari [Al Baraa`] bahwa jika Rasulullah shallallahu 'alaihi wasallam kembali dari bepergian, beliau membaca: \"AAYIBUUN TAA`IBUUN 'AABIDUUN LIRABBINAA HAAMIDUUN (Kami kembali dengan bertaubat, beribadah dan memuji Rabb kami).\""},"2103":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَاقَ قَالَقِيلَ لِلْبَرَاءِ أَكَانَ وَجْهُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدِيدًا هَكَذَا مِثْلَ السَّيْفِ قَالَ لَا بَلْ كَانَ مِثْلَ الْقَمَرِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdul Malik] ia berkata, Telah menceritakan kepada kami [Zuhair] Telah menceritakan kepada kami [Abu Ishaq] ia berkata; Pernah ditanyakan kepada [Al Barra`]: \"Apakah wajah Rasulullah shallallahu 'alaihi wasallam keras seperti pedang ini?\" Ia menjawab, \"Tidak, bahkan wajah beliau laksana bulan.\""},"2104":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنِ الْبَرَاءِ بْنِ عَازِبٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَنَزَلْنَا بِغَدِيرِ خُمٍّ فَنُودِيَ فِينَا الصَّلَاةُ جَامِعَةٌ وَكُسِحَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَحْتَ شَجَرَتَيْنِ فَصَلَّى الظُّهْرَ وَأَخَذَ بِيَدِ عَلِيٍّ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَقَالَ أَلَسْتُمْ تَعْلَمُونَ أَنِّي أَوْلَى بِالْمُؤْمِنِينَ مِنْ أَنْفُسِهِمْ قَالُوا بَلَى قَالَ أَلَسْتُمْ تَعْلَمُونَ أَنِّي أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ قَالُوا بَلَى قَالَ فَأَخَذَ بِيَدِ عَلِيٍّ فَقَالَ مَنْ كُنْتُ مَوْلَاهُ فَعَلِيٌّ مَوْلَاهُ اللَّهُمَّ وَالِ مَنْ وَالَاهُ وَعَادِ مَنْ عَادَاهُقَالَ فَلَقِيَهُ عُمَرُ بَعْدَ ذَلِكَ فَقَالَ هَنِيئًا يَا ابْنَ أَبِي طَالِبٍ أَصْبَحْتَ وَأَمْسَيْتَ مَوْلَى كُلِّ مُؤْمِنٍ وَمُؤْمِنَةٍ قَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنِ الْبَرَاءِ بْنِ عَازِبٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Ali bin Zaid] dari [Adi bin Tsabit] dari [Al Baraa` bin Azib] ia berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Kemudian kami singgah di Ghadir Khum dan tak lama kemudian adzan shalat pun dikumandangkan. Sebagai tempat beliau, dibersihkanlah semak-semak yang berada di bawah dua batang pohon, baru kemudian beliau shalat Zhuhur. Setelah itu, beliau langsung memegang tangan Ali radliallahu 'anhu seraya bertanya: \"Bukankah kalian telah mengetahui bahwa diriku lebih berhak terhadap kaum mukminin atas diri mereka sendiri?\" para sahabat menjawab, \"Benar.\" Beliau bertanya lagi, \"Bukankah kalian telah mengetahui bahwa saya lebih berhak terhadap setiap mukmin atas dirinya sendiri?\" para sahabat menjawab, \"Benar.\" Kemudian beliau memegang erat tangan Ali dan bersabda: \"Barang siapa yang menjadikan aku sebagai walinya, maka Ali juga merupakan wali baginya. Ya Allah, tolonglah orang-orang yang menolongnya, dan musuhilah orang yang memusuhinya.\" Setelah itu, Umar bin Khaththab Radliayallahu 'Anhu berkata, \"Selamat bagimu wahai Ali, kamu telah menjadi wali bagi setiap mukmin dan mukminah.\" Abu Abdurrahman berkata, Telah menceritakan kepada kami [Hudbah bin Khalid] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dari [Adi bin Tsabit] dari [Al Barra` bin 'Azib] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"2105":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ عَلْقَمَةُ بْنُ مَرْثَدٍ قَالَ أَخْبَرَنِي عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنِ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْقَبْرِ إِذَا سُئِلَ فَعَرَفَ رَبَّهُ قَالَ وَقَالَ شَيْءٌ لَا أَحْفَظُهُ فَذَلِكَ قَوْلُهُ عَزَّ وَجَلَّ{ يُثَبِّتُ اللَّهُ الَّذِينَ آمَنُوا بِالْقَوْلِ الثَّابِتِ فِي الْحَيَاةِ الدُّنْيَا وَفِي الْآخِرَةِ }","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] ia berkata, [Alqamah bin Martsad], ia berkata; telah mengabarkan kepadaku dari [Sa'ad bin Ubaidah] dari [Al Baraa` bin 'Azib] bahwa Nabi shallallahu 'alaihi wasallam bersabda berkenaan dengan kubur: \"Jika seorang hamba ditanya, kemudian ia mengetahui Rabb-nya, -kemudian beliau mengatakan sesuatu namun saya tidak menghafalnya- dan itulah yang termaktub dalam firman Allah: 'Allah meneguhkan (iman) orang-orang yang beriman dengan Ucapan yang teguh itu dalam kehidupan di dunia dan di akhirat. (QS. Ibrahim 27).'\""},"2106":{"ar":"حَدَّثَنَا زِيَادُ بْنُ عَبْدِ اللَّهِ الْبَكَّائِيُّ قَالَ حَدَّثَنَا مَنْصُورٌ وَالْأَعْمَشُ عَنْ إِبْرَاهِيمَ عَنِ الْأَسْوَدِ عَنْ أَبِي السَّنَابِلِ قَالَوَلَدَتْ سُبَيْعَةُ بَعْدَ وَفَاةِ زَوْجِهَا بِثَلَاثٍ وَعِشْرِينَ أَوْ خَمْسٍ وَعِشْرِينَ لَيْلَةً فَتَشَوَّفَتْ فَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأُخْبِرَ فَقَالَ إِنْ تَفْعَلْ فَقَدْ مَضَى أَجَلُهَا","id":"Telah menceritakan kepada kami [Ziyad bin Abdullah Al Baka`i] ia berkata, Telah menceritakan kepada kami [Manshur] dan [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Abu As Sanabil] ia berkata; Bahwa Subai'ah melahirkan setelah wafatnya suaminya selang dua puluh tiga atau dua puluh lima malam. Maka wanita itu pun berhias (sebagai ungkapan dirinya ingin dinikahi), dan wanita itu pun didatangkan kepada Nabi shallallahu 'alaihi wasallam, lalu dikabarkanlah hal itu pada beliau. Maka beliau bersabda: \"Jika kamu melakukannya, maka waktunya (waktu dibolehkan menikah) pun telah berlalu.\""},"2107":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ ح وَعَفَّانُ قَالَ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنِ الْأَسْوَدِ عَنْ أَبِي السَّنَابِلِ بْنِ بَعْكَكٍ قَالَوَضَعَتْ سُبَيْعَةُ بِنْتُ الْحَارِثِ بَعْدَ وَفَاةِ زَوْجِهَا بِثَلَاثٍ وَعِشْرِينَ أَوْ خَمْسٍ وَعِشْرِينَ لَيْلَةً فَلَمَّا تَعَلَّتْ تَشَوَّفَتْ لِلنِّكَاحِ فَأَنْكَرَ ذَلِكَ عَلَيْهَا وَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ تَفْعَلْ فَقَدْ حَلَّ أَجَلُهَا قَالَ عَفَّانُ فَقَدْ خَلَى أَجَلُهَا","id":"Telah menceritakan kepada kami [Husain bin Muhammad] Telah menceritakan kepada kami [Syaiban] dari [Manshur] -dalam riwayat lain- [Affan] berkata, Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Aswad] dari [Abu As Sanabil bin Ba'kak] ia berkata; Subai'ah bintu Al Harits melahirkan setelah suaminya meninggal selang dua puluh tiga atau dua puluh lima malam. Maka setelah ia mendapatkan alasan, ia pun berhias kembali untuk menikah, lalu perbuatannya itu pun diingkari (tidak disetujui), hingga hal itu disampaikan kepada Nabi shallallahu 'alaihi wasallam. maka beliau bersabda: \"Jika kamu melakukannya, maka waktunya (masa iddahnya) pun telah berlalu.\" Affan berkata; \"Sesungguhnya waktunya (masa iddahnya) Telah habis.\""},"2108":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عَدِيِّ بْنِ الْحَمْرَاءِ الزُّهْرِيَّ أخْبَرَهُ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِالْحَزْوَرَةِ فِي سُوقِ مَكَّةَ وَاللَّهِ إِنَّكِ لَخَيْرُ أَرْضِ اللَّهِ وَأَحَبُّ أَرْضِ اللَّهِ إِلَى اللَّهِ عَزَّ وَجَلَّ وَلَوْلَا أَنِّي أُخْرِجْتُ مِنْكِ مَا خَرَجْتُ","id":"Telah menceritakan kepada kami [Abu Al Yaman] Telah mengabarkan kepada kami [Syu'aib] telah mengabarkan kepada kami [Az Zuhri] telah mengabarkan kepada kami [Abu Salamah bin Abdurrahman] bahwa [Abdullah bin Adi bin Al Hamra' Az Zuhri] telah mengabarkan kepadanya, bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam yang sedang berdiri di pasar kota Makkah, beliau bersabda untuk kota Makkah: \"Demi Allah, sesungguhnya kamu (kota makkah, pent) adalah bumi Allah yang terbaik, dan tanah yang paling dicintai oleh Allah, kalau bukan karena aku diusir, maka aku tidak akan keluar darimu.\""},"2109":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَبْدَ اللَّهِ بْنَ عَدِيِّ بْنِ الْحَمْرَاءِ أَخْبَرَهُ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِالْحَزْوَرَةِ مِنْ مَكَّةَ يَقُولُ لِمَكَّةَ وَاللَّهِ إِنَّكِ لَأَخْيَرُ أَرْضِ اللَّهِ وَأَحَبُّ أَرْضِ اللَّهِ إِلَى اللَّهِ عَزَّ وَجَلَّ وَلَوْلَا أَنِّي أُخْرِجْتُ مِنْكِ مَا خَرَجْتُ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibarahim] Telah menceritakan kepada kami [bapakku] dari [Shalih] ia berkata, [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Abdullah bin Adi Al Hamra`] telah mengabarkan kepadanya bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda kepada kota Makkah saat beliau berdiri di Al Hazwarah: \"Demi Allah, kamu adalah bumi Allah yang terbaik, dan juga tanah yang paling dicintai Allah 'azza wajalla. kalau sekiranya bukan karena aku diusir, maka aku tidak keluar darimu.\""},"2110":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَوَقَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْحَزْوَرَةِ فَقَالَ عَلِمْتُ أَنَّكِ خَيْرُ أَرْضِ اللَّهِ وَأَحَبُّ الْأَرْضِ إِلَى اللَّهِ وَلَوْلَا أَنَّ أَهْلَكِ أَخْرَجُونِي مِنْكِ مَا خَرَجْتُقَالَ عَبْدُ الرَّزَّاقِ وَالْحَزْوَرَةُ عِنْدَ بَابِ الْحَنَّاطِينَ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri di atas Hazwarah bertempat di Makkah seraya bersabda: \"Aku tahu, kamu adalah tanah Allah yang terbaik dan paling dicintai Allah. Kalau bukan karena pendudukmu telah mengusirku, maka aku tidak akan keluar.\" Abdurrazaq berkata; Al Hazwarah berada di sisi Al Hannaathiin."},"2111":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ حَدَّثَنَا رَبَاحٌ عَنْ مَعْمَرٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ شِهَابٍ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بَعْضِهِمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ فِي سُوقِ الْحَزْوَرَةِ وَاللَّهِ إِنَّكِ لَخَيْرُ أَرْضِ اللَّهِ وَأَحَبُّ الْأَرْضِ إِلَى اللَّهِ وَلَوْلَا أَنِّي أُخْرِجْتُ مِنْكِ مَا خَرَجْتُ","id":"Telah menceritakan kepada kami [Ibrahim bin Khalid] Telah menceritakan kepada kami [Rabbah] dari [Ma'mar] dari [Muhammad bin Muslim bin Syihab Az Zuhri] dari [Abu Salamah bin Abdurrahman] dari [sebagian mereka] bahwa Rasulullah shallallahu 'alaihi wasallam berada di pasha Al Hazwarah dan beliau bersabda: \"Demi Allah, kamu adalah bumi Allah yang paling baik, dan paling dicintai-Nya, kalau bukan karena aku diusir darimu, niscaya aku tidak akan keluar.\""},"2112":{"ar":"حَدَّثَنَا أَبُو زَكَرِيَّا يَحْيَى بْنُ إِسْحَاقَ مِنْ كِتَابِهِ أَخْبَرَنَا ابْنُ لَهِيعَةَ وَحَدَّثَنَا إِسْحَاقُ بْنُ عِيسَى حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ عَمْرٍو عَنْ أَبِي ثَوْرٍ وَقَالَ إِسْحَاقُ الْفَهْمِيُّ قَالَكُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَأُتِيَ بِثَوْبٍ مِنْ ثِيَابِ الْمَعَافِرِ فَقَالَ أَبُو سُفْيَانَ لَعَنَ اللَّهُ هَذَا الثَّوْبَ وَلَعَنَ مَنْ يَعْمَلُ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلْعَنْهُمْ فَإِنَّهُمْ مِنِّي وَأَنَا مِنْهُمْ قَالَ إِسْحَاقُ وَلَعَنَ اللَّهُ مَنْ يَعْمَلُهُ","id":"Telah menceritakan kepada kami [Abu Zakaria Yahya bin Ishaq] dari kitabnya, telah mengabarkan kepada kami [Ibnu Lahi'ah] -Dan dalam riwayat lain- Telah menceritakan kepada kami [Ishaq bin Isa] Telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Yazid bin Amru] dari [Abu Tsaur] -dan dalam riwayat lain- Ishaq Al Fahmi berkata; Suatu hari, kami pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam, maka didatangkanlah sehelai pakaian dari kampung Ma'afir, lalu Abu Sufyan pun berkata, \"Semoga Allah melaknati pakaian ini, dan melaknati orang yang membuatnya.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jangan kamu melaknati mereka, karena penduduk perkampungan itu termasuk golonganku, dan aku pun bagian dari mereka.\" -Dalam riwayat lain- Ishaq berkata; Dan semoga Allah melaknati orang yang membuatnya.\" "},"2113":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ عَنْ ضِرْغَامَةَ بْنِ عُلَيْبَةَ بْنِ حَرْمَلَةَ الْعَنْبَرِيِّ قَالَ حَدَّثَنِي أَبِي عَنْ أَبِيهِ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصِنِي قَالَ اتَّقِ اللَّهَ وَإِذَا كُنْتَ فِي مَجْلِسِ قَوْمٍ فَسَمِعْتَهُمْ يَقُولُونَ مَا يُعْجِبُكَ فَأْتِهِ وَإِذَا سَمِعْتَهُمْ يَقُولُونَ مَا تَكْرَهُ فَاتْرُكْهُ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Qurrah bin Khalid] dari [Dlirghamah bin Ulaibatah bin Harmalah Al Ambari] ia berkata, telah menceritakan kepadaku [bapakku] dari [bapaknya] ia berkata; Saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam berwasiatlah padaku.\" Maka beliau pun bersabda: \"Bertaqwalah kepada Allah. Apabila kamu berada di majlis suatu kaum dan kamu mendengar mereka berbincang dengan sesuatu yang membuatmu terkagum, maka ikutlah. Namun, jika kamu mendengar mereka membicarakan sesuatu yang kamu benci, maka tinggalkanlah majelis itu.\""},"2114":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سَلَمَةُ بْنُ نُبَيْطٍ عَنْ أَبِيهِ وَكَانَ قَدْ حَجَّ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَرَأَيْتُهُ يَخْطُبُ يَوْمَ عَرَفَةَ عَلَى بَعِيرِهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Salamah bin Nubaith] dari [bapaknya] dan ia telah menunaikan haji bersama Nabi shallallahu 'alaihi wasallam, ia berkata; Saya telah melihat beliau berkhutbah pada hari Arafah di atas kendaraannya."},"2115":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ حَدَّثَنِي أَبُو مَالِكٍ الْأَشْجَعِيُّ حَدَّثَنِي نُبَيْطُ بْنُ شَرِيطٍ قَالَإِنِّي لَرَدِيفُ أَبِي فِي حَجَّةِ الْوَدَاعِ إِذْ تَكَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ عَلَى عَجُزِ الرَّاحِلَةِ فَوَضَعْتُ يَدِي عَلَى عَاتِقِ أَبِي فَسَمِعْتُهُ يَقُولُ أَيُّ يَوْمٍ أَحْرَمُ قَالُوا هَذَا الْيَوْمُ قَالَ فَأَيُّ بَلَدٍ أَحْرَمُ قَالُوا هَذَا الْبَلَدُ قَالَ فَأَيُّ شَهْرٍ أَحْرَمُ قَالُوا هَذَا الشَّهْرُ قَالَ فَإِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا فِي شَهْرِكُمْ هَذَا فِي بَلَدِكُمْ هَذَا هَلْ بَلَّغْتُ قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ","id":"Telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] telah menceritakan kepadaku [Abu Malik Al Asyja'i] telah menceritakan kepadaku [Nubaith bin Syarith] ia berkata; Saya membonceng di belakang bapakku pada saat Haji Wada', kemudian Nabi shallallahu 'alaihi wasallam berbicara, dan saya pun berdiri di atas hewan tunggangan bagian belakang, saya meletakkan tanganku di atas pundak bapakku. Lalu saya mendengar beliau bertanya: \"Hari apakah yang paling suci?\" para sahabat menjawab, \"Hari ini.\" beliau bertanya lagi: \"Negeri manakah yang paling suci?\" para sahabat menjawab, \"Negeri ini.\" beliau bertanya lagi: \"Bulan apakah yang paling suci?\" mereka menjawab, \"Bulan ini.\" kemudian beliau bersabda: \"Sesungguhnya darah dan harta kalian adalah haram atas kalian, sebagaimana keharaman hari ini, pada bulan ini dan di negeri kalian ini. Apakah saya telah menyampaikan?\" para sahabat menjawab, \"Ya.\" Beliau bersabda: \"Ya Allah, saksikanlah.\""},"2116":{"ar":"حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ عَبْدِ الرَّحْمَنِ أَبُو يَحْيَى الْحِمَّانِيُّ قَالَ حَدَّثَنَا سَلَمَةُ بْنُ نُبَيْطٍ قَالَ كَانَ أَبِي وَجَدِّي وَعَمِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَخْبَرَنِي أَبِي قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَشِيَّةَ عَرَفَةَ عَلَى جَمَلٍ أَحْمَرَ","id":"Telah menceritakan kepada kami [Abdul Hamid bin Abdurrahman Abu Yahya Al Himmani] ia berkata, Telah menceritakan kepada kami [Salamah bin Nubaith] ia berkata; Bapak, kakek dan pamanku, pernah bersama Nabi shallallahu 'alaihi wasallam. Maka [ayahku] mengabarkanku, ia berkata; Saya melihat Nabi shallallahu 'alaihi wasallam berkhutbah pada sore hari di Arafah, sedangkan beliau berada di atas Unta merahnya."},"2117":{"ar":"قَالَ قَالَ سَلَمَةُأَوْصَانِي أَبِي بِصَلَاةِ السَّحَرِ قُلْتُ يَا أَبَتْ إِنِّي لَا أُطِيقُهَا قَالَ فَانْظُرْ الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ فَلَا تَدَعَنَّهُمَا وَلَا تَشْخَصَنَّ فِي الْفِتْنَةِ","id":"Perawi berkata, [Salamah] berkata; [Bapakku] telah berwasiat padaku dengan Shalat Sahar. Saya berkata; \"Wahai ayahku, saya tidak mampu melakukannya.\" Maka bapakku berkata, \"Shalat-lah dua rakaat sebelum fajar, dan jangnlah sekali-kali engkau tinggalkan dan janganlah kamu turut campur dalam fitnah.\""},"2118":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا رَافِعُ بْنُ سَلَمَةَ يَعْنِي الْأَشْجَعِيَّ وَسَالِمُ بْنُ أَبِي الْجَعْدِ عَنْ أَبِيهِ قَالَ حَدَّثَنِي سَلَمَةُ بْنُ نُبَيْطٍ الْأَشْجَعِيُّأَنَّ أَبَاهُ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ رِدْفًا خَلْفَ أَبِيهِ فِي حَجَّةِ الْوَدَاعِ قَالَ فَقُلْتُ يَا أَبَتِ أَرِنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُمْ فَخُذْ بِوَاسِطَةِ الرَّحْلِ قَالَ فَقُمْتُ فَأَخَذْتُ بِوَاسِطَةِ الرَّحْلِ فَقَالَ انْظُرْ إِلَى صَاحِبِ الْجَمَلِ الْأَحْمَرِ الَّذِي يُومِئُ بِيَدِهِ فِي يَدِهِ الْقَضِيبُ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Rafi' bin Salamah yakni Al Asyja'i], dan [Salim bin Abul Ja'd] dari [bapaknya] ia berkata, telah menceritakan kepadaku [Salamah bin Nubaith Al Asyja'i] bahwa [bapaknya] telah menjumpai Nabi shallallahu 'alaihi wasallam, dan ia pernah membonceng di belakang bapaknya pada saat Haji Wada'. Salamah berkata; Saya berkata, \"Wahai bapakku, tunjukkanlah padaku wajah Nabi shallallahu 'alaihi wasallam.\" ia berkata, \"Berdirilah di tengah-tengah kendaraan ini.\" Salamah berkata; Saya berkata, \"Maka, saya pun berdiri pas di tengah-tengah kendaraan dan ia berkata, 'Lihatlah ke arah pemilik Unta yang merah yang sedang memberi isyarat dengan tangannya dan di tangannya terdapat pedang tipis.\""},"2119":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ عَنْ أَخِيهِ عَنْ أَبِي كَاهِلٍ قَالَ إِسْمَاعِيلُ قَدْ رَأَيْتُ أَبَا كَاهِلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَوْمَ عِيدٍ عَلَى نَاقَةٍ خَرْمَاءَ وَحَبَشِيٌّ مُمْسِكٌ بِخِطَامِهَا","id":"Telah menceritakan kepada kami [Waki'] dari [Isma'il bin Abu Khalid] dari [saudaranya] dari [Abu Kahil] -telah berkata Isma'il; saya melihat Abu Kahil- ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada manusia pada saat hari raya. Sedangkan saat itu, beliau berada di atas Untanya yang dilubangi telinganya, sementara seorang budak Habsyi memegang tali kekangnya."},"2120":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ تَصَدَّقُوا فَيُوشِكُ الرَّجُلُ يَمْشِي بِصَدَقَتِهِ فَيَقُولُ الَّذِي أُعْطِيَهَا لَوْ جِئْتَ بِهَا بِالْأَمْسِ قَبِلْتُهَا وَأَمَّا الْآنَ فَلَا حَاجَةَ لِي فِيهَا فَلَا يَجِدُ مَنْ يَقْبَلُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Ma'bad bin Khalid] ia berkata, saya mendengar [Haritsah bin Wahb] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kalian, karena hampir saja akan datang masanya, yang ketika itu seorang laki-laki berjalan (dengan menyuguhkan) sedekahnya, namun orang yang akan menerimanya berkata, 'Sekiranya kamu datang kemarin, pasti akan saya terima. Namun sekarang, saya tidak akan menerimanya, saya tidak butuh lagi dengan sedekahmu.' Hingga laki-laki itu pun tidak mendapatkan orang yang mau menerima sedekahnya.\""},"2121":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ بْنِ وَهْبٍ الْخُزَاعِيِّ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَالْعَصْرَ بِمِنًى أَكْثَرَ مَا كَانَ النَّاسُ وَآمَنَهُ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Haritsah bin Wahb Al Khuza'i] ia berkata; Saya shalat Zhuhur dan Ashar (masing-masing) dua raka'at bersama Nabi shallallahu 'alaihi wasallam di Mina, yang ketika itu kami paling banyak jumlahnya daripada biasanya dan paling banyak mendapatkan thumakninah."},"2122":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُخْبِرُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعَّفٍ لَوْ يُقْسِمُ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُخْبِرُكُمْ بِأَهْلِ النَّارِ كُلُّ جَوَّاظٍ جَعْظَرِيٍّ مُسْتَكْبِرٍ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ma'mad bin Khalid] ia berkata, saya mendengar [Haritsah bin Wahb Al Khuza'i] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku bertahu tentang penduduk surga? Yaitu, setiap orang yang lemah dan ditindas, dan jiga ia bersumpah atas nama Allah, niscaya Allah akan mengabulkan (do'anya). Maukah kalian aku bertahu akan penghuni neraka? Yaitu, setiap orang kasar, bengis, lagi sombong.\""},"2123":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ شُعْبَةَ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَصَدَّقُوا فَإِنَّهُ يُوشِكُ أَحَدُكُمْ أَنْ يَخْرُجَ بِصَدَقَتِهِ فَلَا يَجِدُ مَنْ يَقْبَلُهَا مِنْهُ","id":"Telah menceritakan kepada kami [Waki'] dari [Syu'bah] dari [Ma'bad bin Khalid] ia berkata, saya mendengar [Haritsah bin Wahb] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersedekahlah kalian, karena hampir saja datang suatu masa, yang ketika itu salah seorang dari kaian keluar dengan membawa sedekahnya, namun tak seorang pun yang mau menerimanya.\""},"2124":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مَعْبَدِ بْنِ خَالِدٍ عَنْ حَارِثَةَ بْنِ وَهْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا أُنَبِّئُكُمْ بِأَهْلِ الْجَنَّةِ كُلُّ ضَعِيفٍ مُتَضَعَّفٍ لَوْ أَقْسَمَ عَلَى اللَّهِ لَأَبَرَّهُ أَلَا أُنَبِّئُكُمْ بِأَهْلِ النَّارِ كُلُّ عُتُلٍّ جَوَّاظٍ مُسْتَكْبِرٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Ma'bad bin Khalid] dari [Kharitsah bin Wahb] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah kalian aku bertahu tentang penduduk surga? Yaitu, setiap orang yang lemah dan ditindas, dan jika ia bersumpah atas nama Allah, niscaya Allah akan mengabulkan (do'anya). Maukah kalian aku bertahu akan penghuni neraka? Yaitu, setiap orang kuat, bengis lagi sombong.\""},"2125":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَاقَ يُحَدِّثُ عَنْ حَارِثَةَ بْنِ وَهْبٍ الْخُزَاعِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ مَا كُنَّا وَآمَنَهُ بِمِنًى رَكْعَتَيْنِحَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ مَعْبَدِ بْنِ خَالِدٍ قَالَ سَمِعْتُ حَارِثَةَ بْنَ وَهْبٍ الْخُزَاعِيَّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Abu Ishaq] menceritakan dari [Haritsah bin Wahb Al Khuza'i] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat bersama kami dua raka'at di Mina, yang ketika itu jumlah kami paling banyak tidak seperti sebelumnya, dan paling bisa memperoleh thumakninah. Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Sufyan] dari [Ma'bad bin Khalid] berkata, saya mendengar [Haritsah bin Wahb Al Khuza'i] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam. dan ia pun menyebutkan hadits."},"2126":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ وَالْمَسْعُودِيُّ عَنِ الْوَلِيدِ بْنِ سَرِيعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ إِذَا الشَّمْسُ كُوِّرَتْ وَسَمِعْتُهُ يَقُولُ{ وَاللَّيْلِ إِذَا عَسْعَسَ }","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Mis'ar] dan [Al Mas'udi] dari [Al Walid bin Sari'] dari [Amru bin Huraits] ia berkata; Saat menunaikah shalat Fajar (Subuh), saya mendengar Rasulullah shallallahu 'alaihi wasallam membaca: \"IDZAASY SYAMSU KUWWIRAT.\""},"2127":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُسَاوِرٌ الْوَرَّاقُ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Musawir Al Warraq] dari [Ja'far bin Amru bin Huraits] dari [bapaknya] bahwa Nabi shallallahu 'alaihi wasallam berkhutbah kepada manusia, dan saat itu, beliau mengenakan Imamah (sejenis surban) yang berwarna hitam."},"2128":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ السُّدِّيِّ عَمَّنْ سَمِعَ عَمْرَو بْنَ حُرَيْثٍ يَقُولُصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَعْلَيْهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [As Sudi] dari [seorang] yang mendengar [Amru bin] Huraits, ia berkata; Rasulullah shallallahu 'alaihi wasallam shalat dengan mengenakan terompahnya."},"2129":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنْ السُّدِّيِّ حَدَّثَنِي مَنْ سَمِعَ عَمْرَو بْنَ حُرَيْثٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِي نَعْلَيْنِ مَخْصُوفَيْنِ","id":"Telah menceritakan kepada kami [Abdurrahman] Telah menceritakan kepada kami [Sufyan] dari [As Sudi] telah menceritakan kepadaku [seorang] yang mendengar [Amru bin Huraits], ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan memakai terompah yang sering beliau gunakan untuk bepergian."},"2130":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَجَّاجِ الْمُحَارِبِيِّ عَنْ أَبِي الْأَسْوَدِ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ يَقْرَأُ{ لَا أُقْسِمُ بِالْخُنَّسِ الْجَوَارِ الْكُنَّسِ }","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hajjaj Al Muharibi] dari [Abul Aswad] dari [Amru bin Huraits] ia berkata; Saya pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam, dan saya pun mendengarnya membaca surat: \"LAA UQSIMU BIL KHUNNAS AL JAWAARIL KUNNAS.\""},"2131":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا مِسْعَرٌ عَنْ الْوَلِيدِ بْنِ سَرِيعٍ عَنْ عَمْرِو بْنِ حُرَيْثٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي الْفَجْرِ{ وَاللَّيْلِ إِذَا عَسْعَسَ }","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] Telah menceritakan kepada kami [Mis'ar] dari [Al Walid bin Sari'] dari [Amru bin Huraits] ia berkata; Saat menunaikan shalat Fajar (Subuh), saya mendengar Nabi shallallahu 'alaihi wasallam membaca: \"WAL LAILI IDZAA 'AS'AS.\""},"2132":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنِي إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ يَعْنِي ابْنَ مُهَاجِرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ سَعِيدِ بْنِ حُرَيْثٍ أَخٍ لِعَمْرِو بْنِ حُرَيْثٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ بَاعَ دَارًا أَوْ عَقَارًا فَلَمْ يَجْعَلْ ثَمَنَهَا فِي مِثْلِهِ كَانَ قَمِنًا أَنْ لَا يُبَارَكَ لَهُ فِيهِ","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepadaku [Isma'il bin Ibrahim yakni Ibnu Muhajir], dari [Abdul Malik bin Umair] dari [Sa'id bin Huraits] saudaranya Amru bin Huraits, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menjual rumah atau tempat tinggal, namun ia tidak menentukan harganya sebagaimana harga rumah yang lain, maka sudah sepantasnya ia tidak mendapatkan keberkahan padanya.\""},"2133":{"ar":"حَدَّثَنَا وَكِيعٌ وَابْنُ جَعْفَرٍ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ عَدِيِّ بْنِ ثَابِتٍ قَالَ ابْنُ جَعْفَرٍ سَمِعْتُ عَبْدَ اللَّهِ بْنَ يَزِيدَ الْأَنْصَارِيَّ يُحَدِّثُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النُّهْبَةِ وَالْمُثْلَةِ","id":"Telah menceritakan kepada kami [Waki'] dan [Ibnu Ja' far] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Adi bin Tsabit] -dalam riwayat lain- Ibnu Ja'far berkata, saya mendengar [Abdullah bin Yazid Al Anshari] menceritakan, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang Nuhbah (mengambil harta secara paksa dan terang-terangan) dan Mutslah (mencincang tubuh baik sebelum mati atau setelah menjadi mayat)."},"2134":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنِي عَبْدُ الْجَبَّارِ بْنُ عَبَّاسٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ مَعْرُوفٍ صَدَقَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepadaku [Abdul Jabbar bin Abbas] dari [Adi bin Tsabit] dari [Abdullah bin Yazid Al Al Khathmi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap kebaikan adalah sedekah.\""},"2135":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ عَنْ شُعْبَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ وَهُوَ الْأَنْصَارِيُّ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النُّهْبَةِ وَالْمُثْلَةِ","id":"Telah menceritakan kepada kami [Ibrahim bin Isma'il] dari [Syu'bah] dari [Adi bin Tsabit] dari [Abdullah bin Yazid Al Khathmi Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang Nuhbah (mengambil harta secara paksa dan terang-terangan) dan Mutslah (mencincang tubuh baik sebelum mati atau setelah menjadi mayat)."},"2136":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ قَالَ سَمِعْتُ أَبِي يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى بِالْبَطْحَاءِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ الظُّهْرَ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ يَمُرُّ مِنْ وَرَائِهِ الْمَرْأَةُ وَالْحِمَارُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] dari [Aun bin Abu Juhaifah] ia berkata, saya mendengar [bapakku] menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah shalat Zhuhur dua raka'at dan Ashar dua raka'at di Bathha`, sedangkan di hadapannya terdapat tongkat (yang ditancapkan). Saat itu, dibelakang beliau lewat seorang wanita dan seekor Himar."},"2137":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا إِسْمَاعِيلُ يَعْنِي ابْنَ خَالِدٍ حَدَّثَنِي أَبُو جُحَيْفَةَ أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَشْبَهَ النَّاسِ بِهِ الْحَسَنُ بْنُ عَلِيٍّ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Isma'il yakni Ibnu Khalid], telah menceritakan kepadaku [Abu Juhaifah] bahwa ia pernah melihat Rasulullah shallallahu 'alaihi wasallam dan orang yang paling mirip dengan beliau adalah Al Hasan bin Ali."},"2138":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ قَالَ أَخْبَرَنِي مَالِكُ بْنُ مِغْوَلٍ وَعُمَرُ بْنُ أَبِي زَائِدَةَ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ الظُّهْرَ وَالْعَصْرَ رَكْعَتَيْنِ رَكْعَتَيْنِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ قَدْ أَقَامَهَا بَيْنَ يَدَيْهِ يَمُرُّ مِنْ وَرَائِهَا النَّاسُ وَالْحِمَارُ وَالْمَرْأَةُ","id":"Telah menceritakan kepada kami [Yahya bin Zakaria bin Abu Za`idah] ia berkata, telah mengabarkan kepadaku [Malik bin Mighwal] dan [Amru bin Za`idah] dari [Aun bin Abu Juhaifah] dari [bapaknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat Zhuhur dan Ashar dua raka'at dua raka'at bersama kami di Bathha`, sedangkan di hadapan beliau terdapat tongkat yang telah beliau tancapkan. Sehingga orang-orang pun lewat di belakang beliau, begitu juga Himar dan wanita.\""},"2139":{"ar":"حَدَّثَنَا يَزِيدُ قَالَ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ قَالَ سَمِعْتُ أَبَا جُحَيْفَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنْ كَانَ أَشْبَهَ النَّاسِ بِهِ الْحَسَنُ بْنُ عَلِيٍّ","id":"Telah menceritakan kepada kami [Yazid] ia berkata, telah mengabarkan kepada kami [Isma'il bin Abu Khalid] ia berkata, saya mendengar [Abu Juhaifah] ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam, dan sesungguhnya orang yang paling mirip dengan beliau adalah Al Hasan bin Ali."},"2140":{"ar":"حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنِي شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ أَنَّهُشَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى الظُّهْرَ بِالْبَطْحَاءِ رَكْعَتَيْنِ وَالْعَصْرَ رَكْعَتَيْنِ وَبَيْنَ يَدَيْهِ عَنَزَةٌ يَمُرُّ مِنْ وَرَائِهَا الْحِمَارُ وَالْمَرْأَةُ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepadaku [Syu'bah] dari [Aun bin Abu Juhaifah] dari [bapaknya] bahwa pernah menyaksiakan Nabi shallallahu 'alaihi wasallam shalat Zhuhur dan Ashar dua raka'at dua raka'at di Bathha` dan di hadapan beliau terdapat tancapan tongkat, hingga Himar dan wanita lewat di belakang beliau."},"2141":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي جُحَيْفَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ الْعَصْرَ رَكْعَتَيْنِقَالَ قِيلَ لَهُ مِثْلُ مَنْ أَنْتَ يَوْمَئِذٍ قَالَ أَبْرِي النَّبْلَ وَأَرِيشُهَا","id":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Abu Juhaifah] ia berkata; Saya pernah shalat Ashar dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Al Abthah. Kemudian ditanyakan kepadanya, \"Seperti yang kamu lakukan pada hari itu?\" ia berkata, \"Saya meruncingkan kayu, lalu menancapkannya.\""},"2142":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ أَبِي إِسْحَاقَ عَنْ أَبِي جُحَيْفَةَ وَهْبِ بْنِ عَبْدِ اللَّهِ السُّوَائِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِالْأَبْطَحِ الْعَصْرَ رَكْعَتَيْنِ ثُمَّ قَدَّمَ بَيْنَ يَدَيْهِ عَنَزَةً بَيْنَهُ وَبَيْنَ مَارَّةِ الطَّرِيقِ وَرَأَيْتُ الشَّيْبَ بِعَنْفَقَتِهِ أَسْفَلَ مِنْ شَفَتِهِ السُّفْلَى","id":"Telah menceritakan kepada kami [Isma'il bin Umar] Telah menceritakan kepada kami [Yunus] dari [Abu Ishaq] dari [Abu Juhaifah Wahb bin Abdullah As Suwa`i] ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam shalat Ashar dua raka'at di Abthah, kemudian beliau meletakkan tombak di depannya, yakni tepat antara beliau dan jalan. Dan saya melihat uban pada rambut yang tumbuh antara bawah bibir dan dagunya."},"2143":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَاقَ عَنْ ابْنِ أَبِي جُحَيْفَةَ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِالْأَبْطَحِ صَلَاةَ الْعَصْرِ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari [Ibnu Abu Juhaifah] dari [bapaknya] ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam shalat Ashar dua raka'at di di Abthah."},"2144":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنْ وَهْبٍ السُّوَائِيِّ أَنَّهُصَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْأَبْطَحِ الْعَصْرَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Ahmad] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Wahb As Suwa`i] bahwa ia pernah shalat Ashar dua raka'at di Al Abthah."},"2145":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي عَوْنُ بْنُ أَبِي جُحَيْفَةَ قَالَرَأَيْتُ أَبِي اشْتَرَى حَجَّامًا فَأَمَرَ بِالْمَحَاجِمِ فَكُسِرَتْ قَالَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَمَنِ الدَّمِ وَثَمَنِ الْكَلْبِ وَكَسْبِ الْبَغِيِّ وَلَعَنَ الْوَاشِمَةَ وَالْمُسْتَوْشِمَةَ وَآكِلَ الرِّبَا وَمُوكِلَهُ وَلَعَنَ الْمُصَوِّرَ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Aun bin Abu Juhaifah] ia berkata; Saya melihat [bapakku] membeli seorang budak yang berprofesi sebagai tukang bekam. Kemudian ia memerintahkannya untuk mengambil alat-alat bekam miliknya lalu alat-alat bekam itu pun dipecahkan. Maka menanyakan hal itu kepadanya, dan ia pun menjawab, \"Rasulullah shallallahu 'alaihi wasallam melarang, Tsaman Ad Dam (bayaran dari hasil bekam), hasil penjualan anjing, pendapatan wanita pelacur. Dan beliau melaknat orang yang mentato dan yang minta ditato serta melaknati pemakan riba dan orang yang memberi makan dari hasil riba, kemudian beliau juga melaknat tukang gambar.\""},"2146":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمَرَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ عَنْ الْحَجِّ بِعَرَفَةَ فَقَالَ الْحَجُّ يَوْمُ عَرَفَةَ أَوْ عَرَفَاتٍ وَمَنْ أَدْرَكَ لَيْلَةَ جَمْعٍ قَبْلَ صَلَاةِ الصُّبْحِ فَقَدْ تَمَّ حَجُّهُ أَيَّامُ مِنًى ثَلَاثَةٌ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Bukair bin Atha`] ia berkata, saya mendengar [Abdurrahman bin Ya'mar] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam ditanya oleh seorang laki-laki mengenai haji di Arafah. Maka beliau menjawab: \"Haji itu adalah pada hari Arafah -atau Arafaat-, barangsiapa yang mendapati Lailah Jami' (malam di Muzdalifah) sebelum shalat Subuh, maka hajinya telah sempurna. Hari-hari di Mina ada tiga hari, barangsiapa yang ingin cepat berangkat (dari Mina) sesudah dua hari, Maka tiada dosa baginya. dan barangsiapa yang ingin menangguhkan (keberangkatannya dari dua hari itu), Maka tidak ada dosa pula baginya.\""},"2147":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ اللَّيْثِيِّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمَرَ الدِّيلِيَّ يَقُولُشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِعَرَفَةَ وَأَتَاهُ نَاسٌ مِنْ أَهْلِ نَجْدٍ فَقَالُوا يَا رَسُولَ اللَّهِ كَيْفَ الْحَجُّ فَقَالَ الْحَجُّ عَرَفَةُ فَمَنْ جَاءَ قَبْلَ صَلَاةِ الْفَجْرِ مِنْ لَيْلَةِ جَمْعٍ فَقَدْ تَمَّ حَجُّهُ أَيَّامُ مِنًى ثَلَاثَةُ أَيَّامٍ{ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ }ثُمَّ أَرْدَفَ رَجُلًا خَلْفَهُ فَجَعَلَ يُنَادِي بِهِنَّ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Bukair bin Atha` Al Laitsi] ia berkata, saya mendengar [Abdurrahman bin Ya'mar Ad Daili] berkata; Saya telah menyaksikan Rasulullah shallallahu 'alaihi wasallam wukuf di Arafah. Kemudian orang-orang dari penduduk Najd mendatanginya dan bertanya, \"Wahai Rasulullah, bagaimanakah Haji itu?\" beliau menjawab: \"Haji itu intinya adalah wukuf di Arafah. Maka barangsiapa yang datang sebelum shalat Subuh, pada Lailah Jami' (malam Muzdalifah), maka hajinya telah sempurna. Hari-hari Mina adalah tiga hari, barangsiapa yang ingin cepat berangkat (dari Mina) sesudah dua hari, Maka tiada dosa baginya. dan barangsiapa yang ingin menangguhkan (keberangkatannya dari dua hari itu), Maka tidak ada dosa pula baginya.\" Kemudian seorang laki-laki mengikuti di belakangnya dan menyerukan hal itu."},"2148":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا شُعْبَةُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ اللَّيْثِيِّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمَرَ الدِّيلِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَسَأَلَهُ رَجُلٌ عَنْ الْحَجِّ فَقَالَ الْحَجُّ يَوْمُ عَرَفَاتٍ أَوْ عَرَفَةَ مَنْ أَدْرَكَ لَيْلَةَ جَمْعٍ قَبْلَ أَنْ يُصَلِّيَ الصُّبْحَ فَقَدْ أَدْرَكَ الْحَجَّ أَيَّامُ مِنًى ثَلَاثَةُ أَيَّامٍ{ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ }","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Syu'bah] dari [Bukair bin Atha` Al Laitsi] ia berkata, saya mendengar [Abdurrahman bin Ya'mar Ad Daili] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, yang salah seorang laki-laki bertanya kepadanya tentang haji, maka beliau menjawab: \"Haji itu adalah pada hari Arafaat atau Arafah. Barangsiapa yang mendapatkan Lailah Jam'i (malam hari di Muzdalifah) sebelum ia menunaikan shalat Subuh, maka ia telah mendapatkan haji. Hari-hari di Mina adalah tiga hari, barangsiapa yang ingin cepat berangkat (dari Mina) sesudah dua hari, Maka tiada dosa baginya. Dan barangsiapa yang ingin menangguhkan (keberangkatannya dari dua hari itu), Maka tidak ada dosa pula baginya.\""},"2149":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ قَالَ سَمِعْتُ عَطِيَّةَ الْقُرَظِيَّ يَقُولُعُرِضْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَكَانَ مَنْ أَنْبَتَ قُتِلَ وَلَمْ يُنْبِتْ خُلِّيَ سَبِيلُهُ فَكُنْتُ فِيمَنْ لَمْ يُنْبِتْ فَخُلِّيَ سَبِيلِي","id":"Telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin Umair] berkata: \"Aku mendengar [Atiyyah Al Quradiyyi] berkata: \"Bahwa pada hari ditaklukkan bani Quraidloh dihadapkan tawanan dari mereka, maka yang telah tumbuh rambut kemaluannya (baligh, pent) maka dia dibunuh, dan barang siapa yang belum tumbuh rambut kemaluannya, maka dibiarkan, dan aku adalah termasuk yang belum tumbuh rambut kemaluannya, lalu dibiarkannya oleh beliau\""},"2150":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَاصِمٍ أَخْبَرَنَا الْمُغِيرَةُ عَنْ شِبَاكٍ عَنْ عَامِرٍ أَخْبَرَنِي فُلَانٌ الثَّقَفِيُّ قَالَسَأَلْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَلَاثٍ فَلَمْ يُرَخِّصْ لَنَا فِي شَيْءٍ مِنْهُنَّ سَأَلْنَاهُ أَنْ يَرُدَّ إِلَيْنَا أَبَا بَكْرَةَ وَكَانَ مَمْلُوكًا وَأَسْلَمَ قَبْلَنَا فَقَالَ لَا هُوَ طَلِيقُ اللَّهِ ثُمَّ طَلِيقُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ سَأَلْنَاهُ أَنْ يُرَخِّصَ لَنَا فِي الشِّتَاءِ وَكَانَتْ أَرْضُنَا أَرْضًا بَارِدَةً يَعْنِي فِي الطَّهُورِ فَلَمْ يُرَخِّصْ لَنَا وَسَأَلْنَاهُ أَنْ يُرَخِّصَ لَنَا فِي الدُّبَّاءِ فَلَمْ يُرَخِّصْ لَنَا فِيهِ","id":"Telah menceritakan kepada kami [Ali Bin ashim] Telah mengabarkan kepada kami [Al-Mughirah] dari [Syibak] dari ['Amir] telah mengabarkan kepadaku [Fulan Atstsaqafi] mengatakan, kami bertanya Rasulullah Shallallahu'alaihiwasallam tentang tiga perkara dan beliau sama sekali tidak memberi kami keringanan (rukhsah, dispensasi) dalam ketiga-tiganya. Pernah kami meminta beliau untuk mengembalikan Abu Bakrah kepada kami, ia sebelumnya adalah seorang budak, namun beliau menolak seraya berujar \"Oh tidak, ia adalah orang yang dibebaskan Rasulullah Shallallahu'alaihiwasallam! Kemudian kami meminta beliau untuk memberi keringanan kepada kami saat musim dingin, sebab ketika itu pemukiman kami adalah pemukiman yang dingin, maksudnya ketika bersuci, namun beliau sama sekali tidak memberi keringanan, dan kami meminta beliau untuk memberi keringanan perihal duba' (rendaman anggur yang dibuat dalam kulit labu), dan beliau sama sekali tidak memberi keringanan kepada kami."},"2151":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبَانُ بْنُ عَبْدِ اللَّهِ الْبَجَلِيُّ حَدَّثَنِي عُمُومَتِي عَنْ جَدِّهِمْ صَخْرِ بْنِ عَيْلَةَأَنَّ قَوْمًا مِنْ بَنِي سُلَيْمٍ فَرُّوا عَنْ أَرْضِهِمْ حِينَ جَاءَ الْإِسْلَامُ فَأَخَذْتُهَا فَأَسْلَمُوا فَخَاصَمُونِي فِيهَا إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّهَا عَلَيْهِمْ وَقَالَ إِذَا أَسْلَمَ الرَّجُلُ فَهُوَ أَحَقُّ بِأَرْضِهِ وَمَالِهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Aban bin Abdullah Al Balhili] Telah menceritakan kepadaku [paman-pamanku] dari [Shakhr bin Abdullah] Bahwa kaum dari bani Sulaim lari dari tanah kediaman mereka ketika Islam datang. Maka saya pun mengambil tanah milik mereka. Setelah itu, mereka masuk Islam lalu mengadukan permasalahan tersebut kepada Nabi shallallahu 'alaihi wasallam, maka beliau pun mengembalikan semua tanah mereka dan bersabda: \"Jika seseorang telah memeluk Islam, maka dialah yang paling berhak atas tanah dan hartanya.\""},"2152":{"ar":"حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي جَعْفَرٍ الْفَرَّاءِ قَالَ سَمِعْتُ أَبَا أُمَيَّةَ الْفَزَارِيَّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْتَجِمُوَلَمْ يَقُلْ أَبُو نُعَيْمٍ مَرَّةً الْفَرَّاءَ قَالَ أَبُو جَعْفَرٍ وَلَمْ يَقُلْ الْفَرَّاءَ","id":"Telah menceritakan kepada kami [Al Fadl bin Dukain] Telah menceritakan kepada kami [Syarik] dari [Abu Ja'far Al Farra`] ia berkata, saya mendengar [Abu Umayyah Al Fazari] berkata; Saya telah melihat Rasulullah shallallahu 'alaihi wasallam bekam. Dan sekali waktu, Abu Nu'aim tidak menyebutkan, Al Faraa`. Abu Ja'far berkata; Ia belum menyebutkan Al Farraa`."},"2153":{"ar":"حَدَّثَنَا وَكِيعٌ وَابْنُ جَعْفَرٍ قَالَا ثَنَا شُعْبَةُ عَنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ ابْنُ جَعْفَرٍ سَمِعْتُ ابْنَ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ الْجُهَنِيِّ قَالَأَتَانَا كِتَابُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ بِأَرْضِ جُهَيْنَةَ وَأَنَا غُلَامٌ شَابٌّ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Waki'] dan [Ibnu Ja'far] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] -dalam riwayat lain- [Ibnu Ja'far] bekata, saya mendengar [Ibnu Laila] dari [Abdullah bin Ukaim Al Juhani] ia berkata; Telah datang kepada kami surat dari baginda Rasulullah shallallahu 'alaihi wasallam saat kami berada di Juhainah, sementara waktu itu saya masih kecil. (Yang isinya tertulis), \"Janganlah kalian mengambil manfaat dari bangkai yang belum disamak dan juga tulang.\""},"2154":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ قَالَدَخَلْنَا عَلَى عَبْدِ اللَّهِ بْنِ عُكَيْمٍ وَهُوَ مَرِيضٌ نَعُودُهُ فَقِيلَ لَهُ لَوْ تَعَلَّقْتَ شَيْئًا فَقَالَ أَتَعَلَّقُ شَيْئًا وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَعَلَّقَ شَيْئًا وُكِلَ إِلَيْهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Ibnu Abu Laila] dari [Saudaranya yakni Isa bin Abdurrahman], ia berkata; Kami berkunjung untuk menemui [Abdullah bin Ukaim] yang saat itu sedang sakit. Lalu dikatakanlah kepadanya, \"Sekiranya kamu mau menggantungkan sesuatu (sejenis tamimah).\" Maka ia pun berkata, \"Apakah saya akan menggantungkan sesuatu sementara Rasulullah shallallahu 'alaihi wasallam telah bersabda: 'Barangsiapa yang menggantungkan sesuatu, maka (Allah akan menjadikan) ketergantungannya pada sesuatu tersebut.'\""},"2155":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ الثَّقَفِيُّ عَنْ خَالِدٍ عَنِ الْحَكَمِ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَكَتَبَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ وَفَاتِهِ بِشَهْرٍ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Abdul Majid Ats Tsaqafi] dari [Khalid] dari [Al Hakam] dari [Abdullah bin Ukaim] ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada kami sebulan sebelum wafatnya, (yang isinya), \"Janganlah kalian mengambil manfaat dari bangkai yang belum disamak dan juga tulang.\""},"2156":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبَّادٌ يَعْنِي ابْنَ عَبَّادٍ قَالَ ثَنَا خَالِدٌ الْحَذَّاءُ عَنِ الْحَكَمِ بْنِ عُتَيْبَةَ عَنِ ابْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ الْجُهَنِيِّ قَالَأَتَانَا كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْضِ جُهَيْنَةَ قَالَ وَأَنَا غُلَامٌ شَابٌّ قَبْلَ وَفَاتِهِ بِشَهْرٍ أَوْ شَهْرَيْنِ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] Telah menceritakan kepada kami [Abbad yakni Ibnu Abbad], ia berkata, Telah menceritakan kepada kami [Khalid Al Hadzdza`] dari [Al Hakam bin Utaibah] dari [Ibnu Abu Laila] dari [Abdullah bin Ukaim Al Juhani] ia berkata; Surat Rasulullah shallallahu 'alaihi wasallam telah sampai pada kami ketika berada di Juhainah, sementara saya waktu itu masih kecil, yakni satu bulan atau dua bulan sebelum wafatnya. (surat itu berisikan), \"Janganlah kalian mengambil manfaat dari bangkai yang belum disamak dan juga tulang.\""},"2157":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا شَرِيكٌ عَنْ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ قَالَجَاءَنَا أَوْ قَالَ كَتَبَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا تَنْتَفِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Ibrahim bin Abul Abbas] Telah menceritakan kepada kami [Syarik] dari [Hilal] dari [Abdullah bin 'Ukaim] ia berkata; Telah datang kepada kami -atau ia mengatkan- Rasulullah shallallahu 'alaihi wasallam menulis surat kepada kami (yang isinya), \"Janganlah kalian mengambil manfaat dari bangkai yang belum disamak dan juga tulang.\""},"2158":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍ أَنَّهُقَالَ قُرِئَ عَلَيْنَا كِتَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَرْضِ جُهَيْنَةَ وَأَنَا غُلَامٌ شَابٌّ أَنْ لَا تَسْتَمْتِعُوا مِنْ الْمَيْتَةِ بِإِهَابٍ وَلَا عَصَبٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata, saya mendengar [Ibnu Abu Laila] menceritakan dari [Abdullah bin Ukaim] bahwa ia berkata; Telah dibacakan kepada kami kitab Rasulullah shallallahu 'alaihi wasallam di bumi Juhainah. Saat itu, saya masih kecil, (surat bertuliskan), \"Janganlah kalian mengambil manfaat dari bangkai, baik kulitnya yang belum disemak, atau pun tulangnya.\""},"2159":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدٍ يَعْنِي ابْنَ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى عَنْ عَبْدِ اللَّهِ بْنِ عُكَيْمٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ تَعَلَّقَ شَيْئًا أُكِلَ عَلَيْهِ أَوْ إِلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Muhammad yakni Ibnu Abu Laila], dari [saudaranya yakni Isa], dari [Abdullah bin Ukaim] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Barangsiapa yang menggantungkan sesuatu (tamimah), maka (Allah akan menjadikan) ketergantungan hatinya pada sesuatu tersebut.\""},"2160":{"ar":"حَدَّثَنَا بَهْزٌ وَأَبُو كَامِلٍ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا سِمَاكٌ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ طَارِقِ بْنِ سُوَيْدٍ الْحَضْرَمِيِّ أَنَّهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بِأَرْضِنَا أَعْنَابًا نَعْتَصِرُهَا فَنَشْرَبُ مِنْهَا قَالَ لَا فَعَاوَدْتُهُ فَقَالَ لَا فَقُلْتُ إِنَّا نَسْتَشْفِي بِهَا لِلْمَرِيضِ فَقَالَ إِنَّ ذَاكَ لَيْسَ شِفَاءً وَلَكِنَّهُ دَاءٌحَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا ثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ وَائِلِ بْنِ حُجْرٍ الْحَضْرَمِيِّ قَالَ حَجَّاجٌ إِنَّهُ شَهِدَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلَهُ رَجُلٌ مِنْ خَثْعَمٍ يُقَالُ لَهُ سُوَيْدُ بْنُ طَارِقٍ وَقَالَ ابْنُ جَعْفَرٍ أَوْ طَارِقُ بْنُ سُوَيْدٍ الْجُعْفِيُّ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَمْرِ فَنَهَاهُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Bahz] dan [Abu Kamil] keduanya berkata, Telah menceritakan kepada kami [Hammad bin Salamah] Telah menceritakan kepada kami [Simak] dari [Alqamah bin Wa`il] dari [Thariq bin Suwaid Al Hadlrami] bahwa ia berkata; saya berkata, \"Wahai Rasulullah, di lahan kami terdapat hasil anggur yang kemudian kami memerasnya dan meminumnya, \" Beliau bersabda: \"(Hal itu) tidak boleh (kamu lakukan).\" Saya mengulanginya kembali, kemudian beliau tetap bersabda: \"Tidak boleh.\" Saya berkata lagi, \"Kami meminumkannya kepada orang sakit.\" Maka beliau bersabda: \"Itu bukanlah obat tapi justru penyakit.\" Telah menceritakan kepada kami [Hajjaj bin Muhammad] dan [Muhammad bin Ja'far] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Alqamah bin Wa`il] dari [bapaknya yakni Wa`il bin Hujr Al Hadlrami] -Hajjaj berkata, bahwa ia telah menyaksikan Nabi shallallahu 'alaihi wasallam- ditanya oleh seorang laki-laki dari Ja'tsam yang biasa dipanggil Suwaid bin Thariq -Ibnu Ja'far berkata- atau Thariq bin Suwaid Al Ju'fi bahwa pernah bertanya kepada Nabi shallallahu 'alaihi wasallam tentang khamer. Maka beliau pun melarangnya. Kemudian ia menyebutkan hadits."},"2161":{"ar":"حَدَّثَنَا إِسْحَاقُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ عُبَيْدِ بْنِ عَلِيٍّ عَنْ أَبِي سَلَامَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُوصِي الرَّجُلَ بِأُمِّهِ أُوصِي الرَّجُلَ بِأُمِّهِ أُوصِي الرَّجُلَ بِأُمِّهِ أُوصِي الرَّجُلَ بِأَبِيهِ أُوصِي الرَّجُلَ بِأَبِيهِ أُوصِي الرَّجُلَ بِمَوْلَاهُ الَّذِي يَلِيهِ وَإِنْ كَانَ عَلَيْهِ فِيهِ أَذًى يُؤْذِيهِ","id":"Telah menceritakan kepada kami [Ishaq bin Yusuf] dari [Sufwan] dari [Manshur] dari [Ubaid bin Ali] dari [Abu Salamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku berwasiat kepada setiap orang (untuk berbakti kepada) ibunya, aku berwasiat kepada setiap orang (untuk berbakti kepada) ibunya, aku berwasiat kepada setiap orang (untuk berbakti kepada) ibunya, aku berwasiat kepada setiap orang (untuk berbakti kepada) bapaknya, aku berwasiat kepada setiap orang (untuk berbakti kepada) bapaknya, dan aku berwasiat kepada setiap orang (untuk berbuat baik) kepada budak miliknya, meskipun padanya terdapat sesuatu yang menyakitkannya.\""},"2162":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ عُرْفُطَةَ السُّلَمِيِّ عَنْ خِدَاشٍ أَبِي سَلَامَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ أُوصِي امْرَأً بِأُمِّهِ أُوصِي امْرَأً بِأَبِيهِ أُوصِي امْرَأً بِأُمِّهِ أُوصِي امْرَأً بِأَبِيهِ أُوصِي امْرَأً بِأَبِيهِ أُوصِي امْرَأً بِمَوْلَاهُ الَّذِي يَلِيهِ وَإِنْ كَانَتْ عَلَيْهِ فِيهِ أَذَاةٌ تُؤْذِيهِحَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عُرْفُطَةَ السُّلَمِيِّ عَنْ خِدَاشٍ أَبِي سَلَامَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُوصِي امْرَأً فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Husain bin Muhammad] Telah menceritakan kepada kami [Syaiban] dari [Manshur] dari [Abdullah bin Ali bin 'Urfuthah As Sulami] dari [Al Khidasy Abu Salamah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Saya mewasiatkan kepada setiap orang (untuk berbakti) kepada ibunya, saya mewasiatkan kepada setiap orang (untuk berbakti) kepada bapaknya, saya mewasiatkan kepada setiap orang (untuk berbakti) kepada ibunya, saya mewasiatkan kepada setiap orang (untuk berbakti) kepada bapaknya, dan aku berwasiat kepada setiap orang (untuk berbuat baik) kepada budak miliknya, meskipun padanya terdapat sesuatu yang menyakitkannya.\" Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Abu Awanah] dari [Manshur] dari [Ubaidullah bin Urfuthah As Sulami] dari [Khidasy Abu Salamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya berwasiat kepada setiap orang.., \" kemudian ia pun menyebutkan maknanya."},"2163":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ سِنَانٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَحْلُبُ فَقَالَ دَعْ دَاعِيَ اللَّبَنِ","id":"Telah menceritakan kepada kami [Abdurrahman] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abdullah bin Sinan] dari [Dlirar Al Azwar] bahwa Nabi shallallahu 'alaihi wasallam pernah melewatinya yang saat itu sedang memeras susu, maka beliau pun bersabda: \"Tinggalkan pemeras susu.\""},"2164":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا عُمَرُ مِنْ آلِ حُذَيْفَةَ عَنِ الشَّعْبِيِّ عَنْ دِحْيَةَ الْكَلْبِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَلَا أَحْمِلُ لَكَ حِمَارًا عَلَى فَرَسٍ فَيُنْتِجَ لَكَ بَغْلًا فَتَرْكَبُهَا قَالَ إِنَّمَا يَفْعَلُ ذَلِكَ الَّذِينَ لَا يَعْلَمُونَ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] Telah menceritakan kepada kami [Umar] yakni dari keluarga Hudzaifah, dari [Asy Sya'bi] dari [Dihyah Al Kalbi] ia berkata; saya berkata, \"Wahai Rasulullah, maukah tuan jika keledai milik tuan dikawinkan dengan kuda sehingga ia melahirkan Baghal dan tuan pun dapat mengendarainya?\" beliau bersabda: \"Sesungguhnya yang melakukan hal itu hanyalah orang yang tidak mengetahui.\""},"2165":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ عَرْفَجَةَ قَالَكُنْتُ فِي بَيْتٍ فِيهِ عُتْبَةُ بْنُ فَرْقَدٍ فَأَرَدْتُ أَنْ أُحَدِّثَ بِحَدِيثٍ قَالَ فَكَانَ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّهُ أَوْلَى بِالْحَدِيثِ مِنْهُ قَالَ فَحَدَّثَ الرَّجُلُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ فِي رَمَضَانَ تُفَتَّحُ أَبْوَابُ السَّمَاءِ وَتُغَلَّقُ أَبْوَابُ النَّارِ وَيُصَفَّدُ فِيهِ كُلُّ شَيْطَانٍ مَرِيدٍ وَيُنَادِي مُنَادٍ كُلَّ لَيْلَةٍ يَا طَالِبَ الْخَيْرِ هَلُمَّ وَيَا طَالِبَ الشَّرِّ أَمْسِكْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Atha` bin Sa`ib] dari [Arfajah] ia berkata; Saya berada di dalam rumah dan di situ terdapat Utbah bin Farqad. Kemudian saya ingin menceritakan suatu hadits. (Arfajah) Berkata; [Seorang laki-laki] dari sahabat Rasulullah shallallahu 'alaihi wasallam -sepertinya ia lebih mengetahui hadits- kemudian laki-laki itu menceritakan dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Pada bulan Ramadlan, pintu-pintu langit akan dibuka dan pintu-pintu neraka akan ditutup, serta setiap syetan akan dirantai. Kemudian pada setiap malam sang penyeru akan menyerukan, 'Wahai para pencari kebaikan, mendekatlah. Dan wahai pencari keburukan, tahan dan berhentilah.'\""},"2166":{"ar":"حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ أَبُو عَبْدِ الرَّحْمَنِ حَدَّثَنِي عَطَاءُ بْنُ السَّائِبِ عَنْ عَرْفَجَةَ قَالَكُنْتُ عِنْدَ عُتْبَةَ بْنِ فَرْقَدٍ وَهُوَ يُحَدِّثُ عَنْ رَمَضَانَ قَالَ فَدَخَلَ عَلَيْنَا رَجُلٌ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَآهُ عُتْبَةُ هَابَهُ فَسَكَتَ قَالَ فَحَدَّثَ عَنْ رَمَضَانَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رَمَضَانَ تُغَلَّقُ فِيهِ أَبْوَابُ النَّارِ وَتُفَتَّحُ فِيهِ أَبْوَابُ الْجَنَّةِ وَتُصَفَّدُ فِيهِ الشَّيَاطِينُ قَالَ وَيُنَادِي فِيهِ مَلَكٌ يَا بَاغِيَ الْخَيْرِ أَبْشِرْ يَا بَاغِيَ الشَّرِّ أَقْصِرْ حَتَّى يَنْقَضِيَ رَمَضَانُ","id":"Telah menceritakan kepada kami [Ubaidah bin Humaid Abu Abdurrahman] Telah menceritakan kepadaku [Atha` bin As Sa`ib] dari [Arfajah] ia berkata; saya berada di sisi Utbah bin Farqad dan ia sedang menceritakan hadits tentang Ramadhan. Tiba-tiba masuklah [seorang laki-laki] dari kalangan sahabat Rasulullah shallallahu 'alaihi wasallam. Maka ketika Utbah melihatnya, ia pun mempersilahkannya lalu ia diam. Kemudian laki-laki itu pun menceritakan hadits mengenai bulan Ramadhan, ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabada: \"Pada bulan Ramadlan, pintu-pintu langit akan dibuka dan pintu-pintu neraka akan ditutup, serta setiap syetan akan dirantai. Kemudian pada setiap malam sang penyeru akan menyerukan, 'Wahai para pencari kebaikan, mendekatlah. Dan wahai pencari keburukan, tahan dan berhentilah.' Hingga bulan Ramadlan belalu.\""},"2167":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنَا شُعْبَةُ عَنِ الْأَسْوَدِ بْنِ قَيْسٍ أَنَّهُ سَمِعَ جُنْدُبًا الْبَجَلِيَّ قَالَقَالَتْ امْرَأَةٌ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَرَى صَاحِبَكَ إِلَّا قَدْ أَبْطَأَ عَلَيْكَ قَالَ فَنَزَلَتْ هَذِهِ الْآيَةُ{ مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah mengabarkan kepada kami [Syu'bah] dari [Al Aswad bin Qais] bahwa ia mendengar [Jundub Al Al Bajali] ia berkata; Seorang wanita berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Saya tidak melihat temanmu (Jibril), kecuali telah meninggalkanmu.\" Maka turunlah ayat: \"Tuhanmu tiada meninggalkan kamu dan tiada (pula) benci kepadamu.\" (QS. Adhdhuha 3)."},"2168":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنِي الْأَسْوَدُ بْنُ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبًا يُحَدِّثُ أَنَّهُشَهِدَ الْعِيدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى ثُمَّ خَطَبَ فَقَالَ مَنْ كَانَ ذَبَحَ قَبْلَ أَنْ يُصَلِّيَ فَلْيُعِدْ مَكَانَهَا أُخْرَى وَقَالَ مَرَّةً أُخْرَى فَلْيَذْبَحْ وَمَنْ كَانَ لَمْ يَذْبَحْ فَلْيَذْبَحْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepadaku [Al Aswad bin Qais] ia berkata, saya mendengar [Jundub] menceritakan bahwa ia pernah mengikuti shalat Ied bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau berkhutbah seraya bersabda: \"Barang siapa yang menyembelih sebelum ditunaikannya shalat, maka ia harus mengulangi (untuk menyembelih hewan kurban) yang lain.\" Kemudian sekali waktu, beliau bersabda: \"Dan barang siapa yang belum menyembelih, maka sembelihlah dengan menyebut nama Allah.\""},"2169":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبِي أَخْبَرَنَا الْجُرَيْرِيُّ عَنِ أَبِي عَبْدِ اللَّهِ الْجُشَمِيِّ حَدَّثَنَا جُنْدُبٌ قَالَجَاءَ أَعْرَابِيٌّ فَأَنَاخَ رَاحِلَتَهُ ثُمَّ عَقَلَهَا ثُمَّ صَلَّى خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى رَاحِلَتَهُ فَأَطْلَقَ عِقَالَهَا ثُمَّ رَكِبَهَا ثُمَّ نَادَى اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تُشْرِكْ فِي رَحْمَتِنَا أَحَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَقُولُونَ هَذَا أَضَلُّ أَمْ بَعِيرُهُ أَلَمْ تَسْمَعُوا مَا قَالَ قَالُوا بَلَى قَالَ لَقَدْ حَظَرْتَ رَحْمَةُ اللَّهِ وَاسِعَةٌ إِنَّ اللَّهَ خَلَقَ مِائَةَ رَحْمَةٍ فَأَنْزَلَ اللَّهُ رَحْمَةً وَاحِدَةً يَتَعَاطَفُ بِهَا الْخَلَائِقُ جِنُّهَا وَإِنْسُهَا وَبَهَائِمُهَا وَعِنْدَهُ تِسْعٌ وَتِسْعُونَ أَتَقُولُونَ هُوَ أَضَلُّ أَمْ بَعِيرُهُ","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [bapakku] Telah mengabarkan kepada kami [Al Jurairi] dari [Abu Abdullah Al Jusyammi] Telah menceritakan kepada kami [Jundub] ia berkata; Seorang A'rabi (Arab Baduwi) datang kemudian turun dari hewan tunggangannya dan mengikatnya, lalu ia shalat dibelakang Rasulullah shallallahu 'alaihi wasallam. Ketika Rasulullah shallallahu 'alaihi wasallam selesai menunaikan shalat, laki-laki itu pun mendatangi hewan tunggangannya kemudian melepaskan tali pelana dan kembali menaikinya. Setelah itu, ia pun menyerukan, \"Ya Allah, kasihanilah aku dan Muhammad, dan janganlah Engkau mengasihi yang lainnya.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bertanya (kepada para sahabat): \"Apakah kalian akan mengatakan bahwa orang ini adalah lebih sesat, ataukah (yang lebih sesat itu) Unta miliknya? Tidakkah kalian mendengar apa yang telah dikatakannya?\" para sahabat menjawab, \"Ya, benar.\" Beliau bersabda: \"Sungguh, kamu telah menyempitkan (rahmat-Nya). Sesungguhnya rahmat Allah sangatlah luas. Allah menciptakan telah seratus rahmat, kemudian yang Dia turunkan hanyalah satu rahmat. (Dan satu rahmat itulah) yang menyelimuti seluruh makhluk-Nya, dari kalangan jin dan manusia. Sedangkan di sisi-Nya, masih tersimpan Sembilan puluh Sembilan rahmat. Apakah kalian akan mengatakan bahwa laki-laki itu lebih sesat, atau Unta miliknya?\""},"2170":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا زُهَيْرٌ عَنِ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبَ بْنَ سُفْيَانَ يَقُولُاشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقُمْ لَيْلَتَيْنِ أَوْ ثَلَاثًا فَجَاءَتْهُ امْرَأَةٌ فَقَالَتْ يَا مُحَمَّدُ لَمْ أَرَهُ قَرَبَكَ مُنْذُ لَيْلَتَيْنِ أَوْ ثَلَاثٍ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Zuhair] dari [Al Aswad bin Qais] ia berkata, saya mendengar [Jundub bin Sufyan] berkata; Rasulullah shallallahu 'alaihi wasallam sakit selama dua malam atau tiga malam. Kemudian datanglah seorang wanita seraya berkata, \"Wahai Muhammad, saya tidak melihat temanmu semenjak dua malam atau tiga malam terakhir ini.\" Maka Allah 'azza wajalla menurunkan ayat: \"Demi waktu matahari sepenggalahan naik, Dan demi malam apabila Telah sunyi (gelap), Tuhanmu tiada meninggalkan kamu dan tiada (pula) benci kepadamu.\" (QS. Adhdhuha 1-2)."},"2171":{"ar":"حَدَّثَنَا عَبِيدَةُ بْنُ حُمَيْدٍ حَدَّثَنِي الْأَسْوَدُ بْنُ قَيْسٍ عَنْ جُنْدُبِ بْنِ سُفْيَانَ الْبَجَلِيِّ ثُمَّ الْعَلَقِيِّ أَنَّهُصَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أَضْحَى فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِذَا هُوَ بِاللَّحْمِ وَذَبَائِحِ الْأَضْحَى فَعَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا ذُبِحَتْ قَبْلَ أَنْ يُصَلِّيَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ ذَبَحَ قَبْلَ أَنْ نُصَلِّيَ فَلْيَذْبَحْ مَكَانَهَا أُخْرَى وَمَنْ لَمْ يَكُنْ ذَبَحَ حَتَّى صَلَّيْنَا فَلْيَذْبَحْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Ubaidah bin Humaid] Telah menceritakan kepadaku [Al Aswad bin Qais] dari [Jundub bin Sufyan Al Bajali Al 'Aqali] bahwa ia pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam pada hari Adlha. Setelah Rasulullah shallallahu 'alaihi wasallam usai menunaikan shalat, beliau mendapati daging dan sembelihan Adlha. Akhirnya, beliau tahu, bahwa semua itu disembelih sebelum shalat. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang telah menyembelih sebelu ditunaikannya shalat, maka hendaklah ia menyembelih hewan lain sebagai gantinya. Dan siapa yang belum menyembelih sampai selesai shalat, maka hendaklah ia menyembelih dengan menyebut nama Allah.\""},"2172":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَلِيِّ بْنِ زَيْدٍ وَحُمَيْدٍ عَنِ الْحَسَنِ عَنْ جُنْدُبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى صَلَاةَ الْفَجْرِ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا تُخْفِرُوا ذِمَّةَ اللَّهِ عَزَّ وَجَلَّ وَلَا يَطْلُبَنَّكُمْ بِشَيْءٍ مِنْ ذِمَّتِهِ","id":"Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Ali bin Zaid] dan [Humaid] dari [Al Hasan] dari [Jundub] bahwasanya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menunaikan shalat Fajar, maka ia akan berada dalam penjagaan Allah. Karena itu, janganlah kalian memutuskan Dzimmatullah (penjagaan dan naungan-Nya) dan janganlah sekali-laki, "},"2173":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ وَعَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنِ الْأَسْوَدِ بْنِ قَيْسٍ الْعَبْدِيِّ قَالَ سَمِعْتُ جُنْدُبَ بْنَ سُفْيَانَ الْعَلَقِيَّ حَيٌّ مِنْ بَجِيلَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَبْدُ الرَّحْمَنِ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْأَضْحَى عَلَى قَوْمٍ قَدْ ذَبَحُوا أَوْ نَحَرُوا أَوْ قَوْمٍ لَمْ يَذْبَحُوا أَوْ لَمْ يَنْحَرُوا فَقَالَ مَنْ ذَبَحَ أَوْ نَحَرَ قَبْلَ صَلَاتِنَا فَلْيُعِدْ وَمَنْ لَمْ يَذْبَحْ أَوْ يَنْحَرْ فَلْيَذْبَحْ أَوْ يَنْحَرْ بِاسْمِ اللَّهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dan [Abdurrahman] dari [Sufyan] dari [Al Aswad bin Qais Al Abdi] ia berkata, saya mendengar [Jundub bin Sufyan Al 'Alaqi] penduduk dari Bajilah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda, -sementara Abdurrahman mengatakan- Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada hari Idul Adlha menemui kaum muslimin yang mereka telah menyembelih (Nahr/Dzabh) atau kaum muslimin yang belum menyembelih (hewan kurban), maka beliau pun bersabda: \"Barangsiapa yang telah menyembelih sebelum shlalat kita ini (Idul Adlha), maka hendaklah ia mengulanginya (dengan menyembelih hewan kurban yang lain). Sedangkan siapa yang belum menyembelih, maka hendaklah ia menyembelih dengan menyebut nama Allah.\""},"2174":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنِ الْأَسْوَدِ بْنِ قَيْسٍ قَالَ سَمِعْتُ جُنْدُبًا الْعَلَقِيَّ يُحَدِّثُأَنَّ جِبْرِيلَ أَبْطَأَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَزِعَ قَالَ فَقِيلَ لَهُ قَالَ فَ��َزَلَتْ{ وَالضُّحَى وَاللَّيْلِ إِذَا سَجَى مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَى }","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Al Aswad bin Qais] ia berkata, saya mendengar [Jundub Al Alaqi] menceritakan bahwa jibril menangguhkan (penurunan wahyu) kepada Nabi shallallahu 'alaihi wasallam sehingga beliau pun gelisah dan sedih. Kemudian ditanyakanlah hal itu kepadanya, maka turunlah ayat: \"Demi waktu matahari sepenggalahan naik, Dan demi malam apabila Telah sunyi (gelap), Tuhanmu tiada meninggalkan kamu dan tiada (pula) benci kepadamu.\" (QS. Adhdhuha 1-3)."},"2175":{"ar":"حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ جُنْدُبًا يَقُولُ قَالَ عَبْدُ الرَّحْمَنِ الْبَجَلِيُّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يُسَمِّعْ يُسَمِّعْ اللَّهُ بِهِ وَمَنْ يُرَاءِ يُرَاءِ اللَّهُ بِهِ","id":"Telah menceritakan kepada kami [Waki'] dan [Abdurrahman] keduanya berkata, Telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] ia berkata, saya mendengar [Jundub] berkata; Abdurrahman Al Bajali berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang beramal karena sum'ah, maka Allah akan menjadikan amalannya itu sebagai amalan sum'ah. Dan barangsiapa yang berbuat karena riya`, maka Allah akan menjadikan perbutan tersebut sebagai perbuatan riya`.\""},"2176":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جُنْدُبٍ الْعَلَقِيِّ سَمِعَهُ مِنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ","id":"Telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Abdul Malik bin Umair] dari [Jundub Al 'Alaqi] ia mendengar (hadits itu) darinya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akulah yang akan mendahului kalian untuk memasuki Al Haudl (telaga, tempat minumnya para penghuni surga).\""},"2177":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يِسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Hilal bin Bisaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu berwudlu, maka lakukanlah Intitsar (menghirup air ke dalam hidung lalu mengeluarkannya). Dan jika kamu bersuci dengan batu, maka lakukanlah dengan bilangan ganjil.\""},"2178":{"ar":"حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ سُفْيَانَ عَنْ هِلَالٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Sufyan] dari [Hilal] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu berwudlu, maka lakukanlah Intitsar (menghirup air ke dalam hidung lalu mengeluarkannya). Dan jika kamu bersuci dengan batu, maka lakukanlah dengan bilangan ganjil.\""},"2179":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَا يُتَلَقَّى جَلَبٌ وَلَا يَبِعْ حَاضِرٌ لِبَادٍ وَمَنْ اشْتَرَى شَاةً مُصَرَّاةً أَوْ نَاقَةً قَالَ شُعْبَةُ إِنَّمَا قَالَ نَاقَةً مَرَّةً وَاحِدَةً فَهُوَ فِيهَا بِآخِرِ النَّظَرَيْنِ إِذَا هُوَ حَلَبَ إِنْ رَدَّهَا رَدَّ مَعَهَا صَاعًا مِنْ طَعَامٍ قَالَ الْحَكَمُ أَوْ قَالَ صَاعًا مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata, saya mendengar [Ibnu Abu Laila] menceritakan dari [seorang laki-laki] dari kalangan sahabat Nabi shallallahu 'alaihi wasallam, ia berkata; Tidaklah ditemui seorang yang melakukan Jalab (yakni menghadirkan harta kepada Amil, untuk mengambil zakatnya). Dan orang kota jangan menjual untuk orang desa. Barangsiapa yang membeli kambing atau Unta Musharrah (yang telah ditahan susunya agar kelihatan gemuk), -Syu'bah berkata; ia hanya mengatakan Unta- maka ia mempunyai dua hak pilih dua hal (melangsungkan akad jual beli atau membatalkannya) setelah ia memerahnya. Jika ia mengembalikannya, maka ia mengembalikannya dengan satu Sha' makanan. Al Hakam berkata; Atau satu Sha' kurma."},"2180":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُنَهَى عَنْ الْبَلَحِ وَالتَّمْرِ وَالزَّبِيبِ وَالتَّمْرِ","id":"Telah menceritakan kepada kami [Affan] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Al Hakam] ia berkata, saya mendengar [Ibnu Abu Laila] dari [seorang laki-laki] dari sahabat Nabi shallallahu 'alaihi wasallam, bahwa beliau telah melarang Al Balah (Kurma basah yang masih hijau) dan At Tamr kemudian Az Zabib dan At Tamr."},"2181":{"ar":"حَدَّثَنَا وَكِيعٌ وَمُحَمَّدُ بْنُ جَعْفَرٍ قَالَا ثَنَا شُعْبَةُ عَنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ ابْنُ جَعْفَرٍ سَمِعْتُ ابْنَ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَلَقَّوْا الرُّكْبَانَ قَالَ ابْنُ جَعْفَرٍ لَا يُتَلَقَّى جَلَبٌ وَلَا يَبِعْ حَاضِرٌ لِبَادٍ وَمَنْ اشْتَرَى مُصَرَّاةً فَهُوَ فِيهَا بِآخِرِ النَّظَرَيْنِ وَقَالَ ابْنُ جَعْفَرٍ بِأَحَدِ النَّظَرَيْنِ إِنْ رَدَّهَا رَدَّ مَعَهَا صَاعًا مِنْ طَعَامٍ أَوْ صَاعًا مِنْ تَمْرٍ","id":"Telah menceritakan kepada kami [Waki'] dan [Muhammad bin Ja'far] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] -dalam riwayat yang lain- Ibnu Ja'far berkata, saya mendengar [seorang laki-laki] dari kalangan sahabat Nabi shallallahu 'alaihi wasallam berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menemui para pedagang (di luar daerah) -dalam riwayat lain Ibnu Ja'far berakta- Para pedagang tidak boleh ditemui (di luar daerah). Dan orang kota jangan menjual untuk orang desa. Barangsiapa yang membeli Musharrah (kambing atau Unta yang telah ditahan susunya agar kelihatan gemuk), -Syu'bah berkata; ia hanya mengatakan Unta- maka ia mempunyai dua hak pilih dua hal (melangsungkan akad jual beli atau membatalkannya) setelah ia memerahnya. Jika ia mengembalikannya, maka ia mengembalikannya dengan satu Sha' makanan atau satu Sha' kurma.\""},"2182":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ حَدَّثَنِي رَجُلٌ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْحِجَامَةِ وَالْمُوَاصَلَةِ وَلَمْ يُحَرِّمْهَا إِبْقَاءً عَلَى أَصْحَابِهِ فَقِيلَ يَا رَسُولَ اللَّهِ إِنَّكَ تُوَاصِلُ إِلَى السَّحَرِ فَقَالَ إِنْ أُوَاصِلُ إِلَى السَّحَرِ فَرَبِّي يُطْعِمُنِي وَيَسْقِينِي","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Abdurrahman bin Abis] dari [Abdurrahman bin Abu Laila] ia berkata, Telah menceritakan kepadaku [salah seorang sahabat] Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam melarang Al Hijamah (berbekam), Al Muwashalah (puasa wishal/menyambung puasa), akan tetapi beliau tidak mengharamkannya sehingga tetap ada ditengah-tengah para sahabatnya. Kemudian dikatakanlah kepada beliau, \"Namun Anda sendiri melakukan wishal hingga waktu sahur.\" Maka beliau pun bersabda: \"Jika melakukan wishal hingga waktu sahur, maka Tuhanku-lah yang memberiku makan dan minum.\""},"2183":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِجَامَةِ لِلصَّائِمِ وَالْمُوَاصَلَةِ وَلَمْ يُحَرِّمْهَا عَلَى أَحَدٍ مِنْ أَصْحَابِهِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ تُوَاصِلُ إِلَى السَّحَرِ فَقَالَ إِنِّي أُوَاصِلُ إِلَى السَّحَرِ وَإِنَّ رَبِّي عَزَّ وَجَلَّ يُطْعِمُنِي وَيَسْقِينِي","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Sufyan] dari [Abdurrahman bin Abis] dari [Abdurrahman bin Abu Laila] dari [salah seorang sahabat Nabi shallallahu 'alaihi wasallam] ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melarang Al Hijamah (berbekam) bagi orang yang sedang berpuasa, dan beliau juga melarang Al Muwashalah (menyambung puasa dua hari tanpa berbuka), namun beliau tidak mengharamkannya atas seorang pun dari para sahabatnya. Para sahabat berkata, \"Wahai Rasulullah, sesungguhnya Anda sendiri telah melakukan wishal hingga waktu sahur.\" Maka beliau bersabda: \"Sesungguhnya saya melakukan wishal hingga waktu sahur, dan Rabb-kulah 'azza wajalla yang memberiku makan dan minum.\""},"2184":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ ثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ بَعْضِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَأَصْبَحَ النَّاسُ لِتَمَامِ ثَلَاثِينَ يَوْمًا فَجَاءَ أَعْرَابِيَّانِ فَشَهِدَا أَنَّهُمَا أَهَلَّاهُ بِالْأَمْسِ عَشِيَّةً فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُفْطِرُوا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] ia berkata, Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Rib'i bin Hirasy] dari [sebagian sahabat] Rasulullah shallallahu 'alaihi wasallam, ia berkata; \"Kaum muslimin telah mamasuki hari genap yakni tiga puluh hari (bulan Ramadlan), kemudian datanglah dua orang Arab Baduwi seraya bersaksi bahwa keduanya telah melihat Hilal pada sore hari kemarin, maka Rasulullah shallallahu 'alaihi wasallam pun memerintahkan kaum muslimin untuk berbuka.\""},"2185":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ بَعْضِ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقَدَّمُوا الشَّهْرَ حَتَّى تُكْمِلُوا الْعِدَّةَ أَوْ تَرَوْا الْهِلَالَ وَصُومُوا وَلَا تُفْطِرُوا حَتَّى تُكْمِلُوا الْعِدَّةَ أَوْ يَرَوْا الْهِلَالَ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Rib'i bin Hirasy] dari [sebagian sahabat] Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menentukan awal bulan hingga kalian menyempurnakan hitungannya atau sampai kalian melihat Hilal. Kemudian berpuasalah dan janganlah kalian berbuka hingga kalian menyempurnakan bilangannya atau melihat Hilal.\""},"2186":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنِ الْحَكَمِ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى يُحَدِّثُ عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُنَهَى عَنْ الْبَلَحِ وَالتَّمْرِ وَالتَّمْرِ وَالزَّبِيبِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] ia berkata, saya mendengar [Ibnu Abu Laila] menceritakan dari [salah seorang sahabat] Nabi shallallahu 'alaihi wasallam bahwasanya; Beliau melarang Al Balah (Kurma basah yang masih hijau) dan At Tamr kemudian Az Zabib dan At Tamr."},"2187":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ مُخَارِقِ بْنِ خَلِيفَةَ الْأَحْمَسِيِّ عَنْ طَارِقٍأَنَّ الْمِقْدَادَ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَدْرٍ يَا رَسُولَ اللَّهِ إِنَّا لَا نَقُولُ لَكَ كَمَا قَالَتْ بَنُو إِسْرَائِيلَ لِمُوسَى{ اذْهَبْ أَنْتَ وَرَبُّكَ فَقَاتِلَا إِنَّا هَاهُنَا قَاعِدُونَ }وَلَكِنْ اذْهَبْ أَنْتَ وَرَبُّكَ فَقَاتِلَا إِنَّا مَعَكُمْ مُقَاتِلُونَ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Mukhariq bin Khalifah Al Ahmasi] dari [Thariq] bahwa pada saat perang Badar Miqdad berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, kami tidak akan mengatakan sebagaimana apa yang telah dikatakan oleh Bani Isra`il kepada Musa, 'Berangkatlah kamu dan Tuhanmu untuk berperang, sesungguhnya kami hanya akan duduk-duduk di sini.' Akan tetapi (kami akan katakan), 'Pergilah kamu dan Tuhanmu untuk berperang, sesungguhnya kami bersamamu untuk berperang.'\""},"2188":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ عَنْ طَارِقٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيُّ الْجِهَادِ أَفْضَلُ قَالَ كَلِمَةُ حَقٍّ عِنْدَ إِمَامٍ جَائِرٍ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Alqamah] dari [Thariq] ia berkata; Seorang laki-laki datang menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Jihad manakah yang paling utama?\" beliau menjawab: \"Yaitu (mengungkapkan) kalimat yang benar (haq) di hadapan penguasa yang zhalim.\""},"2189":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ شُعْبَةَ وَابْنُ جَعْفَرٍ قَالَ ثَنَا شُعْبَةُ عَنْ قَيْسِ بْنِ مُسْلِمٍ قَالَ سَمِعْتُ طَارِقَ بْنَ شِهَابٍ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَزَوْتُ فِي خِلَافَةِ أَبِي بَكْرٍ وَعُمَرَ بِضْعًا وَأَرْبَعِينَ أَوْ بِضْعًا وَثَلَاثِينَ مِنْ بَيْنِ غَزْوَةٍ وَسَرِيَّةٍو قَالَ ابْنُ جَعْفَرٍ ثَلَاثًا وَثَلَاثِينَ أَوْ ثَلَاثًا وَأَرْبَعِينَ مِنْ غَزْوَةٍ إِلَى سَرِيَّةٍ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Syu'bah] dan [Ibnu Ja'far] ia berkata, Telah menceritakan kepada kami [Syu'bah] dari [Qais bin Muslim] ia berkata, saya mendengar [Thariq bin Syihab] berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam dan saya juga pernah berperang pada masa kekhilafahan Abu Bakar dan Umar sebanyak empat puluh kali lebih atau tiga puluh kali lebih ghazwah dan Sariyyah. Ibnu Ja'far berkata; Tiga puluh tiga atau empat puluh tiga kali peperangan dari Ghazwah hingga Sariyyah (pasukan khusus yang dikirim untuk operasi khusus)."},"2190":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ طَارِقِ بْنِ شِهَابٍأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ وَضَعَ رِجْلَهُ فِي الْغَرْزِ أَيُّ الْجِهَادِ أَفْضَلُ قَالَ كَلِمَةُ حَقٍّ عِنْدَ سُلْطَانٍ جَائِرٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Alqamah bin Martsad] dari [Thariq bin Syihab] bahwa seorang laki-laki -yang telah meletakkan kakinya pada batang kayu- bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Jihad manakah yang paling utama?\" beliau menjawab: \"Kalimat hak yang diungkapkan di hadapan penguasa zhalim.\""},"2191":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَمْ يَضَعْ دَاءً إِلَّا وَضَعَ لَهُ شِفَاءً فَعَلَيْكُمْ بِأَلْبَانِ الْبَقَرِ فَإِنَّهَا تَرُمُّ مِنْ كُلِّ الشَّجَرِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Sufyan] dari [Yazid bin Abu Khalid] dari [Qais bin Muslim] dari [Thariq bin Syihab] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla belum pernah menurunkan penyakit, kecuali juga menurunkan obatnya. Karena itu, hendaklah kalian meminum susu Sapi, sebab ia makan dari beragam jenis dedaunan.\""},"2192":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُخَارِقٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَأَجْنَبَ رَجُلَانِ فَتَيَمَّمَ أَحَدُهُمَا فَصَلَّى وَلَمْ يُصَلِّ الْآخَرُ فَأَتَيَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَعِبْ عَلَيْهِمَا","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Mukhariq] dari [Thariq bin Syihab] ia berkata; Dua orang junub, kemudian salah seorang darinya bertayammum dan shalat, sementara yang satunya tidak shalat. Setelah itu, keduanya menemui Rasulullah shallallahu 'alaihi wasallam, dan ternyata beliau tidak mencela salah satu pun dari keduanya."},"2193":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُخَارِقٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَقَدِمَ وَفْدُ بَجِيلَةَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اكْسُوا الْبَجَلِيِّينَ وَابْدَءُوا بِالْأَحْمَسِيِّينَ قَالَ فَتَخَلَّفَ رَجُلٌ مِنْ قَيْسٍ قَالَ حَتَّى أَنْظُرَ مَا يَقُولُ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَدَعَا لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسَ مَرَّاتٍ اللَّهُمَّ صَلِّ عَلَيْهِمْ أَوْ اللَّهُمَّ بَارِكْ فِيهِمْ مُخَارِقٌ الَّذِي يَشُكُّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Mukhariq] dari [Thariq bin Syihab] ia berkata; Utusan Bajilah datang menghadap Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Berikanlah pakaian kepada Al Bajjaliyyin dan mulailah dari Bani Al Ahmasiyyin.\" Kemudian seorang laki-laki dari Qais mundur, hingga saya dapat melihat apa yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam kepada mereka. Setelah itu, Rasulullah shallallahu 'alaihi wasallam pun mendo'akan mereka sebanyak lima kali: \"ALLAHUMMA SHALLI 'ALAIHIM (Ya Allah, bershalawatlah atas mereka) -atau- ALLAHUMMA BAARIK FIIHIM (Ya Allah, berikanlah keberkahan atas mereka).\" Yang ragu adalah Mukhariq."},"2194":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ عَنْ مُخَارِقٍ عَنْ طَارِقٍ قَالَقَدِمَ وَفْدُ أَحْمَسَ وَوَفْدُ قَيْسٍ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْدَءُوا بِالْأَحْمَسِيِّينَ قَبْلَ الْقَيْسِيِّينَ وَدَعَا لِأَحْمَسَ فَقَالَ اللَّهُمَّ بَارِكْ فِي أَحْمَسَ وَخَيْلِهَا وَرِجَالِهَا سَبْعَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abu Ahmad Muhammad bin Abdullah] Telah menceritakan kepada kami [Sufyan] dari [Al Mukhariq] dari [Thariq] ia berkata; Utusan Bani Ahmas dan Qais datang menghadap Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Mulailah dari Bani Ahmasiyyin sebelum Al Qaisiyyin.\" Kemudian beliau mendo'kan Bani Ahmas seraya membaca: \"ALLAHUMMA BAARIK FI AHMAS WA KHAILIHA WA RIJAALIHAA (Ya Allah, berilah keberkahan untuk Bani Ahmas, beserta kuda dan rijalnya.\" Sebanyak tujuh kali."},"2195":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ طَارِقِ بْنِ شِهَابٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَغَزَوْتُ فِي خِلَافَةِ أَبِي بَكْرٍ وَعُمَرَ ثَلَاثًا وَثَلَاثِينَ أَوْ ثَلَاثًا وَأَرْبَعِينَ مِنْ غَزْوَةٍ إِلَى سَرِيَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Qais bin Muslim] dari [Thariq bin Syihab] ia berkata; Saya telah melihat Rasulullah shallallahu 'alaihi wasallam dan saya juga telah berperang pada masa kekhilafahan Abu Bakar dan Umar sebanyak tiga puluh tiga atau empat puluh tiga kali, dari Ghazwah hingga Sariyyah (pasukan khusus yang dikirim untuk operasi khusus). "},"2196":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا سُفْيَانُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَابِسٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ رَجُلٍ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحِجَامَةِ لِلصَّائِمِ وَالْمُوَاصَلَةِ وَلَمْ يُحَرِّمْهَا عَلَى أَصْحَابِهِ قَالُوا يَا رَسُولَ اللَّهِ إِنَّكَ تُوَاصِلُ إِلَى السَّحَرِ قَالَ إِنْ أُوَاصِلُ إِلَى السَّحَرِ فَرَبِّي عَزَّ وَجَلَّ يُطْعِمُنِي وَيَسْقِينِي","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Sufyan] dari [Abdurrahman bin Abis] dari [Abdurrahman bin Abu Laila] dari [salah seorang sahabat Nabi shallallahu 'alaihi wasallam] ia berkata; Rasulullah shallallahu 'alaihi wasallam melang Al Hijamah (berbekam) bagi orang yang sedang berpuasa. Dan beliau juga melarang Al Muwashalah (menyambung puasa dua hari tanpa berbuka), namun beliau tidak sampai mengharamkannya bagi para sahabatnya. Kemudian ditanyakanlah kepada beliau, \"Wahai Rasulullah, sesungguhnya Anda sendiri melakukan puasa Wishal hingga waktu sahur.\" Maka beliau pun bersabda: \"Jika saya melakukan puasa wishal hingga sahur, maka Rabb-kulah yang memberiku makan dan minum.\""},"2197":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا هِلَالُ بْنُ خَبَّابٍ قَالَ حَدَّثَنِي مَيْسَرَةُ أَبُو صَالِحٍ عَنْ سُوَيْدِ بْنِ غَفَلَةَ قَالَأَتَانَا مُصَدِّقُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجَلَسْتُ إِلَيْهِ فَسَمِعْتُهُ وَهُوَ يَقُولُ إِنَّ فِي عَهْدِي أَنْ لَا آخُذَ مِنْ رَاضِعِ لَبَنٍ وَلَا يُجْمَعُ بَيْنَ مُتَفَرِّقٍ وَلَا يُفَرَّقُ بَيْنَ مُجْتَمِعٍ وَأَتَاهُ رَجُلٌ بِنَاقَةٍ كَوْمَاءَ فَقَالَ خُذْهَا فَأَبَى أَنْ يَأْخُذَهَا","id":"Telah menceritakan kepada kami [Husyaim] Telah memberitakan kepada kami [Hilal bin Khabbab] ia berkata, Telah menceritakan kepadaku [Maisarah Abu Shalih] dari [Suwaid bin Ghafalah] ia berkata; [Mushaddiq (pemungut zakat dan sedekah)] Nabi shallallahu 'alaihi wasallam. Lalu saya duduk di sisinya hingga saya pun mendengarnya berkata, \"Sesungguhnya pada zamanku dulu, saya tidak boleh mengambil dari Radli' Laban, sesuatu yang terpisah tidak boleh dikumpulkan dan sesuatu yang telah dikumpulkan tida boleh dipisah.\" Kemudian seorang laki-laki mendatanginya dengna membawa Unta yang besar punuknya seraya berkata, \"Ambillah.\" Namun ia tidak mau mengambilnya. "},"2198":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مِسْعَرٌ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ قَالَ حَدَّثَنِي أَهْلِي عَنْ أَبِي قَالَأُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِدَلْوٍ مِنْ مَاءٍ فَشَرِبَ مِنْهُ ثُمَّ مَجَّ فِي الدَّلْوِ ثُمَّ صَبَّ فِي الْبِئْرِ أَوْ شَرِبَ مِنْ الدَّلْوِ ثُمَّ مَجَّ فِي الْبِئْرِ فَفَاحَ مِنْهَا مِثْلُ رِيحِ الْمِسْكِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Mis'ar] dari [Abdul Jabbar bin Wa`il] ia berkata, Telah menceritakan kepadaku [keluargaku] dari [bapakku] Nabi shallallahu 'alaihi wasallam dibawakan ember berisi air, dan beliau pun minum darinya kemudian memuntahkannya kembali ke dalam ember. Setelah itu, beliau menuangkannya ke dalam sumur atau minum air dari ember kemudian memuntahkannya kembai ke dalam Sumur, hingga dari sumur itu keluar bau wangi seperti wanginya Misk."},"2199":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا حَجَّاجٌ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَضَعَ أَنْفَهُ عَلَى الْأَرْضِ","id":"Telah menceritakan kepada kami [Yazid] Telah mengabarkan kepada kami [Hajjaj] dari [Abdul Jabbar bin Wa`il] dari [bapaknya] ia berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam, jika beliau sujud, maka beliau meletakkan hidungnya di atas tanah."},"2200":{"ar":"حَدَّثَنَا عَبْدُ الْقُدُّوسِ أَخْبَرَنَا الْحَجَّاجُ عَنْ عَبْدِ الْجَبَّارِ عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ آمِينَ","id":"Telah menceritakan kepada kami [Abdul Qudus] Telah mengabarkan kepada kami [Al Hajjaj] dari [Abdul Jabbar] dari [bapaknya] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam membaca: \"AAMIIN (Ya Allah, kabulkanlah).\""},"2201":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ حُجْرِ بْنِ عَنْبَسٍ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ{ وَلَا الضَّالِّينَ }فَقَالَ آمِينَ يَمُدُّ بِهَا صَوْتَهُحَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ وَقَالَ شُعْبَةُ وَخَفَضَ بِهَا صَوْتَهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Hujr bin Anbas] dari [Wa`il bin Hujr] ia berkata, saya mendengar Nabi shallallahu 'alaihi wasallam membaca: \"WALADL DLALLIIN.\" Kemudian beliau membaca amiin dengan memanjangkan suaranya. Telah menceritakan kepada kami [Abdurrahman] berkata; dan [Syu'bah] berkata; Dan beliau membacanya dengan merendahkan suara."},"2202":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْجَبَّارِ بْنِ وَائِلٍ حَدَّثَنِي أَهْلُ بَيْتِي عَنْ أَبِي أَنَّهُرَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْجُدُ بَيْنَ كَفَّيْهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al Mas'udi] dari [Abdul Jabbar bin Wa`il] Telah menceritakan kepadaku [keluargaku] dari [bapakku] bahwa pernah melihat Rasulullah shallallahu 'alaihi wasallam sujud di antara dua telapak tangannya."},"2203":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مُوسَى بْنُ عُمَيْرٍ الْعَنْبَرِيُّ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَمِينَهُ عَلَى شِمَالِهِ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Musa bin Umair Al Bari] dari [Alqamah bin Wa`il Al Hadlrami] dari [bapaknya] ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam meletakkan tangan kanannya di atas tangan kirinya dalam shalat."},"2204":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَلْقَمَةَ بْنِ وَائِلِ بْنِ حُجْرٍ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الشِّتَاءِ قَالَ فَرَأَيْتُ أَصْحَابَهُ يَرْفَعُونَ أَيْدِيَهُمْ فِي ثِيَابِهِمْ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Syarik] dari [Ashim bin Kulaib] dari [Alqamah bin Wa`il bin Hujr] dari [bapaknya] ia berkata; Saya mendatangi Nabi shallallahu 'alaihi wasallam pada musim semi, maka saya melihat para sahabatnya mengangkat kedua tangan mereka ke atas pakaian mereka."},"2205":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي الْبَخْتَرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْيَحْصُبِيِّ عَنْ وَائِلِ بْنِ حُجْرٍ الْحَضْرَمِيِّ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ مَعَ التَّكْبِيرِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] dari [Abu Al Bakhtari] dari [Abdurrahman bin Al Yahshubi] dari [Wa`il bin Hujr Al Hadlrami] berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya bersamaan dengan takbir."},"2206":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ الْحَضْرَمِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَأَنْظُرَنَّ كَيْفَ يُصَلِّي قَالَ فَاسْتَقْبَلَ الْقِبْلَةَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى كَانَتَا حَذْوَ مَنْكِبَيْهِ قَالَ ثُمَّ أَخَذَ شِمَالَهُ بِيَمِينِهِ قَالَ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَ يَدَيْهِ حَتَّى كَانَتَا حَذْوَ مَنْكِبَيْهِ فَلَمَّا رَكَعَ وَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَ يَدَيْهِ حَتَّى كَانَتَا حَذْوَ مَنْكِبَيْهِ فَلَمَّا سَجَدَ وَضَعَ يَدَيْهِ مِنْ وَجْهِهِ بِذَلِكَ الْمَوْضِعِ فَلَمَّا قَعَدَ افْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى رُكْبَتِهِ الْيُسْرَى وَوَضَعَ حَدَّ مِرْفَقِهِ عَلَى فَخِذِهِ الْيُمْنَى وَعَقَدَ ثَلَاثِينَ وَحَلَّقَ وَاحِدَةً وَأَشَارَ بِإِصْبَعِهِ السَّبَّابَةِ","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Ashim bin Kulaib] dari [bapaknya] dari [Wa`il bin Hujr Al Hadlrami] ia berkata; Saya mendatangi Nabi shallallahu 'alaihi wasallam dan saya berkata, \"Saya benar-benar akan melihat, bagaimana beliau menunaikan shalat.\" Wa`il berkata; Beliau menghadap kiblat, kemudian beliau bertakbir dan mengangkat kedua tangannya hingga sejajar dengan kedua pundaknya, sedangkan tangan kanannya memegang tangan kirinya. Ketika beliau ruku', beliau meletakkan kedua tangannya di atas kedua lutut dan saat bangkit dari ruku', beliau kembali mengangkat kedua tangannya hingga sejajar dengna kedua bahunya. Dan ketika sujud, beliau meletakkan kedua tangannya dalam posisi seperti itu. Ketika duduk, beliau menduduki telapak kaki kirinya, kemudian meletakkan tangan kirinya di atas lutut kirinya dan beliau meletakkan sikunya di atas paha kanannya, sedangkan jari tangannya membentuk angka tiga puluh dengan menurunkan ibu jarinya dan memberi isyarat dengan jari telunjuknya."},"2207":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ قَالَ سَمِعْتُ عَبْدَ الْجَبَّارِ بْنَ وَائِلٍ يَذْكُرُ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِدَلْوٍ مِنْ مَاءٍ فَشَرِبَ مِنْهُ ثُمَّ مَجَّ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Mis'ar] ia berkata, saya mendengar [Abdul Jabbar bin Wa`il] menyebutkan dari [bapaknya] bahwa Nabi shallallahu 'alaihi wasallam dibawakan ember berisi air, kemudian beliau minum darinya dan memuntahkannya kembali."},"2208":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ أَبِي الْبَخْتَرِيِّ قَالَقَالَ عَمَّارٌ يَوْمَ صِفِّينَ ائْتُونِي بِشَرْبَةِ لَبَنٍ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ آخِرُ شَرْبَةٍ تَشْرَبُهَا مِنْ الدُّنْيَا شَرْبَةُ لَبَنٍ فَأُتِيَ بِشَرْبَةِ لَبَنٍ فَشَرِبَهَا ثُمَّ تَقَدَّمَ فَقُتِلَ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Habib bin Abu Tsabit] dari [Abul Bakhtari] ia berkata; [Ammar] berkata pada hari Shiffin. Berikanlah aku segelas susu, karena Rasulullah shallallahu 'alaihi wasallam bersabda: \"Minuman yang terakhir kali yang akan kamu minum di dunia adalah susu.\" Maka ia pun disuguhkan segelas susu lalu meminumnya. Setelah itu, ia maju ke depan hingg ia pun terbunuh.\""},"2209":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا زِيَادٌ أَبُو عُمَرَ عَنِ الْحَسَنِ عَنْ عَمَّارِ بْنِ يَاسِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ أُمَّتِي مَثَلُ الْمَطَرِ لَا يُدْرَى أَوَّلُهُ خَيْرٌ أَمْ آخِرُهُ","id":"Telah menceritakan kepada kami [Abdurrahman] Telah menceritakan kepada kami [Ziyad Abu Umar] dari [Al Hasan] dari [Ammar bin Yasir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan umatku adalah seperti hujan yang tidak diketahui, apakah awalnya lebih baik ataukah akhirnya.\""},"2210":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ حَبِيبٍ عَنْ أَبِي الْبُخْتُرِيِّ أَنَّ عَمَّارَ بْنَ يَاسِرٍأُتِيَ بِشَرْبَةِ لَبَنٍ فَضَحِكَ قَالَ فَقَالَ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ آخِرَ شَرَابٍ أَشْرَبُهُ لَبَنٌ حَتَّى أَمُوتَ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Habib] dari [Abul Bukhtari] bahwa [Ammar bin Yasir], disuguhkan minuman berupa air susu, lalu ia tertawa dan berkata; Sesungguhnya Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya minuman yang terakhir kali aku teguk adalah susu hingga aku meninggal.\""},"2211":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ سَلَمَةَ يَقُولُرَأَيْتُ عَمَّارًا يَوْمَ صِفِّينَ شَيْخًا كَبِيرًا آدَمَ طُوَالًا آخِذًا الْحَرْبَةَ بِيَدِهِ وَيَدُهُ تَرْعَدُ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ قَاتَلْتُ بِهَذِهِ الرَّايَةِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ وَهَذِهِ الرَّابِعَةُ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ ضَرَبُونَا حَتَّى يَبْلُغُوا بِنَا شَعَفَاتِ هَجَرَ لَعَرَفْتُ أَنَّ مُصْلِحِينَا عَلَى الْحَقِّ وَأَنَّهُمْ عَلَى الضَّلَالَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] ia berkata, saya mendengar [Abdullah bin Salamah] berkata; Saya melihat [Ammar] pada perang Shiffin. Ia adalah seorang yang telah tua renta berkulit sawo matang dan berpostur tinggi. Ia sedang mengambil tombak dengan tangannya seraya berguruh dan berkata, \"Demi Dzat yang jiwaku berada di tangan-Nya, sungguh, saya telah berperang dengan bendera ini bersama dengan Rasulullah shallallahu 'alaihi wasallam sebanyak tiga kali peperangan, dan ini adalah keempat kalinya. Dan demi Dzat yang jiwaku berada di tangan-Nya, sekiranya mereka memukul kami hingga mendapati kami di puncak gunung, niscaya aku tahu bahwa Mushlih (yang mendamaikan) kami berada di atas kebenaran dan mereka berada di atas kesesatan.\""},"2212":{"ar":"مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ وَحَجَّاجٌ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَبِي نَضْرَةَ قَالَ حَجَّاجٌ سَمِعْتُ أَبَا نَضْرَةَ عَنْ قَيْسِ بْنِ عَبَّادٍ قَالَقُلْتُ لِعَمَّارٍ أَرَأَيْتَ قِتَالَكُمْ رَأْيًا رَأَيْتُمُوهُ قَالَ حَجَّاجٌ أَرَأَيْتَ هَذَا الْأَمْرَ يَعْنِي قِتَالَهُمْ رَأْيًا رَأَيْتُمُوهُ فَإِنَّ الرَّأْيَ يُخْطِئُ وَيُصِيبُ أَوْ عَهْدٌ عَهِدَهُ إِلَيْكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا عَهِدَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا لَمْ يَعْهَدْهُ إِلَى النَّاسِ كَافَّةً وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي أُمَّتِي قَالَ شُعْبَةُ وَيَحْسِبُهُ قَالَ حَدَّثَنِي حُذَيْفَةُ إِنَّ فِي أُمَّتِي اثْنَيْ عَشَرَ مُنَافِقًا فَقَالَ لَا يَدْخُلُونَ الْجَنَّةَ وَلَا يَجِدُونَ رِيحَهَا حَتَّى يَلِجَ الْجَمَلُ فِي سَمِّ الْخِيَاطِ ثَمَانِيَةٌ مِنْهُمْ تَكْفِيكَهُمُ الدُّبَيْلَةُ سِرَاجٌ مِنْ نَارٍ يَظْهَرُ فِي أَكْتَافِهِمْ حَتَّى يَنْجُمَ فِي صُدُورِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dan [Hajjaj] ia berkata, telah menceritakan kepadaku [Syu'bah] ia berkata, saya mendengar [Qatadah] menceritakan dari [Abu Nadlrah]. Telah berkata [Hajjaj] saya mendengar [Abu Nadlrah] dari [Qais bin Abbad] ia berkata; Saya bertanya kepada [Ammar], \"Apakah peperangan kalian ini merupakan pendapat yang telah kalian putuskan?\" Hajjaj berkata; \"Apakah menurut kalian perkara ini, yakni peperangan kalian ini merupakan pendapat yang telah kalian putuskan? Sebab suatu pendapat bisa salah dan juga bisa benar. Atau pun merupakan janji yang telah dijanjikan Rasulullah shallallahu 'alaihi wasallam kepada kalian?\" Maka Ammar menjawab, \"Rasulullah shallallahu 'alaihi wasallam tidak pernah menjanjikan sesuatu pun kepada kami yang tidak beliau janjikan kepada umat secara keseluruhan.\" Ammar juga berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Sesungguhnya di antara ummatku..\" Syu'bah berkata; Menurut dugaannya ia berkata, telah menceritakan kepadaku [Hudzaifah]; \"Sesungguhnya di dalam umatku terdapat dua belas orang munafik. Mereka tidak akan masuk surga dan tidak pula mencium baunya, hingga seekor unta masuk ke dalam lubang jarum. Cekuplah delapan orang dari mereka (binasa) dengan Dubailah (bisul besar yang membinasakan), pada pundak-pundak mereka terdapat siraj (cahaya) dari neraka hingga merambat ke dada-dada mereka.\""},"2213":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ عَنْ ذَرٍّ عَنِ ابْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى عَنْ أَبِيهِأَنَّ رَجُلًا سَأَلَ عُمَرَ بْنَ الْخَطَّابِ عَنْ التَّيَمُّمِ فَلَمْ يَدْرِ مَا يَقُولُ فَقَالَ عَمَّارُ بْنُ يَاسِرٍ أَمَا تَذْكُرُ حَيْثُ كُنَّا فِي سَرِيَّةٍ فَأَجْنَبْتُ فَتَمَعَّكْتُ فِي التُّرَابِ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّمَا يَكْفِيكَ هَكَذَا وَضَرَبَ شُعْبَةُ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَنَفَخَ فِي يَدَيْهِ ثُمَّ مَسَحَ بِهِمَا وَجْهَهُ وَكَفَّيْهِ مَرَّةً وَاحِدَةً","id":"Telah menceritakan kepada kami [Bahz] Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Dzarr] dari [Ibnu Abdurrahman bin Abza] dari [bapaknya] bahwa seorang laki-laki bertanya kepada Umar bin Khathab tentang tayammum, namun Umar tidak tahu apa yang harus ia katakan, maka [Ammar] berkata, \"Tidakkah Anda ingat ketika kita berada dalam suatu Sariyyah (pasukan khusus dengan operasi khusus) kemudian saya junub lalu berguling-guling di hamparan pasir. Dan setelah itu, saya mendatangi Rasulullah shallallahu 'alaihi wasallam, kemudian beliau pun bersabda: 'Bagimu cukup seperti ini.'\" Syu'bah menepukkan kedua telapak tangannya di atas kedua lututnya, kemudian meniup kedua telapak tangannya, lalu mengusapkan keduanya ke wajahnya sekali usapan."},"2214":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ عَمَّارِ بْنِ يَاسِرٍ أَبِي الْيَقْظَانِ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلَكَ عِقْدٌ لِعَائِشَةَ فَأَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَضَاءَ الْفَجْرُ فَتَغَيَّظَ أَبُو بَكْرٍ عَلَى عَائِشَةَ فَنَزَلَتْ عَلَيْهِمْ الرُّخْصَةُ فِي الْمَسْحِ بِالصُّعُدَاتِ فَدَخَلَ عَلَيْهَا أَبُو بَكْرٍ فَقَالَ إِنَّكِ لَمُبَارَكَةٌ لَقَدْ نَزَلَ عَلَيْنَا فِيكِ رُخْصَةٌ فَضَرَبْنَا بِأَيْدِينَا إِلَى وُجُوهِنَا وَضَرَبْنَا بِأَيْدِينَا ضَرْبَةً إِلَى الْمَنَاكِبِ وَالْآبَاطِ","id":"Telah menceritakan kepada kami [Hajjaj] Telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] dari [Ammar bin Yasir Abul Yaqzhan] ia berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam. Tiba-tiba kalung Aisyah terputus, maka Rasulullah shallallahu 'alaihi wasallam mencarinya hingga cahaya Fajar tampak terang. Maka Abu Bakar pun marah dan kesal terhadap Aisyah. Dalam suasana seperti itu, turunlah rukhsah keringanan bagi mereka untuk membasuh (bersuci) dengan debu. Akhirnya Abu Bakar menemui Aisyah dan berkata, \"Kamu benar-benar seorang wanita yang berbarakah, berkenaan denganmu telah turun rukhshah tayammum.\" Maka kami pun mengusapkan kedua telapak tangan kami ke wajah-wajah kami. Dan mengusapkan keduanya ke pundak dan ketiak."},"2215":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ وَرَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءِ بْنِ أَبِي الْخَوَّارِ أَنَّهُ سَمِعَ يَحْيَى بْنَ يَعْمَرَ يُخْبِرُ عَنْ رَجُلٍ أخْبَرَهُ عَنْ عَمَّارِ بْنِ يَاسِرٍ زَعَمَ عُمَرُ أَنَّ يَحْيَى قَدْ سَمَّى ذَلِكَ الرَّجُلَ وَنَسِيَهُ عُمَرُ أَنَّ عَمَّارًا قَالَتَخَلَّقْتُ خَلُوقًا فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَهَرَنِي وَقَالَ اذْهَبْ يَا ابْنَ أُمِّ عَمَّارٍ فَاغْسِلْ عَنْكَ فَرَجَعْتُ فَغَسَلْتُ عَنِّي قَالَ ثُمَّ رَجَعْتُ إِلَيْهِ فَانْتَهَرَنِي أَيْضًا قَالَ ارْجِعْ فَاغْسِلْ عَنْكَ فَذَكَرَ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dan [Rauh] Telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Umar bin 'Atha` bin Al Khawwar] bahwa ia mendengar [Yahya bin Ya'mar] dari [seorang laki-laki] telah mengabarkan kepadanya dari [Ammar bin Yasir] -Umar menyangka bahwa Yahya telah mendengar laki-laki itu namun ia lupa- bahwa ia berkata; Saya memakai khaluq (sejenis wewangian berwarna kuning) kemudian mendatangi Rasulullah shallallahu 'alaihi wasallam, namun beliau membentakku seraya bersabda: \"Pergilah kamu wahai Ibnu Ummu Ammar, dan cucilah (khaluq itu).\" maka saya pun kembali dan membersihkan bekas khaluq itu dari diriku. Setelah itu saya kembali lagi menemui beliau, namun beliau tetap membentakku lagi seraya bersabda: \"Kembali dan cucilah bekas khaluq itu darimu.\" Ia mengulanginya hingga tiga kali."},"2216":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَمَّارَ بْنَ يَاسِرٍ كَانَ يُحَدِّثُأَنَّهُ كَانَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ مَعَهُ عَائِشَةُ فَهَلَكَ عِقْدُهَا فَحُبِسَ النَّاسُ فِي ابْتِغَائِهِ حَتَّى أَصْبَحُوا وَلَيْسَ مَعَهُمْ مَاءٌ فَنَزَلَ التَّيَمُّمُ قَالَ عَمَّارٌ فَقَامُوا فَمَسَحُوا بِهَا فَضَرَبُوا أَيْدِيَهُمْ فَمَسَحُوا وُجُوهَهُمْ ثُمَّ عَادُوا فَضَرَبُوا بِأَيْدِيهِمْ ثَانِيَةً ثُمَّ مَسَحُوا أَيْدِيَهُمْ إِلَى الْإِبِطَيْنِ أَوْ قَالَ إِلَى الْمَنَاكِبِ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ubaidullah bin Abdullah bin Utbah] bahwa [Ammar bin Yasir] menceritakan bahwa ia pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, di mana Aisyah ikut serta di dalamnya. Saat itu, kalung Aisyah putus, akhirnya para sahabat pun mencarinya hingga masuk waktu pagi, sementara mereka tidak mempunyai air, maka turunlah keringanan tayammum. Ammar berkata; Kemudian mereka pun berdiri dan menempukkan kedua tangan lalu mengusapkan keduanya pada wajah-wajah mereka. Mereka mengulanginya untuk yang kedua kalinya, dan mengusapkannya ke ketiak -atau ia mengatakan- ke pundak-pundak mereka."},"2217":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عَطَاءٍ عَنْ عَائِشِ بْنِ أَنَسٍ سَمِعَهُ مِنْ عَلِيٍّ يَعْنِي عَلَى مِنْبَرِ الْكُوفَةِكُنْتُ أَجِدُ الْمَذْيَ فَاسْتَحْيَيْتُ أَنْ أَسْأَلَهُ أَنَّ ابْنَتَهُ عِنْدِي فَقُلْتُ لِعَمَّارٍ سَلْهُ فَسَأَلَهُ فَقَالَ يَكْفِي مِنْهُ الْوُضُوءُحَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ قَالَ ثَنَا يُونُسُ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَمَّارَ بْنَ يَاسِرٍ كَانَ يُحَدِّثُ أَنَّ الرُّخْصَةَ الَّتِي أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي الصَّعِيدِ فَذَكَرَ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ إِنَّهُمْ ضَرَبُوا أَكُفَّهُمْ فِي الصَّعِيدِ فَمَسَحُوا بِهِ وُجُوهَهُمْ مَسْحَةً وَاحِدَةً ثُمَّ عَادُوا فَضَرَبُوا فَمَسَحُوا أَيْدِيَهُمْ إِلَى الْمَنَاكِبِ وَالْآبَاطِ","id":"Telah menceritakan kepada kami [Sufyan] dari [Amru] dari ['Atha`] dari [A`isy bin Anas] ia mendengarnya dari [Ali] yakni di atas mimbar Kufah; Saya mendapatkan madzi yang keluar, lalu saya malu untuk menanyakannya pada beliau, sebab anak beliau adalah isteriku. Lalu saya berkata kepada Ammar, \"Tanyakanlah pada beliau.\" Ia menanyakannya, ia pun menjawab: \"Baginya cukup berwudlu.\" Telah menceritakan kepada kami Utsman bin Umar ia berkata, Telah menceritakan kepada kami Yunus dari Az Zuhri dari Ubaidullah bin Abdullah bin Utbah bahwa Ammar bin Yasir menceritakan; Bahwa rukhshah yang diturunkan Allah 'azza wajalla untuk bersuci dengan debu. Lalu ia pun menyebutkan hadits. Hanya saja ia mengatakan; \"Sesungguhnya mereka menepukkan telapak-telapak tangan mereka di atas hamparan debu, lalu membasuhkannya pada wajah-wajah mereka sekali basuh. Kemudian mereka mengulanginya lagi, dan membasuhkannya pada bahu dan pundak-pundak mereka.\""},"2218":{"ar":"حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا قَالَ أَخْبَرَنَا حَجَّاجٌ عَنْ حُسَيْنِ بْنِ الْحَارِثِ الْجَدَلِيِّ قَالَخَطَبَ عَبْدُ الرَّحْمَنِ بْنُ زَيْدِ بْنِ الْخَطَّابِ فِي الْيَوْمِ الَّذِي يُشَكُّ فِيهِ فَقَالَ أَلَا إِنِّي قَدْ جَالَسْتُ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَأَلْتُهُمْ أَلَا وَإِنَّهُمْ حَدَّثُونِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صُومُوا لِرُؤْيَتِهِ وَأَفْطِرُوا لِرُؤْيَتِهِ وَأَنْ تَشَكُّوا لَهَا فَإِنْ غُمَّ عَلَيْكُمْ فَأَتِمُّوا ثَلَاثِينَ وَإِنْ شَهِدَ شَاهِدَانِ مُسْلِمَانِ فَصُومُوا وَأَفْطِرُوا","id":"Telah menceritakan kepada kami [Yahya bin Zakariya] ia berkata, telah mengabarkan kepada kami [Hajjaj] dari [Husain bin Al Harits Al Jadali] ia berkata; [Abdurrahman bin Zaid bin Al Khaththab] pada hari yang diragukan (kepastiannya). Kemudian ia berkata; Saya telah duduk bersama [sahabat] Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada mereka. Dan mereka telah menceritakan kepadaku, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berpuasalah ketika kalian melihatnya (hilal) dan berbukalah karena ru`yah (melihat hilal). Jika kalian terhalangi untuk melihatnya (karena mendung), maka genapkanlah menjadi tiga puluh hari. Dan jika dua orang muslim bersaksi telah melihat hilal, maka berpuasa dan berbukalah kalian.\""},"2219":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ ثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ رَجُلٍ عَنْ كَعْبِ بْنِ مُرَّةَ الْبَهْزِيِّ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ اللَّيْلِ أَجْوَبُ وَقَالَ سُفْيَانُ مَرَّةً أَسْمَعُ قَالَ جَوْفُ اللَّيْلِ الْآخِرِ وَمَنْ أَعْتَقَ رَقَبَةً أَعْتَقَ اللَّهُ بِكُلِّ عُضْوٍ مِنْهَا عُضْوًا مِنْهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Abdurrazaq] ia berkata, Telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Salim bin Abul Ja'd] dari [seorang laki-laki] dari [Ka'b bin Murrah Al Bahzi] ia berkata; Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"(Bagian) malam manakah yang paling mustajab (dikabulkannya do'a)?\" -dan sekali waktu Sufyan mengatakan; Asma' (lebih didengar) - beliau menjawab: \"Sepertiga malam terakhir. Barangsiapa yang memerdekakan satu orang budak wanita, makan Allah akan membebaskan setiap anggota tubuhnya dengan setiap organ budak wanita itu (sebagai tebusannya) dari api neraka.\""},"2220":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ رَجُلٍ عَنْ كَعْبِ بْنِ مُرَّةَ الْبَهْزِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ اللَّيْلِ أَسْمَعُ قَالَ جَوْفُ اللَّيْلِ الْآخِرِ قَالَ ثُمَّ قَالَ ثُمَّ الصَّلَاةُ مَقْبُولَةٌ حَتَّى يُصَلَّى الْفَجْرُ ثُمَّ لَا صَلَاةَ حَتَّى تَكُونَ الشَّمْسُ قِيدَ رُمْحٍ أَوْ رُمْحَيْنِ ثُمَّ الصَّلَاةُ مَقْبُولَةٌ حَتَّى يَقُومَ الظِّلُّ قِيَامَ الرُّمْحِ ثُمَّ لَا صَلَاةَ حَتَّى تَزُولَ الشَّمْسُ ثُمَّ الصَّلَاةُ مَقْبُولَةٌ حَتَّى تَكُونَ الشَّمْسُ قِيدَ رُمْحٍ أَوْ رُمْحَيْنِ ثُمَّ لَا صَلَاةَ حَتَّى تَغْرُبَ الشَّمْسُ قَالَ إِذَا غَسَلْتَ وَجْهَكَ خَرَجَتْ خَطَايَاكَ مِنْ وَجْهِكَ وَإِذَا غَسَلْتَ يَدَيْكَ خَرَجَتْ خَطَايَاكَ مِنْ يَدَيْكَ وَإِذَا غَسَلْتَ رِجْلَيْكَ خَرَجَتْ خَطَايَاكَ مِنْ رِجْلَيْكَ","id":"Telah menceritakan kepada kami [Abdurrazaq] katanya, Telah mengabarkan kepada kami [Sofyan] dari [Manshur] dari [Salim bin Abil Ja'd] dari [seseorang] dari [Ka'b bin Murrah Al Bahzi], Katanya, saya bertanya 'Wahai Rasulullah, waktu malam mana yang doanya paling didengar? Rasulullah menjawab 'kegelapan malam akhir\", kemudian beliau bersabda \" kemudian shalat yang diterima hingga ia shalat fajar, kemudian tidak ada shalat hingga matahari setinggi setinggi tombak atau dua tombak (ketika pagi), kemudian shalat yang diterima hingga bayangan persis di pusaran tombak (tepat setengah siang), kemudian tak ada shalat hingga matahari miring, kemudian shalat yang diterima hingga matahari setinggi tombak atau dua tombak (ketika sore), kemudian tak ada shalat hingga matahari terbenam, kata Ka'b, jika engkau basuh wajahmu, maka kesalahanmu keluar dari wajahmu, dan jika kau basuh tanganmu, kesalahanmu keluar dari kedua tanganmu, jika kau basuh kedua kakimu, kesalahanmu keluar dari kedua kakimu."},"2221":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنِي سُفْيَانُ الْعُصْفُرِيُّ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ النُّعْمَانِ الْأَسَدِيِّ أَحَدُ بَنِي عَمْرِو بْنِ أَسَدٍ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا انْصَرَفَ قَامَ قَائِمًا فَقَالَ عَدَلَتْ شَهَادَةُ الزُّورِ الْإِشْرَاكَ بِاللَّهِ عَزَّ وَجَلَّ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ وَاجْتَنِبُوا قَوْلَ الزُّورِ حُنَفَاءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِ }","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] telah menceritakan kepadaku [Sufyan Al Ushfuri] dari [bapaknya] dari [Habib bin Nu'man Al Asadi] salah seorang dari Bani Amru bin Asad, dari [Khuraim bin Fatik Al Asadi] ia berkata; Rasulullah shallallahu 'alaihi wasallam menunaikan shalat subuh. Setelah itu, beliau berdiri dan bersabda: \"Persaksikan palsu dosanya, menyamai dosa perbuatan syirik kepada Allah 'azza wajalla.\" Kemudian beliau membaca ayat ini; \"Maka jauhilah olehmu berhala-berhala yang najis itu dan jauhilah perkataan-perkataan dusta.31. Dengan ikhlas kepada Allah, tidak mempersekutukan sesuatu dengan Dia.\""},"2222":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَبِي إِسْحَاقَ عَنْ شِمْرٍ عَنْ خُرَيْمٍ رَجُلٍ مِنْ بَنِي أَسَدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنْ فِيكَ اثْنَتَيْنِ كُنْتَ أَنْتَ قَالَ إِنْ وَاحِدَةً تَكْفِينِي قَالَ تُسْبِلُ إِزَارَكَ وَتُوَفِّرُ شَعْرَكَ قَالَ لَا جَرَمَ وَاللَّهِ لَا أَفْعَلُ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Abu Ishaq] dari [Syimr] dari [Khuraim] seorang laki-laki dari Bani Asad, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya pada tidak terdapat dua hal, niscaya kamu ankan menjadi..\" Khuraim berkata, \"Kalu satu, apakah telah cukup.\" beliau bersabda: \"Kamu menjulurkan kainmu dan memanjangkan rambutmu.\" Khuraim berkata, \"Tidak ada masalah, demi Allah, saya tidak akan lagi melakukannya.\""},"2223":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا الْمَسْعُودِيُّ عَنِ الرُّكَيْنِ بْنِ الرَّبِيعِ عَنْ رَجُلٍ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَعْمَالُ سِتَّةٌ وَالنَّاسُ أَرْبَعَةٌ فَمُوجِبَتَانِ وَمِثْلٌ بِمِثْلٍ وَحَسَنَةٌ بِعَشْرِ أَمْثَالِهَا وَحَسَنَةٌ بِسَبْعِ مِائَةٍ فَأَمَّا الْمُوجِبَتَانِ فَمَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ وَمَنْ مَاتَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ النَّارَ وَأَمَّا مِثْلٌ بِمِثْلٍ فَمَنْ هَمَّ بِحَسَنَةٍ حَتَّى يَشْعُرَهَا قَلْبُهُ وَيَعْلَمَهَا اللَّهُ مِنْهُ كُتِبَتْ لَهُ حَسَنَةً وَمَنْ عَمِلَ سَيِّئَةً كُتِبَتْ عَلَيْهِ سَيِّئَةً وَمَنْ عَمِلَ حَسَنَةً فَبِعَشْرِ أَمْثَالِهَا وَمَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ فَحَسَنَةٌ بِسَبْعِ مِائَةٍ وَأَمَّا النَّاسُ فَمُوَسَّعٌ عَلَيْهِ فِي الدُّنْيَا مَقْتُورٌ عَلَيْهِ فِي الْآخِرَةِ وَمَقْتُورٌ عَلَيْهِ فِي الدُّنْيَا مُوَسَّعٌ عَلَيْهِ فِي الْآخِرَةِ وَمَقْتُورٌ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَمُوَسَّعٌ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Al Mas'udi] dari [Ar Rukain bin Ar Rabi'] dari [seorang laki-laki] dari [Khuraim bin Fatik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Balasan) amalan itu ada enam, sedangkan manusia ada empat (golongan). Yaitu, Mujibatan (amalan yang mendapatkan dua balasan) Mitslu bi Mitslin (amalan yang mendapat balasan yang setimpal), amalan yang akan dilipatgandakan menjadi sepuluh kebaikan, dan amalan kebaikan yang menjadi tujuh ratus. Adapun Mujibatan adalah; siapa saja yang meninggal dalam keadaan tidak menyekutukan Allah dengan sesuatu apapun, maka dia akan masuk surga. Dan barangsiapa yang meninggal dalam keadaan menyekutukan Allah dengan sesuatu yang lain, maka ia akan masuk neraka. (Adapun) Mitslu bi Mitslin; Siapa yang berkeinginan untuk melakukan kebaikan hingga hatinya merasakannya, dan Allah pun tahu akan hal itu, maka hal itu akan ditulis baginya menjadi satu kebaikan. Barangsiapa yang mengerjakan amal keburukan, maka akan ditulis atasnya satu keburukan. Namun barangsiapa yang beramal kebajikan, maka akan dicatat baginya sepuluh kebaikan semisalnya. Dan siapa yang memberikan nafkah di jalan Allah, maka satu kebaikan itu (dilipatgandakan menjadi) tujuh ratus kali. Sedangkan manusia itu ada empat yaitu; (pertama) seorang yang mendapat kelapangan di dunia, namun di akhirat, yang ia dapatkan adalah kesempitan. (kedua) seorang yang mendapat kelapangan di akhirat, namun ia selalu berada dalam kesempitan di dunia. (yang ketiga) seorang yang mendapat kesempitan baik di dunia maupun di akhirat. Dan (yang keempat) seorang yang mendapat kelapangan di dunia dan juga kelapangan di di akhirat.\""},"2224":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرٍ عَنْ أَبِي إِسْحَاقَ عَنْ شِمْرِ بْنِ عَطِيَّةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الرَّجُلُ أَنْتَ يَا خُرَيْمُ لَوْلَا خُلَّتَانِ فِيكَ قُلْتُ وَمَا هُمَا يَا رَسُولَ اللَّهِ قَالَ إِسْبَالُكَ إِزَارَكَ وَإِرْخَاؤُكَ شَعْرَكَ","id":"Telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Abu Bakar] dari [Abu Ishaq] dari [Syimr bin 'Athiyyah] dari [Khuraim bin Fatik Al Asadi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Senikmat-nikmat laki-laki adalah kamu wahai Khuraim, sekiranya bukan karena dua hal yang ada padamu.\" Saya berkata, \"Apakah kedua hal itu wahai Rasulullah?\" berliau menjawab: \"(Yaitu) kainmu yang Isbal (menjulur hingga melewati kedua mata kaki) dan rambutmu yang panjang.\""},"2225":{"ar":"حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ أَخْبَرَنَا سُفْيَانُ بْنُ زِيَادٍ عَنْ فَاتِكِ بْنِ فَضَالَةَ عَنْ أَيْمَنَ بْنِ خُرَيْمٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطِيبًا فَقَالَ يَا أَيُّهَا النَّاسُ عَدَلَتْ شَهَادَةُ الزُّورِ إِشْرَاكًا بِاللَّهِ عَزَّ وَجَلَّ ثَلَاثًا ثُمَّ قَالَ{ اجْتَنِبُوا الرِّجْسَ مِنْ الْأَوْثَانِ وَاجْتَنِبُوا قَوْلَ الزُّورِ }","id":"Telah menceritakan kepada kami [Marwan bin Mu'awiyah] telah mengabarkan kepada kami [Sufyan bin Ziyad] dari [Fatik bin Fadlalah] dari [Aiman bin Khuraim] ia berkata; Rasulullah shallallahu 'alaihi wasallam berdiri menyampaikan khutbah seraya bersabda: \"Wahai sekalian manusia, persaksikan palsu menyamai dosa perbuatan syirik kepada Allah 'azza wajalla.\" Beliau mengucapkannya hingga tiga kali. Kemudian beliau bersabda: \"Jauihilah perkara najis dan kotor dari berhala-berhala, serta jauhilah persaksian palsu.\""},"2226":{"ar":"حَدَّثَنَا يَعْلَى حَدَّثَنَا مِسْعَرٌ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَمِّهِ قُطْبَةَ بْنِ مَالِكٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْفَجْرِ وَالنَّخْلَ بَاسِقَاتٍ","id":"Telah menceritakan kepada kami [Ya'la] Telah menceritakan kepada kami [Mis'ar] dari [Ziyad bin Ilaqah] dari [pamannya, Quthbah bin Malik], ia berkata; Pada saat shalat Fajar, saya mendengar Rasulullah shallallahu 'alaihi wasallam membaca: \"WAN NAKHLI BAASIQAAT.\""},"2227":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَطَاءٍ يَعْنِي ابْنَ السَّائِبِ عَنْ رَجُلٍ مِنْ بَكْرِ بْنِ وَائِلٍ عَنْ خَالِهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أُعْشِرُ قَوْمِي فَقَالَ إِنَّمَا الْعُشُورُ عَلَى الْيَهُودِ وَالنَّصَارَى وَلَيْسَ عَلَى الْإِسْلَامِ عُشُورٌ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari ['Atha`] yakni Ibnu Sa`ib, dari [seorang laki-laki] dari Bakr bin Wa`il, dari [pamannya] ia berkata; Saya bertanya, \"Wahai Rasulullah, bolehkah aku melakukan Al 'Usyru (mengambil sepersepuluh) dari harta kaumku?\" Maka beliau bersabda: \"Yang melakukan Al 'Usyru hanyalah kaum Yahudi dan Nasrani. Tidak ada Usyru atas kaum muslimin.\""},"2228":{"ar":"حَدَّثَنَا وَكِيعٌ وَأَبُو مُعَاوِيَةَ قَالَا ثَنَا الْأَعْمَشُ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ قَالَبَعَثَنِي أَهْلِي بِلَقُوحٍ وَقَالَ أَبُو مُعَاوِيَةَ بِلَقْحٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ بِهَا فَأَمَرَنِي أَنْ أَحْلُبَهَا ثُمَّ قَالَ دَعْ دَاعِيَ اللَّبَنِقَالَ أَبُو مُعَاوِيَةَ لَا تُجْهِدَنَّهَا","id":"Telah menceritakan kepada kami [Waki'] dan [Abu Mu'awiyah] keduanya berkata, Telah menceritakan kepada kami [Al A'masy] dari [Ya'qub bin Bahir] dari [Dlirar bin Al Azwar] ia berkata; Keluargaku mengutusku menghadap Nabi shallallahu 'alaihi wasallam dengan membawa Laquh (Unta bunting yang hampir beranak), maka aku pun mendatangi beliau. Kemudian beliau menyuruhku untuk memeras susunya dan bersabda: \"Tinggalkanlah sedikit susunya, untuk memancing air susu yang lain.\" Abu Mu'awiyah berkata; \"Janganlah kamu mengeringkan (air susunya).\""},"2229":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنِ ابْنِ إِسْحَاقَ قَالَ وَقَالَ ابْنُ شِهَابٍ الزُّهْرِيُّ حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمْعَةَ بْنِ الْأَسْوَدِ بْنِ الْمُطَّلِبِ بْنِ أَسَدٍ قَالَلَمَّا اسْتُعِزَّ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عِنْدَهُ فِي نَفَرٍ مِنْ الْمُسْلِمِينَ قَالَ دَعَا بِلَالٌ لِلصَّلَاةِ فَقَالَ مُرُوا مَنْ يُصَلِّي بِالنَّاسِ قَالَ فَخَرَجْتُ فَإِذَا عُمَرُ فِي النَّاسِ وَكَانَ أَبُو بَكْرٍ غَائِبًا فَقَالَ قُمْ يَا عُمَرُ فَصَلِّ بِالنَّاسِ قَالَ فَقَامَ فَلَمَّا كَبَّرَ عُمَرُ سَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَوْتَهُ وَكَانَ عُمَرُ رَجُلًا مُجْهِرًا قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْنَ أَبُو بَكْرٍ يَأْبَى اللَّهُ ذَلِكَ وَالْمُسْلِمُونَ يَأْبَى اللَّهُ ذَلِكَ وَالْمُسْلِمُونَ قَالَ فَبَعَثَ إِلَى أَبِي بَكْرٍ فَجَاءَ بَعْدَ أَنْ صَلَّى عُمَرُ تِلْكَ الصَّلَاةَ فَصَلَّى بِالنَّاسِ قَالَ وَقَالَ عَبْدُ اللَّهِ بْنُ زَمْعَةَ قَالَ لِي عُمَرُ وَيْحَكَ مَاذَا صَنَعْتَ بِي يَا ابْنَ زَمْعَةَ وَاللَّهِ مَا ظَنَنْتُ حِينَ أَمَرْتَنِي إِلَّا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَكَ بِذَلِكَ وَلَوْلَا ذَلِكَ مَا صَلَّيْتُ بِالنَّاسِ قَالَ قُلْتُ وَاللَّهِ مَا أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكِنْ حِينَ لَمْ أَرَ أَبَا بَكْرٍ رَأَيْتُكَ أَحَقَّ مَنْ حَضَرَ بِالصَّلَاةِ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Abu Ishaq] ia berkata, [Ibnu Syihab Az Zuhri] berkata, telah menceritakan kepadaku [Abdul Malik bin Abu Bakr bin Abdurrahman bin Harits bin Hisyam] dari [bapaknya] dari [Abdullah bin Zam'ah bin Aswad bin Al Muthallib bin Asad] ia berkata; Ketika sakit Rasulullah shallallahu 'alaihi wasallam semakin parah -sementara saya saat itu berada di sisi beliau beserta beberapa orang dari kaum muslimin- Bilal mengumandangkan adzan shalat, maka beliau bersabda: \"Perintahkanlah seseorang untuk shalat (mengimami) orang-orang.\" Abdullah bin Zam'ah berkata; Saya pun keluar dan ternyata Umar ada di tengah-tengah para sahabat, sementara Abu Bakar tidak ada. Abdullah bin Zam'ah berkata, \"Berdirilah wahai Umar, shalatlah (menjadi imam) bersama kaum muslimin.\" Maka Umar pun berdiri, dan ketika ia bertakbir, Rasulullah shallallahu 'alaihi wasallam mendengar suaranya -sebab Umar adalah seorang laki-laki yang lantang suaranya-, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mana Abu Bakar, Allah dan kaum muslimin enggan akan hal itu. Allah dan kaum muslimin enggan akan hal itu.\" Akhirnya beliau mengutus seseorang kepada Abu Bakar. Maka ia pun datang setelah Umar usai menunaikan shalat itu, kemudian Abu Bakar pun shalat (mengimami) bersama kaum muslimin. Abdullah bin Zam'ah berkata; Umar berkata kepadaku, \"Celaka kamu, apa yang kamu lakukan terhadapku wahai Ibnu Zam'ah. Demi Allah, saya tidak berpikir ketika kamu memerintahkanku, kecuali Rasulullah shallallahu 'alaihi wasallam-lah yang memerintahkanmu (untuk menyuruhku menjadi Imam). Kalau bukan karena itu, aku tidak akan shalat (mengimami) kaum muslimin.\" Saya berkata, \"Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidaklah memerintahkanku. Namun ketika saya tidak melihat Abu Bakar, saya memandang, Andalah yang lebih berhak untuk mengimami shalat.\""},"2230":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ حَدَّثَتْنَا أُمُّ بَكْرٍ بِنْتُ الْمِسْوَرِ بْنِ مَخْرَمَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنِ الْمِسْوَرِ أَنَّهُبَعَثَ إِلَيْهِ حَسَنُ بْنُ حَسَنٍ يَخْطُبُ ابْنَتَهُ فَقَالَ لَهُ قُلْ لَهُ فَلْيَلْقَنِي فِي الْعَتَمَةِ قَالَ فَلَقِيَهُ فَحَمِدَ الْمِسْوَرُ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ أَمَّا بَعْدُ وَاللَّهِ مَا مِنْ نَسَبٍ وَلَا سَبَبٍ وَلَا صِهْرٍ أَحَبُّ إِلَيَّ مِنْ سَبَبِكُمْ وَصِهْرِكُمْ وَلَكِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاطِمَةُ مُضْغَةٌ مِنِّي يَقْبِضُنِي مَا قَبَضَهَا وَيَبْسُطُنِي مَا بَسَطَهَا وَإِنَّ الْأَنْسَابَ يَوْمَ الْقِيَامَةِ تَنْقَطِعُ غَيْرَ نَسَبِي وَسَبَبِي وَصِهْرِي وَ��ِنْدَكَ ابْنَتُهَا وَلَوْ زَوَّجْتُكَ لَقَبَضَهَا ذَلِكَ قَالَ فَانْطَلَقَ عَاذِرًا لَهُ","id":"Telah menceritakan kepada kami [Abu Sa'id] bekas budak Bani Hasyim, Telah menceritakan kepada kami [Abdullah bin Ja'far] Telah menceritakan kepada kami [Ummu Bakr binti Al Miswar bin Makhramah] dari [Ubaidullah bin Abu Rafi'] dari [Miswar] bahwasanya; Hasan bin Hasan mengutus seseorang padanya untuk meminang anak putrinya. Maka ia pun berkata, \"Katakanlah padanya, hendaklah ia menemui setelah shalat Isya`.\" Maka Hasan menemuinya. Setelah Miswar memuji Allah dan membaca pujian-pujian atasnya, ia berkata, \"Amma ba'du, demi Allah, tidak ada hubungan kekeluargaan, tidak pula nasab dan kerabat yang paling aku sukai daripada nasab dan hubungan kekerabatan kalian. Akan tetapi, Rasulullah Shallallahu 'Alaihi Wasallam pernah bersabda: 'Sesungguhnya Fathimah adalah bagian dariku, aku merasa tersakiti atas semua yang menyakitinya dan aku merasa senang dengan apa saja yang membuatnya senang. Sesungguhnya pada hari Kiamat, semua nasab (keturunan) akan terputus kecuali nasab, hubungan kekeluargaan dan hubungan kekerabatanku, sementara putrinya (Abu Jahal) berada dalam asuhanmu! Sekiranya aku menikahkanmu, niscaya aku telah menyakitinya.” Lalu Ali pergi berpamitan."},"2231":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ مَرْوَانَ وَالْمِسْوَرِ بْنِ مَخْرَمَةَ يَزِيدُ أَحَدُهُمَا عَلَى صَاحِبِهِخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فِي بِضْعَ عَشْرَةَ مِائَةً مِنْ أَصْحَابِهِ فَلَمَّا كَانَ بِذِي الْحُلَيْفَةِ قَلَّدَ الْهَدْيَ وَأَشْعَرَ وَأَحْرَمَ مِنْهَا وَبَعَثَ عَيْنًا لَهُ بَيْنَ يَدَيْهِ فَسَأَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah] dari [Marwan] dan [Miswar bin Makhramah] -salah seorand dari keduanya menambahkan atas temannya- Pada tahun Hudaibiyah, Rasulullah shallallahu 'alaihi wasallam berangkat beserta seratus orang lebih sahabatnya. Ketika beliau sampai di Hudaibiyah, beliau menuntun Hadyu (hewan kurban) dan memberi tanda padanya serta beliau memulai niat ihram dari tempat itu. kemudian beliau mengutus mata-matanya. Maka Rasulullah shallallahu 'alaihi wasallam pun bertanya hingga..."},"2232":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَاقَ بْنِ يَسَارٍ عَنِ الزُّهْرِيِّ مُحَمَّدِ بْنِ مُسْلِمِ بْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنِ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَمَرْوَانَ بْنِ الْحَكَمِ قَالَاخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ يُرِيدُ زِيَارَةَ الْبَيْتِ لَا يُرِيدُ قِتَالًا وَسَاقَ مَعَهُ الْهَدْيَ سَبْعِينَ بَدَنَةً وَكَانَ النَّاسُ سَبْعَ مِائَةِ رَجُلٍ فَكَانَتْ كُلُّ بَدَنَةٍ عَنْ عَشَرَةٍ قَالَ وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَ بِعُسْفَانَ لَقِيَهُ بِشْرُ بْنُ سُفْيَانَ الْكَعْبِيُّ فَقَالَ يَا رَسُولَ اللَّهِ هَذِهِ قُرَيْشٌ قَدْ سَمِعَتْ بِمَسِيرِكَ فَخَرَجَتْ مَعَهَا الْعُوذُ الْمَطَافِيلُ قَدْ لَبِسُوا جُلُودَ النُّمُورِ يُعَاهِدُونَ اللَّهَ أَنْ لَا تَدْخُلَهَا عَلَيْهِمْ عَنْوَةً أَبَدًا وَهَذَا خَالِدُ بْنُ الْوَلِيدِ فِي خَيْلِهِمْ قَدِمُوا إِلَى كُرَاعِ الْغَمِيمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا وَيْحَ قُرَيْشٍ لَقَدْ أَكَلَتْهُمْ الْحَرْبُ مَاذَا عَلَيْهِمْ لَوْ خَلَّوْا بَيْنِي وَبَيْنَ سَائِرِ النَّاسِ فَإِنْ أَصَابُونِي كَانَ الَّذِي أَرَادُوا وَإِنْ أَظْهَرَنِي اللَّهُ عَلَيْهِمْ دَخَلُوا فِي الْإِسْلَامِ وَهُمْ وَافِرُونَ وَإِنْ لَمْ يَفْعَلُوا قَاتَلُوا وَبِهِمْ قُوَّةٌ فَمَاذَا تَظُنُّ قُرَيْشٌ وَاللَّهِ إِنِّي لَا أَزَالُ أُجَاهِدُهُمْ عَلَى الَّذِي بَعَثَنِي اللَّهُ لَهُ حَتَّى يُظْهِرَهُ اللَّهُ لَهُ أَوْ تَنْفَرِدَ هَذِهِ السَّالِفَةُ ثُمَّ أَمَرَ النَّاسَ فَسَلَكُوا ذَاتَ الْيَمِينِ بَيْنَ ظَهْرَيْ ال��حَمْضِ عَلَى طَرِيقٍ تُخْرِجُهُ عَلَى ثَنِيَّةِ الْمِرَارِ وَالْحُدَيْبِيَةِ مِنْ أَسْفَلِ مَكَّةَ قَالَ فَسَلَكَ بِالْجَيْشِ تِلْكَ الطَّرِيقَ فَلَمَّا رَأَتْ خَيْلُ قُرَيْشٍ قَتَرَةَ الْجَيْشِ قَدْ خَالَفُوا عَنْ طَرِيقِهِمْ نَكَصُوا رَاجِعِينَ إِلَى قُرَيْشٍ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا سَلَكَ ثَنِيَّةَ الْمِرَارِ بَرَكَتْ نَاقَتُهُ فَقَالَ النَّاسُ خَلَأَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا خَلَأَتْ وَمَا هُوَ لَهَا بِخُلُقٍ وَلَكِنْ حَبَسَهَا حَابِسُ الْفِيلِ عَنْ مَكَّةَ وَاللَّهِ لَا تَدْعُونِي قُرَيْشٌ الْيَوْمَ إِلَى خُطَّةٍ يَسْأَلُونِي فِيهَا صِلَةَ الرَّحِمِ إِلَّا أَعْطَيْتُهُمْ إِيَّاهَا ثُمَّ قَالَ لِلنَّاسِ انْزِلُوا فَقَالُوا يَا رَسُولَ اللَّهِ مَا بِالْوَادِي مِنْ مَاءٍ يَنْزِلُ عَلَيْهِ النَّاسُ فَأَخْرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْمًا مِنْ كِنَانَتِهِ فَأَعْطَاهُ رَجُلًا مِنْ أَصْحَابِهِ فَنَزَلَ فِي قَلِيبٍ مِنْ تِلْكَ الْقُلُبِ فَغَرَزَهُ فِيهِ فَجَاشَ الْمَاءُ بِالرَّوَاءِ حَتَّى ضَرَبَ النَّاسُ عَنْهُ بِعَطَنٍ فَلَمَّا اطْمَأَنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بُدَيْلُ بْنُ وَرْقَاءَ فِي رِجَالٍ مِنْ خُزَاعَةَ فَقَالَ لَهُمْ كَقَوْلِهِ لِبُشَيْرِ بْنِ سُفْيَانَ فَرَجَعُوا إِلَى قُرَيْشٍ فَقَالُوا يَا مَعْشَرَ قُرَيْشٍ إِنَّكُمْ تَعْجَلُونَ عَلَى مُحَمَّدٍ وَإِنَّ مُحَمَّدًا لَمْ يَأْتِ لِقِتَالٍ إِنَّمَا جَاءَ زَائِرًا لِهَذَا الْبَيْتِ مُعَظِّمًا لَحَقِّهِ فَاتَّهَمُوهُمْ قَالَ مُحَمَّدٌ يَعْنِي ابْنَ إِسْحَاقَ قَالَ الزُّهْرِيُّ وَكَانَتْ خُزَاعَةُ فِي غَيْبَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْلِمُهَا وَمُشْرِكُهَا لَا يُخْفُونَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا كَانَ بِمَكَّةَ قَالُوا وَإِنْ كَانَ إِنَّمَا جَاءَ لِذَلِكَ فَلَا وَاللَّهِ لَا يَدْخُلُهَا أَبَدًا عَلَيْنَا عَنْوَةً وَلَا تَتَحَدَّثُ بِذَلِكَ الْعَرَبُ ثُمَّ بَعَثُوا إِلَيْهِ مِكْرَزَ بْنَ حَفْصِ بْنِ الْأَخْيَفِ أَحَدَ بَنِي عَامِرِ بْنِ لُؤَيٍّ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا رَجُلٌ غَادِرٌ فَلَمَّا انْتَهَى إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوٍ مِمَّا كَلَّمَ بِهِ أَصْحَابَهُ ثُمَّ رَجَعَ إِلَى قُرَيْشٍ فَأَخْبَرَهُمْ بِمَا قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَبَعَثُوا إِلَيْهِ الْحِلْسَ بْنَ عَلْقَمَةَ الْكِنَانِيَّ وَهُوَ يَوْمَئِذٍ سَيِّدُ الْأَحَابِشِ فَلَمَّا رَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا مِنْ قَوْمٍ يَتَأَلَّهُونَ فَابْعَثُوا الْهَدْيَ فِي وَجْهِهِ فَبَعَثُوا الْهَدْيَ فَلَمَّا رَأَى الْهَدْيَ يَسِيلُ عَلَيْهِ مِنْ عَرْضِ الْوَادِي فِي قَلَائِدِهِ قَدْ أَكَلَ أَوْتَارَهُ مِنْ طُولِ الْحَبْسِ عَنْ مَحِلِّهِ رَجَعَ وَلَمْ يَصِلْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِعْظَامًا لِمَا رَأَى فَقَالَ يَا مَعْشَرَ قُرَيْشٍ قَدْ رَأَيْتُ مَا لَا يَحِلُّ صَدُّهُ الْهَدْيَ فِي قَلَائِدِهِ قَدْ أَكَلَ أَوْتَارَهُ مِنْ طُولِ الْحَبْسِ عَنْ مَحِلِّهِ فَقَالُوا اجْلِسْ إِنَّمَا أَنْتَ أَعْرَابِيٌّ لَا عِلْمَ لَكَ فَبَعَثُوا إِلَيْهِ عُرْوَةَ بْنَ مَسْعُودٍ الثَّقَفِيَّ فَقَالَ يَا مَعْشَرَ قُرَيْشٍ إِنِّي قَدْ رَأَيْتُ مَا يَلْقَى مِنْكُمْ مَنْ تَبْعَثُونَ إِلَى مُحَمَّدٍ إِذَا جَاءَكُمْ مِنْ التَّعْنِيفِ وَسُوءِ اللَّفْظِ وَقَدْ عَرَفْتُمْ أَنَّكُمْ وَالِدٌ وَأَنِّي وَلَدٌ وَقَدْ سَمِعْتُ بِالَّذِي نَابَكُمْ فَجَمَعْتُ مَنْ أَطَاعَنِي مِنْ قَوْمِي ثُمَّ جِئْتُ حَتَّى آسَيْتُكُمْ بِنَفْسِي قَالُوا صَدَقْتَ مَا أَنْتَ عِنْدَنَا بِمُتَّهَمٍ فَخَرَجَ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ بَيْنَ يَدَيْهِ فَقَالَ يَا مُحَمَّدُ جَمَعْتَ أَوْبَاشَ النَّاسِ ثُمَّ جِئْتَ بِهِمْ لِبَيْضَتِكَ لِتَفُضَّهَا إِنَّهَا قُرَيْشٌ قَدْ خَرَجَتْ مَعَهَا الْعُوذُ الْمَطَافِيلُ قَدْ لَبِسُوا جُلُودَ النُّمُورِ يُعَاهِدُونَ اللَّهَ أَنْ لَا تَدْخُلَهَا عَلَيْهِمْ عَنْوَةً أَبَدًا وَأَيْمُ اللَّهِ لَكَأَنِّي بِهَؤُلَاءِ قَدْ انْكَشَفُوا عَنْكَ غَدًا قَالَ وَأَبُو بَكْرٍ الصِّدِّيقُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ فَقَالَ امْصُصْ بَظْرَ اللَّاتِ أَنَحْنُ نَنْكَشِفُ عَنْهُ قَالَ مَنْ هَذَا يَا مُحَمَّدُ قَالَ هَذَا ابْنُ أَبِي قُحَافَةَ قَالَ وَاللَّهِ لَوْلَا يَدٌ كَانَتْ لَكَ عِنْدِي لَكَافَأْتُكَ بِهَا وَلَكِنَّ هَذِهِ بِهَا ثُمَّ تَنَاوَلَ لِحْيَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُغِيرَةُ بْنُ شُعْبَةَ وَاقِفٌ عَلَى رَأْسِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَدِيدِ قَالَ يَقْرَعُ يَدَهُ ثُمَّ قَالَ أَمْسِكْ يَدَكَ عِنْ لِحْيَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ وَاللَّهِ لَا تَصِلُ إِلَيْكَ قَالَ وَيْحَكَ مَا أَفَظَّكَ وَأَغْلَظَكَ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ هَذَا يَا مُحَمَّدُ قَالَ هَذَا ابْنُ أَخِيكَ الْمُغِيرَةُ بْنُ شُعْبَةَ قَالَ أَغُدَرُ هَلْ غَسَلْتَ سَوْأَتَكَ إِلَّا بِالْأَمْسِ قَالَ فَكَلَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ مَا كَلَّمَ بِهِ أَصْحَابَهُ فَأَخْبَرَهُ أَنَّهُ لَمْ يَأْتِ يُرِيدُ حَرْبًا قَالَ فَقَامَ مِنْ عِنْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ رَأَى مَا يَصْنَعُ بِهِ أَصْحَابُهُ لَا يَتَوَضَّأُ وُضُوءًا إِلَّا ابْتَدَرُوهُ وَلَا يَبْسُقُ بُسَاقًا إِلَّا ابْتَدَرُوهُ وَلَا يَسْقُطُ مِنْ شَعَرِهِ شَيْءٌ إِلَّا أَخَذُوهُ فَرَجَعَ إِلَى قُرَيْشٍ فَقَالَ يَا مَعْشَرَ قُرَيْشٍ إِنِّي جِئْتُ كِسْرَى فِي مُلْكِهِ وَجِئْتُ قَيْصَرَ وَالنَّجَاشِيَّ فِي مُلْكِهِمَا وَاللَّهِ مَا رَأَيْتُ مَلِكًا قَطُّ مِثْلَ مُحَمَّدٍ فِي أَصْحَابِهِ وَلَقَدْ رَأَيْتُ قَوْمًا لَا يُسْلِمُونَهُ لِشَيْءٍ أَبَدًا فَرُوا رَأْيَكُمْ قَالَ وَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ ذَلِكَ بَعَثَ خِرَاشَ بْنَ أُمَيَّةَ الْخُزَاعِيَّ إِلَى مَكَّةَ وَحَمَلَهُ عَلَى جَمَلٍ لَهُ يُقَالُ لَهُ الثَّعْلَبُ فَلَمَّا دَخَلَ مَكَّةَ عَقَرَتْ بِهِ قُرَيْشٌ وَأَرَادُوا قَتْلَ خِرَاشٍ فَمَنَعَهُمْ الْأَحَابِشُ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَعَا عُمَرَ لِيَبْعَثَهُ إِلَى مَكَّةَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَخَافُ قُرَيْشًا عَلَى نَفْسِي وَلَيْسَ بِهَا مِنْ بَنِي عَدِيٍّ أَحَدٌ يَمْنَعُنِي وَقَدْ عَرَفَتْ قُرَيْشٌ عَدَاوَتِي إِيَّاهَا وَغِلْظَتِي عَلَيْهَا وَلَكِنْ أَدُلُّكَ عَلَى رَجُلٍ هُوَ أَعَزُّ مِنِّي عُثْمَانَ بْنِ عَفَّانَ قَالَ فَدَعَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَهُ إِلَى قُرَيْشٍ يُخْبِرُهُمْ أَنَّهُ لَمْ يَأْتِ لِحَرْبٍ وَأَنَّهُ جَاءَ زَائِرًا لِهَذَا الْبَيْتِ مُعَظِّمًا لِحُرْمَتِهِ فَخَرَجَ عُثْمَانُ حَتَّى أَتَى مَكَّةَ وَلَقِيَهُ أَبَانُ بْنُ سَعِيدِ بْنِ الْعَاصِ فَنَزَلَ عَنْ دَابَّتِهِ وَحَمَلَهُ بَيْنَ يَدَيْهِ وَرَدِفَ خَلْفَهُ وَأَجَارَهُ حَتَّى بَلَّغَ رِسَالَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ عُثْمَانُ حَتَّى أَتَى أَبَا سُفْيَانَ وَعُظَمَاءَ قُرَيْشٍ فَبَلَّغَهُمْ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَرْسَلَهُ بِهِ فَقَالُوا لِعُثْمَانَ إِنْ شِئْتَ أَنْ تَطُوفَ بِالْبَيْتِ فَطُفْ بِهِ فَقَالَ مَا كُنْتُ لِأَفْعَلَ حَتَّى يَطُوفَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَاحْتَبَسَتْهُ قُرَيْشٌ عِنْدَهَا فَبَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْمُسْلِمِينَ أَنَّ عُثْمَانَ قَدْ قُتِلَ قَالَ مُحَمَّدٌ فَحَدَّثَنِي الزُّهْرِيُّ أَنَّ قُرَيْشًا بَعَثُوا سُهَيْل","id":"Telah menceritakan kepada kami [Yazid bin harun] Telah mengabarkan kepada kami [Muhammad bin Ishaq bin Yasar] dari [Az Zuhri Muhammad bin Muslim bin Syihab] dari ['Urwah bin Zubair] dari [Miswar bin Makhramah] dan [Marwan bin Hakam], kata keduanya, Pada tahun Hudaibiyah Rasulullah Shallallahu'alaihiwasallam berangkat dengan niyat mengunjungi baitullah, ka'bah, bukan niyat untuk berperang, sekaligus beliau giring unta sembelihannya (hadyu) sebanyak tujuh puluh ekor. Sahabat ketika itu berjumlah tujuh ratus orang. Setiap satu ekor unta untuk sepuluh orang. Kata Miswar atau Marwan, Rasulullah Shallallahu'alaihiwasallam terus melanjutkan perjalanan, hingga ketika beliau di 'Usfan, Bisyir bin Sufyan alka'bi memergoki beliau dan berujar \"Hai Rasulullah, ini quraisy telah mendengar berita keberangkatanmu dan mereka ikutsertakan wanita dan anak-anak, baik yang masih kecil atau dewasa. Telah mereka pakai kulit macan loreng - kulit macan loreng mereka pakai sebagai symbol kebanggaan dan keberingasan, dan kesiapan matinya betul-betul serius--, mereka telah berjanji kepada Allah agar engkau tidak memasuki baitullah secara paksa. Disana telah ada Khalid bin Walid yang tiba di Kura'il ghamim. Rasulullah Shallallahu'alaihiwasallam kontan bersabda \"Celaka quraisy, mereka telah tercabik-cabik oleh perang, apa beratnya sekiranya mereka tidak menghalang-halangi aku dan sahabatku, kalaulah mereka berhasil mengalahkanku, itu ambisi mereka, dan sekiranya Allah menjadikanku menang atas mereka, jumlah mereka banyak sekali. Kalaulah (keIslaman) itu tidak mereka kerjakan, musti mereka lakukan peperangan karena mereka juga mempunyai kekuatan. Quraisy, apa lagi keinginan mereka? Demi Allah, sungguh aku tidak akan berhenti memerangi mereka karena risalah Allah yang utuskan kepadaku hingga Allah memenangkannya atau tali kekang unta tinggal satu -maksudnya hingga binasa, sebab tali kekang hewan yang biasanya sepasang sangat jarang satunya putus selain karena pembunuhan atau peperangan--. Kemudian beliau perintahkan para sahabat hingga mereka menyusuri jalan jalur sebelah kanan antara dua rerimbunan pohon yang bisa menghantarkan mereka ke Tsaniyatul mirar dan Hudaibiyah di bawah Makkah. Kata Marwan atau Miswar, sahabat Nabi menyusuri jalan tersebut. Ketika pasukan berkuda quraisy melihat debu-debu para sahabat nabi menyelisihi jalur mereka, mereka kembali pulang menemui Quraisy. Rasulullah Shallallahu'alaihiwasallam terus berangkat hingga ketika beliau selesai menempuh Tsaniyyatul mirar, unta beliau menderum. Para sahabat berujar \"Wah, unta Nabi rupanya mogok.\" Rasulullah Shallallahu'alaihiwasallam menjawab \"Unta ini tidak mogok karena kemauannya sendiri, dan mogok bukanlah adat kebiasaannya, namun Dzat yang pernah menahan gajah (pasukan Abrahah) dari Makkah-lah yang menahannya. Demi Allah, tidaklah quraisy mengajakku hari ini kepada ajakan yang isinya memintaku untuk menyambung silatu rahim, selain akan aku penuhi. Dan beliau katakan kepada para sahabatnya \"Silahkan kalian turun.\" Para sahabat berujar \"Ya rasulullah, lembah yang dijadikan kawan-kawan untuk singgah ini tak ada sumber mata air.\" Rasulullah kemudian mencabut anak panah dari tabungnya, beliau berikan kepada salah seorang sahabatnya, lantas beliau singgah di sebuah sumur tua dari beberapa sumur tua yang ada. Beliau lemparkan anak panahnya ke dalam sumur tersebut hingga air memancar deras. Para sahabat minum dengan puas, untanya juga minum dengan puas, sehingga mereka jadikan tempat bermukim. Ketika Rasulullah Shallallahu'alaihiwasallam tenang, tak tahunya Budail bin Warqa' bersama rombongan bani khuza'ah datang dan Rasulullah berujar kepada mereka sebagaimana ucapannya kepada Busyair bin Abi Sofyan. Akhirnya mereka kembali ke quraisy dan berujar \"Wahai segenap quraisy, kalian tergesa-gesa menimpakan bahaya kepada Muhammad, sungguh Muhammad datang bukan untuk berperang, hanyasanya ia datang dalam rangka mengunjungi baitullah untuk menghormati haknya.Quraisy pun menuduh dengan tuduhan buruk kepada Budail bin Warqa' dan rombongannya ini. Kata Muhammad, alias Ibn ishaq, kata Azzuhri, Tradisi bani Khuza'ah ketika itu, mereka senantiasa membongkar keburukan Rasulullah Shallallahu'alaihiwasallam, baik mereka yang muslim maupun yang musyrik, mereka tak pernah menyembunyikan sedikitpun berita yang ada pada diri Rasulullah Shallallahu'alaihiwasallam ketika di Makkah. Kata Quraisy, \"Sekalipun ia datang untuk itu, demi Allah, selama-lamanya mereka tak bisa memasukinya secara paksa, dan jangan sampai bangsa arab berbicara mengenai hal itu!\" Lantas quraisy mengutus Mikraz bin Hafs bin al-akhyaf salah seorang bani Amir bin Lu'ay. Ketika Rasulullah Shallallahu'alaihiwasallam melihatnya, Rasulullah Shallallahu'alaihiwasallam berkomentar \"Yang ini laki-laki pengkhianat! Ketika Mikraz sampai ke Rasulullah Shallallahu'alaihiwasallam, Rasulullah Shallallahu'alaihiwasallam menyampaikan kepadanya sebagaimana yang telah beliau konsultasikan kepada para sahabatnya. Lantas Mikraz kembali ke Quraisy dan mengabari mereka segala yang diucapkan Rasulullah Shallallahu'alaihiwasallam. Kata Miswar atau Marwan, Quraisy kemudian mengutus Alhilsa bin 'Alqamah Alkinani yang ketika itu adalah tokoh kabilah yang ikut bersekutu dengan quraisy. Ketika Rasulullah Shallallahu'alaihiwasallam melihatnya, Rasulullah Shallallahu'alaihiwasallam berkomentar: \"Laki-laki ini dari sebuah kaum yang suka menyembah tuhan, tolong persiapkanlah hewan kurban yang bisa dilihatnya.\" Para sahabat pun mengumpulkan beberapa hewan kurban. Ketika Hilsa bin 'Alqamah melihat hewan kurban susul-menyusul berjalan menghadapnya dari lembah bagian lebarnya dan lengkap dengan kalung-kalungnya, --tradisi arab mengalungi hewan yang akan dijadikan kurban- dan hewan tersebut memakan tali kalungnya karena sekian lama tertahan ditempatnya, Hilsa langsung pulang dan tidak menemui Rasulullah Shallallahu'alaihiwasallam sebagai penghormatan atas peristiwa yang dilihatnya sendiri. Dan ia katakan kepada quraisy \"Wahai segenap quraisy, telah kulihat kejadian yang terlarang dihalang-halangi, yaitu hewan-hewan kurban lengkap dengan kalung-kalungnya, mereka memangsa tali-tali kalungnya karena sekian lama tertahan di tempatnya. Quraisy menjawab \"Duduk engkau hai Hilsa, kau adalah manusia arab primitife yang tak kenal apa-apa.\" Quraisy kemudian mengutus 'Urwah bin mas'ud atstsaqafi. 'Urwah kemudian mengatakan \"Hai segenap quraisy, telah kulihat segala yang kalian temui dari sahabat-sahabat yang kalian utus kepada Muhammad, yang membawa kata-kata menyakitkan dan penghinaan. Kalian telah sama-sama mengerti bahwa kalian adalah orang tua dan aku adalah anak kecil, dan telah kudengar utusan yang mewakili kalian. Maka aku kumpulkan siapapun yang menaatiku dari kaumku, kemudian aku datang hingga aku tolong kalian dengan pribadiku sendiri. Qurays menjawab \"Engkau benar, engkau tak lagi tersanksikan lagi oleh kami-kami ini.\" Urwah spontan berangkat hingga menemui Rasulullah Shallallahu'alaihiwasallam. Ia pun duduk di hadapannya dan berujar \"Hai Muhammad, telah kau kumpulkan sekian banyak kabilah kemudian kau datangkan mereka kepada keluargamu untuk kau pecah belah. Ketahuilah bahwa quraisy telah berangkat membawa isteri-isteri dan anak-anak mereka, telah mereka pakai kulit-kulit harimau -ungkapan kesombongan bahwa mereka siap mati, menumpahkan darah, dan pantang mundur-mereka ikrarkan janji kepada Allah agar engkau tidak memasukinya secara paksa selama-lamanya. Demi Allah, sungguh seolah-olah aku bersama mereka akan kelihatan olehmu tinggal esok saja! Kata Marwan atau miswar, Abu Bakar ketika itu duduk di belakang Rasulullah Shallallahu'alaihiwasallam dan berujar \"Hisaplah kemaluan berhala Lattamu, apa mungkin kami kelihatan oleh berhalamu itu! (Perkataan ini Abu bakar ucapkan untuk menghina Urwah bin mas'ud). Urwah bertanya \"Siapa ini hai Muhammad!\"Itu Ibnu Abu Quhafah!\" jawab Rasulullah. Urwah berujar \"Kalaulah bukan karena budi baikmu kepadaku yang belum sempat saya balas, niscaya kubalas ucapan kotormu, namun cukuplah ucapan kotormu sekarang cukuplah sebagai pembalasan budi baikmu yang belum terbalaskan.\" Selanjutnya Urwah berusaha ingin menarik jenggot Rasulullah Shallallahu'alaihiwasallam yang ketika itu Mughirah bin Syu'bah berdiri diatas kepala Rasulullah Shallallahu'alaihiwasallam dengan berbaju besi yang menutup seluruh tubuhnya. Kata Marwan atau Miswar, Mughirah seketika itu juga memukul tangan 'Urwah bin mas'ud agar jangan sampai menarik jenggot Rasul. Mughirah katakan \" Heih, tahan tanganmu dari jenggot Rasulullah Shallallahu'alaihiwasallam, demi Allah, tanganmu tak bakalan bisa meraih jenggotnya! 'Urwah menjawab \"Huss, alangkah jahat dan kasarnya engkau! Rasulullah Shallallahu'alaihiwasallam pun tersenyum. Urwah bertanya \"Siapa ini ya Muhammad! Rasul menjawab \"Ini anak saudaramu,. Mughirah bin Syu'bah. Kata 'Urwah \" Pengkhianatan apa lagi ini, engkau tidak menghapus kesalahanmu masa lalu selain baru kemaren?! Kemudian Rasulullah sampaikan kepada 'Urwah bin mas'ud sebagaimana yang telah ia konsultasikan terlebih dahulu kepada para sahabatnya. Dan Rasul beritahukan bahwa beliau tidak berambisi berperang. Kata Marwan atau Miswar, kemudian Urwah tinggalkan Rasulullah Shallallahu'alaihiwasallam, dan ia lihat perlakuan para sahabatnya terhadap beliau. Tidaklah Rasulullah berwudhu, selain para sahabatnya berebutan memperoleh sisa air wudhunya, dan tidaklah Rasulullah meludah selain mereka juga berebutan untuk memperoleh sisa ludahnya. Tidaklah rambut rasululah terjatuh selain mereka mengambilnya. Urwah kontan kembali menemui quraisy dan berujar \"Wahai segenap quraisy, aku pernah menemui Kisra dalam kerajaannya, dan juga pernah kudatangi Kaisar dan Najasyi dalam dua kerajaannya. Demi Allah, sama sekali belum pernah kulihat raja seorang pun yang seperti Muhammad di kalangan sahabat-shaabatnya. Telah kulihat sebuah kaum yang mereka tidak menyerahkannya kepada apapun selama-lamanya. Maka sekarang keluarkanlah saran dan ide kalian. Kata Marwan atau Miswar, sebelum itu Rasulullah Shallallahu'alaihiwasallam telah mengirim Khirasy bin Umayyah alkhuza'i ke Makkah dan beliau berikan kendaraan untanya yang seringkali dijuluki Tsa'lab. Ketika Khirasy bin Umayyah masuk Makkah, Quraisy membantai untanya dan ingin membantai Khirasy, namun sekutu-sekutu Quraisy mencegahnya hingga Khirasy datangi Rasulullah Shallallahu'alaihiwasallam, lantas Rasulullah panggil 'Umar untuk beliau utus ke Makkah. 'Umar menampik seraya mengatakan \"Wahai Rasulullah, saya khawatir Quraisy akan mencelakai diriku, sementara disana tidak ada seorang pun dari bani Adi yang membelaku, dan semua quraisy tahu permusuhanku terhadapnya dan kekasaranku kepadanya, namun baiklah kutunjukkan kepadamu seseorang yang lebih kuat daripadaku, yaitu Usman bin Affan.\" Kemudian Rasulullah Shallallahu'alaihiwasallam panggil Usman bin Affan, dan beliau utus ke Quraisy dengan misi memberitahu mereka bahwa kedatangan Nabi bukan untuk menyalakan perang, hanyasanya tujuannya sekedar mengunjungi baitullah, mengagungkan kehormatannya. Usman terus berangkat hingga beliau datangi Makkah, dan Usman dicegat oleh Abban bin Sa'id bin 'Ash. Usman turun dari untanya. Abban bin Sa'id menaikkan Usman keatas untanya, dan ia dudukkan didepannya sedang ia sendiri membonceng di belakangnya dan melindunginya, hingga 'Usman bisa menyampaikan surat Rasulullah Shallallahu'alaihiwasallam. Usman terus berangkat hingga ia temui Abu Sofyan dan pejabat-pejabat elit quraisy. Ia sampaikan semua misi pengutusannya dari Rasulullah Shallallahu'alaihiwasallam. Mereka katakan kepada Usman \"Kalaulah engkau berkenan, silahkan engkau thawaf di baitullah. Usman hanya menjawab \"Saya tak akan melakukan thawaf sampai Rasulullah Shallallahu'alaihiwasallam melakukan tawaf.\" Quraisy kemudian menahan Usman di baitullah, namun Rasulullah dan para sahabatnya keburu mendapat issue (alias hanya ghosip) bahwa Usman telah dibunuh. Kata Muhammad, telah menceritakan kepadaku Azzuhri, Quraisy mengutus Suhail bin Amru dan salah seorang bani 'Amir bin Lu'ay seraya mereka pesankan \"Tolong kalian berdua datangilah Muhammad dan ajaklah untuk berdamai. Dan jangan sampai terjadi dalam perdamaiannya selain ia harus pulang untuk tahun ini, demi Allah, jangan sampai bangsa arab berujar bahwa Rasulullah bisa menemui kita secara paksa selama-lamanya! Suhail kemudian mendatangi Nabi, ketika Nabi Shallallahu'alaihiwasallam melihatnya, Nabi berkomentar \"Quraisy rupanya ingin berdamai ketika mengutus si laki-laki ini! Sesampai Suhail di hadapan Rasulullah Shallallahu'alaihiwasallam, Suhail dan kawannya berbicara, mengajak diskusi yang sedemikian lama dan berlangsung alot hingga terjadi perdamaian diantara keduanya. Setelah terjadi titik kesepakatan dan hanya tinggal penulisan, Umar bin Khattab berlari dan ia datangi Abu bakar seraya berujar \"Wahai Abu bakar, bukankah dia itu Rasulullah Shallallahu'alaihiwasallam? Bukankah kita muslimin? Bukankah mereka musyrikin? Abu bakar hanya menjawab \"Benar.\" Kata Umar \"Lantas karena alasan apa kita memberi kehinaan terhadap agama kita?!\" Abu bakar menjawab \"Wahai Umar, jagalah kayu tunggangannya sebagaimana apa adanya, karena saya bersaksi bahwa ia adalah Rasulullah Shallallahu'alaihiwasallam. Kata Umar \"Kalau masalah bersaksi, aku juga bersaksi!.\" Rasulullah Shallallahu'alaihiwasallam kemudian datang, lantas Umar menyatakan protesnya sevara vulgar \"Wahai Rasulullah, bukankah kita muslimin dan mereka musyrikin?\"Benar\" Jawab Rasulullah.\" Lanjut Umar \" lalu mengapa kita kita berikan kehinaan terhadap agama kita? Nabi hanya menjawab \"Ingat, saya adalah hamba Allah dan Rasul-Nya, sekali-kali aku tak bakalan menyelisihi perintah-Nya, dan sekali-kali Allah tak bakalan menelantarkan keadaanku.\" Kemudian hari Umar katakan, \"Aku tidak berhenti melakukan puasa dan bersedekah, shalat dan membebaskan budak untuk menebus kesembronoanku terhadap Rasulullah, tepatnya karena ketakutanku terhadap ucapanku yang kuucapkan ketika itu, hingga aku berharap semua itu membawa kebaikan. Kata Miswar atau Marwan, Rasulullah Shallallahu'alaihiwasallam lalu memanggil Ali bin Abi Thalib dan Rasulullah Shallallahu'alaihiwasallam katakana \"Coba kamu tulis Bismillaahirrohmaanirrohiim.\" Suhail memprotes seraya ia katakan \"Saya tidak tahu kalimat ini, namun ucapkanlah Alloohumma.\" Rasulullah pun mengucapkan \"Yah, tulis saja Bismikalloohumma, inilah perjanjian damai yang ditetapkan Rasulullah untuk Suhail bin Amru.\" Suhail protes lagi seraya mengatakan \"Kalaulah aku bersaksi bahwa engkau adalah Rasulullah, niscaya aku tidak akan memerangimu, namun tulis saja Ini perjanjian yang ditetapkan Muhammad bin Abdullah dan Suhail bin Amru untuk menghentikan perang selama sepuluh tahun. Selama sepuluh tahun itu manusia aman dan satu sama lain saling menahan diri. Siapa saja yang menemui Rasulullah Shallallahu'alaihiwasallam dari sahabat Suhail dengan tanpa seijin walinya, maka Rasulullah wajib mengembalikan kepada mereka. Sebaliknya siapa saja yang menemui Quraisy dari sahabat Rasulullah Shallallahu'alaihiwasallam, maka Quraisy tak berkewajiban mengembalikan kepada mereka. Sesama kita (Quraisy dan muslimin) harus melupakan balas dendam yang terjadi masa lalu yang bisa menyulutkan perang, juga tidak ada pencurian, tak ada pengkhianatan. Dalam syarat mereka ketika penulisan dilangsungkan juga disetujui, siapa yang ingin memihak akad Muhammad dan janjinya, maka ia bersama Muhammad, dan barangsiapa memihak akad quraisy dan janji mereka, ia bersama quraisy. Serta merta Bani khuza'ah datang dan berujar \"Kami memihak akad Rasulullah Shallallahu'alaihiwasallam dan janjinya.\" Sedang banu Bakar bergegas datang dan berujar \"Adapun kami akan memihak akad quraisy dan janji mereka.\" Dan engkau (Muhammad) tidak berhak memasuki baitullah tahun ini, maka janganlah menemui kami (Quraisy Makkah), adapun tahun depan kami (Quraisy) mengosongkan Mekkah untuk anda (Muhammad) sehingga engkau bisa memasuki Makkah bersama sahabatmu dan tinggal disana selama tiga hari saja, engkau (Muhammad) boleh membawa senjata sebatas senjata pengendara, maksudnya selain pedang itupun harus disarungkan. Ketika Rasulullah Shallallahu'alaihiwasallam melangsungkan penulisan, tiba-tiba Abu jandal bin Suhail bin Amru datang dengan terantai besi, ia melarikan diri kepada Rasulullah Shallallahu'alaihiwasallam. Kata Marwan atau Miswar, sahabat-sahabat Rasulullah Shallallahu'alaihiwasallam sebelumnya keluar dengan "},"2233":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي عَلِيُّ بْنُ حُسَيْنٍ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أَخَبَرَهُأَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ خَطَبَ ابْنَةَ أَبِي جَهْلٍ وَعِنْدَهُ فَاطِمَةُ ابْنَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا سَمِعَتْ بِذَلِكَ فَاطِمَةُ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ لَهُ إِنَّ قَوْمَكَ يَتَحَدَّثُونَ أَنَّكَ لَا تَغْضَبُ لِبَنَاتِكَ وَهَذَا عَلِيٌّ نَاكِحٌ ابْنَةَ أَبِي جَهْلٍ قَالَ الْمِسْوَرُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَمِعْتُهُ حِينَ تَشَهَّدَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنِّي أَنْكَحْتُ أَبَا الْعَاصِ بْنَ الرَّبِيعِ فَحَدَّثَنِي فَصَدَقَنِي وَإِنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ بَضْعَةٌ مِنِّي وَأَنَا أَكْرَهُ أَنْ تَفْتِنُوهَا وَإِنَّهَا وَاللَّهِ لَا تَجْتَمِعُ ابْنَةُ رَسُولِ اللَّهِ وَابْنَةُ عَدُوِّ اللَّهِ عِنْدَ رَجُلٍ وَاحِدٍ أَبَدًا قَالَ فَتَرَكَ عَلِيٌّ الْخِطْبَةَ","id":"Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Ali bin Husain] bahwa [Miswar bin Makhramah] telah mengabarkan kepadanya bahwasanya; Ali bin Abu Thalib meminang putri Abu Jahal, sementara di sisinya (isterinya) ada Fathimah putri Nabi shallallahu 'alaihi wasallam. Ketika Fathimah mendengar hal itu, ia langsung mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya kaum Anda tengah berbincang-bincang bahwa Anda tidak marah lantaran putri Anda. Sedangkan Ali hendak menikahi putri Abu Jahal.\" Miswar berkata; Maka Nabi shallallahu 'alaihi wasallam berdiri dan saya mendengarnya ketika beliau bersyahadat kemudian beliau bersabda: \"Amma ba'du, saya telah menikahkan Abul Ash bin Rabi', lalu ia bercerita kepadaku dan membenarkanku. Dan sesungguhnya Fathimah binti Muhammad adalah bagian dariku, dan saya benci jika kalian berbuat fitnah atasnya. Demi Allah, putri Rasulullah tidak akan berkumpul dengan putri mush Allah pada seorang laki-laki selama-lamanya.\" (Miswar) Berkata; Maka Ali pun meninggalkan pinangan itu."},"2234":{"ar":"حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنِ الْوَلِيدِ بْنِ كَثِيرٍ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ حَلْحَلَةَ الدُّؤَلِيُّ أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ أَنَّ عَلِيَّ بْنَ الْحُسَيْنِ حَدَّثَهُأَنَّهُمْ حِينَ قَدِمُوا الْمَدِينَةَ مِنْ عِنْدِ يَزِيدَ بْنِ مُعَاوِيَةَ مَقْتَلَ حُسَيْنِ بْنِ عَلِيٍّ لَقِيَهُ الْمِسْوَرُ بْنُ مَخْرَمَةَ فَقَالَ هَلْ لَكَ إِلَيَّ مِنْ حَاجَةٍ تَأْمُرُنِي بِهَا قَالَ فَقُلْتُ لَهُ لَا قَالَ لَهُ هَلْ أَنْتَ مُعْطِيَّ سَيْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنِّي أَخَافُ أَنْ يَغْلِبَكَ الْقَوْمُ عَلَيْهِ وَأَيْمُ اللَّهِ لَئِنْ أَعْطَيْتَنِيهِ لَا يُخْلَصُ إِلَيْهِ أَبَدًا حَتَّى تَبْلُغَ نَفْسِي إِنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ خَطَبَ ابْنَةَ أَبِي جَهْلٍ عَلَى فَاطِمَةَ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ النَّاسَ فِي ذَلِكَ عَلَى مِنْبَرِهِ هَذَا وَأَنَا يَوْمَئِذٍ مُحْتَلِمٌ فَقَالَ إِنَّ فَاطِمَةَ بَضْعَةٌ مِنِّي وَأَنَا أَتَخَوَّفُ أَنْ تُفْتَنَ فِي دِينِهَا قَالَ ثُمَّ ذَكَرَ صِهْرًا لَهُ مِنْ بَنِي عَبْدِ شَمْسٍ فَأَثْنَى عَلَيْهِ فِي مُصَاهَرَتِهِ إِيَّاهُ فَأَحْسَنَ قَالَ حَدَّثَنِي فَصَدَقَنِي وَوَعَدَنِي فَوَفَى لِي وَإِنِّي لَسْتُ أُحَرِّمُ حَلَالًا وَلَا أُحِلُّ حَرَامًا وَلَكِنْ وَاللَّهِ لَا تَجْتَمِعُ ابْنَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَابْنَةُ عَدُوِّ اللَّهِ مَكَانًا وَاحِدًا أَبَدًا","id":"Telah menceritakan kepada kami [Ya'qub] yakni Ibnu Ibrahim, Telah menceritakan kepada kami [bapakku] dari [Al Walid bin Katsir] telah menceritakan kepadaku [Muhammad bin Amru bin Halhalah Ad Du`ali] bahwa [Ibnu Syihab] telah menceritakan kepadanya bahwa [Ali bin Husain] telah menceritakan kepadanya, bahwasanya; Ketika mereka mendatangi kota Madinah dari sisi Yazid bin Mu'awiyah Maqtal (tempat dibunuhnya) Husain bin Ali, [Miswar bin Makhramah] menemuinya dan bertanya, \"Apakah Anda ada perlu denganku, atau keperluan yang Anda perintahkan padaku?\" (Ali bin Husain) Berkata; Saya menjawab, \"Tidak.\" Miswar bertanya lagi, \"Apakah Anda yang memberi pedang Rasulullah shallallahu 'alaihi wasallam? Saya khawatir, kaum itu akan mengalahkanku dan menguasainya. Demi Allah, sekiranya kamu memberikannya padaku, maka tidak akan ada yang sampai padanya selama-lamanya hingga diriku beranjak dewasa. Sesungguhnya Ali bin Abu Thalib telah meminang putri Abu Jahal (untuk memadu) Fathimah. Maka saya mendengar Rasulullah shallallahu 'alaihi wasallam menyampaikan khutbah kepada manusian di atas mimbar terkait dengan persoalan itu. Saat itu, saya adalah seorang yang muhtalim (baru menginjak masa aqil baligh). Beliau bersabda: \"Fathimah adalah bagian dari diriku, dan saya mengkhawatirkan akan terjadi fitnah terkait dengan agamanya.\" Kemudian beliau menyebutkan menyebutkan kerabatnya dari Bani Abdu Syams dan memuji hubungan kekerabatan dengannya. Berliau bersabda: \"Ia telah menceritakan kepadaku, membenarkanku, berjanji padaku, dan ia telah memenuhi janjinya padaku. Sesungguhnya, saya tidaklah mengharamkan yang halal, dan pula mengharamkan yang halal, akan tetapi, demi Allah, tidak akan berkumpul putri Rasulullah shallallahu 'alaihi wasallam dan putri musuh Allah di tempat yang satu selama-lamanya.\""},"2235":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ وَزَعَمَ عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ مَرْوَانَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَخْبَرَاهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ حِينَ جَاءَهُ وَفْدُ هَوَازِنَ مُسْلِمِينَ فَسَأَلُوا أَنْ يَرُدَّ إِلَيْهِمْ أَمْوَالَهُمْ وَسَبْيَهُمْ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعِي مَنْ تَرَوْنَ وَأَحَبُّ الْحَدِيثِ إِلَيَّ أَصْدَقُهُ فَاخْتَارُوا إِحْدَى الطَّائِفَتَيْنِ إِمَّا السَّبْيُ وَإِمَّا الْمَالُ وَقَدْ كُنْتُ اسْتَأْنَيْتُ بِكُمْ وَكَانَ أَنْظَرَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضْعَ عَشْرَةَ لَيْلَةً حِينَ قَفَلَ مِنْ الطَّائِفِ فَلَمَّا تَبَيَّنَ لَهُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ رَادٍّ إِلَيْهِمْ إِلَّا إِحْدَى الطَّائِفَتَيْنِ قَالُوا فَإِنَّا نَخْتَارُ سَبْيَنَا فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمُسْلِمِينَ فَأَثْنَى عَلَى اللَّهِ عَزَّ وَجَلَّ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ إِخْوَانَكُمْ قَدْ جَاءُوا تَائِبِينَ وَإِنِّي قَدْ رَأَيْتُ أَنْ أَرُدَّ إِلَيْهِمْ سَبْيَهُمْ فَمَنْ أَحَبَّ مِنْكُمْ أَنْ يُطَيِّبَ ذَلِكَ فَلْيَفْعَلْ وَمَنْ أَحَبَّ مِنْكُمْ أَنْ يَكُونَ عَلَى حَظِّهِ حَتَّى نُعْطِيَهُ إِيَّاهُ مِنْ أَوَّلِ مَا يُفِيءُ اللَّهُ عَزَّ وَجَلَّ عَلَيْنَا فَلْيَفْعَلْ فَقَالَ النَّاسُ قَدْ طَيَّبْنَا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا لَا نَدْرِي مَنْ أَذِنَ مِنْكُمْ فِي ذَلِكَ مِمَّنْ لَمْ يَأْذَنْ فَارْجِعُوا حَتَّى يَرْفَعَ إِلَيْنَا عُرَفَاؤُكُمْ أَمْرَكُمْ فَجَمَعَ النَّاسُ فَكَلَّمَهُمْ عُرَفَاؤُهُمْ ثُمَّ رَجَعُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرُوهُ أَنَّهُمْ قَدْ طَيَّبُوا وَأَذِنُوا هَذَا الَّذِي بَلَغَنِي عَنْ سَبْيِ هَوَازِنَ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [Ibnu Akhi bin Syihab] dari [pamannya] ia berkata, [Urwah bin Zubair] telah berdalih bahwa [Marwan] dan [Miswar bin Makhramah] telah mengabarkan kepadanya, bahwasanya; Rasulullah shallallahu 'alaihi wasallam berdiri ketika utusan Hawazin mendatanginya dalam keadaan telah memeluk Islam. Kemudian mereka meminta agar harta dan para tawanan (wanita dan anak-anak) mereka dibebaskan dan dikembalikan. Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka: \"Kalau aku, terserah pendapat kalian. perkataan yang paling aku sukai adalah perkataan yang paling benar. Maka pilihlah salah satu dari dua hal, imma As Sabyu (tawanan para wanita dan anak-anak) ataukah harta. Dan saya tidak memaksa (kalian untuk memutuskannya) dengan segera.\" Rasulullah shallallahu 'alaihi wasallam memberi waktu kepada mereka selama sepuluh malam lebih saat beliau kembali dari Tha`if. Ketika telah jelas bagi mereka bahwa Rasulullah shallallahu 'alaihi wasallam tidak ridla kecuali salah satu dari dua hal itu, mereka pun berkata, \"Kami lebih memilih para tawanan wanita dan anak-anak kami (untuk dikembalikan).\" Rasulullah shallallahu 'alaihi wasallam berdiri di hadapan kaum muslimin, beliau memuji Allah 'azza wajalla dengan pujian yang memang layak untuk-Nya. Kemudian beliau bersabda: \"Amma ba'du. Sesungguhnya saudara kalian telah datang dengan bertaubat. Dan saya berpendapat untuk mengembalikan para tawanan wanita dan anak-anak kepada mereka. karena itu, siapa diantara kalian yang merelakan hal itu, maka hendaklah ia melakukannya. Dan siapa di antara kalian yang lebih memilih untuk mengambil bagiannya dari Fai` yang telah diberikan Allah, hendaknya ia juga melakukannya.\" Kemudian kaum muslimin pun berkata, \"Kami telah merelakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kami tidak tahu, siapa di antara kalian yang merelakannya dan siapa pula yang tidak merelakannya. Karena itu, pulanglah kalian hingga orang-orang 'arif kalian menyerahkan urusan itu kepada kami.\" Maka kaum muslimin pun berkumpul dan bermusyawarah dengan orang-orang arif mereka. setelah itu, mereka kembali kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau bahwa mereka telah merelakan dan mengizinkannya. Inilah yang sampai padaku mengenai tawanan wanita dan anak-anak Hawazin."},"2236":{"ar":"حَدَّثَنَا رَوْحٌ قَالَ ثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ أخْبَرَهُ قَالَ وَثَنَا إِسْحَاقُ يَعْنِي ابْنَ الطَّبَّاعِ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنِ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ سُبَيْعَةَ الْأَسْلَمِيَّةَ نُفِسَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِلَيَالٍ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ حَلَلْتِ فَانْكِحِي","id":"Telah menceritakan kepada kami [Rauh] ia berkata, Telah menceritakan kepada kami [Malik bin Anas] dari [Hisyam bin Urwah] dari [bapaknya] bahwa [Miswar bin Makhramah] -dalam riwayat lain- (Imam Ahmad) Berkata, dan Telah menceritakan kepada kami [Ishaq] yakni Ibnu Thabba', ia berkata, telah mengabarkan kepadaku [Malik] dari [Hisyam] dari [bapaknya] dari [Miswar bin Makhramah] bahwasanya Subai'ah Al Aslamiyyah melahirkan setelah beberapa malam dari kematian suaminya, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Kamu telah halal, silahkan menikah.\""},"2237":{"ar":"حَدَّثَنَا حَمَّادُ بْنُ أُسَامَةَ أَخْبَرَنَا هِشَامٌ عَنْ أَبِيهِ عَنِ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ سُبَيْعَةَ الْأَسْلَمِيَّةَ تُوُفِّيَ عَنْهَا زَوْجُهَا وَهِيَ حَامِلٌ فَلَمْ تَمْكُثْ إِلَّا لَيَالِيَ حَتَّى وَضَعَتْ فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا خُطِبَتْ فَاسْتَأْذَنَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي النِّكَاحِ فَأَذِنَ لَهَا أَنْ تَنْكِحَ فَنَكَحَتْحَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَاصِمِ بْنِ عُمَرَ عَنِ الْمِسْوَرِ بْنِ مَخْرَمَةَ قَالَ وَضَعَتْ سُبَيْعَةُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Hammad bin Usamah] telah mengabarkan kepada kami [Hisyam] dari [bapaknya] dari [Miswar bin Makhramah] bahwa Subai'ah Al Aslamiyyah ditinggal mati oleh suaminya sedangkan ia dalam keadaan hamil. Selang beberapa malam kemudian, ia melahirkan. Dan setelah suci dari nifasnya, ia dipinang. Maka ia pun meminta izin kepada Nabi shallallahu 'alaihi wasallam untuk menikah dan beliau mengizinkannya. Akhirnya, ia pun menikah. Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Ashim bin Umar] dari [Miswar bin Makhramah] ia berkata; Subai'ah melahirkan. Maka ia pun menyebutkan hadits."},"2238":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَوْفِ بْنِ الْحَارِثِ وَهُوَ ابْنُ أَخِي عَائِشَةَ لِأُمِّهَا أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِ قَالَ فِي بَيْعٍ أَوْ عَطَاءٍ أَعْطَتْهُ وَاللَّهِ لَتَنْتَهِيَنَّ عَائِشَةُ أَوَ لَأَحْجُرَنَّ عَلَيْهَا فَقَالَتْ عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا أَوَقَالَ هَذَا قَالُوا نَعَمْ قَالَتْ هُوَ لِلَّهِ عَلَيَّ نَذْرٌ أَنْ لَا أُكَلِّمَ ابْنَ الزُّبَيْرِ كَلِمَةً أَبَدًا فَاسْتَشْفَعَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ وَهُمَا مِنْ بَنِي زُهْرَةَ فَذَكَرَ الْحَدِيثَ وَطَفِقَ الْمِسْوَرُ وَعَبْدُ الرَّحْمَنِ يُنَاشِدَانِ عَائِشَةَ إِلَّا كَلَّمَتْهُ وَقَبِلَتْ مِنْهُ وَيَقُولَانِ لَهَا إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَى عَمَّا قَدْ عَلِمْتِ مِنْ الْهَجْرِ إِنَّهُ لَا يَحِلُّ لِمُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثِ لَيَالٍحَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنِ الطُّفَيْلِ بْنِ الْحَارِثِ وَكَانَ رَجُلًا مِنْ أَزْدِ شَنُوءَةَ وَكَانَ أَخًا لِعَائِشَةَ لِأُمِّهَا أُمِّ رُومَانَ فَذَكَرَ الْحَدِيثَ فَاسْتَعَانَ عَلَيْهَا بِالْمِسْوَرِ بْنِ مَخْرَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ بْنِ عَبْدِ يَغُوثَ فَاسْتَأْذَنَا عَلَيْهَا فَأَذِنَتْ لَهُمَا فَكَلَّمَاهَا وَنَاشَدَاهَا اللَّهَ وَالْقَرَابَةَ وَقَوْلَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ لِامْرِئٍ مُسْلِمٍ أَنْ يَهْجُرَ أَخَاهُ فَوْقَ ثَلَاثٍ حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنِ الزُّهْرِيِّ حَدَّثَنِي عَوْفُ بْنُ الْحَارِثِ بْنِ الطُّفَيْلِ وَهُوَ ابْنُ أَخِي عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُمِّهَا أَنَّ عَائِشَةَ حَدَّثَتْهُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Auf bin Harits] -ia adalah anak dari saudara Aisyah seibu- bahwa [Aisyah] telah menceritakan kepadanya, bahwa Abdullah bin Zubair berkata terkait dengan penjualan atau pemberian yang telah diberikannya oleh Aisyah, \"Aisyah benar-benar mau berhenti (melakukannya) ataukah saya benar-benar akan mendiamkannya.\" Aisyah bertanya, \"Apakah ia benar-benar mengatakan hal ini?\" mereka menjawab, \"Ya.\" Aisyah berkata, \"Hal itu, karena aku mempunyai tanggungan nadzar kepada Allah, yaitu aku tidak akan berbicara sepatah kata pun dengan Ibnu Zubair selama-lamanya.\" Maka Abdullah bin Zubair meminta bantuan Miswar bin Makhramah dan Abdurrahman bin Aswad bin Abdu Yaghuts, keduanya adalah dari Bani Zuhrah. Ia pun menyebutkan hadits. [Miswar] dan [Abdurrahman] mulai berbicara dengan Aisyah, ia pun menerimanya. Mereka berdua berkata kepadanya, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang dari sesuatu yang telah Anda ketahui, yaitu Al Hajr. Sesungguhnya tidak halal bagi seorang muslim, untuk mendiamkan saudaranya lebih dari tiga malam.\" Telah menceritakan kepada kami [Al Walid bin Muslim] Telah menceritakan kepada kami [Al Auza'i] Telah menceritakan kepada kami [Az Zuhri] dari [Thufail bin Harits] -ia adalah seorang yang berasal dari Azd Syanu`ah, dan ia juga saudara seibu Aisyah yaitu Ummu Rumman. Maka ia pun menyebutkan hadits. Maka ia meminta bantuan kepada [Miswar bin Makhramah] dan [Abdurrahman bin Al Aswad bin Abd Yaghuts]. Kemudian keduanya meminta izin kepada Aisyah, dan Aisyah pun mengizinkan mereka berdua. Keduanya pun berbicara kepada Aisyah dan bersumpah dengan nama Allah, serta mengingatkan akan sabda Rasulullah shallallahu 'alaihi wasallam, \"Tidak halal bagi seorang muslim untuk mendiamkan saudaranya lebih dari tiga hari.\" Telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah menceritakan kepadaku ['Auf bin Harits bin Thufail] -ia adalah anak dari saudara Aisyah isteri Nabi shallallahu 'alaihi wasallam seibu- bahwa Aisyah telah menceritakan kepadanya. lalu ia menyebutkan hadits."},"2239":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنِ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ مَرْوَانَ وَالْمِسْوَرِ بْنِ مَخْرَمَةَ يَزِيدُ أَحَدُهُمَا عَلَى صَاحِبِهِخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْحُدَيْبِيَةِ فِي بِضْعَ عَشْرَةَ مِائَةً مِنْ أَصْحَابِهِ فَلَمَّا كَانَ بِذِي الْحُلَيْفَةِ قَلَّدَ الْهَدْيَ وَأَشْعَرَ وَأَحْرَمَ مِنْهَا وَقَالَ سُفْيَانُ مَرَّةً مِنْ عُمْرَةٍ وَلَمْ يُسَمِّ الْمِسْوَرَ وَبَعَثَ عَيْنًا لَهُ بَيْنَ يَدَيْهِ فَسَارَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Urwah bin Zubair] dari [Marwan] dan [Miswar bin Makhramah] -salah seorang dari keduanya menambah atas temannya- Pada tahun Hudaibiyah, Rasulullah shallallahu 'alaihi wasallam keluar bersama seratus sepuluh lebih dari sahabatnya. Ketika beliau sampai di Dzul Hulaifah, beliau mulai menuntun Hadyu (hewan kurban) dan memberinya tanda serta beliau memulai ihram dari tempat itu. Sekali waktu Sufyan mengatakan; (Beliau melakukan ihram dengan niat) Umrah -sementara Miswar tidak menyebutkannya- kemudian beliau mengutus mata-matanya. Dan Rasulullah shallallahu 'alaihi wasallam terus berjalan hingga.."},"2240":{"ar":"حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ لَيْثٌ يَعْنِي ابْنَ سَعْدٍ حَدَّثَنِي بَكْرٌ يَعْنِي ابْنَ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ نَابِلٍ صَاحِبِ الْعَبَاءِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ صُهَيْبٍ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُقَالَ مَرَرْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَسَلَّمْتُ فَرَدَّ إِلَيَّ إِشَارَةً وَقَالَ لَا أَعْلَمُ إِلَّا أَنَّهُ قَالَ إِشَارَةً بِإِصْبَعِهِ","id":"Telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata, [Laits] yakni Ibnu Sa'd berkata, telah menceritakan kepadaku [Bakr bin Abdullah bin Al Asyaj] dari [Nabl Shahibil Aba] dari [Abdullah bin Umar] dari [Shuhaib] salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam, bahwa ia berkata; Suatu ketika saya melewati Rasulullah shallallahu 'alaihi wasallam yang saat itu sedang shalat, lalu saya mengucapkan salam, maka beliau membalasnya dengan isyarat. (Abdullah bin Umar) Berkata; Saya tidak tahu kecuali mengatakan; \"Isyarat dengan jari tangannya.\""},"2241":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ عَنِ الْحَسَنِ بْنِ مُحَمَّدٍ الْأَنْصَارِيِّ قَالَ حَدَّثَنِي رَجُلٌ مَنْ النَّمِرِ بْنِ قَاسِطٍ قَالَ سَمِعْتُ صُهَيْبَ بْنَ سِنَانٍ يُحَدِّثُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا رَجُلٍ أَصْدَقَ امْرَأَةً صَدَاقًا وَاللَّهُ يَعْلَمُ أَنَّهُ لَا يُرِيدُ أَدَاءَهُ إِلَيْهَا فَغَرَّهَا بِاللَّهِ وَاسْتَحَلَّ فَرْجَهَا بِالْبَاطِلِ لَقِيَ اللَّهَ يَوْمَ يَلْقَاهُ وَهُوَ زَانٍ وَأَيُّمَا رَجُلٍ ادَّانَ مِنْ رَجُلٍ دَيْنًا وَاللَّهُ يَعْلَمُ أَنَّهُ لَا يُرِيدُ أَدَاءَهُ إِلَيْهِ فَغَرَّهُ بِاللَّهِ وَاسْتَحَلَّ مَالَهُ بِالْبَاطِلِ لَقِيَ اللَّهَ عَزَّ وَجَلَّ يَوْمَ يَلْقَاهُ وَهُوَ سَارِقٌ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abdul Hamid bin Ja'far] dari [Al Hasan bin Muhammad Al Anshari] ia berkata, telah menceritakan kepadaku [seorang laki-laki] dari Namr bin Qasith, ia berkata, saya mendengar [Shuhaib bin Sinan] menceritakan, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa saja laki-laki yang memberikan mahar kepada seorang wanita, sedangkan Allah mengetahui bahwa ia (bermaksud) tidak akan menyerahkannya sehingga ia meniupnya dengan nama Allah dan menghalalkan kemaluannya dengan batil, maka laki-laki itu akan menjumpai Allah kelak pada hari kiamat sebagai orang yang berzina. Dan siapa saja laki-laki yang berhutang dari seseorang, sedang Allah mengetahui bahwa ia tidak bermaksud untuk melunasinya, dan ia meniupnya dengan nama Allah dan menggalalkan hartanya dengan batil, maka ia akan menemui Allah sebagai seorang pencuri.\""},"2242":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَرِّكُ شَفَتَيْهِ أَيَّامَ حُنَيْنٍ بِشَيْءٍ لَمْ يَكُنْ يَفْعَلُهُ قَبْلَ ذَلِكَ قَالَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ نَبِيًّا كَانَ فِيمَنْ كَانَ قَبْلَكُمْ أَعْجَبَتْهُ أُمَّتُهُ فَقَالَ لَنْ يَرُومَ هَؤُلَاءِ شَيْءٌ فَأَوْحَى اللَّهُ إِلَيْهِ أَنْ خَيِّرْهُمْ بَيْنَ إِحْدَى ثَلَاثٍ إِمَّا أَنْ أُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ فَيَسْتَبِيحَهُمْ أَوْ الْجُوعَ أَوْ الْمَوْتَ قَالَ فَقَالُوا أَمَّا الْقَتْلُ أَوْ الْجُوعُ فَلَا طَاقَةَ لَنَا بِهِ وَلَكِنْ الْمَوْتُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَاتَ فِي ثَلَاثٍ سَبْعُونَ أَلْفًا قَالَ فَقَالَ فَأَنَا أَقُولُ الْآنَ اللَّهُمَّ بِكَ أُحَاوِلُ وَبِكَ أَصُولُ وَبِكَ أُقَاتِلُ","id":"Telah menceritakan kepada kami [Waki'] dari [Hammad bin Salamah] dari [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam menggerakkan kedua bibirinya dengan sesuatu yang belum pernah beliau lakukan sebelumnya. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhya ada seorang Nabi sebelum masa kalian yang terkagum-kagum akan banyaknya umatnya, sehingga ia pun berkata, 'Mereka ini tidak akan lagi terkalah oleh sesuatu pun.' Akhirnya Allah mewahyuhkan padanya, 'Hendaknya kamu memilih salah satu dari tiga hal yaitu; mereka dikalahkan oleh musuh dari selain golongan mereka dan membinasakan mereka. Atau (mereka ditimpa) kelaparan, ataukah kematian yang akan menjemput mereka.' Maka umat sang Nabi itu pun berkata, 'Kalau musuh, maka tidak ada ketaatan kami terhadap mereka. Adapun kelaparan, maka kami tidak akan sabar atasnya. Akan tetapi (biarlah kami dijemput) oleh kematian.'\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka dalam waktu tiga hari, telah meninggal dari mereka sebanyak tujuh puluh ribu orang.\" Beliau bersabda lagi: \"Maka sekarang aku akan berdo'a, 'ALLAHUMMA BIKA UHAAWIL WABIKA ASHUULU WABIKA UQAATIL (Ya Allah, kepada-Mulah kuserahkan segala daya dan upaya, dengan-Mulah kami menyerang, dan dengan (kekuatan-Mulah) kami berperang).'\""},"2243":{"ar":"حَدَّثَنَا بَهْزٌ وَحَجَّاجٌ قَالَا ثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِبْتُ مِنْ أَمْرِ الْمُؤْمِنِ إِنَّ أَمْرَ الْمُؤْمِنِ كُلَّهُ لَهُ خَيْرٌ وَلَيْسَ ذَلِكَ لِأَحَدٍ إِلَّا لِلْمُؤْمِنِ إِنْ أَصَابَتْهُ سَرَّاءُ شَكَرَ كَانَ ذَلِكَ لَهُ خَيْرًا وَإِنْ أَصَابَتْهُ ضَرَّاءُ فَصَبَرَ كَانَ ذَلِكَ لَهُ خَيْرًا","id":"Telah menceritakan kepada kami [Bahz] dan [Hajjaj] keduanya berkata, Telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya terkagum akan perkara seorang mukmin. Sesungguhnya seluruh perkara orang mukmin itu adalah baik baginya, dan keadaan itu tidak ada pada seorang pun kecuali pada orang mukmin. Jika ia mendapatkan kemudahan, maka ia bersyukur, dan hal itu adalah kebaikan baginya. Dan jika ia tertimpa kesempitan, maka ia akan bersabar, dan hal itu juga merupakan kebaikan baginya.\""},"2244":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ نُودُوا يَا أَهْلَ الْجَنَّةِ إِنَّ لَكُمْ مَوْعِدًا عِنْدَ اللَّهِ لَمْ تَرَوْهُ فَقَالُوا وَمَا هُوَ أَلَمْ تُبَيِّضْ وُجُوهَنَا وَتُزَحْزِحْنَا عَنْ النَّارِ وَتُدْخِلْنَا الْجَنَّةَ قَالَ فَيُكْشَفُ الْحِجَابُ فَيَنْظُرُونَ إِلَيْهِ فَوَاللَّهِ مَا أَعْطَاهُمْ اللَّهُ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْهُ ثُمَّ تَلَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit Al Banani] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika penghuni surga telah memasuki surga, maka mereka akan diseru, 'Wahai penduduk surga, sesungguhnya kalian masih memiliki janji di sisi Allah yang belum kalian lihat.' Mereka bertanya, 'Janji apakah itu? bukankah wajah kami telah diberi cahanya, kami dibebaskan dari api nereka dan dimasukkan ke dalam surga? ' kemudian hijab pun disingkap hingga mereka pun melihat (wajah-Nya). Maka Demi Allah, tidak sesuatu pun yang telah diberikan Allah kepada mereka yang lebih mereka cintai dari pada hal itu.\" kemudian Rasulullah shallallahu 'alaihi wasallam membaca ayat: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya.\""},"2245":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ نُودُوا يَا أَهْلَ الْجَنَّةِ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا فَقَالُوا أَلَمْ يُثَقِّلْ مَوَازِينَنَا وَيُعْطِينَا كُتُبَنَا بِأَيْمَانِنَا وَيُدْخِلْنَا الْجَنَّةَ وَيُنْجِينَا مِنْ النَّارِ فَيُكْشَفُ الْحِجَابُ قَالَ فَيَتَجَلَّى اللَّهُ عَزَّ وَجَلَّ لَهُمْ قَالَ فَمَا أَعْطَاهُمْ اللَّهُ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْ النَّظَرِ إِلَيْهِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika penghuni surga telah memasuki surga, maka mereka akan diseru, 'Wahai penduduk surga, sesungguhnya kalian masih memiliki janji di sisi Allah yang belum kalian lihat.' Mereka bertanya, 'Janji apakah itu? bukankah timbangan kami telah diberatkan, dan kami telah diberikan kitab-kitab kami dengan tangan kanan kami? Dan kami juga dimasukkan ke dalam surga dan diselamatkan dari neraka? ' kemudian hijab pun disingkap hingga Allah menampakkan wajah-Nya bagi mereka. Maka tidak sesuatu pun yang telah diberikan Allah kepada mereka yang lebih mereka cintai dari pada melihat wajah-Nya.\""},"2246":{"ar":"قَالَ حَدَّثَنَا عَفَّانُ مِنْ كِتَابِهِ قَالَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ قَالَ ثَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى هَمَسَ شَيْئًا لَا نَفْهَمُهُ وَلَا يُحَدِّثُنَا بِهِ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطِنْتُمْ لِي قَالَ قَائِلٌ نَعَمْ قَالَ فَإِنِّي قَدْ ذَكَرْتُ نَبِيًّا مِنْ الْأَنْبِيَاءِ أُعْطِيَ جُنُودًا مِنْ قَوْمِهِ فَقَالَ مَنْ يُكَافِئُ هَؤُلَاءِ أَوْ مَنْ يَقُومُ لِهَؤُلَاءِ أَوْ كَلِمَةً شَبِيهَةً بِهَذِهِ شَكَّ سُلَيْمَانُ قَالَ فَأَوْحَى اللَّهُ إِلَيْهِ اخْتَرْ لِقَوْمِكَ بَيْنَ إِحْدَى ثَلَاثٍ إِمَّا أَنْ أُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ أَوْ الْجُوعَ أَوْ الْمَوْتَ قَالَ فَاسْتَشَارَ قَوْمَهُ فِي ذَلِكَ فَقَالُوا أَنْتَ نَبِيُّ اللَّهِ نَكِلُ ذَلِكَ إِلَيْكَ فَخِرْ لَنَا قَالَ فَقَامَ إِلَى صَلَاتِهِ قَالَ وَكَانُوا يَفْزَعُونَ إِذَا فَزِعُوا إِلَى الصَّلَاةِ قَالَ فَصَلَّى قَالَ أَمَّا عَدُوٌّ مِنْ غَيْرِهِمْ فَلَا أَوْ الْجُوعُ فَلَا وَلَكِنْ الْمَوْتُ قَالَ فَسُلِّطَ عَلَيْهِمْ الْمَوْتُ ثَلَاثَةَ أَيَّامٍ فَمَاتَ مِنْهُمْ سَبْعُونَ أَلْفًا فَهَمْسِي الَّذِي تَرَوْنَ أَنِّي أَقُولُ اللَّهُمَّ يَا رَبِّ بِكَ أُقَاتِلُ وَبِكَ أُصَاوِلُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِحَدَّثَنَا عَفَّانُ قَالَ ثَنَا حَمَّادُ بْنُ سَلَمَةَ بِهَذَا الْحَدِيثِ سَوَاءً بِهَذَا الْكَلَامِ كُلِّهِ وَبِهَذَا الْإِسْنَادِ وَلَمْ يَقُلْ فِيهِ كَانُوا إِذَا فَزِعُوا فَزِعُوا إِلَى الصَّلَاةِ","id":"Telah menceritakan kepada kami [Affan] dari kitabnya, katanya, Telah menceritakan kepada kami [Sulaiman] yaitu Ibnul Mughirah, katanya, Telah menceritakan kepada kami [Tsabit] dari [Abdurrahman bin Abi Laila] dari [Shuhaib] katanya, Pernah Rasulullah Shallallahu'alaihiwasallam shalat, dan beliau ucapkan kata-kata samar yang kami tak mendengarnya, dan ucapan samar itu tidak beliau beritakan kepada kami. Katanya, Rasulullah Shallallahu'alaihiwasallam lantas bertanya \"Apakah kalian paham bacaanku? Ada seseorang menjawab 'Benar.\" Kata Nabi, aku ingat seorang nabi yang diberi beberapa tentara dari kaumnya lantas mengatakan, siapa yang bisa menyamai mereka itu? -atau dengan redaksi 'Siapa yang bisa setanding mereka? atau kata-kata yang mirip -Sulaeman ragu kepastian redaksinya-, lantas Allah memberi wahyu kepadanya \"Pilihlah untuk kaummu salah satu diantara tiga, aku kuasakan musuh atas mereka dari selainnya, kelaparan, atau kematian. Kata Nabi, lantas nabi tersebut meminta saran kaumnya dalam hal ini. Mereka menjawab \"Engkau nabiyullah, kami menurut saja kepadamu, maka pilihlah untuk kami! Maka nabi tersebut menuju shalatnya sementara kaumnya dalam keadan panik, tradisi mereka sat itu jika panik, mereka menghampiri shalatnya. Maka nabi itu pun shalat dan berdoa' Adapun musuh dari selain mereka, jangan, adapun kelaparan, juga jangan, namun kematian sajalah!\" Maka mereka kemudian dikuasi oleh kematian selama tiga hari yang menyebabkan tujuh puluh ribu orang meninggal. Maka bicara rahasiaku tadi yang kalian lihat adalah doaku \"Aloohumma rabbi, bika uqaatil, wabika ushoowilu, walaa haula walaa quwwata illa billah (Ya Allah, karena-Mu aku berperang, karena-Mu aku menerjang, tiada daya dan kekuatan selain dengan pertolongan Allah.\" Telah menceritakan kepada kami ['Affan], katanya, Telah menceritakan kepada kami [Hammad bin Salamah] dengan hadis ini dengan redaksi yang sama dan juga dengan isnad ini, hanya tak ada redaksi \"Jika mereka dalam kepanikan, mereka hampiri shalat.\""},"2247":{"ar":"حَدَّثَنَا عَفَّانُ مِنْ كِتَابِهِ حَدَّثَنَا سُلَيْمَانُ حَدَّثَنَا ثَابِتٌ عَنِ ابْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِبْتُ لِأَمْرِ الْمُؤْمِنِ إِنَّ أَمْرَ الْمُؤْمِنِ كُلَّهُ لَهُ خَيْرٌ لَيْسَ ذَلِكَ لِأَحَدٍ إِلَّا لِلْمُؤْمِنِ إِنْ أَصَابَتْهُ سَرَّاءُ شَكَرَ وَكَانَ خَيْرًا وَإِنْ أَصَابَتْهُ ضَرَّاءُ صَبَرَ وَكَانَ خَيْرًا","id":"Telah menceritakan kepada kami ['Affan] dari kitabnya; Telah menceritakan kepada kami [Sulaiman] Telah menceritakan kepada kami [Tsabit] dari [Ibnu Abu Laila] dari [Shuhaib] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya terkagum akan perkara seorang mukmin. Sesungguhnya seluruh perkara orang mukmin itu adalah baik baginya, dan keadaan itu tidak ada pada seorang pun kecuali pada orang mukmin. Jika ia mendapatkan kemudahan, maka ia bersyukur, dan hal itu adalah kebaikan baginya. Dan jika ia tertimpa kesempitan, maka ia akan bersabar, dan hal itu juga merupakan kebaikan baginya.\""},"2248":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ حَدَّثَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ أَيَّامَ حُنَيْنٍ يُحَرِّكُ شَفَتَيْهِ بَعْدَ صَلَاةِ الْفَجْرِ بِشَيْءٍ لَمْ نَكُنْ نَرَاهُ يَفْعَلُهُ فَقُلْنَا يَا رَسُولَ اللَّهِ إِنَّا نَرَاكَ تَفْعَلُ شَيْئًا لَمْ تَكُنْ تَفْعَلُهُ فَمَا هَذَا الَّذِي تُحَرِّكُ شَفَتَيْكَ قَالَ إِنَّ نَبِيًّا فِيمَنْ كَانَ قَبْلَكُمْ أَعْجَبَتْهُ كَثْرَةُ أُمَّتِهِ فَقَالَ لَنْ يَرُومَ هَؤُلَاءِ شَيْءٌ فَأَوْحَى اللَّهُ إِلَيْهِ أَنْ خَيِّرْ أُمَّتَكَ بَيْنَ إِحْدَى ثَلَاثٍ إِمَّا أَنْ نُسَلِّطَ عَلَيْهِمْ عَدُوًّا مِنْ غَيْرِهِمْ فَيَسْتَبِيحَهُمْ أَوْ الْجُوعَ وَإِمَّا أَنْ أُرْسِلَ عَلَيْهِمْ الْمَوْتَ فَشَاوَرَهُمْ فَقَالُوا أَمَّا الْعَدُوُّ فَلَا طَاقَةَ لَنَا بِهِمْ وَأَمَّا الْجُوعُ فَلَا صَبْرَ لَنَا عَلَيْهِ وَلَكِنْ الْمَوْتُ فَأَرْسَلَ عَلَيْهِمْ الْمَوْتَ فَمَاتَ مِنْهُمْ فِي ثَلَاثَةِ أَيَّامٍ سَبْعُونَ أَلْفًا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنَا أَقُولُ الْآنَ حَيْثُ رَأَى كَثْرَتَهُمْ اللَّهُمَّ بِكَ أُحَاوِلُ وَبِكَ أُصَاوِلُ وَبِكَ أُقَاتِلُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hamamd] yakni Ibnu Salamah, Telah menceritakan kepada kami [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] bahwa Rasulullah shallallahu 'alaihi wasallam pada hari Hunain menggerakkan kedua bibirnya setelah menunaikan shalat Fajar, suatu pemandangan yang belum pernah kami lihat sebelumnya. Maka kami berkata, \"Wahai Rasulullah, kami melihat Anda melakukan sesuatu yang belum pernah Anda lakukan sebelumnya. Apa maksud Anda menggerakkan kedua bibir Anda?\" beliau menjawab: \"Sesungguhnya para Nabi sebelum (masa) kalian terkagum-kagum akan banyaknya umatnya. Maka Nabi itu pun berkata, 'Mereka ini tidaklah diinginkan oleh sesuatu pun.' Akhirnya Allah mewahyuhkan padanya, 'Hendaknya kamu memilih salah satu dari tiga hal yaitu; mereka dikalahkan oleh musuh dari selain golongan mereka dan membinasakan mereka. Atau (mereka ditimpa) kelaparan, ataukah kematian yang akan menjemput mereka.' Maka sang Nabi itu pun bermusyawarah dengan mereka. mereka berkata, 'Adapan musuh, maka tidak ada ketaatan kami terhadap mereka. Sedangkan kelaparan, maka kami tidak akan sabar atasnya. Akan tetapi (biarlah kami dijemput) oleh kematian.' Setelah itu, Allah pun mengirimkan kematian atas mereka. Sehingga yang meninggal dari mereka dalam waktu tiga hari mencapai tujuh puluh ribu orang.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maka sekarang aku akan berdo'a -saat melihat banyaknya jumlah mereka-, 'ALLAHUMMA BIKA UHAAWIL WABIKA USHAAWIL WABIKA UQAATIL (Ya Allah, kepada-Mulah kuserahkan segala daya dan upaya, dengan-Mulah kami menyerang, dan dengan (kekuatan-Mulah) kami berperang).'\""},"2249":{"ar":"حَدَّثَنَا عَفَّانُ أَخْبَرَنَا حَمَّادٌ أَخْبَرَنَا ثَابِتٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَلَا هَذِهِ الْآيَةَ{ لِلَّذِينَ أَحْسَنُوا الْحُسْنَى وَزِيَادَةٌ }قَالَ إِذَا دَخَلَ أَهْلُ الْجَنَّةِ الْجَنَّةَ وَأَهْلُ النَّارِ النَّارَ نَادَى مُنَادٍ يَا أَهْلَ الْجَنَّةِ إِنَّ لَكُمْ عِنْدَ اللَّهِ مَوْعِدًا يُرِيدُ أَنْ يُنْجِزَكُمُوهُ فَيَقُولُونَ وَمَا هُوَ أَلَمْ يُثَقِّلْ مَوَازِينَنَا وَيُبَيِّضْ وُجُوهَنَا وَيُدْخِلْنَا الْجَنَّةَ وَيُجِرْنَا مِنْ النَّارِ قَالَ فَيُكْشَفُ لَهُمْ الْحِجَابُ فَيَنْظُرُونَ إِلَيْهِ قَالَ فَوَاللَّهِ مَا أَعْطَاهُمْ شَيْئًا أَحَبَّ إِلَيْهِمْ مِنْ النَّظَرِ إِلَيْهِ وَلَا أَقَرَّ بِأَعْيُنِهِمْ","id":"Telah menceritakan kepada kami ['Affan] telah mengabarkan kepada kami [Hammad] telah mengabarkan kepada kami [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] bahwa Rasulullah shallallahu 'alaihi wasallam membaca ayat ini: \"Bagi orang-orang yang berbuat baik, ada pahala yang terbaik (surga) dan tambahannya.\" (Kemudian beliau melanjutkan sabdanya): \"Jika penghuni surga telah memasuki surga, dan penghuni neraka telah memasuki neraka, maka sang penyeru pun akan menyerukan, 'Wahai penduduk surga, sesungguhnya kalian masih memiliki janji di sisi Allah, dan Dia ingin memenuhinya untuk kalian.' Mereka bertanya, 'Janji apakah itu? bukankah timbangan kami telah diberatkan, memberi cahaya pada wajah-wajah kami? Bukankah kami telah dimasukkan ke dalam surga dan dibebaskan dari api nereka? ' kemudian hijab pun disingkap hingga mereka pun melihat (wajah-Nya). Maka Demi Allah, tidak sesuatu pun yang telah diberikan Allah kepada mereka yang lebih mereka cintai dari pada (kenikmatan) melihat wajah-Nya.\""},"2250":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ نَاجِيَةَ الْخُزَاعِيِّ قَالَوَكَانَ صَاحِبَ بُدْنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قُلْتُ كَيْفَ أَصْنَعُ بِمَا عَطِبَ مِنْ الْبُدْنِ قَالَ انْحَرْهُ وَاغْمِسْ نَعْلَهُ فِي دَمِهِ وَاضْرِبْ صَفْحَتَهُ وَخَلِّ بَيْنَ النَّاسِ وَبَيْنَهُ فَلْيَأْكُلُوهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [bapaknya] dari [Najiyah Al Khuza'i] ia adalah pemilik Unta Rasulullah shallallahu 'alaihi wasallam, ia berkata; Saya bertanya, \"Apa yang mesti saya lakukan terhadap Unta yang sekarat?\" beliau menjawab: \"Sembelihlah ia, dan celupkan kakinya ke dalam darahnya (sebagai tanda). Kemudian biarkan, dan hendaklah orang-orang memakannya.\""},"2251":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ نَاجِيَةَ الْخُزَاعِيِّ وَكَانَ صَاحِبَ بُدْنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ كَيْفَ أَصْنَعُ بِمَا عَطِبَ مِنْ الْإِبِلِ أَوْ الْبُدْنِ قَالَ انْحَرْهَا ثُمَّ أَلْقِ نَعْلَهَا فِي دَمِهَا ثُمَّ خَلِّ عَنْهَا وَعَنْ النَّاسِ فَلْيَأْكُلُوهَا","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [bapaknya] dari [Najiyah Al Khuza'i] pemilik Unta Rasulullah shallallahu 'alaihi wasallam, ia berkata; Saya bertanya, \"Apa yang mesti saya lakukan terhadap Unta yang sekarat?\" beliau menjawab: \"Sembelihlah ia, dan celupkan kakinya ke dalam darahnya (sebagai tanda). Kemudian biarkan, dan hendaklah orang-orang memakannya.\""},"2252":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ أَبُو عَبْد الرَّحْمَنِ وَكَتَبَ بِهِ إِلَىَّ قُتَيْبَةُ بْنُ سَعِيدٍ كَتَبْتُ إِلَيْكَ بِخَطِّي وَخَتَمْتُ الْكِتَابَ بِخَاتَمِي وَنَقْشُهُ اللَّهُ وَلِيُّ سَعِيدٍ رَحِمَهُ اللَّهُ وَهُوَ خَاتَمُ أَبِي حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ بَكْرِ بْنِ سَوَادَةَ عَنْ مُسْلِمِ بْنِ مَخْشِيٍّ عَنِ ابْنِ الْفِرَاسِيِّ أَنَّ الْفِرَاسِيَّقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْأَلُ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَإِنْ كُنْتَ سَائِلًا لَا بُدَّ فَاسْأَلْ الصَّالِحِينَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] -Abu Abdurrahman berkata- dan Qutaibah bin Sa'id telah menulis kepadaku; Saya menulis kepadamu dengan tulisan tanganku dan mengesahkannya dengan stempelku yang berukiran, \"Allah Waliyyu Sa'id Rahimahullah\" itu adalah stempel bapakku- Telah menceritakan kepada kami [Laits bin Sa'id] dari [Ja'far bin Rabi'ah] dari [Bakr bin Sawadah] dari [Muslim bin Makhsyi] dari [Ibnul Firasiy] bahwa Al Firasiy bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah aku boleh meminta-minta?\" Nabi shallallahu 'alaihi wasallam menjawab: \"Tidak, dan jika memang kamu harus meminta, maka mintalah kepada orang-orang yang shalih.\""},"2253":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَكَتَبَ بِهِ إِلَيَّ قُتَيْبَةُ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَحْيَى بْنِ مَيْمُونٍ الْحَضْرَمِيِّ أَنَّ أَبَا مُوسَى الْغَافِقِيَّ سَمِعَ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يُحَدِّثُ عَلَى الْمِنْبَرِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَادِيثَ فَقَالَ أَبُو مُوسَىإِنَّ صَاحِبَكُمْ هَذَا لَحَافِظٌ أَوْ هَالِكٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ آخِرُ مَا عَهِدَ إِلَيْنَا أَنْ قَالَ عَلَيْكُمْ بِكِتَابِ اللَّهِ وَسَتَرْجِعُونَ إِلَى قَوْمٍ يُحِبُّونَ الْحَدِيثَ عَنِّي فَمَنْ قَالَ عَلَيَّ مَا لَمْ أَقُلْ فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ النَّارِ وَمَنْ حِفْظَ عَنِّي شَيْئًا فَلْيُحَدِّثْهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] -dan Qutaibah telah menuliskannya kepadaku- Telah menceritakan kepada kami [Laits bin Sa'id] dari [Amru bin Harits] dari [Yahya bin Maimun Al Hadlrami] bahwa Abu Musa Al Ghafiqi telah mendengar Uqbah bin Amir Al Juhani menceritakan beberapa hadits di atas mimbar dari Rasulullah shallallahu 'alaihi wasallam. Maka [Abu Musa] berkata, \"Sesungguhnya teman kalian ini adalah seorang yang Hafizh ataukah seorang yang binasa. Sesungguhnya pesan terakhir yang disampaikan Rasulullah shallallahu 'alaihi wasallam kepada kami adalah beliau bersabda: 'Hendaklah kalian senantiasa berpegang teguh dengan Kitabullah dan kalian benar-benar akan kembali (menemui) suatu kaum yang sangat menggemari periwayatan hadits dariku. Maka siapa yang berkata atas namaku sesuatu yang belum pernah aku katakan, hendaklah ia mempersiapkan tempat duduknya dari neraka. Dan barangsiapa yang menghafal suatu hadits dariku, hendaklah ia menceritakannya.'\""},"2254":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَمَا تَكُونُ الذَّكَاةُ إِلَّا فِي الْحَلْقِ أَوْ اللَّبَّةِ قَالَ لَوْ طَعَنْتَ فِي فَخِذِهَا لَأَجْزَأَكَحَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ قَالَ وَسَمِعْتُهُ يَقُولُ وَأَبِيكَ حَدَّثَنَاه هُدْبَةُ بْنُ خَالِدٍ وَإِبْرَاهِيمُ بْنُ الْحَجَّاجِ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ ثَنَا أَبُو الْعُشَرَاءِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ وَكِيعٍ حَدَّثَنَا حَوْثَرَةُ بْنُ أَشْرَسَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Abul 'Usyara`] dari [bapaknya] ia berkata; Saya bertanya, \"Wahai Rasulullah, apakah penyembelihan tidak boleh dilakukan kecuali pada ujung leher atau pangkal leher?\" beliau menjawab: \"Jika kamu menikam pahanya, maka hal itu telah mencukupimu.\" Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Abul 'Usyara`] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam semisalnya. (Imam Ahmad) Berkata; Dan saya mendengarnya berkata -dan juga bapamu-, Telah menceritakannya kepada kami [Hudbah bin Khalid] dan [Ibrahim bin Hajjaj] keduanya berkata, Telah menceritakan kepada kami [Hammad bin Salamah] ia berkata, Telah menceritakan kepada kami [Abul 'Usyara`] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, semisal dengan haditsnya Waki'. Telah menceritakan kepada kami [Hautsarah bin Asyras] Telah menceritakan kepada kami [Hammad bin Salamah], lalu ia pun menyebutkan maknanya."},"2255":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَكَتَبَ بِهِ إِلَيَّ قُتَيْبَةُ حَدَّثَنَا مُجَمِّعُ بْنُ يَعْقُوبَ عَنْ مُحَمَّدِ بْنِ إِسْمَاعِيلَ بْنِ مُجَمِّعٍ قَالَ قِيلَ لِعَبْدِ اللَّهِ بْنِ أَبِي حَبِيبَةَمَا أَدْرَكْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ وَهُوَ غُلَامٌ حَدِيثٌ قَالَ جَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا إِلَى مَسْجِدِنَا يَعْنِي مَسْجِدَ قُبَاءَ قَالَ فَجِئْنَا فَجَلَسْنَا إِلَيْهِ وَجَلَسَ إِلَيْهِ النَّاسُ قَالَ فَجَلَسَ مَا شَاءَ اللَّهُ أَنْ يَجْلِسَ ثُمَّ قَامَ يُصَلِّي فَرَأَيْتُهُ يُصَلِّي فِي نَعْلَيْهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] -dan Qutaibah telah menuliskannya kepadaku- Telah menceritakan kepada kami [Mujammi' bin Ya'qub] dari [Muhammad bin Isma'il bin Mujammi'] ia berkata; Telah ditanyakan kepada [Abdullah bin Abu Habibah], \"Apa yang telah Anda dapatkan dari Rasulullah shallallahu 'alaihi wasallam?\" -Saat Rasulullah shallallahu 'alaihi wasallam datang, waktu itu ia masih anak kecil- Abdullah bin Abu Habibah menjawab, \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam mendatangi kami di Masjid kami, yakni Masjid Quba`. Maka kami pun segera datang dan duduk bersama beliau, hingga orang-orang pun iut berkumpul. Beliau duduk sekehendak Allah, setelah itu beliau berdiri dan shalat. Maka saat itu, saya melihat beliau shalat dengan mengenakan kedua terompahnya.\""},"2256":{"ar":"حَدَّثَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا الْعَطَّافُ حَدَّثَنِي مُجَمِّعُ بْنُ يَعْقُوبَ عَنْ غُلَامٍ مِنْ أَهْلِ قُبَاءَ أَنَّهُ أَدْرَكَهُ شَيْخًا قَالَجَاءَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقُبَاءَ فَجَلَسَ فِي فِنَاءِ الْأُجُمِ وَاجْتَمَعَ إِلَيْهِ نَاسٌ فَاسْتَسْقَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسُقِيَ فَشَرِبَ وَأَنَا عَنْ يَمِينِهِ وَأَنَا أَحْدَثُ الْقَوْمِ فَنَاوَلَنِي فَشَرِبْتُ وَحَفِظْتُ أَنَّهُ صَلَّى بِنَا يَوْمَئِذٍ وَعَلَيْهِ نَعْلَانِ لَمْ يَنْزِعْهُمَا","id":"Telah menceritakan kepada kami [Yunus bin Muhammad] Telah menceritakan kepada kami [Al 'Aththaf] telah menceritakan kepadaku [Mujammi' bin Ya'qub] dari [seorang anak] dari penduduk Quba`, bahwa ia mendapati seorang syaikh ia berkata; Rasulullah shallallahu 'alaihi wasallam mendatangi kami di Masjid Quba`, lalu beliau duduk di sekitar tiang, maka para sahabat pun berkumpul di sekelilingnya. Kemudian beliau meminta minum, maka beliau pun diberi minum dan langsung meminumnya. Saat itu, saya berada di sebelah kanan beliau dan paling dekat dengannya. Beliau kemudian menyerahkannya padaku dan aku pun meminumnya. Saya ingat bahwa pada hari itu, beliau shalat dengan mengenakan dua terompah dan tidak melepaskannya."},"2257":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ عَبْد اللَّهِ وسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ الدَّرَاوَرْدِيُّ عَنْ إِسْمَاعِيلَ بْنِ أَبِي حَبِيبَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ قَالَجَاءَنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِنَا فِي مَسْجِدِ بَنِي عَبْدِ الْأَشْهَلِ فَرَأَيْتُهُ وَاضِعًا يَدَهُ فِي ثَوْبِهِ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] -Abdullah berkata; Dan saya mendengarnya dari Abdullah bin Muhammad bin Abu Syaibah- Telah menceritakan kepada kami [Abdul Aziz bin Muhammad Ad Darawardi] dari [Isma'il bin Abu Habibah] dari [Abdullah bin Abdurrahman] ia berkata; Rasulullah shallallahu 'alaihi wasallam mendatangi kami, lalu beliau shalat di kediaman kami yakni di Masjid Bani Abdul Asyhal, maka saya pun melihat beliau shalat dengan meletakkan tangannya di atas kainnya ketika beliau sujud."},"2258":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ بُكَيْرِ بْنِ عَطَاءٍ اللَّيْثِيِّ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَعْمَرَ الدِّيلِيَّ يَقُولُشَهِدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ وَاقِفٌ بِعَرَفَةَ فَأَتَاهُ نَاسٌ مِنْ أَهْلِ نَجْدٍ فَقَالُوا يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ الْحَجُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْحَجُّ حَجُّ عَرَفَةَ مَنْ جَاءَ قَبْلَ صَلَاةِ الْفَجْرِ مِنْ لَيْلَةِ جَمْعٍ تَمَّ حَجُّهُ أَيَّامُ مِنًى ثَلَاثَةٌ{ فَمَنْ تَعَجَّلَ فِي يَوْمَيْنِ فَلَا إِثْمَ عَلَيْهِ وَمَنْ تَأَخَّرَ فَلَا إِثْمَ عَلَيْهِ }ثُمَّ أَرْدَفَ خَلْفَهُ فَجَعَلَ يُنَادِي بِهِنَّ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Bukair bin Atha` Al Laitsi] ia berkata, saya mendengar [Abdurrahman bin Ya'mar Ad Daili] berkata; Saya menyaksikan Rasulullah shallallahu 'alaihi wasallam wukuf di Arafah. Kemudian orang-orang dari penduduk Najed pun mendatangi beliau dan bertanya, \"Wahai Rasulullah, bagaimanakah (mansik) haji itu?\" beliau menjawab: \"(Inti dari ibadah) haji itu, adalah ketika haji di Arafah. Barangsiapa yang datang sebelum shalat Fajar (Shubuh) pada malam Jam', maka hajinya telah sempurna. Hari-hari di Mina adalah tiga hari. Maka barangsiapa yang ingin cepat berangkat (dari Mina) sesudah dua hari, Maka tiada dosa baginya. dan barangsiapa yang ingin menangguhkan (keberangkatannya dari dua hari itu), Maka tidak ada dosa pula baginya.\" Maka ia pun membonceng di belakang beliau, dan menyerukan kalimat tadi."},"2259":{"ar":"حَدَّثَنَا سُرَيْجٌ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ بِشْرِ بْنِ سُحَيْمٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ أَنْ يُنَادَى أَيَّامَ التَّشْرِيقِ أَنَّهُ لَا يَدْخُلُ الْجَنَّةَ إِلَّا مُؤْمِنٌ وَهِيَ أَيَّامُ أَكْلٍ وَشُرْبٍحَدَّثَنَا ابْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ حَبِيبٍ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ بِشْرِ بْنِ سُحَيْمٍ قَالَ خَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَيَّامِ التَّشْرِيقِ فَذَكَرَ نَحْوَهُ وَقَالَ إِنَّ هَذِهِ أَيَّامُ أَكْلٍ وَشُرْبٍ","id":"Telah menceritakan kepada kami [Suraij] Telah menceritakan kepada kami [Hammad bin Zaid] dari [Amru bin Dinar] dari [Nafi' bin Jubair] dari [Bisyr bin Suhaim] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan pada hari tasyriq untuk menyerukan bahwasanya, \"Tidak akan masuk surga kecuali orang mukmin.\" Hari itu adalah makan-makan dan minum. Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Habib] dari [Nafi' bin Jubair] dari [Bisyr bin Suhaim] ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah pada hari-hari tasyrik. Beliau pun menyebutkan semisalnya. Dan beliau berkata; \"Sesungguhnya hari-hari ini adalah hari makan-makan dan minum.\""},"2260":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ قَالَ ثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ الْمُغِيرَةِ الْمَعَافِرِيُّ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بِشْرٍ الْخَثْعَمِيُّ عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَتُفْتَحَنَّ الْقُسْطَنْطِينِيَّةُ فَلَنِعْمَ الْأَمِيرُ أَمِيرُهَا وَلَنِعْمَ الْجَيْشُ ذَلِكَ الْجَيْشُ قَالَ فَدَعَانِي مَسْلَمَةُ بْنُ عَبْدِ الْمَلِكِ فَسَأَلَنِي فَحَدَّثْتُهُ فَغَزَا الْقُسْطَنْطِينِيَّةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] -dan saya mendengarnya dari Abdullah bin bin Muhammad bin Abu Syaibah- ia berkata, Telah menceritakan kepada kami [Zaid bin Hubab] ia berkata, telah menceritakan kepadaku [Al Walid bin Al Mughirah Al Ma'afiri] ia berkata, telah menceritakan kepadaku [Abdullah bin Busyr Al Khats'ami] dari [bapaknya] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Konstantinovel benar-benar akan ditaklukkan, maka senikmat-nikmat pemimpin adalah pemimpinnya dan senikmat-nikmat pasukan adalah pasukan itu.\" Lalu Maslamah bin Abdul Malik pun memanggilku dan bertanya kepadaku, maka aku menceritakan hadits itu, dan setelah itu, ia pun memerangi Konstantinovel."},"2261":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ عَبْد اللَّهِ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ الطَّائِفِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ خَالِدٍ الْعَدْوَانِيِّ عَنْ أَبِيهِ أَنَّهُأَبْصَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَشْرِقِ ثَقِيفٍ وَهُوَ قَائِمٌ عَلَى قَوْسٍ أَوْ عَصًا حِينَ أَتَاهُمْ يَبْتَغِي عِنْدَهُمْ النَّصْرَ قَالَ فَسَمِعْتُهُ يَقْرَأُ وَالسَّمَاءِ وَالطَّارِقِ حَتَّى خَتَمَهَا قَالَ فَوَعَيْتُهَا فِي الْجَاهِلِيَّةِ وَأَنَا مُشْرِكٌ ثُمَّ قَرَأْتُهَا فِي الْإِسْلَامِ قَالَ فَدَعَتْنِي ثَقِيفٌ فَقَالُوا مَاذَا سَمِعْتَ مِنْ هَذَا الرَّجُلِ فَقَرَأْتُهَا عَلَيْهِمْ فَقَالَ مَنْ مَعَهُمْ مِنْ قُرَيْشٍ نَحْنُ أَعْلَمُ بِصَاحِبِنَا لَوْ كُنَّا نَعْلَمُ مَا يَقُولُ حَقًّا لَتَبِعْنَاهُ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] -Abdullah berkata; dan saya mendengarnya dari Abdullah bin Muhammad bin Abu Syaibah- Telah menceritakan kepada kami [Marwan bin Mu'awiyah Al Fazari] dari [Abdullah bin Abdurrahman Ath Tha`ifi] dari [Abdurrahman bin Khalid Al Adwani] dari [bapaknya] bahwa ia melihat Rasulullah shallallahu 'alaihi wasallam di sebelah Timur Tsaqif sedang bersandar di atas sebatang tongkat, yakni saat beliau mendatangi mereka untuk mengharap pertolongan. (Khalid Al Adwani) Berkata; Lalu saya mendengar beliau membaca: \"WAS SAMAA`I WATH THAARIQ (Demi langit dan yang datang pada malam hari).\" hingga beliau merampungkannya. Maka saya pun menghafalkannya pada masa jahiliyah dan waktu saya masih musyrik. Kemudian setelah memeluk Islam, saya membacanya lagi. Lalu orang-orang Tsaqif memanggilku dan bertanya, \"Apa yang telah kamu dengar dari laki-laki ini?\" maka saya pun membacakannya kepada mereka. kemudian seorang Quraisy yang bersama mereka berkata, \"Kami lebih tahu akan sahabat kami, sekiranya kami tahu apa yang dikatakannya itu benar, niscaya kami akan mengikutinya.\""},"2262":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَاقَ عَنْ نُمَيْرِ بْنِ عَرِيبٍ عَنْ عَامِرِ بْنِ مَسْعُودٍ الْجُمَحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّوْمُ فِي الشِّتَاءِ الْغَنِيمَةُ الْبَارِدَةُ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abu Ishaq] dari [Numair bin Arib] dari [Amir bin Mas'ud Al Jumahi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Puasa pada musim semi, dan ghanimah itu pada musim dingin.\" "},"2263":{"ar":"حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ نَافِعِ بْنِ كَيْسَانَ أَنَّ أَبَاهُ أخْبَرَهُأَنَّهُ كَانَ يَتَّجِرُ بِالْخَمْرِ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ أَقْبَلَ مِنْ الشَّامِ وَمَعَهُ خَمْرٌ فِي الزِّقَاقِ يُرِيدُ بِهَا التِّجَارَةَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي جِئْتُكَ بِشَرَابٍ جَيِّدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا كَيْسَانُ إِنَّهَا قَدْ حُرِّمَتْ بَعْدَكَ قَالَ أَفَأَبِيعُهَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا قَدْ حُرِّمَتْ وَحُرِّمَ ثَمَنُهَا فَانْطَلَقَ كَيْسَانُ إِلَى الزِّقَاقِ فَأَخَذَ بِأَرْجُلِهَا ثُمَّ أَهْرَقَهَا","id":"Telah menceritakan kepada kami [Qutaibah] Telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Sulaiman bin Abdurrahman] dari [Nafi' bin Kaisan] bahwa [bapaknya] telah mengabarkan kepadanya bahwasanya; Ia berjulan khamer pada masa Nabi shallallahu 'alaihi wasallam. Suatu ketika ia datang dari Syam dengan membawa Ziqaq (bejana-bejana yang berisi khamer) untuk menjualnya. Kemudian ia mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, sesungguhnya aku datang kepada Anda dengan membawa minuman yang baik.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Kaisan, sesungguhnya minuman itu telah diharamkan setelahmu.\" Ia berkata, \"Apakah boleh saya menjualnya wahai Rasulullah?\" beliau bersabda: \"Sesungguhnya minuman itu telah diharamkan dan diharamkan pula labanya.\" Akhirnya Kaisan kembali ke Ziqaq miliknya, lalu menumpahkannya."},"2264":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ زُهْرَةَ بْنِ مَعْبَدٍ عَنْ جَدِّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ آخِذٌ بِيَدِ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَقَالَ وَاللَّهِ يَا رَسُولَ اللَّهِ لَأَنْتَ أَحَبُّ إِلَيَّ مِنْ كُلِّ شَيْءٍ إِلَّا نَفْسِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسِي بِيَدِهِ لَا يُؤْمِنُ أَحَدُكُمْ حَتَّى أَكُونَ أَحَبَّ إِلَيْهِ مِنْ نَفْسِهِ قَالَ فَأَنْتَ الْآنَ وَاللَّهِ أَحَبُّ إِلَيَّ مِنْ نَفْسِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآنَ يَا عُمَرُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Zuhair bin Ma'bad] dari [kakeknya] ia berkata; Kami pernah bersama Nabi shallallahu 'alaihi wasallam, saat itu beliau memegang tangannya Umar bin Al Khaththab radliallahu 'anhu. Maka Umar pun berkata, \"Demi Allah, wahai Rasulullah, Anda benar-benar orang yang paling saya cintai dari segala sesuatu, kecuali dari diriku sendiri.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, tidaklah salah seorang dari kalian beriman, hingga aku lebih ia cintai daripada dirinya sendiri.\" Kemudian Umar berkata, \"Sungguh, sekarang Anda adalah orang yang paling saya cintai daripada diriku sendiri.\" Akhirnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekaranglah wahai Umar (sempurna imanmu).\""},"2265":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ مَعْنِ بْنِ مُحَمَّدِ بْنِ مَعْنِ بْنِ نَضْلَةَ بْنِ عَمْرٍو الْغِفَارِيُّ مَدِينِيٌّ قَالَ حَدَّثَنِي جَدِّي مُحَمَّدُ بْنُ مَعْنٍ عَنْ أَبِيهِ مَعْنِ بْنِ نَضْلَةَ عَنْ نَضْلَةَ بْنِ عَمْرٍو الْغِفَارِيِّ أَنَّهُلَقِيَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَرَّبَيْنَ فَهَجَمَ عَلَيْهِ شَوَائِلُ لَهُ فَسَقَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ شَرِبَ فَضْلَةَ إِنَاءٍ فَامْتَلَأَ بِهِ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كُنْتُ لَأَشْرَبُ السَّبْعَةَ فَمَا أَمْتَلِئُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمُؤْمِنَ يَشْرَبُ فِي مِعًى وَاحِدٍ وَإِنَّ الْكَافِرَ يَشْرَبُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] ia berkata, telah menceritakan kepadaku [Muhammad bin Ma'n bin Muhammad bin Ma'n bin Nadllah bin Amr Al Ghifari Madini] ia berkata, telah menceritakan kepadaku [kakekku, Muhammad bin Ma'n] dari bapaknya [Ma'n bin Nadllah] dari [Nadllah bin Amru Al Ghifari] bahwa ia pernah menjumpai Rasulullah shallallahu 'alaihi wasallam di Marrabain. Kemudian ia segera memeras susu Unta miliknya dan memberi minum Rasulullah shallallahu 'alaihi wasallam, dan ia pun meminum susu yang tersisa dan ia pun kenyang. Kemudian Nadllah berkata, \"Wahai Rasulullah, dulu saya benar-benar minum tujuh kali, namun saya tidak kenyang.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang mukmin itu minum dengan satu usus, sementara orang kafir minum dengan tujuh usus.\""},"2266":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا جَابِرُ بْنُ صُبْحٍ قَالَ حَدَّثَنِي الْمُثَنَّى بْنُ عَبْدِ الرَّحْمَنِ الْخُزَاعِيُّ وَصَحِبْتُهُ إِلَى وَاسِطٍوَكَانَ يُسَمِّي فِي أَوَّلِ طَعَامِهِ وَفِي آخِرِ لُقْمَةٍ يَقُولُ بِسْمِ اللَّهِ فِي أَوَّلِهِ وَآخِرِهِ فَقُلْتُ لَهُ إِنَّكَ تُسَمِّي فِي أَوَّلِ مَا تَأْكُلُ أَرَأَيْتَ قَوْلَكَ فِي آخِرِ مَا تَأْكُلُ بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ قَالَ أُخْبِرُكَ عَنْ ذَلِكَ إِنَّ جَدِّي أُمَيَّةَ بْنَ مَخْشِيٍّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعْتُهُ يَقُولُ إِنَّ رَجُلًا كَانَ يَأْكُلُ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ فَلَمْ يُسَمِّ حَتَّى كَانَ فِي آخِرِ طَعَامِهِ لُقْمَةٌ فَقَالَ بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ الشَّيْطَانُ يَأْكُلُ مَعَهُ حَتَّى سَمَّى فَلَمْ يَبْقَ فِي بَطْنِهِ شَيْءٌ إِلَّا قَاءَهُ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Jabir bin Shubh] ia berkata, telah menceritakan kepadaku [Al Mutsanna bin Abdurrahman Al Khuza'i] suatu ketika saya menemaninya ke Wasith. Saat makan ia memulainya dengan basmalah, di akhir suapan makanannya ia membaca lagi, \"BISMILLAH (Dengan nama Allah).\" Maka saya pun berkata, \"Ketika pertama kali Anda makan, Anda membaca Basmalah, lalu bagaimana dengan bacaan, 'BISMILLAH.' di akhir suapan yang Anda makan?\" Ia menjawab; Saya akan mengabarkan mengenai hal itu kepadamu. Kakekku [Umayyah bin Makhsyi] adalah salah seorang dari sahabat Nabi shallallahu 'alaihi wasallam, saya telah mendengarnya berkata; \"Seorang laki-laki sedang makan, sementara Nabi shallallahu 'alaihi wasallam melihatnya. Laki-laki itu belum membaca Basmalah hingga ia menyudahi makannya, dan pada suapan terakhir ia membaca, 'BISMILLAH AWWALAHU WA AAKHIRAHU (Dengan menyebut nama Allah di awal dan di akhir).' Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Syetan masih terus makan bersamanya hingga ia membaca Basmalah. Maka tidak ada sedikit makanan pun yang tersisa di perutnya kecuali syetan mengeluarkannya.'\""},"2267":{"ar":"حَدَّثَنَا وَكِيعٌ قَالَ ثَنَا شُعْبَةُ عَنِ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ السُّلَمِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَسَمِعَ مُؤَذِّنًا يَقُولُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشْهَدُ أَنِّي مُحَمَّدٌ رَسُولُ اللَّهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَجِدُونَهُ رَاعِيَ غَنَمٍ أَوْ عَازِبًا عَنْ أَهْلِهِ فَلَمَّا هَبَطَ الْوَادِي قَالَ مَرَّ عَلَى سَخْلَةٍ مَنْبُوذَةٍ فَقَالَ أَتَرَوْنَ هَذِهِ هَيِّنَةً عَلَى أَهْلِهَا لَلدُّنْيَا أَهْوَنُ عَلَى اللَّهِ مِنْ هَذِهِ عَلَى أَهْلِهَا","id":"Telah menceritakan kepada kami [Waki'] ia berkata, Telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Abdurrahman bin Abu Laila] dari [Abdullah bin Rabi'ah As Sulamai] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam berada suatu perjalanan, lalu beliau mendengar seorang mudzin membaca, \"ASYHADU ANLAA ILAAHA ILLALLAH (Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah).\" Maka Rasulullah shallallahu 'alaihi wasallam membaca: \"ASYHADU ANLAA ILAAHA ILLALLAH (Aku bersaksi bahwa tidak ada Tuhan yang berhak disembah selain Allah).\" Kemudian muadzin membaca, \"ASYHADU ANNA MUHAMMADAN RASUULULLAH.\" Nabi shallallahu 'alaihi wasallam membaca: \"ASYHADU ANNII MUHAMMAD RASUULULLAH (Aku bersaksi bahwa aku adalah Muhammad utusan Allah).\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian akan mendapatinya sebagai seorang penggembala kambing atau seorang yang jauh dari anggota keluarganya.\" Ketika beliau menuruni suatu lembah, beliau melewati bangkai anak kambing yang dibuang, maka beliau pun bersabda: \"Apakah kalian melihat alangkah hinanya bangkai ini di mata pemiliknya? Sesungguhnya dunia lebih hina di sisi Allah daripada hinanya bangkai ini di mata pemiliknya.\""},"2268":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ قَالَ أَبُو عَبْد الرَّحْمَنِ وَحَدَّثَنِي أَبُو خَيْثَمَةَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ عَنْ حَارِثَةَ بْنِ مُضَرِّبٍ عَنْ فُرَاتِ بْنِ حَيَّانَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِهِ وَكَانَ عَيْنًا لِأَبِي سُفْيَانَ وَحَلِيفًا فَمَرَّ بِحَلْقَةٍ مِنْ الْأَنْصَارِ فَقَالَ إِنِّي مُسْلِمٌ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ يَزْعُمُ أَنَّهُ مُسْلِمٌ فَقَالَ إِنَّ مِنْكُمْ رِجَالًا نَكِلُهُمْ إِلَى إِيمَانِهِمْ مِنْهُمْ فُرَاتُ بْنُ حَيَّانَ","id":"Telah menceritakan kepada kami [Ali bin Abdullah] Telah menceritakan kepada kami [Bisyr bin As Sariy] -Abdu Abdurrahman berkata- dan telah menceritakan kepadaku [Abu Khaitsamah] Telah menceritakan kepada kami [Bisyr bin As Sariy] Telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Haritsah bin Mudlarrib] dari [Furat bin Hayyan] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuhnya. Ia adalah mata-matanya Sufyan dan juga sekutunya. Suatu ketika ia melewati suatu halaqah kaum Anshar dan berkata, \"Saya adalah seorang muslim.\" Mereka pun berkata, \"Wahai Rasulullah, ia mengaku bahwa ia adalah seorang muslim.\" Maka beliau bersabda: \"Sesungguhnya di antara kalian terdapat orang-orang yang kita tinggalkan iman mereka. Di antara mereka itu adalah Furat bin Hayyan.\""},"2269":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا جَرِيرُ بْنُ عَبْدِ الْحَمِيدِ عَنْ مُغِيرَةَ عَنْ مُوسَى بْنِ زِيَادِ بْنِ حِذْيَمٍ السَّعْدِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِ حِذْيَمٍ السَّعْدِيِّ أَنَّهُشَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ فَقَالَ أَلَا إِنَّ دِمَاءَكُمْ وَأَمْوَالَكُمْ وَأَعْرَاضَكُمْ عَلَيْكُمْ حَرَامٌ كَحُرْمَةِ يَوْمِكُمْ هَذَا وَكَحُرْمَةِ شَهْرِكُمْ هَذَا وَكَحُرْمَةِ بَلَدِكُمْ هَذَاقَالَ أَبُو عَبْد الرَّحْمَنِ و حَدَّثَنِي أَبُو خَيْثَمَةَ حَدَّثَنَا جَرِيرٌ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ali bin Bahr] Telah menceritakan kepada kami [Jarir bin Abdul Hamid] dari [Mughirah] dari [Musa bin Ziyad bin Hidzyam As Sa'di] dari [bapaknya] dari [kakeknya, Hidzyam As Sa'di], bahwasanya; Ia turut menyaksikan Rasulullah shallallahu 'alaihi wasallam pada saat haji wada', yang mana beliau bersabda: \"Sesungguhnya darah kalian, harta kalian, dan kehormatan kalian adalah haram atas kalian, sebagaimana haramnya hari kalian ini, bulan kalian ini dan negeri kalian ini.\" Abu Abdurrahman berkata, telah menceritakan kepadaku [Abu Khutsaimah] Telah menceritakan kepada kami [Jarir]. Ia pun menyebutkan hadits semisalnya."},"2270":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عَقِيلٍ قَاضِي وَاسِطٍ عَنْ سَابِقِ بْنِ نَاجِيَةَ عَنْ أَبِي سَلَّامٍ قَالَمَرَّ رَجُلٌ فِي مَسْجِدِ حِمْصَ فَقَالُوا هَذَا خَادِمُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقُمْتُ إِلَيْهِ فَقُلْتُ حَدِّثْنِي حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَتَدَاوَلُهُ بَيْنَكَ وَبَيْنَهُ الرِّجَالُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ مُسْلِمٍ يَقُولُ حِينَ يُصْبِحُ وَحِينَ يُمْسِي ثَلَاثَ مَرَّاتٍ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيًّا إِلَّا كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُرْضِيَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Syu'bah] dari [Abu 'Aqil] Qadli Wasith, dari [Sabiq bin Najiyah] dari [Abu Sallam] ia berkata; [Seorang laki-laki] berjalan melewati Masjid Himsh, maka orang-orang pun berkata, \"Orang ini adalah Khadimnya Nabi shallallahu 'alaihi wasallam.\" Maka saya pun beranjak ke arahnya dan berkata, \"Ceritakanlah kepadaku suatu hadits yang telah Anda denganr dari Rasulullah shallallahu 'alaihi wasallam, tanpa seorang perantara pun.\" Ia pun berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim membaca, 'RADLITU BILLAHI RABBA WA BIL ISLAAMI DIINA WA BIMUHAMMADIN NABIYYA (Aku ridla Allah sebagai Rabb-ku, Islam sebagai agamaku, dan Muhammad sebagai Nabi-ku).' saat ia memasuki sore hari sebanyak tiga kali dan di pagi hari tiga kali, kecuali wajib bagi Allah untuk meridlainya pada hari kiamat.\""},"2271":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ عَنْ أَبِي عَقِيلٍ عَنْ سَابِقٍ عَنْ أَبِي سَلَّامٍ عَنْ خَادِمِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ قَالَ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ نَبِيًّا حِينَ يُمْسِي ثَلَاثًا وَحِينَ يُصْبِحُ ثَلَاثًا كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُرْضِيَهُ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Mis'ar] dari [Abu 'Aqil] dari [Sabiq] dari [Abu Sallam] dari [Khadim Nabi shallallahu 'alaihi wasallam] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Barangsiapa yang mengatakan, 'RADLITU BILLAHI RABBA WA BIL ISLAAMI DIINA WA BIMUHAMMADIN NABIYYA (Aku ridla Allah sebagai Rabb-ku, Islam sebagai agamaku, dan Muhammad sebagai Nabi-ku).' saat ia memasuki sore hari sebanyak tiga kali dan di pagi hari tiga kali, maka wajib bagi Allah untuk meridlainya pada hari kiamat.\""},"2272":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عَقِيلٍ هَاشِمِ بْنِ بِلَالٍ عَنْ سَابِقِ بْنِ نَاجِيَةَ عَنْ أَبِي سَلَّامٍ قَالَ أَبُو النَّضْرِ الْحَبَشِيُّ قَالَمَرَّ بِهِ رَجُلٌ فِي مَسْجِدِ حِمْصَ فَقِيلَ هَذَا خَدَمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ إِلَيْهِ فَقَالَ حَدِّثْنِي حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَتَدَاوَلْهُ بَيْنَكَ وَبَيْنَهُ الرِّجَالُ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَقُولُ حِينَ يُمْسِي وَحِينَ يُصْبِحُ رَضِيتُ بِاللَّهِ رَبًّا وَبِالْإِسْلَامِ دِينًا وَبِمُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيًّا ثَلَاثَ مَرَّاتٍ إِلَّا كَانَ حَقًّا عَلَى اللَّهِ أَنْ يُرْضِيَهُ","id":"Telah menceritakan kepada kami [Hasyim bin Qasim] Telah menceritakan kepada kami [Syu'bah] dari [Abu Aqil Hasyim bin Bilal] dari [Sabiq bin Najiyah] dari [Abu Sallam] -dalam riwayat lain, telah berkata Abu An Nadlr Al Habasyi- ia berkata; [Seorang laki-laki] melewatinya di Masjid Himsh, kemudian dikatakanlah bahwa, \"Ini adalah orang yang pernah menjadi Khadim (pelayan) Nabi shallallahu 'alaihi wasallam.\" Maka ia pun beranjak mendatangi laki-laki tersebut dan berkata, \"Ceritakanlah kepadaku suatu hadits yang telah Anda dengar langsung dari Rasulullah shallallahu 'alaihi wasallam dan tidak seorang pun memperantarai antara kamu dan beliau.\" Laki-laki itu pun berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba memasuki waktu sore dan pagi hari, kemudian ia membaca, 'RADLIITU BILLAHI RABBAA, WA BIL ISLAAMI DIINAA, WA BIMUHAMMAD SHALLALLAHU 'ALAIHI WASALLAM NABIYYAA (Aku rela Allah sebagai Rabb-ku, Islam sebagai agama-ku dan Muhammad shallallahu 'alaihi wasallam sebagai Nabi-ku).' sebanyak tiga kali, kecuali telah menjadi keharusan bagi Allah untuk meridlainya.\""},"2273":{"ar":"حَدَّثَنَا يَحْيَى بْنُ غَيْلَانَ حَدَّثَنَا رِشْدِينُ بْنُ سَعْدٍ حَدَّثَنَا بَكْرُ بْنُ عَمْرٍو عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرٍ أَنَّهُ حَدَّثَهُ رَجُلٌ خَدَمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِ سِنِينَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قُرِّبَ لَهُ طَعَامٌ قَالَ بِسْمِ اللَّهِ فَإِذَا فَرَغَ مِنْ طَعَامِهِ قَالَ اللَّهُمَّ أَطْعَمْتَ وَأَسْقَيْتَ وَأَغْنَيْتَ وَأَقْنَيْتَ وَهَدَيْتَ وَاجْتَبَيْتَ فَلَكَ الْحَمْدُ عَلَى مَا أَعْطَيْتَ","id":"Telah menceritakan kepada kami [Yahya bin Ghailan] Telah menceritakan kepada kami [Risydin bin Sa'd] Telah menceritakan kepada kami [Bakr bin Amr] dari [Abdullah bin Hubairah] dari [Abdurrahman bin Jubair] bahwa telah menceritakan kepadanya [seorang laki-laki] yang pernah menjadi Khadim (pelayan) Nabi shallallahu 'alaihi wasallam selama delapan tahun, ia berkata; Jika Nabi shallallahu 'alaihi wasallam disuguhkan makanan, maka beliau membaca: \"BISMILLAH.\" Dan jika beliau telah selesai makan, beliau membaca: \"ALLAHUMMA ATH'AMTA WA ASQAITA, WA AGHNAITA, WA AQNAITA WA HADAITA, WAJTABAITA, FALAKAL HAMDU MAA A'THAITA (Ya Allah, Engkau telah memberi makan dan minum. Engkau telah memberi kecukupan. Dan Engkaulah yang telah memberi petunjuk, serta memilih dan mensucikan -yang Engkau kehendaki dari para hambaMu- maka segala puji hanya bagi-Mu atas segala yang telah Engkau berikan).\""},"2274":{"ar":"حَدَّثَنَا وَكِيعٌ أَخْبَرَنَا هِشَامُ بْنُ سَعْدٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنِ ابْنِ الْأَدْرَعِ قَالَكُنْتُ أَحْرُسُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَخَرَجَ لِبَعْضِ حَاجَتِهِ ق��الَ فَرَآنِي فَأَخَذَ بِيَدِي فَانْطَلَقْنَا فَمَرَرْنَا عَلَى رَجُلٍ يُصَلِّي يَجْهَرُ بِالْقُرْآنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَسَى أَنْ يَكُونَ مُرَائِيًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ يُصَلِّي يَجْهَرُ بِالْقُرْآنِ قَالَ فَرَفَضَ يَدِي ثُمَّ قَالَ إِنَّكُمْ لَنْ تَنَالُوا هَذَا الْأَمْرَ بِالْمُغَالَبَةِ قَالَ ثُمَّ خَرَجَ ذَاتَ لَيْلَةٍ وَأَنَا أَحْرُسُهُ لِبَعْضِ حَاجَتِهِ فَأَخَذَ بِيَدِي فَمَرَرْنَا عَلَى رَجُلٍ يُصَلِّي بِالْقُرْآنِ قَالَ فَقُلْتُ عَسَى أَنْ يَكُونَ مُرَائِيًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَلَّا إِنَّهُ أَوَّابٌ قَالَ فَنَظَرْتُ فَإِذَا هُوَ عَبْدُ اللَّهِ ذُو الْبِجَادَيْنِ","id":"Telah menceritakan kepada kami [Waki'] telah mengabarkan kepada kami [Hisyam bin Sa'd] dari [Zaid bin Aslam] dari [Ibnu Al Adra'] ia berkata; Pada suatu malam, saya pernah menjaga Nabi shallallahu 'alaihi wasallam. kemudian beliau pun keluar untuk suatu keperluan. Beliau menggandeng tanganku dan kami pun pergi. Kemudian kami melewati seorang laki-laki yang sedang shalat dengan mengeraskan bacaan Alqur`annya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Boleh jadi ia melakukannya karena riya`.\" Saya bertanya, \"Wahai Rasulullah, bukankah ia shalat dan dengan mengeraskan bacaan Al Qur`annya?\" Beliau pun melepaskan tanganku kemudian bersabda: \"Kalian tidak akan meraih Islam ini dengan cara mendebatku.\" Pada suatu malam, beliau keluar lagi untuk suatu keperluan. Saat itu, saya sedang menjaganya. Beliau kemudian menggandeng tanganku kemudian pergi dan melewati seorang laki-laki yang sedang shalat dengan membaca Al Qur`an, dan saya pun berkata, \"Boleh jadi ia melakukannya karena riya`.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak, bahkan ia adalah seorang yang banyak bertaubat dan kembali kepada Allah.\" Saya menolehnya, dan ternyata ia adalah Abdullah Dzul Bijadain.\""},"2275":{"ar":"حَدَّثَنَا يَزِيدُ أَخْبَرَنَا الْمَسْعُودِيُّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ نَافِعِ بْنِ عُتْبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُقَاتِلُونَ جَزِيرَةَ الْعَرَبِ فَيَفْتَحُهَا اللَّهُ وَتُقَاتِلُونَ فَارِسَ فَيَفْتَحُهُمْ اللَّهُ وَتُقَاتِلُونَ الرُّومَ فَيَفْتَحُهُمْ اللَّهُ وَتُقَاتِلُونَ الدَّجَّالَ فَيَفْتَحُهُ اللَّهُ","id":"Telah menceritakan kepada kami [Yazid] telah mengabarkan kepada kami [Al Mas'udi] dari [Abdul Malik bin Umair] dari [Jabir bin Samurah] dari [Nafi' bin Utbah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kalian memerangi bangsa Arab hingga Allah menaklukkannya. Kemudian kalian akan memerangi bangsa Persia, hingga Allah menaklukkan mereka, dan kalian akan memerangi bangsa Romawi, hingga Allah menaklukkan mereka. Dan kalian juga akan memerangi Dajjal, sehingga Allah menaklukkannya.\""},"2276":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَاقَ يَعْنِي الْفَزَارِيَّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَابِرِ بْنِ سَمُرَةَ عَنْ نَافِعِ بْنِ عُتْبَةَ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَأَتَاهُ قَوْمٌ مِنْ قِبَلِ الْمَغْرِبِ عَلَيْهِمْ ثِيَابُ الصُّوفِ فَوَافَقُوهُ عِنْدَ أَكَمَةٍ وَهُمْ قِيَامٌ وَهُوَ قَاعِدٌ فَأَتَيْتُهُ فَقُمْتُ بَيْنَهُمْ وَبَيْنَهُ فَحَفِظْتُ مِنْهُ أَرْبَعَ كَلِمَاتٍ أَعُدُّهُنَّ فِي يَدِي قَالَ تَغْزُونَ جَزِيرَةَ الْعَرَبِ فَيَفْتَحُهَا اللَّهُ ثُمَّ تَغْزُونَ فَارِسَ فَيَفْتَحُهَا اللَّهُ ثُمَّ تَغْزُونَ الرُّومَ فَيَفْتَحُهَا اللَّهُ ثُمَّ تَغْزُونَ الدَّجَّالَ فَيَفْتَحُهُ اللَّهُ قَالَ نَافِعٌ يَا جَابِرُ أَلَا تَرَى أَنَّ الدَّجَّالَ لَا يَخْرُجُ حَتَّى تُفْتَحَ الرُّومُ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Amr] Telah menceritakan kepada kami [Abu Ishaq] yakni Al Fazari, dari [Abdul Malik bin Umair] dari [Jabir bin Samurah] dari [Nafi' bin Utbah] ia berkata; Saya pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan, kemudian beliau didatangi suatu kaum dari arah Barat yang semuanya memakai pakaian dari bahan wool. Dan mereka pun berpapasan dengan beliau di sisi bukit kecil. Mereka semua berdiri, sedangkan beliau duduk. Saya pun mendatanginya dan berdiri tepat di antara mereka dan tempat beliau berdiri. Akhirnya saya dapat menghafal empat kalimat dari beliau yang saya hitung dengan jari-jari tanganku. Beliau bersabda: \"Kalian memerangi bangsa Arab hingga Allah menaklukkannya. Kemudian kalian akan memerangi bangsa Persia, hingga Allah menaklukkan mereka, dan kalian akan memerangi bangsa Romawi, hingga Allah menaklukkan mereka. Dan kalian juga akan memerangi Dajjal, sehingga Allah menaklukkannya.\" Nafi' bertanya kepada Jabir, \"Wahai Jabir, bukankah Dajjal tidak akan keluar hingga Romawi ditaklukkan?\""},"2277":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنِي أَبِي حَدَّثَنَا حُسَيْنٌ يَعْنِي الْمُعَلِّمَ عَنِ ابْنِ بُرَيْدَةَ حَدَّثَنِي حَنْظَلَةُ بْنُ عَلِيٍّ أَنَّ مِحْجَنَ بْنَ الْأَدْرَعِ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ فَإِذَا هُوَ بِرَجُلٍ قَدْ قَضَى صَلَاتَهُ وَهُوَ يَتَشَهَّدُ وَهُوَ يَقُولُ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِاللَّهِ الْوَاحِدِ الْأَحَدِ الصَّمَدِ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ أَنْ تَغْفِرَ لِي ذُنُوبِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ قَالَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غُفِرَ لَهُ قَدْ غُفِرَ لَهُ قَدْ غُفِرَ لَهُ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Abdush Shamad] telah menceritakan kepadaku [bapakku] Telah menceritakan kepada kami [Husain] yakni Al Mu'allim, dari [Ibnu Buraidah] telah menceritakan kepadaku [Hanzhalah bin Ali] bahwa [Mihjan bin Al Adra'] telah menceritakan kepadanya, bahwa suatu ketika, Rasulullah shallallahu 'alaihi wasallam masuk masjid, kemudian beliau mendapati seorang laki-laki yang sedang bertasyahud mengakhiri shalatnya dengan membaca: \"ALLAHUMMA INNII ASALUKA BILLAHIL WAAHIDIL AHADISH SHAMAD ALLADZI LAM YALID WA LAM YUULAD, WALAM YAKUN LAHU KUFUWAN AHAD, AN TAGHFIRLII DZUNUUBII, INNAKA ANTAL GHAFUURUR RAHIIM (Ya Allah, aku meminta kepada-Mu dengan nama Allah yang Maha Esa, Yang tiada beranak dan tidak pula diperanakkan, Dan tidak ada seorangpun yang setara dengan Dia).\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh, ia telah diampuni. Sungguh, ia telah diampuni. Sungguh, ia telah diampuni.\""},"2278":{"ar":"حَدَّثَنَا يُونُسُ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ مِحْجَنِ بْنِ الْأَدْرَعِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ النَّاسَ فَقَالَ يَوْمُ الْخَلَاصِ وَمَا يَوْمُ الْخَلَاصِ يَوْمُ الْخَلَاصِ وَمَا يَوْمُ الْخَلَاصِ يَوْمُ الْخَلَاصِ وَمَا يَوْمُ الْخَلَاصِ ثَلَاثًا فَقِيلَ لَهُ وَمَا يَوْمُ الْخَلَاصِ قَالَ يَجِيءُ الدَّجَّالُ فَيَصْعَدُ أُحُدًا فَيَنْظُرُ الْمَدِينَةَ فَيَقُولُ لِأَصْحَابِهِ أَتَرَوْنَ هَذَا الْقَصْرَ الْأَبْيَضَ هَذَا مَسْجِدُ أَحْمَدَ ثُمَّ يَأْتِي الْمَدِينَةَ فَيَجِدُ بِكُلِّ نَقْبٍ مِنْهَا مَلَكًا مُصْلِتًا فَيَأْتِي سَبْخَةَ الْحَرْفِ فَيَضْرِبُ رُوَاقَهُ ثُمَّ تَرْجُفُ الْمَدِينَةُ ثَلَاثَ رَجَفَاتٍ فَلَا يَبْقَى مُنَافِقٌ وَلَا مُنَافِقَةٌ وَلَا فَاسِقٌ وَلَا فَاسِقَةٌ إِلَّا خَرَجَ إِلَيْهِ فَذَلِكَ يَوْمُ الْخَلَاصِ","id":"Telah menceritakan kepada kami [Yunus] Telah menceritakan kepada kami [Hammad] yakni Ibnu Salamah, dari [Sa'id Al Jurairi] dari [Abdullah bin Syaqiq] dari [Mihjan bin Al Adra'] bahwa Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada manusia seraya bersabda: \"Hari Al Khalash, dan apakah itu hari Al Khalash? Hari Al Khalash, dan apakah itu hari Al Khalash? Hari Al Khalash, dan apakah itu hari Al Khalash?\" beliau mengulanginya hingga tiga kali, lalu ditanyakanlah kepada beliau, \"Dan apakah itu hari Al Khalash?\" beliau menjawab: \"Yaitu, saat keluarnya Dajjal, lalu ia menaiki gunung Uhud sehingga ia pun melihat kota Madinah. Kepada ia pun berkata kepada para sahabatnya, 'Tidakkah kalian melihat istana yang putih ini? ini adalah Masjidnya Ahmad.\" Kemudian ia mendatangi Madinah, dan ia pun mendapati pada setiap jalannya satu Malaikat yang telah siap dengan hunusan pedangnya. Lalu ia mendatangi Sabhatul Harf (tanah kering di penghujung kota Madinah), kemudian ia memukul-mukul perkemahaman, Qubah beserta tempat-tempat duduknya, dengan itu, kota Madinah pun bergetar dengan tiga kali getaran. Sehingga tidak seorang munafik pun baik laki-laki atau perempuan dan tidak juga seorang fasik pun baik laki-laki maupun perempuan yang tersisa, kecuali semuanya keluar mengikuti Dajjal. Dan hari itulah yang dinamakan Yaumul Khalash.\" "},"2279":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ رَجَاءِ بْنِ أَبِي رَجَاءٍ قَالَكَانَ بُرَيْدَةُ عَلَى بَابِ الْمَسْجِدِ فَمَرَّ مِحْجَنٌ عَلَيْهِ وَسُكْبَةُ يُصَلِّي فَقَالَ بُرَيْدَةُ وَكَانَ فِيهِ مُرَاحٌ لِمِحْجَنٍ أَلَا تُصَلِّي كَمَا يُصَلِّي هَذَا فَقَالَ مِحْجَنٌ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخَذَ بِيَدِي فَصَعِدَ عَلَى أُحُدٍ فَأَشْرَفَ عَلَى الْمَدِينَةِ فَقَالَ وَيْلُ أُمِّهَا قَرْيَةً يَدَعُهَا أَهْلُهَا خَيْرَ مَا تَكُونُ أَوْ كَأَخْيَرِ مَا تَكُونُ فَيَأْتِيهَا الدَّجَّالُ فَيَجِدُ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِهَا مَلَكًا مُصْلِتًا جَنَاحَيْهِ فَلَا يَدْخُلُهَا قَالَ ثُمَّ نَزَلَ وَهُوَ آخِذٌ بِيَدِي فَدَخَلَ الْمَسْجِدَ وَإِذَا هُوَ بِرَجُلٍ يُصَلِّي فَقَالَ لِي مَنْ هَذَا فَأَتَيْتُ عَلَيْهِ فَأَثْنَيْتُ عَلَيْهِ خَيْرًا فَقَالَ اسْكُتْ لَا تُسْمِعْهُ فَتُهْلِكَهُ قَالَ ثُمَّ أَتَى حُجْرَةَ امْرَأَةٍ مِنْ نِسَائِهِ فَنَفَضَ يَدَهُ مِنْ يَدِي قَالَ إِنَّ خَيْرَ دِينِكُمْ أَيْسَرُهُ إِنَّ خَيْرَ دِينِكُمْ أَيْسُرُهُحَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ شَقِيقٍ يُحَدِّثُ عَنْ رَجَاءِ بْنِ أَبِي رَجَاءٍ الْبَاهِلِيِّ عَنْ مِحْجَنٍ رَجُلٍ مِنْ أَسْلَمَ فَذَكَرَ مَعْنَاهُ وَلَمْ يَقُلْ حَجَّاجٌ وَلَا أَبُو النَّضْرِ بِجَنَاحِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Abdullah bin Syaqiq] dari [Raja` bin Abu Raja`] ia berkata; Suatu ketika, Burdah berada di pintu Masjid, kemudian lewatlah Mihjan, sementara Sukbah sedang menunaikan shalat. Maka Burdah pun bertanya -di sekitar tempat itu, ada kandang Unta milik Mihjan-, \"Tidakkah kamu shalat sebagaimana orang ini shalat?\" kemudian [Mihjan] menjawab, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah menggandeng tanganku, kemudian beliau menaiki gunung Uhud dan memandangi kota Madinah. Kemudian beliau bersabda: 'Musibah akan menimpa Ummul Qura. Sebuah daerah yang akan ditinggal pergi oleh sebagian penduduknya, dan hal itu merupakan peristiwa yang paling baik yang pernah terjadi. Kemudian Dajjal mendatanginya, dan ia pun mendapati pada setiap pintu kota Madinah satu Malaikat yang mengepakkan sayapnya, hingga ia tidak dapat memasukinya.' Kemudian beliau turun sambil memegang tanganku, dan masuk ke dalam Masjid. Ternyata beliau mendapati seorang laki-laki yang sedang shalat, beliau bertanya, 'Siapakah orang ini? ' saya pun mendatangi laki-laki itu dan memujinya dengan kebaikan. Maka beliau bersabda: 'Diamlah. Jangan kamu memperdengarkannya hingga kamu menghancurkannya.' Setelah itu, beliau mendatangi kamar salah seorang dari isteri-isterinya, dan beliau pun melepaskan tanganku dari tangannya. Beliau bersabda: 'Sesungguhnya yang terbaik dari Agama kalian adalah yang termudah. Sesungguhnya yang terbaik dari Agama kalian adalah yang termudah.'\" Telah menceritakan kepada kami [Hajjaj] Telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] ia berkata, saya mendengar [Abdullah bin Syaqiq] menceritakan dari [Raja` bin Abu Raja` Al Bahili] dari [Mihjan] seorang laki-laki berasal dari Bani Aslam, Maka ia pun menyebutkan maknanya. Dan [Hajjaj] tidak Mengatakan, \"Sayapnya.\" Dan tidak pula [Abu An Nadlr]."},"2280":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ بْنِ أَسْلَمَ قَالَ سُفْيَانُ مَرَّةً عَنْ بُسْرٍ أَوْ بُسْرِ بْنِ مِحْجَنٍ ثُمَّ كَانَ يَقُولُ بَعْدُ عَنْ أَبِي مِحْجَنٍ الدِّيلِيِّ عَنْ أَبِيهِ قَالَأَت��يْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي الْمَسْجِدِ فَحَضَرَتْ الصَّلَاةُ فَصَلَّى فَقَالَ لِي أَلَا صَلَّيْتَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ قَدْ صَلَّيْتُ فِي الرَّحْلِ ثُمَّ أَتَيْتُكَ قَالَ فَإِذَا فَعَلْتَ فَصَلِّ مَعَهُمْ وَاجْعَلْهَا نَافِلَةًقَالَ أَبِي وَلَمْ يَقُلْ أَبُو نُعَيْمٍ وَلَا عَبْدُ الرَّحْمَنِ وَاجْعَلْهَا نَافِلَةً","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] -dan sekali waktu Sufyan berkata- dari [Busr] atau Busrun bin Mihjan -setelah itu ia mengatakan, dari ayahku, Mihjan Ad Dili- dari [bapaknya] ia berkata; Saya mendatangi Nabi shallallahu 'alaihi wasallam, yang saat itu beliau berada di Masjid. Kemudian masuklah waktu shalat, beliau pun shalat dan bertanya kepadaku: \"Tidakkah kamu shalat?\" saya menjawab, \"Wahai Rasulullah, saya telah menunaikan shalat di perjalanan, baru kemudian menemui Anda.\" Beliau bersabda: \"Jika kamu telah laksanakan, maka shalatlah bersama mereka, dan jadikanlah ia sebagai Nafilah.\" Bapakku berkata; [Abu Nu'aim] tidak mengatakan, \"Dan jadikanlah ia sebagai shalat Nafilah.\" Dan tidak pula [Abdurrahman]."},"2281":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ سُلَيْمَانَ بْنِ سُلَيْمٍ عَنْ يَحْيَى بْنِ جَابِرٍ عَنْ ضَمْرَةَ بْنِ ثَعْلَبَةَ أَنَّهُأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ حُلَّتَانِ مِنْ حُلَلِ الْيَمَنِ فَقَالَ يَا ضَمْرَةُ أَتَرَى ثَوْبَيْكَ هَذَيْنِ مُدْخِلَيْكَ الْجَنَّةَ فَقَالَ لَئِنْ اسْتَغْفَرْتَ لِي يَا رَسُولَ اللَّهِ لَا أَقْعُدُ حَتَّى أَنْزَعَهُمَا عَنِّي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اغْفِرْ لِضَمْرَةَ بْنِ ثَعْلَبَةَ فَانْطَلَقَ سَرِيعًا حَتَّى نَزَعَهُمَا عَنْهُ","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] Telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Sulaiman bin Sulaim] dari [Yahya bin Jabir] dari [Dlamrah bin Tsa'labah] bahwa ia pernah mendatangi Nabi shallallahu 'alaihi wasallam dengan mengenakan dua helai pakaian yang berasal dari Yaman. maka beliau pun bertanya: \"Wahai Dlamrah, apakah kamu mengira kedua helai pakaianmu ini akan memasukkanmu ke dalam surga?\" ia menjawab, \"Jika Anda mau meminta ampun bagiku, wahai Rasulullah, niscaya saya tidak akan duduk, hingga aku menanggalkannya dari tubuhku.\" Maka Nabi shallallahu 'alaihi wasallam membaca: \"Ya Allah, Ampunilah Dlamrah bin Tsa'labah.\" Ia pun segera pergi dan menanggalkan pakaiannya."},"2282":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ قَالَبَعَثَنِي أَهْلِي بِلَقُوحٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَنِي أَنْ أَحْلُبَهَا فَحَلَبْتُهَا فَقَالَ لِي دَعْ دَاعِيَ اللَّبَنِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al A'masy] dari [Ya'qub bin Bahir] dari [Dlirar bin Al Azwar] ia berkata; Suatu ketika, aku diutus oleh keluargaku untuk membawa Unta perahan kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau memerintahkanku untuk memerah susunya, maka saya pun memerahnya. Kemudian beliau bersabda: \"Tinggalkanlah sedikit dari susunya, agar ia menurunkan air susu yang lain.\""},"2283":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنِ الْأَعْمَشِ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ رَجُلٍ مِنْ الْحَيِّ قَالَ سَمِعْتُ ضِرَارَ بْنَ الْأَزْوَرِ قَالَأَهْدَيْنَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقْحَةً قَالَ فَحَلَبْتُهَا قَالَ فَلَمَّا أَخَذْتُ لِأُجْهِدَهَا قَالَ لَا تَفْعَلْ دَعْ دَاعِيَ اللَّبَنِ","id":"Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Zuhair] dari [Al A'masy] dari [Ya'qub bin Bahir] seorang laki-laki dari Al Hayy, ia berkata, saya mendengar [Dlirar bin Al Azwar] ia berkata; Kami menghadiahkan kepada Rasulullah shallallahu 'alaihi wasallam Unta perahan. Kemudian saya pun memerahnya. Ketika saya mengambil untuk memerahnya beliau bersabda: \"Jangan kamu lakukan, tinggalkanlah sedikit dari susunya, agar menurunkan air susu yang lain.\""},"2284":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا سُفْيَانُ عَنِ الْأَعْمَشِ عَنْ عَبْدِ اللَّهِ بْنِ سِنَانٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِهِ وَهُوَ يَحْلُبُ فَقَالَ دَعْ دَاعِيَ اللَّبَنِقَالَ عَبْد اللَّهِ و حَدَّثَنِي مُحَمَّدُ بْنُ بَكَّارٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ حَدَّثَنَا الْأَعْمَشُ أَوْ عَنْ الْأَعْمَشِ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Abdurrahman] Telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Abdullah bin Sinan] dari [Dlirar bin Al Azwar] bahwa Nabi shallallahu 'alaihi wasallam melewatinya, sementara ia sedang memerah susu. Maka beliau pun bersabda: \"Tinggalkanlah sedikit dari susunya, agar menurunkan air susu yang lain.\" Abdullah berkata; Dan telah menceritakan kepadaku [Muhammad bin Bakkar] Telah menceritakan kepada kami [Abdullah bin Mubarak] Telah menceritakan kepada kami [Al A'masy] atau dari Al A'masy dari [Ya'qub bin Bahir] dari [Dlirar bin Al Azwar] dari Nabi shallallahu 'alaihi wasallam, semisalnya."},"2285":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْرَائِيلَ الْجُشَمِيُّ عَنْ شَيْخٍ لَهُمْ يُقَالُ لَهُ جَعْدَةُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى لِرَجُلٍ رُؤْيَا قَالَ فَبَعَثَ إِلَيْهِ فَجَاءَ فَجَعَلَ يَقُصُّهَا عَلَيْهِ وَكَانَ الرَّجُلُ عَظِيمَ الْبَطْنِ قَالَ فَجَعَلَ يَقُولُ بِأُصْبُعِهِ فِي بَطْنِهِ لَوْ كَانَ هَذَا فِي غَيْرِ هَذَا لَكَانَ خَيْرًا لَكَ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abu Isra`il Al Jusyami] dari syaikh mereka yang biasa dipanggil [Ja'dah], bahwa Nabi shallallahu 'alaihi wasallam pernah bermimpi melihat seorang laki-laki, maka beliau pun mengutus seseorang kepadanya. laki-laki itu datang, dan beliau pun mengkisahkan mimpinya. Laki-laki itu adalah seorang yang besar perutnya, maka beliau bersabda seraya menunjuk perut laki-laki itu: \"Sekiranya ini, ditempatkan bukan di sini, niscaya hal itu akan lebih baik.\""},"2286":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ عَنِ السَّائِبِ بْنِ يَزِيدَ عَنِ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ إِنْ شَاءَ اللَّهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَمْكُثُ الْمُهَاجِرُ بِمَكَّةَ بَعْدَ قَضَاءِ نُسُكِهِ ثَلَاثًاقَالَ مَا كَانَ أَشَدَّ عَلَى ابْنِ عُيَيْنَةَ أَنْ يَقُولَ حَدَّثَنَا","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] telah menceritakan kepadaku [Abdurrahman bin Humaid bin Abdurrahman bin Auf] dari [As Sa`ib bin Yazid] dari [Al Ala` bin Al Hadlrami] Insya Allah, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para Muhajir bermukim di Makkah selama tiga malam setelah menunaikan Nusuknya (menyembelih hewan kurban).\" Tidak ada lebih keras atas diri Ibnu Uyainah melebihi ketika ia mengatakan, \"Telah menceritakan kepada kami.\""},"2287":{"ar":"حَدَّثَنَا هُشَيْمٌ حَدَّثَنَا مَنْصُورٌ عَنِ ابْنِ سِيرِينَ عَنِ ابْنِ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَ أَبِي حَدَّثَنَا بِهِ هُشَيْمٌ مَرَّتَيْنِ مَرَّةً عَنْ ابْنِ الْعَلَاءِ وَمَرَّةً لَمْ يَصِلْأَنَّ أَبَاهُ كَتَبَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَدَأَ بِنَفْسِهِ","id":"Telah menceritakan kepada kami [Husyaim] Telah menceritakan kepada kami [Manshur] dari [Ibnu Sirin] dari [Ibnul Ala` bin Al Hadlrami], -bapakku berkata, Husyaim telah menceritakannya kepada kami sebanyak dua kali, sekali dari Ibnul Ala` dan yang satunya lagi tidak bersambung sanadnya- Bahwa [bapaknya] menulis surat kepada Nabi shallallahu 'alaihi wasallam, dan ia pun memulai dari dirinya sendiri."},"2288":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu berwudlu, maka lakukanlah Al Intsar (memasukkan air ke dalam hidung, dan menghembuskannya kembali). Dan jika kamu beristinja` dengan batu, maka ganjilkanlah bilangannya.\""},"2289":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Sufyan] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kamu berwudlu, maka lakukanlah Al Intsar (memasukkan air ke dalam hidung, dan menghembuskannya kembali). Dan jika kamu beristinja` dengan batu, maka ganjilkanlah bilangannya.\""},"2290":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ إِنَّمَا هُنَّ أَرْبَعٌ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَسْرِقُوا وَلَا تَزْنُوا","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada saat Haji Wada': \"Sesungguhnya hanya ada empat perkara, yaitu, Janganlah kalian berbuat syirik kepada Allah, janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan benar, janganlah kalian mencuri dan janganlah kalian berzina.\""},"2291":{"ar":"حَدَّثَنَا هَاشِمٌ قَالَ ثَنَا أَبُو مُعَاوِيَةَ يَعْنِي شَيْبَانَ حَدَّثَنَا مَنْصُورٌ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ الْأَشْجَعِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَجَّةِ الْوَدَاعِ أَلَا إِنَّمَا هُنَّ أَرْبَعٌ أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا تَزْنُوا وَلَا تَسْرِقُوا قَالَ فَمَا أَنَا بِأَشَحَّ عَلَيْهِنَّ مِنِّي إِذْ سَمِعْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Hasyim] ia berkata, Telah menceritakan kepada kami [Abu Mu'awiyah] yakni Syaiban, Telah menceritakan kepada kami [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais Al Asyja'i] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda pada saat Haji Wada': \"Ketahuilah, kuperintahkan kepada kalian empat perkara, yaitu, Janganlah kalian menyekutukan Allah dengan sesuatu apapun, janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan benar, janganlah kalian mencuri dan janganlah kalian berzina.\" Tidaklah saya lebih pelit untuk melakukan semua itu, setelah saya mendengarnya semua dari Rasulullah shallallahu 'alaihi wasallam."},"2292":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ وَالثَّوْرِيُّ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ سَلَمَةَ بْنِ قَيْسٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَوَضَّأْتَ فَانْتَثِرْ وَإِذَا اسْتَجْمَرْتَ فَأَوْتِرْ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dan [Ats Tsauri] dari [Manshur] dari [Hilal bin Yasaf] dari [Salamah bin Qais] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Jika kamu berwudlu, maka lakukanlah Al Intsar (memasukkan air ke dalam hidung, dan menghembuskannya kembali). Dan jika kamu beristinja` dengan batu, maka ganjilkanlah bilangannya.\""},"2293":{"ar":"حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنِ ابْنِ خُثَيْمٍ عَنْ إِسْمَاعِيلَ بْنِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَوْلَى الْقَوْمِ مِنْهُمْ وَابْنُ أُخْتِهِمْ مِنْهُمْ وَحَلِيفُهُمْ مِنْهُمْ","id":"Telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ibnu Khutsaim] dari [Isma'il bin Ubaid bin Rifa'ah] dari [bapaknya] dari [kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bekas budak suatu kaum adalah termasuk golongan mereka, anak saudara perempuannya juga dari golongan mereka, dan sekutu mereka, juga termasuk golongan mereka.\""},"2294":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنِ ابْنِ خُثَيْمٍ عَنْ إِسْمَاعِيلَ بْنِ عُبَيْدِ بْنِ رِفَاعَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَجَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرَيْشًا فَقَالَ هَلْ فِيكُمْ مِنْ غَيْرِكُمْ قَالُوا لَا إِلَّا ابْنُ أُخْتِنَا وَحَلِيفُنَا وَمَوْلَانَا فَقَالَ ابْنُ أُخْتِكُمْ مِنْكُمْ وَحَلِيفُكُمْ مِنْكُمْ وَمَوْلَاكُمْ مِنْكُمْ إِنَّ قُرَيْشًا أَهْلُ صِدْقٍ وَأَمَانَةٍ فَمَنْ بَغَى لَهَا الْعَوَائِرَ أَكَبَّهُ اللَّهُ فِي النَّارِ لِوَجْهِهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Ibnu Khutsaim] dari [Isma'il bin Ubaid bin Rifa'ah] dari [bapaknya] dari [kakeknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam menyatakan orang-orang Quraisy. Beliau pun bertanya: \"Apakah di antara kalian ada orang lain selain dari kabilah kalian?\" mereka menjawab, \"Tidak ada kecuali, anak saudara perempuan kami dan sekutu kami serta bekas budak kami.\" Maka beliau bersabda: \"Sesungguhnya anak saudara perempuan kalian, para sekutu kalian dan bekas budak kalian, semuanya adalah termasuk dari kabilah kalian. Sesungguhnya orang-orang Quraiys adalah orang-orang yang jujur lagi amanahj, maka siapa yang berani bertindak lalim dan gegabah terhadapnya, niscaya Allah akan melemparkannya ke dalam neraka.\""},"2295":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ الْمُفَضَّلِ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُثْمَانَ بْنِ خُثَيْمٍ عَنْ إِسْمَاعِيلَ بْنِ عُبَيْدِ بْنِ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَلِيفُنَا مِنَّا وَمَوْلَانَا مِنَّا وَابْنُ أُخْتِنَا مِنَّا","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Bisyr] yakni Ibnu Al Mufadldlal, Telah menceritakan kepada kami [Abdullah bin Utsman bin Khutsaim] dari [Isma'il bin Ubaid bin Rifa'ah bin Rafi' Az Zuraqi] dari [bapaknya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekutu kami, bekas budak kami dan anak saudara perempuan kami adalah termasuk dari golongan kami.\""},"2296":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ عَلِيِّ بْنِ يَحْيَى بْنِ خَلَّادٍ الزُّرَقِيِّ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَجَاءَ رَجُلٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ فِي الْمَسْجِدِ فَصَلَّى قَرِيبًا مِنْهُ ثُمَّ انْصَرَفَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعِدْ صَلَاتَكَ فَإِنَّكَ لَمْ تُصَلِّ قَالَ فَرَجَعَ فَصَلَّى كَنَحْوٍ مِمَّا صَلَّى ثُمَّ انْصَرَفَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ أَعِدْ صَلَاتَكَ فَإِنَّكَ لَمْ تُصَلِّ فَقَالَ يَا رَسُولَ اللَّهِ عَلِّمْنِي كَيْفَ أَصْنَعُ قَالَ إِذَا اسْتَقْبَلْتَ الْقِبْلَةَ فَكَبِّرْ ثُمَّ اقْرَأْ بِأُمِّ الْقُرْآنِ ثُمَّ اقْرَأْ بِمَا شِئْتَ فَإِذَا رَكَعْتَ فَاجْعَلْ رَاحَتَيْكَ عَلَى رُكْبَتَيْكَ وَامْدُدْ ظَهْرَكَ وَمَكِّنْ لِرُكُوعِكَ فَإِذَا رَفَعْتَ رَأْسَكَ فَأَقِمْ صُلْبَكَ حَتَّى تَرْجِعَ الْعِظَامُ إِلَى مَفَاصِلِهَا وَإِذَا سَجَدْتَ فَمَكِّنْ لِسُجُودِكَ فَإِذَا رَفَعْتَ رَأْسَكَ فَاجْلِسْ عَلَى فَخِذِكَ الْيُسْرَى ثُمَّ اصْنَعْ ذَلِكَ فِي كُلِّ رَكْعَةٍ وَسَجْدَةٍ","id":"Telah menceritakan kepada kami [Yazid bin Harun] ia berkata, telah mengabarkan kepada kami [Muhammad bin Amru] dari [Ali bin Yahya bin Khallad Az Zuraqi] dari [Rifa'ah bin Rafi' Az Zuraqi] ia adalah salah seorang dari sahabat Nabi shallallahu 'alaihi wasallam, ia berkata; Seorang laki-laki datang, sementara Rasulullah shallallahu 'alaihi wasallam sedang duduk di dalam Masjid. Kemudian laki-laki itu shalat di dekat beliau, dan setelah shalat ia pun menemui Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ulangilah shalatmu, karena kamu belum shalat.\" laki-laki itu pun mengulangi shalatnya seperti yang dikerjakannya pertama kali. Setelah selesai, ia pun kembali menemui Rasulullah shallallahu 'alaihi wasallam, dan beliau bersabda lagi: \"Ulangilah shalatmu, karena sesungguhnya kamu belum shalat.\" maka laki-laki itu pun berkata, \"Wahai Rasulullah, ajarilah aku, bagaimana seharusnya saya lakukan!\" beliau bersabda: \"Jika telah menghadap kiblat, maka bertakbir dan bacalah Ummul Qur`an (surat Al Fatihah), kemudian bacalah sesukamu dari Al Qur`an. Dan jika kamu ruku', maka letakkanlah kedua telapak tanganmu di atas kedua lututmu. Luruskanlah punggungmu dan bersikap tenanglah dalam posisi ruku'. Dan ketika kamu mengangkat kepala dari posisi ruku', maka luruskanlah tulang sulbimu, sehingga tulang-tulang dan persendian kembali ke posisinya semula. Kemudian saat kamu sujud, maka bersikap tenanglah dalam sujudmu, dan jika kamu mengangkat kepala dari posisi sujud, maka duduklah di atas paha kirimu. Dan lakukanlah itu semua dalam setiap raka'at dan sujud.\""},"2297":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ عَنْ عَلِيِّ بْنِ يَحْيَى الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ الزُّرَقِيِّ قَالَكُنَّا نُصَلِّي يَوْمًا وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ مِنْ الرَّكْعَةِ وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا لَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْمُتَكَلِّمُ آنِفًا قَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلًا","id":"(Imam Ahmad) Berkata, Saya telah membacakan kepada [Abdurrahman bin Mahdi]: [Malik] dari [Nu'aim bin Abdullah Al Mujmir] dari [Ali bin Yahya Az Zuraqi] dari [ayahnya] dari [Rifa'ah bin Rafi' Az Zuraqi] ia berkata; Pada suatu hari, kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam. Ketika beliau mengangkat kepalanya dari ruku' dan membaca, \"SAMI'ALLAHU LIMAN HAMIDAH (Allah Maha Mendengar bagi siapa saja yang memujinya).\" Tiba-tiba seorang laki-laki menyahut di belakangnya, \"RABBANAA LAKAL HAMDU KATSIIRAN THAYYIBAN MUBAARAKAN FIIH (Ya Rabb kami, bagi-Mu segala pujian yang baik dan banyak, serta mengandung keberkahan).\" Ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, beliau bertanya: \"Siapa yang berkata-kata tadi?\" laki-laki itu pun menjawab, \"Saya wahai Rasulullah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungghnya saya telah melihat tiga puluh lebih Malaikat yang saling berlomba, siapa di antara mereka yang menulisnya pertama kali.\""},"2298":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ عَجْلَانَ حَدَّثَنَا عَلِيُّ بْنُ يَحْيَى بْنِ خَلَّادٍ عَنْ أَبِيهِ عَنْ عَمِّهِ وَكَانَ بَدْرِيًّا قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَسْجِدِ فَدَخَلَ رَجُلٌ فَصَلَّى فِي نَاحِيَةِ الْمَسْجِدِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُهُ ثُمَّ جَاءَ فَسَلَّمَ فَرَدَّ عَلَيْهِ وَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ قَالَ مَرَّتَيْنِ أَوْ ثَلَاثًا فَقَالَ لَهُ فِي الثَّالِثَةِ أَوْ فِي الرَّابِعَةِ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ أَجْهَدْتُ نَفْسِي فَعَلِّمْنِي وَأَرِنِي فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَدْتَ أَنْ تُصَلِّيَ فَتَوَضَّأْ فَأَحْسِنْ وُضُوءَكَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ ثُمَّ كَبِّرْ ثُمَّ اقْرَأْ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ جَالِسًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ قُمْ فَإِذَا أَتْمَمْتَ صَلَاتَكَ عَلَى هَذَا فَقَدْ أَتْمَمْتَهَا وَمَا انْتَقَصْتَ مِنْ هَذَا مِنْ شَيْءٍ فَإِنَّمَا تُنْقِصُهُ مِنْ صَلَاتِكَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Ibnu Ajlan] Telah menceritakan kepada kami [Ali bin Yahya bin Khallad] dari [bapaknya] dari [pamannya] dan ia telah menyaksikan perang Badar, ia berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam berada di dalam Masjid. Kemudian masuklah seorang laki-laki dan shalat di samping Masjid. Maka Rasulullah shallallahu 'alaihi wasallam memandangnya sepintas. Kemudian laki-laki itu pun mendatangi beliau dan mengucapkan salam. beliau pun membalas salamnya dan bersabda: \"Kembali dan shalatlah, karena sesungguhnya kamu belum menunaikan shalat.\" Beliau mengulanginya sebanyak dua atau tiga kali. Maka laki-laki itu pun berkata pada kali yang ketiga atau yang keempat, \"Demi Dzat yang telah mengutusmu dengan membawa kebenaran, sungguh, saya telah berusaha sekuat kemampuan. Karena itu, ajari dan tunjukkanlah (shalat yang benar) padaku.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jika kamu hendak menunaikan shalat, maka berwudlu dan sempurnakanlah wudlumu. Kemudian kamu menghadap kiblat dan bertakbir lalu bacalah (sesuatu dari ayat Al Qur`an). Setelah itu, ruku'lah, sampai kamu tenang dalam posisi ruku'. Kemudian angkatlah kepalamu, hingga kamu tenang dalam posisi berdiri. Dan setelah itu, kamu sujud hingga tenang dalam posisi sujud, kemudian angkatlah kepalamu hingga kamu tenang dalam posisi duduk. Kemudian kamu sujud lagi, hingga tenang dalam posisi sujud, lalu berdirilah. Jika menyempurnakan shalatmu seperti ini, maka sungguh, kamu telah menyempurnakannya, dan jika kamu mengurangi sedikit darinya, maka sesungguhnya kamu hanya mengurangi shalatmu.\""},"2299":{"ar":"حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا عِكْرِمَةُ يَعْنِي ابْنَ عَمَّارٍ قَالَ حَدَّثَنِي طَارِقُ بْنُ عَبْدِ الرَّحْمَنِ الْقُرَشِيُّ قَالَجَاءَ رَافِعُ بْنُ رِفَاعَةَ إِلَى مَجْلِسِ الْأَنْصَارِ فَقَالَ لَقَدْ نَهَانَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْيَوْمَ عَنْ شَيْءٍ كَانَ يَرْفُقُ بِنَا فِي مَعَايِشِنَا فَقَالَ نَهَانَا عَنْ كِرَاءِ الْأَرْضِ قَالَ مَنْ كَانَتْ لَهُ أَرْضٌ فَلْيَزْرَعْهَا أَوْ لِيُزْر��عْهَا أَخَاهُ أَوْ لِيَدَعْهَا وَنَهَانَا عَنْ كَسْبِ الْحَجَّامِ وَأَمَرَنَا أَنْ نُطْعِمَهُ نَوَاضِحَنَا وَنَهَانَا عَنْ كَسْبِ الْأَمَةِ إِلَّا مَا عَمِلَتْ بِيَدِهَا وَقَالَ هَكَذَا بِأَصَابِعِهِ نَحْوَ الْخَبْزِ وَالْغَزْلِ وَالنَّفْشِ","id":"Telah menceritakan kepada kami [Hasyim bin Qasyim] Telah menceritakan kepada kami [Ikrimah] yakni Ibnu Ammar, ia berkata, telah menceritakan kepadaku [Thariq bin Abdurrahman Al Qurasyi] ia berkata, [Rafi' bin Rifa'ah] mendatangi majelis orang-orang Anshar dan berkata; Pada hari ini, Nabi shallallahu 'alaihi wasallam telah melarang kita, dari sesuatu yang telah akrab dengan kehidupan kita. Ia pun melanjutkan berkata; Beliau melarang untuk menyewakan lahan, beliau bersabda: \"Barangsiapa yang memiliki lahan hendaklah ia menanaminya, atau ditanami oleh saudaranya.\" Kemudian beliau juga melarang untuk mencari penghidupan dari hasil bekam. Dan beliau memerintahkan untuk memberi makan Unta, dan melarang untuk mempekejakan budak wanita kecuali apa yang dikerjakannya dengan tangannya sendiri. Dan beliau bersabda -seperti ini, yakni beliau memberikan isyarat dengan jari tangannya menunjuk-: \" roti, tenun dan rumput.\""},"2300":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا شَيْبَانُ عَنْ زِيَادِ بْنِ عِلَاقَةَ عَنْ عَرْفَجَةَ بْنِ شُرَيْحٍ الْأَسْلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا سَتَكُونُ بَعْدِي هَنَاتٌ وَهَنَاتٌ وَرَفَعَ يَدَيْهِ فَمَنْ رَأَيْتُمُوهُ يُفَرِّقُ بَيْنَ أُمَّةِ مُحَمَّدٍ وَهُمْ جَمِيعٌ فَاقْتُلُوهُ كَائِنًا مَنْ كَانَ مِنْ النَّاسِ","id":"Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Syaiban] dari [Ziyad bin Ilaqah] dari [Arfajah bin Suraih Al Aslami] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan terjadi setelahku berbagai macam fitnah, -beliau sambil mengangkat kedua tangannya- maka barangsiapa yang kalian lihat memecahkan perkara umat ini, padahal mereka telah menyatakan ikrar kesepakatan, maka bunuhlah dia, siapa pun orangnya dari kalangan manusia.\""},"2301":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زِيَادِ بْنِ عِلَاقَةَ قَالَ سَمِعْتُ عَرْفَجَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّهُ سَتَكُونُ هَنَاتٌ وَهَنَاتٌ فَمَنْ أَرَادَ أَنْ يُفَرِّقَ أَمْرَ هَذِهِ الْأُمَّةِ وَهِيَ جَمِيعٌ فَاضْرِبُوهُ بِالسَّيْفِ كَائِنًا مَنْ كَانَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Ziyad bin 'Iaaqah] ia berkata, saya mendengar ['Arfajah] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya akan terjadi berbagai macam fitnah, maka barangsiapa yang ingin mencerai-beraikan perkara umat ini padahal mereka telah menyatakan ikrar kesepakatan, maka penggallah ia dengan pedang, siapa pun orangnya.\""},"2302":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ أَنَّ عَبَّادَ بْنَ تَمِيمٍ أَخْبَرَهُ عَنْ عُوَيْمِرِ بْنِ أَشْقَرَأَنَّهُ ذَبَحَ قَبْلَ أَنْ يَغْدُوَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَّهُ ذَكَرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا فَرَغَ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَعُودَ لِأُضْحِيَّتِهِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya] yakni Ibnu Sa'id bahwa [Abbad bin Tamim] telah mengabarkan kepadanya, dari [Uwaimir bin Asyqar] bahwa ia telah menyembelih sebelum keberangkatan Rasulullah shallallahu 'alaihi wasallam (untuk menunaikan shalat Idul Adlha). Setelah itu, ia pun menuturkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam pun memerintahkan untuk mengulangi penyembelihan hewan kurbannya."},"2303":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ عَنْ مُحَمَّدِ بْنِ كَعْبٍ الْقُرَظِيِّ عَنْ كَثِيرِ بْنِ السَّائِبِ قَالَ حَدَّثَنِي ابْنَا قُرَيْظَةَأَنَّهُمْ عُرِضُوا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ قُرَيْظَةَ فَمَنْ كَانَ مِنْهُمْ مُحْتَلِمًا أَوْ نَبَتَتْ عَانَتُهُ قُتِلَ وَمَنْ لَا تُرِكَ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Ja'far Al Khathmi] dari [Muhammad bin Ka'ab Al Qurazhi] dari [Katsir bin Sa`ib] ia berkata, telah menceritakan kepadaku [Ibnu Quraizhah] bahwa mereka (yakni Bani Quraizhah) diringkus ke hadapan Nabi shallallahu 'alaihi wasallam pada peperangan Quraizhah. Siapa di antara mereka yang telah mencapai Ihtilam (mimpi basah), atau rambut kemaluannya telah tumbuh, maka ia dibunuh, sedangkan yang belum, maka akan dilepaskan."},"2304":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنِ الْحُصَيْنِ بْنِ مِحْصَنٍأَنَّ عَمَّةً لَهُ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حَاجَةٍ فَفَرَغَتْ مِنْ حَاجَتِهَا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَذَاتُ زَوْجٍ أَنْتِ قَالَتْ نَعَمْ قَالَ كَيْفَ أَنْتِ لَهُ قَالَتْ مَا آلُوهُ إِلَّا مَا عَجَزْتُ عَنْهُ قَالَ فَانْظُرِي أَيْنَ أَنْتِ مِنْهُ فَإِنَّمَا هُوَ جَنَّتُكِ وَنَارُكِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] ia berkata, telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Al Hushain bin Mihshan] bahwa bibinya pernah mendatangi Nabi shallallahu 'alaihi wasallam untuk suatu keperluan. Setelah urusannya selesai, Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya: \"Apakah kamu mempunyai suami?\" ia menjawab, \"Ya.\" Beliau bertanya lagi: \"Bagaimanakah sikapmu terhadapnya?\" ia menjawab, \"Saya tidak pernah mengabaikannya, kecuali terhadap sesuatu yang memang aku tidak sanggup.\" Beliau bersabda: \"Camkanlah selalu, akan posisimu terhadapnya. Sesungguhnya yang menentukan surga dan nerakamu terdapat pada (sikapmu terhadap) suamimu.\""},"2305":{"ar":"حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي الْعَبَّاسِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ قَالَ أَخْبَرَنِي رَجُلٌ يُقَالُ لَهُ رَبِيعَةُ بْنُ عَبَّادٍ مِنْ بَنِي الدِّيلِ وَكَانَ جَاهِلِيًّا قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَاهِلِيَّةِ فِي سُوقِ ذِي الْمَجَازِ وَهُوَ يَقُولُ يَا أَيُّهَا النَّاسُ قُولُوا لَا إِلَهَ إِلَّا اللَّهُ تُفْلِحُوا وَالنَّاسُ مُجْتَمِعُونَ عَلَيْهِ وَوَرَاءَهُ رَجُلٌ وَضِيءُ الْوَجْهِ أَحْوَلُ ذُو غَدِيرَتَيْنِ يَقُولُ إِنَّهُ صَابِئٌ كَاذِبٌ يَتْبَعُهُ حَيْثُ ذَهَبَ فَسَأَلْتُ عَنْهُ فَذَكَرُوا لِي نَسَبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالُوا لِي هَذَا عَمُّهُ أَبُو لَهَبٍحَدَّثَنَا سُرَيْجٌ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ أَبِيهِ عَنْ رَبِيعَةَ بْنِ عَبَّادٍ الدُّؤَلِيِّ وَكَانَ جَاهِلِيًّا فَأَسْلَمَ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ فَقُلْتُ مَنْ هَذَا قَالَ هَذَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْمُطَّلِبِ وَهُوَ يَذْكُرُ النُّبُوَّةَ قُلْتُ مَنْ هَذَا الَّذِي يُكَذِّبُهُ قَالُوا هَذَا عَمُّهُ أَبُو لَهَبٍ قَالَ أَبُو الزِّنَادِ فَقُلْتُ لِرَبِيعَةَ بْنِ عَبَّادٍ إِنَّكَ يَوْمَئِذٍ كُنْتَ صَغِيرًا قَالَ لَا وَاللَّهِ إِنِّي يَوْمَئِذٍ لَأَعْقِلُ أَنِّي لَأَزْفِرُ الْقِرْبَةَ يَعْنِي أَحْمِلُهَا","id":"Telah menceritakan kepada kami [Ibrahim bin Abul Abbas] Telah menceritakan kepada kami [Abdurrahman bin Abuz Zinad] dari [bapaknya] ia berkata, telah mengabarkan kepadaku seorang laki-laki yang biasa dipanggil [Rabi'ah bin Abbad] dari Bani Ad Dil dan ia adalah seorang yang telah mengenyam masa jahiliyah, ia berkata; Saat masih Jahiliyah, saya pernah melihat Nabi shallallahu 'alaihi wasallam di pasar Dzul Majaz. Saat itu, beliau bersabda: \"Wahai sekalian manusian, ucapkanlah, 'LAA ILAAHA ILLALLAH, niscaya kalian akan selamat.\" Maka orang-orang pun mengerumuninya, sementara di belakangnya ada seorang laki-laki yang berwajah tampan, bermata juling dan rambut terjalin dua bagian, si laki-laki berkata, \"Dia adalah seorang yang murtad (keluar dari agama nenek moyangnya) dan pendusta.\" Laki-laki itu selalu mengikutinya kemana pun beliau pergi. Maka saya pun menanyakan siapa lelaki itu, mereka pun menurutkan nasab Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Laki-laki ini adalah pamannya, yakni Abu Lahab. Telah menceritakan kepada kami [Suraij] Telah menceritakan kepada kami [Ibnu Abu Zinad] dari [bapaknya] dari [Rabi'ah bin Abbad Ad Du`ali] ia adalah seorang yang mengenyam masa jahiliyah dan kemudian memeluk Islam. Ia berkata; Saya pernah melihat Rasulullah shallallahu 'alaihi wasallam, kemudian ia pun menyebutkan hadits. Rabi'ah berkata; Saya bertanya, \"Siapakah orang ini?\" ia menjawab, \"Ia adalah Muhammad bin Abdullah bin Abdul Muthalib.\" Ia pun menyebutkan tentang kenabian. Kemudian saya bertanya lagi, \"Siapakah orang yang selalu mendustakannya ini?\" mereka menjawab, \"Orang ini adalah pamannya, yakni Abu Lahab.\" Abu Zinad berkata; Saya berkata kepada Rabi'ah bin Abbad, \"Sesungguhnya pada hari itu kamu masih kecil.\" Ia menjawab, \"Tidak, demi Allah. Pada hari itu saya telah mencapai masa aqil baligh. Saya benar-benar telah mampu membawa Qirbah (kantong kulit untuk menyimpan air).\""},"2306":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَبُو الْأَشْهَبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ طَرَفَةَأَنَّ جَدَّهُ عَرْفَجَةَ أُصِيبَ أَنْفُهُ يَوْمَ الْكُلَابِ فِي الْجَاهِلِيَّةِ فَاتَّخَذَ أَنْفًا مِنْ وَرِقٍ فَأَنْتَنَ عَلَيْهِ فَأَمَرَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَتَّخِذَ أَنْفًا مِنْ ذَهَبٍقَالَ يَزِيدُ فَقِيلَ لِأَبِي الْأَشْهَبِ أَدْرَكْتَ عَبْدَ الرَّحْمَنِ جَدَّهُ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abu Asyhab] dari [Abdurrahman bin Tharafah] bahwa [kakeknya, Arfajah], hidungnya terlepas pada masa jahiliyah pada peristiwa kulab, maka ia pun memasang hidung yang terbuat dari Waraq (sejenis mata uang logam dirham), dan akhirnya hidungnya itu membusuk. Maka Nabi shallallahu 'alaihi wasallam menyuruhnya untuk memasang hidung dari emas. Yazid berkata; Dan telah ditanyakan kepada Abu Al Asyhab, \"Apakah kamu mendapati kakeknya, Abdurrahman?\" ia menjawab, \"Ya.\" "},"2307":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ مُعَاوِيَةَ يَعْنِي ابْنَ صَالِحٍ عَنِ الْعَلَاءِ يَعْنِي ابْنَ الْحَارِثِ عَنْ حَرَامِ بْنِ حَكِيمٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ أَنَّهُسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَمَّا يُوجِبُ الْغُسْلَ وَعَنْ الْمَاءِ يَكُونُ بَعْدَ الْمَاءِ وَعَنْ الصَّلَاةِ فِي بَيْتِي وَعَنْ الصَّلَاةِ فِي الْمَسْجِدِ وَعَنْ مُؤَاكَلَةِ الْحَائِضِ فَقَالَ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ وَأَمَّا أَنَا فَإِذَا فَعَلْتُ كَذَا وَكَذَا فَذَكَرَ الْغُسْلَ قَالَ أَتَوَضَّأُ وُضُوئِي لِلصَّلَاةِ أَغْسِلُ فَرْجِي ثُمَّ ذَكَرَ الْغُسْلَ وَأَمَّا الْمَاءُ يَكُونُ بَعْدَ الْمَاءِ فَذَلِكَ الْمَذْيُ وَكُلُّ فَحْلٍ يُمْذِي فَأَغْسِلُ مِنْ ذَلِكَ فَرْجِي وَأَتَوَضَّأُ وَأَمَّا الصَّلَاةُ فِي الْمَسْجِدِ وَالصَّلَاةُ فِي بَيْتِي فَقَدْ تَرَى مَا أَقْرَبَ بَيْتِي مِنْ الْمَسْجِدِ وَلَأَنْ أُصَلِّيَ فِي بَيْتِي أَحَبُّ إِلَيَّ مِنْ أَنْ أُصَلِّيَ فِي الْمَسْجِدِ إِلَّا أَنْ تَكُونَ صَلَاةً مَكْتُوبَةً وَأَمَّا مُؤَاكَلَةُ الْحَائِضِ فَآكِلْهَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Mu'awiyah] yakni Ibnu Shalih, dari [Al Ala`] yakni Ibnul Harits, dari [Haram bin Hakim] dari [pamannya, Abdullah bin Sa'd] bahwa ia pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai hal apa saja yang mewajibkan seseorang mandi. Kemudian tentang air yang keluar setelah keluarnya air mani, tentang shalat di rumahku, shalat di Masjid, dan tentang makan bersama wanita yang sedang haid. Maka beliau menjawab, \"Sesungguhnya Allah tidak malu terhadap kebenaran. Adapun saya, jika melakukan ini dan itu, -beliau pun menyebutkan tentang mandi dan bersabda- saya berwudlu sebagaimana wudlu untuk shalat, kemudian saya mencucui kemaluanku -kemudian beliau menyebut tentang mandi-. Adapun air yang keluar setelah keluarnya mani, maka itu adalah Madzi, setiap laki-laki akan mengeluarkan madzi, karena itu, saya pun mencuci kemaluanku darinya, baru kemudian saya shalat. mengenai shalat di Masjid dan shalat di rumahku, maka kamu telah melihat betapa dekatnya rumahku dari Masjid, maka shalat di rumahku lebih aku sukai daripada shalat di rumah, kecuali shalat wajib. Kemudian mengenai makan bersama orang yang haid, maka makanlah bersamanya.\""},"2308":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا مُعَاوِيَةُ بْنُ صَالِحٍ عَنِ الْعَلَاءِ بْنِ الْحَارِثِ عَنْ حَرَامِ بْنِ حَكِيمٍ عَنْ عَمِّهِ عَبْدِ اللَّهِ بْنِ سَعْدٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُؤَاكَلَةِ الْحَائِضِ فَقَالَ وَاكِلْهَا","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Mu'awiyah bin Shalih] dari [Al 'Ala` bin Harits] dari [Haram bin Hakim] dari [pamannya yakni Abdullah bin Sa'd] ia berkata; Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai makan bersama dengan wanita yang sedang haid, maka beliau pun menjawab: \"Makanlah bersamanya.\""},"2309":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا ابْنُ لَهِيعَةَ حَدَّثَنَا بَكْرُ بْنُ سَوَادَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَسْلَمَ مَوْلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لِجَعْفَرِ بْنِ أَبِي طَالِبٍ أَشْبَهْتَ خَلْقِي وَخُلُقِي","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Ibnu Lahi'ah] Telah menceritakan kepada kami [Bakr bin Sawadah] dari [Ubaidullah bin Aslam] bekas budak Nabi shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ja'far bin Abu Thalib: \"Kamu menyerupai wajahku dan juga akhlakku.\""},"2310":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي مَسْعُودٍ يَعْنِي الْجُرَيْرِيَّ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ مَاعِزٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ بِاللَّهِ وَحْدَهُ ثُمَّ الْجِهَادُ ثُمَّ حَجَّةٌ بَرَّةٌ تَفْضُلُ سَائِرَ الْعَمَلِ كَمَا بَيْنَ مَطْلَعِ الشَّمْسِ إِلَى مَغْرِبِهَاحَدَّثَنَا هُدْبَةُ بْنُ خَالِدٍ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنِ الْجُرَيْرِيِّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ حَدَّثَنَا مَاعِزٌ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْأَعْمَالِ أَفْضَلُ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Mas'ud] yakni Al Jurairi dari [Yazid bin Abdullah Asy Syikhkhir] dari [Ma'iz] dari Nabi shallallahu 'alaihi wasallam bahwa beliau pernah ditanya mengenai amalan apakah yang paling utama. Beliau menjawa: \"Yaitu, beriman kepada Allah, jihad di jalan Allah, dan Haji yang mabrur melebihi seluruh amal baik, sebagaimana jarak antara tempat terbitnya matahari hingga tempat terbenamnya.\" Telah menceritakan kepada kami [Hudbah bin Khalid] Telah menceritakan kepada kami [Wuhaib bin Khalid] dari [Al Jurairi] dari [Hayyan bin Umair] Telah menceritakan kepada kami [Ma'iz] bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai amalan yang paling utama. Maka ia pun menyebutkan hadits yang sama."},"2311":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبَّادُ بْنُ رَاشِدٍ قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ ثَنَا أَحْمَرُ بْنُ جَزِيٍّ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَإِنْ كُنَّا لَنَأْوِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّا يُجَافِي مِرْفَقَيْهِ عَنْ جَنْبَيْهِ إِذَا سَجَدَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Abbad bin Rasyid] ia berkata, saya mendengar [Al Hasan] berkata, Telah menceritakan kepada kami [Ahmar bin Jazi'] salah seorang dari sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata; Kami benar-benar bernaung kepada Rasulullah shallallahu 'alaihi wasallam, saat beliau merenggangkan kedua sikunya dari pinggangnya ketika beliau sujud."},"2312":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا كَثِيرُ بْنُ زَيْدٍ عَنِ الْمُطَّلِبِ بْنِ عَبْدِ اللَّهِ عَنْ عِتْبَانَ أَوْ ابْنِ عُتْبَانَ الْأَنْصَارِيِّ قَالَقُلْتُ أَيْ نَبِيَّ اللَّهِ إِنِّي كُنْتُ مَعَ أَهْلِي فَلَمَّا سَمِعْتُ صَوْتَكَ أَقْلَعْتُ فَاغْتَسَلْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَاءُ مِنْ الْمَاءِ","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] Telah menceritakan kepada kami [Katsir bin Zaid] dari [Al Muthallib bn Abdullah] dari ['Ityan atau Ibnu Utban Al Anshari], ia berkata, \"Wahai Nabiyullah, saya pernah bergaul dengan isteriku, dan ketika saya mendengar suaramu, saya pun melepaskannya dan mandi.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keharusan mandi, adalah ketika keluarnya mani.\""},"2313":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ قَالَ قَالَ أَبُو عَبْد الرَّحْمَنِ وَسَمِعْتُهُ أَنَا مِنْ هَارُونَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي حُرَّةَ عَنْ عَمِّهِ حَكِيمِ بْنِ أَبِي حُرَّةَ عَنْ سِنَانِ بْنِ سَنَّةَ صَاحِبِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطَّاعِمُ الشَّاكِرُ لَهُ مِثْلُ أَجْرِ الصَّائِمِ الصَّابِرِحَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَاه أَحْمَدُ بْنُ حَاتِمٍ الطَّوِيلُ حَدَّثَنَا عَبْدُ الْعَزِيزِ الدَّرَاوَرْدِيُّ مِثْلَهُ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] ia berkata, -telah berkata Abu Abdurrahman dan saya mendengarnya dari Harun- Telah menceritakan kepada kami [Abdul Aziz bin Muhammad] ia berkata, telah mengabarkan kepadaku [Muhammd bin Abdullah bin Abu Hurrah] dari [pamannya, Hakim bin Abu Hurrah], dari [Sinan bin Abu Sannah] salah seorang sahabat Nabi shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang yang memberi makan lagi bersyukur, maka baginya seperti pahala seorang yang berpuasa lagi sabar.\" Telah menceritakan kepada kami Abdullah Telah menceritakannya kepada kami [Ahmad bin Hatim Ath Thawil] Telah menceritakan kepada kami [Abdul Aziz Ad Darawardi] hadits semisalnya."},"2314":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حَرْمَلَةَ عَنْ يَحْيَى بْنِ هِنْدٍ أَنَّهُ سَمِعَ حَرْمَلَةَ بْنَ عَمْرٍو وَهُوَ أَبُو عَبْدِ الرَّحْمَنِ قَالَحَجَجْتُ حَجَّةَ الْوَدَاعِ مُرْدِفِي عَمِّي سِنَانُ بْنُ سَنَّةَ قَالَ فَلَمَّا وَقَفْنَا بِعَرَفَاتٍ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا إِحْدَى أُصْبُعَيْهِ عَلَى الْأُخْرَى فَقُلْتُ لِعَمِّي مَاذَا يَقُولُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَقُولُ ارْمُوا الْجَمْرَةَ بِمِثْلِ حَصَى الْخَذْفِ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Wuhaib] Telah menceritakan kepada kami [Abdurrahman bin Harmalah] dari [Yahya bin Hind] bahwa ia telah mendengar [Harmalah bin Amru] ia adalah Abu Abdurrahman, ia berkata; Saya ikut serta dalam haji wada' dengan membonceng di belakang pamanku, Sinan bin Sannah. Ketika kami melakukan wukuf di Arafah, saya melihat Rasulullah shallallahu 'alaihi wasallam salah satu dari dua jarinya di atas jari yang lain. Kemudian saya pun bertanya kepada pamanku, \"Apa yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam?\" ia menjawab; Beliau bersabda: \"Lemparilah jumrah dengan menggunakan batu kerikil.\""},"2315":{"ar":"حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا ابْنُ أَخِي ابْنِ شِهَابٍ عَنْ عَمِّهِ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ بْنِ مَسْعُودٍ أَنَّ شَبْلَ بْنَ حَامِدٍ الْمُزَنِيَّ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ مَالِكٍ الْأَوْسِيَّ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْوَلِيدَةِ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَبِيعُوهَا وَلَوْ بِضَفِيرٍ وَالضَّفِيرُ الْحَبْلُ فِي الثَّالِثَةِ أَوْ فِي الرَّابِعَةِ","id":"Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [Ibnu Akhi Ibnu Syihab] dari [pamannya] ia berkata, telah mengabarkan kepadaku [Ubaidullah bin Abdullah bin Utbah bin Mas'ud] bahwa [Syabl bin Hamid Al Muzani] telah mengabarkan kepadanya, bahwa [Abdullah bin Malik Al Ausi] telah mengabarkan kepadanya, bawha Rasulullah shallallahu 'alaihi wasallam bersabda kepada Al Walidah: \"Jika ia berzina, maka deralah ia. Kemudian jika ia berzina lagi, maka deralah ia. Jika ia berzina lagi, maka deralah ia. Dan jika ia berzina lagi, maka jualah ia, meskipun hanya seharga Ash Shafir.\" Ash Shafir adalah tali. Yakni beliau mengatakannya pada kali yang ketiga atau yang keempat."},"2316":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ حَدَّثَنِي الزُّبَيْدِيُّ عَنِ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ شِبْلَ بْنَ خُلَيْدٍ الْمُزَنِيَّ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ مَالِكٍ الْأَوْسِيَّ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْوَلِيدَةِ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَبِيعُوهَا وَلَوْ بِضَفِيرٍ وَالضَّفِيرُ الْحَبْلُ","id":"Telah menceritakan kepada kami [Yazid bin Abdu Rabbih] Telah menceritakan kepada kami [Baqiyyah bin Al Walid] telah menceritakan kepadaku [Az Zubaidi] dari [Az Zuhri] dari [Ubaidullah bin Abdullah] bahwa [Syibl bin Khulaid Al Muzani] telah mengabarkan kepadanya, bahwa [Abdullah bin Malik Al Ausi] telah mengabarkan kepadanya, bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Al Walidah: \"Jika ia berzina, maka deralah ia. Kemudian jika ia berzina lagi, maka deralah ia. Jika ia berzina lagi, maka deralah ia. Dan jika ia berzina lagi, maka jualah ia, meskipun hanya seharga Ash Shafir.\" Ash Shafir adalah tali."},"2317":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا زَكَرِيَّا عَنِ الشَّعْبِيِّ عَنِ الْحَارِثِ بْنِ مَالِكٍ ابْنِ بَرْصَاءَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُغْزَى مَكَّةُ بَعْدَهَا أَبَدًاقَالَ سُفْيَانُ الْحَارِثُ خُزَاعِيٌّ","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] Telah menceritakan kepada kami [Zakariya] dari [Asy Sya'bi] dari [Harits bin Malik bin Barsha`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kota Makkah tidak akan diperangi setelah pembebasannya, selama-lamanya.\" Sufyan berkata; Al Harits adalah Khuza'i."},"2318":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَخْبَرَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنِ الْحَارِثِ بْنِ مَالِكٍ ابْنِ بَرْصَاءَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ فَتْحِ مَكَّةَ لَا تُغْزَى هَذِهِ بَعْدَهَا أَبَدًا إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] ia berkata, telah mengabarkan kepada kami [Zakariya] dari [Amir] dari [Al Harits bin Malik bin Barsha`] ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada hari penaklukan kota Makkah: \"Kota ini tidak akan diperangi setelah fathu Makkah selama-lamanya hingga datangnya hari kiamat.\""},"2319":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الطَّائِفِيُّ عَنْ عُثْمَانَ بْنِ عَبْدِ اللَّهِ بْنِ أَوْسٍ الثَّقَفِيِّ عَنْ جَدِّهِ أَوْسِ بْنِ حُذَيْفَةَ قَالَكُنْتُ فِي الْوَفْدِ الَّذِينَ أَتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسْلَمُوا مِنْ ثَقِيفٍ مِنْ بَنِي مَالِكٍ أَنْزَلَنَا فِي قُبَّةٍ لَهُ فَكَانَ يَخْتَلِفُ إِلَيْنَا بَيْنَ بُيُوتِهِ وَبَيْنَ الْمَسْجِدِ فَإِذَا صَلَّى الْعِشَاءَ الْآخِرَةَ انْصَرَفَ إِلَيْنَا فَلَا يَبْرَحُ يُحَدِّثُنَا وَيَشْتَكِي قُرَيْشًا وَيَشْتَكِي أَهْلَ مَكَّةَ ثُم��َ يَقُولُ لَا سَوَاءَ كُنَّا بِمَكَّةَ مُسْتَذَلِّينَ أَوْ مُسْتَضْعَفِينَ فَلَمَّا خَرَجْنَا إِلَى الْمَدِينَةِ كَانَتْ سِجَالُ الْحَرْبِ عَلَيْنَا وَلَنَا فَمَكَثَ عَنَّا لَيْلَةً لَمْ يَأْتِنَا حَتَّى طَالَ ذَلِكَ عَلَيْنَا بَعْدَ الْعِشَاءِ قَالَ قُلْنَا مَا أَمْكَثَكَ عَنَّا يَا رَسُولَ اللَّهِ قَالَ طَرَأَ عَنِّي حِزْبٌ مِنْ الْقُرْآنِ فَأَرَدْتُ أَنْ لَا أَخْرُجَ حَتَّى أَقْضِيَهُ فَسَأَلْنَا أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أَصْبَحْنَا قَالَ قُلْنَا كَيْفَ تُحَزِّبُونَ الْقُرْآنَ قَالُوا نُحَزِّبُهُ سِتَّ سُوَرٍ وَخَمْسَ سُوَرٍ وَسَبْعَ سُوَرٍ وَتِسْعَ سُوَرٍ وَإِحْدَى عَشْرَةَ سُورَةً وَثَلَاثَ عَشْرَةَ سُورَةً وَحِزْبُ الْمُفَصَّلِ مِنْ ق حَتَّى تَخْتِمَ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Abdullah bin Abdurrahman Ath Thaifi] dari [Utsman bin Abdullah bin Aus Ats Tsaqafi] dari [kakeknya yakni Aus bin Hudzaifah], ia berkata; Saya berada dalam suatu utusan yang menemui Rasulullah shallallahu 'alaihi wasallam dan menyatakan masuk Islam. Mereka adalah Bani Tsaqif dari Bani Malik. Kami singgah di sebuah kemah milik beliau. Beliau seringkali mendatangi kami yang berada antara rumah beliau dan masjid. Jika beliau selesai shalat isyak (yaitu shalat fardhu terakhir), beliau sering menemui kami, mengajak kami berbincang-bincang dan mengeluhkan quraisy dan juga penduduk Makkah. Kemudian beliau bersabda \"Terus terang tidak sama nasib kita, kita di Makkah dalam keadaan terintimidasi, atau tertindas, ada pun setelah kita mengungsi ke Madinah, keadaan peperangan silih berganti. Terkadang kita yang kalah, dan tak jarang terkadang kita yang menang. Suatu malam beliau tidak menemui sekian lama sehabis isyak. Kata Aus, kami mencoba bertanya \"Wahai rasulullah, apa yang menghalangimu tidak menemui kami? Beliau menjawab \" Maaf, pengelompokan alquran harus kukerjakan, sehingga aku tak bisa pergi hingga aku menyelesaikannya. Pagi harinya kami bertanya sahabat-sahabat Rasulullah, bagaimana kalian mengelompokkan alquran? Mereka jawab \"Kami mengelompokkannya enam surat, lima surat, tujuh surat, Sembilan surat, sebelas surat, tiga belas surat, dan satu hizib (kelompok) yang berisi surat-surat pendek, semenjak surat Qaf hingga khatam."},"2320":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ : مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ أَبِي حَازِمٍ التَّمَّارِّ عَنِ الْبَيَاضِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَى النَّاسِ وَهُمْ يُصَلُّونَ وَقَدْ عَلَتْ أَصْوَاتُهُمْ بِالْقِرَاءَةِ فَقَالَ إِنَّ الْمُصَلِّي يُنَاجِي رَبَّهُ عَزَّ وَجَلَّ فَلْيَنْظُرْ مَا يُنَاجِيهِ وَلَا يَجْهَرْ بَعْضُكُمْ عَلَى بَعْضٍ بِالْقُرْآنِ","id":"(Imam Ahmad) Berkata; Saya telah membacakan kepada [Abdurrahman bin Mahdi]: [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim At Taimi] dari [Abu Hazim At Tammari] dari [Al Bayadli] bahwa Rasulullah shallallahu 'alaihi wasallam keluar menemui para sahabatnya, dan saat itu, mereka sedang menunaikan shalat, sedangkan suara bacaan mereka saling meraung satu sama lain. Maka beliau pun bersabda: \"Seorang yang menunaikan shalat, pada hakekatnya sedang bermunajat kepada Rabb-nya 'azza wajalla. Karena itu, hendaknya setiap orang mencermati doa yang dibacanya, dan janganlah salah seorang di antara kalian mengeraskan bacaan terhadap saudaranya yang lain.\""},"2321":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ عَنْ وُهَيْبٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ حَدَّثَنِي أَبُو أَرْوَى قَالَكُنْتُ أُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ ثُمَّ آتِي الشَّجَرَةَ قَبْلَ غُرُوبِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] dari [Wuhaib] dari [Abu Waqid Al Laitsi] telah menceritakan kepadaku [Abu Arwa] ia berkata; Saya pernah shalat Ashar bersama Nabi shallallahu 'alaihi wasallam, kemudian mendatangi pohon sebelum terbenamnya matahari."},"2322":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ قَالَ حَدَّثَنِي أَبُو حَرْبِ بْنُ أَبِي الْأَسْوَدِ عَنْ فَضَالَةَ اللَّيْثِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْلَمْتُ وَعَلَّمَنِي حَتَّى عَلَّمَنِي الصَّلَوَاتِ الْخَمْسَ لِمَوَاقِيتِهِنَّ قَالَ فَقُلْتُ لَهُ إِنَّ هَذِهِ لَسَاعَاتٌ أُشْغَلُ فِيهَا فَمُرْنِي بِجَوَامِعَ فَقَالَ لِي إِنْ شُغِلْتَ فَلَا تُشْغَلْ عَنْ الْعَصْرَيْنِ قُلْتُ وَمَا الْعَصْرَانِ قَالَ صَلَاةُ الْغَدَاةِ وَصَلَاةُ الْعَصْرِ","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] Telah menceritakan kepada kami [Husyaim] ia berkata, telah mengabarkan kepada kami [Dawud bin Abu Hind] ia berkata, telah menceritakan kepadaku [Abu Harb bin Abul Aswad] dari [Fadlalah Al Laitsi] ia berkata; Saya mendatangi Nabi shallallahu 'alaihi wasallam dan akhirnya memeluk Islam. Kemudian beliau pun mengajariku sehingga beliau mengajarkanku shalat lima waktu beserta waktu-waktunya. Maka saya pun berkata kepada beliau, \"Sesungguhnya waktu-waktu ini merupakan saat-saat sibuk. Karena itu, perintahkanlah kepadaku sesuatu yang (nilainya) menyeluruh.\" Maka beliau pun bersabda kepadaku: \"Jika kamu benar-benar sibuk, maka jangan sampai kamu tersibukkan dari dua waktu.\" Saya bertanya, \"Apakah kedua waktu itu?\" beliau menjawab: \"Yaitu, shalat subuh dan shalat Ashar.\""},"2323":{"ar":"قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ عَلِيُّ بْنُ زَيْدٍ أَخْبَرَنَا عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ مَالِكِ بْنِ الْحَارِثِ رَجُلٍ مِنْهُمْ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ ضَمَّ يَتِيمًا بَيْنَ أَبَوَيْنِ مُسْلِمَيْنِ إِلَى طَعَامِهِ وَشَرَابِهِ حَتَّى يَسْتَغْنِيَ عَنْهُ وَجَبَتْ لَهُ الْجَنَّةُ الْبَتَّةَ وَمَنْ أَعْتَقَ امْرَأً مُسْلِمًا كَانَ فَكَاكَهُ مِنْ النَّارِ يُجْزِي بِكُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْهُ مِنْ النَّارِ","id":"Telah menceritakan kepada kami [Husyaim] ia berkata, [Ali bin Zaid] telah mengabarkan kepada kami dari [Zurarah bin Aufa] dari [Malik bin Harits] yakni seorang laki-laki dari mereka, bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menyerahkan seorang anak yatim pada dua orang tua muslim dengan memenuhi kebutuhan makan dan minumnya hingga anak itu ter cukupi, maka wajib baginya surga. Dan barangsiapa yang memerdekakan satu orang budak muslim, maka budak itu akan menjadi tebusannya dari api neraka. Setiap anggota badan budak itu, akan menjadi tebusan untuk setiap anggota tubuhnya.\""},"2324":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ زَيْدِ بْنِ جُدْعَانَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ عَمْرِو بْنِ مَالِكٍ أَوْ مَالِكِ بْنِ عَمْرٍو كَذَا قَالَ سُفْيَانُ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ ضَمَّ يَتِيمًا بَيْنَ أَبَوَيْهِ فَلَهُ الْجَنَّةُ الْبَتَّةَ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Ali bin Zaid bin Jud'an] dari [Zurarah bin Aufa] dari [Amru bin Malik] -atau Malik bin Amr, seperti inilah yang dikatakan oleh Sufyan- ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menyerahkan seorang anak yatim pada dua orang tua muslim dengan memenuhi kebutuhan makan dan minumnya hingga anak itu ter cukupi, maka wajib baginya surga.\""},"2325":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أُبَيِّ بْنِ مَالِكٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَدْرَكَ وَالِدَيْهِ أَوْ أَحَدَهُمَا ثُمَّ دَخَلَ النَّارَ مِنْ بَعْدِ ذَلِكَ فَأَبْعَدَهُ اللَّهُ وَأَسْحَقَهُحَدَّثَنَا حَجَّاجٌ حَدَّثَنِي شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى يُحَدِّثُ عَنْ أُبَيِّ بْنِ مَالِكٍ عَنْ النَّبِيِّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Qatadah] menceritakan dari [Zurarah bin Aufa] dari [Ubay bin Malik] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau bersabda: \"Barangsiapa yang mendapati kedua orang tuanya, atau salah satu dari keduanya, kemudian setelah itu ia masuk neraka, maka Allah akan menjaukannya (dari rahmat-Nya) dan membinasakannya.\" Telah menceritakan kepada kami [Hajjaj] telah menceritakan kepadaku [Syu'bah] dari [Qatadah] ia berkata, saya mendengar [Zurarah bin Aufa] menceritakan dari [Ubay bin Malik] dari Nabi shallallahu 'alaihi wasallam."},"2326":{"ar":"قَالَ و حَدَّثَنِي بَهْزٌ قَالَ ثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ رَجُلٍ مِنْ قَوْمِهِ يُقَالُ لَهُ أُبَيُّ بْنُ مَالِكٍ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَدْرَكَ وَالِدَيْهِ أَوْ أَحَدَهُمَا فَدَخَلَ النَّارَ فَأَبْعَدَهُ اللَّهُ","id":"(Imam Ahmad) Berkata; Dan telah menceritakan kepadaku [Bahz] ia berkata, Telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Zurarah bin Aufa] dari seorang laki-laki yang berasal dari kaumnya dan biasa dipanggil [Ubay bin Malik], bahwa ia pernah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mendapati kedua orangtuanya, atau salah satu dari keduanya, kemudian ia masuk neraka, maka Allah menjauhkannya (dari rahmat-Nya).\""},"2327":{"ar":"حَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا ثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ عَفَّانُ فِي حَدِيثِهِ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ مَالِكِ بْنِ عَمْرٍو الْقُشَيْرِيِّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أَعْتَقَ رَقَبَةً مُسْلِمَةً فَهِيَ فِدَاؤُهُ مِنْ النَّارِ قَالَ عَفَّانُ مَكَانَ كُلِّ عَظْمٍ مِنْ عِظَامِ مُحَرِّرِهِ بِعَظْمٍ مِنْ عِظَامِهِ وَمَنْ أَدْرَكَ أَحَدَ وَالِدَيْهِ ثُمَّ لَمْ يُغْفَرْ لَهُ فَأَبْعَدَهُ اللَّهُ وَمَنْ ضَمَّ يَتِيمًا مِنْ بَيْنِ أَبَوَيْنِ مُسْلِمَيْنِ قَالَ عَفَّانُ إِلَى طَعَامِهِ وَشَرَابِهِ حَتَّى يُغْنِيَهُ اللَّهُ وَجَبَتْ لَهُ الْجَنَّةُ","id":"Telah menceritakan kepada kami [Bahz] dan ['Affan] keduanya berkata, Telah menceritakan kepada kami [Hammad bin Salamah] -dalam riwayat lain 'Affan berkata dalam haditsnya- telah mengabarkan kepada kami [Ali bin Zaid] dari [Zurarah bin Aufa] dari [Malik bin Amru Al Qusyairi] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memerdekakan seorang budak wanita muslimah, maka wanita itu akan menjadi tebusan baginya dari neraka.\" Affan berkata, \"Yakni setiap anggota tubuh wanita itu akan menjadi tebusan bagi setiap anggota tubuhnya (dari neraka). Dan barangsiapa yang mendapati salah seorang dari kedua orang tuanya, kemudian ia tidak ampuni dosanya, maka Allah telah menjauhkannya (dari rahmat-Nya). Barangsiapa yang menyerahkan seorang anak yatim pada dua orang tua muslim -Affan berkata- dengan memenuhi kebutuhan makan dan minumnya hingga anak itu ter cukupi, maka wajib baginya surga.\""},"2328":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يُونُسُ بْنُ عُبَيْدٍ عَنْ حُصَيْنِ بْنِ أَبِي الْحُرِّ عَنِ الْخَشْخَاشِ الْعَنْبَرِيِّ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعِي ابْنٌ لِي قَالَ فَقَالَ ابْنُكَ هَذَا قَالَ قُلْتُ نَعَمْ قَالَ لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِقَالَ هُشَيْمٌ مَرَّةً يُونُسُ قَالَ أَخْبَرَنِي مُخْبِرٌ عَنْ حُصَيْنِ بْنِ أَبِي الْحُرِّ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Yunus bin Ubaid] dari [Hushain bin Abu Al Hurr] dari [Al Khasykhasy Al 'Anbari] ia berkata; Saya bersama anakku menemui Rasulullah shallallahu 'alaihi wasallam. kemudian beliau bertanya: \"Apakah ini anakmu?\" saya menjawab, \"Ya.\" Beliau bersabda: \"Janganlah ia berbuat lalim atasmu, dan jangan pula kamu berbuat lalim atasnya.\" Sekali waktu, Husyaim berkata; Yunus telah mengabarkan kepadaku seorang penyampai berita dari Hushain bin Abul Hurr."},"2329":{"ar":"حَدَّثَنَا هِشَامُ بْنُ سَعِيدٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ يَعْنِي أَخَا عَمْرِو بْنِ مُهَاجِرٍ قَالَ حَدَّثَنِي عَقِيلُ بْنُ شَبِيبٍ عَنْ أَبِي وَهْبٍ الْجُشَمِيِّ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِأَسْمَاءِ الْأَنْبِيَاءِ وَأَح��بُّ الْأَسْمَاءِ إِلَى اللَّهِ عَزَّ وَجَلَّ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِ وَأَصْدَقُهَا حَارِثٌ وَهَمَّامٌ وَأَقْبَحُهَا حَرْبٌ وَمُرَّةُ وَارْتَبِطُوا الْخَيْلَ وَامْسَحُوا بِنَوَاصِيهَا وَأَعْجَازِهَا أَوْ قَالَ وَأَكْفَالِهَا وَقَلِّدُوهَا وَلَا تُقَلِّدُوهَا الْأَوْتَارَ وَعَلَيْكُمْ بِكُلِّ كُمَيْتٍ أَغَرَّ مُحَجَّلٍ أَوْ أَشْقَرَ أَغَرَّ مُحَجَّلٍ أَوْ أَدْهَمَ أَغَرَّ مُحَجَّلٍحَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا مُحَمَّدُ بْنُ الْمُهَاجَرِ حَدَّثَنَا عَقِيلُ بْنُ شَبِيبٍ عَنْ أَبِي وَهْبٍ الْكَلَاعِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مَعْنَاهُ قَالَ مُحَمَّدٌ وَلَا أَدْرِي بِالْكُمَيْتِ بَدَأَ أَوْ بِالْأَدْهَمِ قَالَ وَسَأَلُوهُ لِمَ فَضَّلَ الْأَشْقَرَ قَالَ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ سَرِيَّةً فَكَانَ أَوَّلَ مَنْ جَاءَ بِالْفَتْحِ صَاحِبُ الْأَشْقَرِ","id":"Telah menceritakan kepada kami [Hisyam bin Sa'id] Telah menceritakan kepada kami [Muhammad bin Muhajir] yakni saudaranya Amru bin Muhajir, ia berkata, telah menceritakan kepadaku ['Aqil bin Syabib] dari [Abu Wahb Al Jusyami] dan ia termasuk salah seorang dari sahabat Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memberi nama dengan nama-nama para Nabi. Nama yang paling disukai Allah 'azza wajalla adalah Abdullah dan Abdurrahman. Kemudian nama yang paling benar adalah Harits dan Hammam. Sedangkan nama yang paling buruk adalah Harb dan Murrah. Persiapkanlah kuda, sisirlah rambut yang tumbuh pada bagian kening dan juga ekornya. -atau beliau mengatakan- (dan juga) pahanya. Dan pasanglah kalung pada lehernya, dan janganlah kalian memasangkannya kalung Al Autar (sejenis kalung untuk menangkal hasad). Kemudian, hendaklah kalian memilih kuda yang berwrana antara putih dan kemerah-merahan, berbelang putih di wajah dan kaki-kakinya. Atau yang rambutnya berwarna blonde dan berbelan putih di wajah serta kaki-kakinya. Atau yang berwarna hitam, dan berbelang putih di wajah serta kaki-kakitnya.\" Telah menceritakan kepada kami [Abul Mughirah] Telah menceritakan kepada kami [Muhammad bin Muhajir] Telah menceritakan kepada kami [Aqil bin Syabib] dari [Abu Wahb Al Kala'i] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda. Maka ia pun menyebutkan maknanya. Muhammad berkata, \"Saya tidak tahu, apakah beliau mendahulukan Al Kumait ataukah Al Adham.\" Dan orang-orang pun bertanya kepadanya, kenapa ia lebih mendahulukan Al Asyqar?\" ia menjawab, \"Karena Rasulullah shallallahu 'alaihi wasallam pernah mengutus Sariyyah (pasukan khusus yang ditugaskan untuk operasi khusus), ternyata yang pertama kali datang adalah shahibul Asyqar (pasukan kuda yang rambut kudanya berwarna blonde).\""},"2330":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ سُئِلَ عَنْ رَجُلٍ يُسَلِّمُ عَلَيْهِ وَهُوَ غَيْرُ مُتَوَضِّئٍ فَقَالَ ثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنِ الْحُضَيْنِ أَبِي سَاسَانَ عَنِ الْمُهَاجِرِ بْنِ قُنْفُذٍأَنَّهُ سَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَتَوَضَّأُ فَلَمْ يَرُدَّ عَلَيْهِ حَتَّى تَوَضَّأَ فَرَدَّ عَلَيْهِ وَقَالَ إِنَّهُ لَمْ يَمْنَعْنِي أَنْ أَرُدَّ عَلَيْكَ إِلَّا أَنِّي كَرِهْتُ أَنْ أَذْكُرَ اللَّهَ إِلَّا عَلَى طَهَارَةٍقَالَ فَكَانَ الْحَسَنُ مِنْ أَجْلِ هَذَا الْحَدِيثِ يَكْرَهُ أَنْ يَقْرَأَ أَوْ يَذْكُرَ اللَّهَ عَزَّ وَجَلَّ حَتَّى يَتَطَهَّرَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far], bahwa pernah ditanyakan kepadanya tentang seorang laki-laki yang diucapkan salam atasnya, sementara saat itu ia tidak berwudlu, maka ia pun berkata, Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Al Hudlain Abu Sasan] dari [Al Muhajir bin Qunfudz] bahwa ia pernah mengucapkan salam atas Nabi shallallahu 'alaihi wasallam dan saat itu, beliau sedang berwudlu. Namun, beliau tidak membalas salamnya hingga beliau selesai wudlu, baru kemudian beliau membalasnya dan bersabda: \"Sesungguhnya tidak ada yang menghalangiku untuk membalas salammu, kecuali karena saya tidak suka menyebut nama Allah selain dalam keadaan suci.\" Maka berdasarkan hadits inilah, Al Hasan tidak suka membaca atau menyebut nama Allah sehingga ia bersuci."},"2331":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شَيْبَانُ بْنُ عَبْدِ الرَّحْمَنِ عَنِ الرُّكَيْنِ بْنِ الرَّبِيعِ عَنْ أَبِيهِ عَنْ عَمِّهِ فُلَانِ بْنِ عَمِيلَةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ النَّاسُ أَرْبَعَةٌ وَالْأَعْمَالُ سِتَّةٌ فَالنَّاسُ مُوَسَّعٌ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَمُوَسَّعٌ لَهُ فِي الدُّنْيَا مَقْتُورٌ عَلَيْهِ فِي الْآخِرَةِ وَمَقْتُورٌ عَلَيْهِ فِي الدُّنْيَا مُوَسَّعٌ عَلَيْهِ فِي الْآخِرَةِ وَشَقِيٌّ فِي الدُّنْيَا وَالْآخِرَةِ وَالْأَعْمَالُ مُوجِبَتَانِ وَمِثْلٌ بِمِثْلٍ وَعَشْرَةُ أَضْعَافٍ وَسَبْعُ مِائَةِ ضِعْفٍ فَالْمُوجِبَتَانِ مَنْ مَاتَ مُسْلِمًا مُؤْمِنًا لَا يُشْرِكُ بِاللَّهِ شَيْئًا فَوَجَبَتْ لَهُ الْجَنَّةُ وَمَنْ مَاتَ كَافِرًا وَجَبَتْ لَهُ النَّارُ وَمَنْ هَمَّ بِحَسَنَةٍ فَلَمْ يَعْمَلْهَا فَعَلِمَ اللَّهُ أَنَّهُ قَدْ أَشْعَرَهَا قَلْبَهُ وَحَرَصَ عَلَيْهَا كُتِبَتْ لَهُ حَسَنَةً وَمَنْ هَمَّ بِسَيِّئَةٍ لَمْ تُكْتَبْ عَلَيْهِ وَمَنْ عَمِلَهَا كُتِبَتْ وَاحِدَةً وَلَمْ تُضَاعَفْ عَلَيْهِ وَمَنْ عَمِلَ حَسَنَةً كَانَتْ لَهُ بِعَشْرِ أَمْثَالِهَا وَمَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ كَانَتْ لَهُ بِسَبْعِ مِائَةِ ضِعْفٍ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Syaiban bin Abdurrahman] dari [Ar Rukain bin Ar Rabi'] dari [bapaknya] dari [pamannya] yakni Fulan bin Alimah, dari [Khuraim bin Fatik Al Asadi] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Manusia ada empat, sedangkan amalan itu ada enam. Manusia ada yang memiliki kelapangan di dunia dan juga di akhirat. Ada yang memiliki kelapangan di dunia, namun ia fakir di akhirat. Ada yang fakir ketika hidup di dunia, akan tetapi di akhiratnya ia mendapat kelapangan. Kemudian, ada juga yang sengsara di dunia dan di juga di akhirat. Sedangkan amalan itu, adalah yang mendapatkan ganjaran dua kali lipat, semisal amalan itu sendiri, ada yang dilipatkan hingga sepuluh kali, dan ada juga yang dilipat gandakan menjadi seratus tujuh kali. Maka yang pertama, barangsiapa yang mati dalam keadaan muslim, dengan tidak menyekutukan Allah dengan sesuatu apa pun, maka wajib baginya surga. Dan siapa yang mati dalam keadaan kafir, maka wajib baginya neraka. Kemudian, barangsiapa yang bertekad untuk berbuat kebaikan, namun ia belum sempat melakukannya, padahal Allah mengetahui bahwa hatinya telah memiliki keinginan keras untuk melakukan amalan tersebut, maka Allah akan menuliskannya sebagai amalan kebaikan. Dan barangsiapa yang bertekat untuk melakukan kejahatan, maka hal itu belum ditulis sebagai suatu keburukan, dan siapa yang melakukannya, baru akan ditulis baginya satu keburukan dan keburukan itu tidaklah dilipatgandakan. Dan barangsiapa yang beramal kebaikan, maka kebaikan itu, akan dilipatgandakan baginya menjadi sepuluh kebaikan. Kemudian, siapa yang mengeluarkan nafaqah di jalan Allah, akan dilipatgandakan baginya menjadi tujuh ratus kali.\""},"2332":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا زَائِدَةُ حَدَّثَنَا الرُّكَيْنُ بْنُ الرَّبِيعِ بْنِ عَمِيلَةَ الْفَزَارِيُّ عَنْ أَبِيهِ عَنْ يُسَيْرِ بْنِ عَمِيلَةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ كُتِبَتْ بِسَبْعِ مِائَةِ ضِعْفٍ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Amru] Telah menceritakan kepada kami [Za`idah] Telah menceritakan kepada kami [Ar Rukain bin Ar Rabi' bin Amilah Al Fazari] dari [bapaknya] dari [Yusair bin Amilah] dari [Khuraim bin Fatik Al Asadi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang mengeluarkan sedekah di jalan Allah, maka akan ditulis baginya menjadi tujuh ratus kali lipat kebaikan.\""},"2333":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا أَبُو بَكْرٍ يَعْنِي ابْنَ عَيَّاشٍ عَنْ أَبِي إِسْحَاقَ عَنْ شَمْرِ بْنِ عَطِيَّةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ الْأَسَدِيِّ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِعْمَ الرَّجُلُ أَنْتَ يَا خُرَيْمُ لَوْلَا خُلَّتَانِ قَالَ قُلْتُ وَمَا هُمَا يَا رَسُولَ اللَّهِ قَالَ إِسْبَالُكَ إِزَارَكَ وَإِرْخَاؤُكَ شَعْرَكَ","id":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Abu Bakr] yakni Ibu 'Ayyasy, dari [Ibnu Ishaq] dari [Syamr bin Athiyyah] dari [Khuraim bin Fatik Al Asadi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Senikmat-nikmat laki-laki adalah kamu, wahai Khuraim, kalau bukan karena dua hal.\" Saya bertanya, \"Apakah kedua hal itu wahai Rasulullah?\" beliau menjawab: \"Isbalnya kainmu (menjulurnya hingga melewati kedua mata kaki), dan rambutmu yang panjang.\""},"2334":{"ar":"حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنِ الرُّكَيْنِ بْنِ الرَّبِيعِ بْنِ عَمِيلَةَ الْفَزَارِيِّ عَنْ أَبِيهِ عَنْ يُسَيْرِ بْنِ عَمِيلَةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ تُضَاعَفُ بِسَبْعِ مِائَةِ ضِعْفٍ","id":"Telah menceritakan kepada kami [Husain bin Ali] dari [Zaidah] dari [Ar Rukain bin Ar Rabi' bin Amilah Al Fazari] dari [bapaknya] dari [Yusair bin Amilah] dari [Khuraim bin Fatik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membelanjakan hartanya di jalan Allah, maka pahalanya akan dilipatgandakan menjadi tujuh ratus kali.\""},"2335":{"ar":"حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا الْمَسْعُودِيُّ عَنِ الرُّكَيْنِ بْنِ الرَّبِيعِ عَنْ أَبِيهِ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَعْمَالُ سِتَّةٌ وَالنَّاسُ أَرْبَعَةٌ فَمُوجِبَتَانِ وَمِثْلٌ بِمِثْلٍ وَالْحَسَنَةُ بِعَشْرِ أَمْثَالِهَا وَالْحَسَنَةُ بِسَبْعِ مِائَةٍ فَأَمَّا الْمُوجِبَتَانِ مَنْ مَاتَ لَا يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ الْجَنَّةَ وَمَنْ مَاتَ يُشْرِكُ بِاللَّهِ شَيْئًا دَخَلَ النَّارَ وَأَمَّا مِثْلٌ بِمِثْلٍ فَمَنْ هَمَّ بِحَسَنَةٍ حَتَّى يُشْعِرَهَا قَلْبَهُ وَيَعْلَمُ اللَّهُ عَزَّ وَجَلَّ ذَلِكَ مِنْهُ كُتِبَتْ لَهُ حَسَنَةً وَمَنْ عَمِلَ سَيِّئَةً كُتِبَتْ عَلَيْهِ سَيِّئَةً وَمَنْ عَمِلَ حَسَنَةً كُتِبَتْ لَهُ بِعَشْرِ أَمْثَالِهَا وَمَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ فَحَسَنَةٌ بِسَبْعِ مِائَةٍ وَالنَّاسُ أَرْبَعَةٌ مُوَسَّعٌ عَلَيْهِ فِي الدُّنْيَا مَقْتُورٌ عَلَيْهِ فِي الْآخِرَةِ وَمُوَسَّعٌ عَلَيْهِ فِي الْآخِرَةِ مَقْتُورٌ عَلَيْهِ فِي الدُّنْيَا وَمُوَسَّعٌ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ وَمَقْتُورٌ عَلَيْهِ فِي الدُّنْيَا وَالْآخِرَةِ","id":"Telah menceritakan kepada kami [Abu An Nadlr] Telah menceritakan kepada kami [Al Mas'udi] dari [Ar Rukain bin Ar Rabi'] dari [bapaknya] dari [Khuraim bin Fatik] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"(Balasan) amalan itu ada enam, sedangkan manusia ada empat (golongan). Yaitu, Mujibatan (amalan yang mendapatkan dua balasan) Mitslu bi Mitslin (amalan yang mendapat dengan balasan yang setimpal), amalan yang akan dilipatgandakan menjadi sepuluh kebaikan, dan amalan kebaikan yang dilipatgandakan menjadi tujuh ratus. Adapun Mujibatan adalah; siapa saja yang meninggal dalam keadaan tidak menyekutukan Allah dengan sesuatu apapun, maka dia akan masuk surga. Dan barangsiapa yang meninggal dalam keadaan menyekutukan Allah dengan sesuatu yang lain, maka ia akan masuk neraka. (Adapun) Mitslu bi Mitslin; Siapa yang berkeinginan untuk melakukan kebaikan hingga hatinya merasakannya, dan Allah pun tahu akan hal itu, maka hal itu akan ditulis baginya menjadi satu kebaikan. Dan barangsiapa yang beramal baik, maka akan dicatat baginya sepuluh kebaikan semisalnya. Dan siapa yang memberikan nafkah di jalan Allah, maka satu kebaikan itu (dilipatgandakan menjadi) tujuh ratus kali. Sedangkan manusia itu ada empat yaitu; (pertama) seorang yang mendapat kelapangan di dunia, namun di akhirat yang ia dapatkan adalah kesempitan. (kedua) seorang yang mendapat kelapangan di akhirat, namun ia selalu berada dalam kesempitan di dunia. (yang ketiga) seorang yang mendapat kelapangan di dunia maupun di akhirat. Dan (yang keempat) seorang yang mendapat kesempitan baik di dunia maupun di akhirat.\""},"2336":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ جَابِرٍ قَالَ سَمِعْتُ الشَّعْبِيَّ قَالَ أَشْهَدُ عَلَى أَبِي سَعِيدِ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّتْ بِهِ جِنَازَةٌ فَقَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Jabir] ia berkata, saya mendengar [Asy Sya'bi] berkata; Saya telah bersaksi atas [ Abu Sa'id bin Zaid], bahwa ketika jenazah lewat di hadapan Rasulullah shallallahu 'alaihi wasallam, beliau berdiri."},"2337":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ رَجُلٍ حَدَّثَهُ مُؤَذِّنُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمٍ مَطِيرٍ صَلُّوا فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Hajjaj] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Dinar] dari [Amru bin Aus] dari [seorang laki-laki] telah menceritakan kepadanya [Muadzin] Nabi shallallahu 'alaihi wasallam, ia berkata; Muadzin Rasulullah shallallahu 'alaihi wasallam menyerukan saat hujan turun, \"SHALLUU FII RIHAALIKUM (Shalatlah di rumah-rumah kalian).\""},"2338":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أُخْبِرْتُ عَنْ أَبِي الزِّنَادِ حَدَّثَنِي مُرَقِّعُ بْنُ صَيْفِيٍّ التَّمِيمِيُّ شَهِدَ عَلَى جَدِّهِ رِيَاحِ بْنِ رُبَيِّعٍ الْحَنْظَلِيِّ الْكَاتِبِ أَنَّهُ أَخْبَرَهُ أَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَ حَدِيثِ ابْنِ أَبِي الزِّنَادِ قَالَ حَدَّثَنَا أَبُو عَامِرٍ قَالَ ثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ قَالَ أَخْبَرَنِي الْمُرَقِّعُ بْنُ صَيْفِيٍّ عَنْ جَدِّهِ رِيَاحِ بْنِ رُبَيِّعٍ أَخِي حَنْظَلَةَ الْكَاتِبِ أَنَّهُ أَخْبَرَهُ أَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا الْمُغِيرَةُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي الزِّنَادِ قَالَ حَدَّثَنِي مُرَقِّعُ بْنُ صَيْفِيٍّ قَالَ حَدَّثَنِي جَدِّي رِيَاحُ بْنُ رُبَيِّعٍ أَخِي حَنْظَلَةَ الْكَاتِبِأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ عَلَى مُقَدِّمَتِ��ِ خَالِدُ بْنُ الْوَلِيدِ فَذَكَرَ رِيَاحًا وَأَصْلَهُ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah dikabarkan [(oleh seseorang)] kepadaku dari [Abu Zinad] telah menceritakan kepadaku [Muraqqi'u bin Shaifi At Tamimi] bahwa ia menyaksikan [kakeknya yakni Riyah bin Rubayyi' Al Hanzhali Al Katib], bahwa ia telah mengabarkan kepadanya bahwasanya; Suatu hari, ia keluar bersama Rasulullah shallallahu 'alaihi wasallam. lalu ia pun menyebutkan hadits semisal hadits Ibnu Abu Zinad. Ia berkata; Telah menceritakan kepada kami [Ibnu Amir] ia berkata, Telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Zinad] ia berkata, telah mengabarkan kepadaku [Al Muraqqi'u bin Shaifi] dari [kakeknya] yakni Riyah bin Rubayyi' saudaranya Hanzhalah Al Katib, bahwa ia telah mengabarkan kepadanya bahwasanya; Ia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam. ia pun menyebutkan hadits. Ia berkata; Telah menceritakan kepada kami [Sa'id bin Manshur] ia berkata, Telah menceritakan kepada kami [Al Mughirah bin Abdurrahman] dari [Abu Zinad] ia berkata, telah menceritakan kepadaku [Muraqqi' bin Shaifi] ia berkata, [kakekku, Riyah bin Rubayyi'] saudaranya Hanzhalah Al Katib, bahwasanya; Ia pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam pada suatu peperangana atas komando Khalid bin Walid. Ia pun menyebutkan Riyah dan asalnya. Lalu ia menyebutkan hadits."},"2339":{"ar":"حَدَّثَنَا أَبُو أَحْمَدَ الزُّبَيْرِيُّ حَدَّثَنَا سُفْيَانُ عَنِ الْجُرَيْرِيِّ عَنْ أَبِي عُثْمَانَ عَنْ حَنْظَلَةَ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا الْجَنَّةَ وَالنَّارَ حَتَّى كَانَا رَأْيَ عَيْنٍ فَقُمْتُ إِلَى أَهْلِي فَضَحِكْتُ وَلَعِبْتُ مَعَ أَهْلِي وَوَلَدِي فَذَكَرْتُ مَا كُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجْتُ فَلَقِيتُ أَبَا بَكْرٍ فَقُلْتُ يَا أَبَا بَكْرٍ نَافَقَ حَنْظَلَةُ قَالَ وَمَاذَاكَ ذَاكَ قُلْتُ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْنَا الْجَنَّةَ وَالنَّارَ حَتَّى كَانَا رَأْيَ عَيْنٍ فَذَهَبْتُ إِلَى أَهْلِي فَضَحِكْتُ وَلَعِبْتُ مَعَ وَلَدِي وَأَهْلِي فَقَالَ إِنَّا لَنَفْعَلُ ذَاكَ قَالَ فَذَهَبْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ يَا حَنْظَلَةُ لَوْ كُنْتُمْ تَكُونُونَ فِي بُيُوتِكُمْ كَمَا تَكُونُونَ عِنْدِي لَصَافَحَتْكُمْ الْمَلَائِكَةُ وَأَنْتُمْ عَلَى فُرُشِكُمْ وَبِالطُّرُقِ يَا حَنْظَلَةُ سَاعَةً وَسَاعَةً","id":"Telah menceritakan kepada kami [Abu Ahmad Az Zubairi] Telah menceritakan kepada kami [Sufyan] dari [Al Jurairi] dari [Abu Utsman] dari [Hanzhalah] ia berkata; Suatu ketika, kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, lalu beliau menyebutkan tentang surga dan neraka, hingga seolah-olah mata melihatnya. Setelah itu saya beranjak pulang menemui keluargaku, dan saat itu aku pun tertawa bersama isteri dan anakku. Kemudian aku teringat, akan perasaanku saat berada di sisi Rasulullah shallallahu 'alaihi wasallam, lalu aku keluar dan berjumpa dengan Abu Bakr. Aku pun berkata, \"Wahai Abu Bakr, Hanzhalah telah munafik.\" Ia bertanya, \"Kenapa bisa begitu?\" saya berkata, \"Ketika kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, beliau mengingatkan kami surga dan neraka hingga seakan-akan mata melihatnya. Namun setelah itu, saya pulang menemui keluargaku, dan saya pun tertawa dan bermain-main bersama anak dan isteriku.\" Abu Bakar berkata, \"Sesungguhnya kami juga melakukan hal yang demikian.\" Maka aku pun menemui Nabi shallallahu 'alaihi wasallam dan menuturkan hal itu pada beliau. Beliau bersabda: \"Wahai Hanzhalah, sekiranya saat kalian berada di rumah-rumah kalian, sebagaimana saat kalian berada di sisiku, niscaya malaikat akan menyalami kalian. Dan saat kalian berada di rumah atau di jalan, maka (ingatlah sewaktu) waktu.\""},"2340":{"ar":"حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا عِمْرَانُ يَعْنِي الْقَطَّانَ عَنْ قَتَادَةَ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الشِّخِّيرِ عَنْ حَنْظَلَةَ الْأُسَيِّدِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا إِذَا كُنَّا عِنْدَكَ كُنَّا فَإِذَا فَارَقْنَاكَ كُنَّا عَلَى غَيْرِ ذَلِكَ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ كُنْتُمْ تَكُونُونَ عَلَى الْحَالِ الَّذِي تَكُونُونَ عَلَيْهَا عِنْدِي لَصَافَحَتْكُمْ الْمَلَائِكَةُ وَلَأَظَلَّتْكُمْ بِأَجْنِحَتِهَا","id":"Telah menceritakan kepada kami [Abu Dawud Ath Thiyalisi] Telah menceritakan kepada kami [Imran] yakni Al Qaththan, dari [Qatadah] dari [Yazid bin Abdullah Asy Syikhkir] dari [Hanzhalah Al Usaidi] ia berkata; Saya berkata, \"Jika kami berada di sisimu, maka (iman) kami (kuat), namun setelah kami meninggalakan Anda, kami tidak lagi seperti itu.\" Maka beliau pun bersabda: \"Demi Dzat yang jiwaku berada di tangan-Nya, sekiranya keadaan kalian seperti saat kalian berada di sisiku, niscaya malaikat menyalami kalian dan menaungi kalian dengan sayap-sayapnya.\""},"2341":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبُو هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ سَوَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٍ مِنْ بَنِي عَبْدِ اللَّهِ بْنِ كَعْبٍ قَالَأَغَارَتْ عَلَيْنَا خَيْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ يَتَغَدَّى فَقَالَ ادْنُ فَكُلْ قُلْتُ إِنِّي صَائِمٌ قَالَ اجْلِسْ أُحَدِّثْكَ عَنْ الصَّوْمِ أَوْ الصِّيَامِ إِنَّ اللَّهَ عَزَّ وَجَلَّ وَضَعَ عَنْ الْمُسَافِرِ شَطْرَ الصَّلَاةِ وَعَنْ الْمُسَافِرِ وَالْحَامِلِ وَالْمُرْضِعِ الصَّوْمَ أَوْ الصِّيَامَ وَاللَّهِ لَقَدْ قَالَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كِلَاهُمَا أَوْ أَحَدُهُمَافَيَا لَهْفَ نَفْسِي هَلَّا كُنْتُ طَعِمْتُ مِنْ طَعَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا أَبُو هِلَالٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَوَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ رَجُلٍ مِنْ بَنِي عَبْدِ اللَّهِ بْنِ كَعْبٍ وَلَيْسَ بِالْأَنْصَارِيِّ قَالَ أَغَارَتْ عَلَيْنَا خَيْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ الْحَدِيثَ قَالَ عَبْد اللَّهِ و حَدَّثَنَاه شَيْبَانُ حَدَّثَنَا أَبُو هِلَالٍ قَالَ فَذَكَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Abu Hilal] dari [Abdullah bin Sawadah] dari [Anas bin Malik] -ia adalah seorang laki-lakid ari Bani Abdullah bin Ka'ab, ia berkata; Kuda Rasulullah shallallahu 'alaihi wasallam tiba-tiba menyerang kami, maka saya pun mendatangi beliau yang sedang makan. Maka beliau berkata: \"Mendekat dan makanlah.\" saya berkata, 'Sesungguhnya, saya sedang berpuasa.\" Beliau bersabda: \"Duduklah, saya akan menceritakanmu tentang shaum atau Shiyam. Sesungguhnya Allah 'azza wajalla meringankan setengah shalat untuk musafir. Dan meringankan shaum bagi Musafir, wanita hamil dan menyusui. Demi Allah, kedua hal itu telah disabdakan oleh Rasulullah shallallahu 'alaihi wasallam. Keduanya atau salah satu dari keduanya berkata \"Duhai, kemarilah, saya telah diberi makan dari makanan Rasulullah shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Abu HIlal] Telah menceritakan kepada kami [Abdullah bin Sawadah] dari [Anas bin Malik] seorang laki-laki dari Bani Abdullah bin Ka'ab dan bukan Al Anshari. Ia berkata; Kuda Rasulullah shallallahu 'alaihi wasallam tiba-tiba menyerang kami. Maka ia pun menyebutkan hadits itu. Abdullah berkata; Dan Telah menceritakannya kepada kami [Syaiban] Telah menceritakan kepada kami [Abu Hilal] ia berkata; Maka ia pun menyebutkan hadits semisalnya."},"2342":{"ar":"حَدَّثَنَا الْحُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَرِيكٌ وَيَزِيدُ بْنُ عَطَاءٍ عَنْ يَزِيدَ يَعْنِي ابْنَ أَبِي زِيَادٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَابِطٍ عَنْ عَيَّاشِ بْنِ أَبِي رَبِيعَةَ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَزَالُ هَذِهِ الْأُمَّةُ بِخَيْرٍ مَا عَظَّمُوا هَذِهِ الْحُرْمَةَ حَقَّ تَعْظِيمِهَا فَإِذَا تَرَكُوهَا وَضَيَّعُوهَا هَلَكُوا وَقَالَ فِي حَدِيثِ يَزِيدَ بْنِ عَطَاءٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ يَزِيدَ عَنِ ابْنِ سَابِطٍ عَنِ الْمُطَّلِبِ أَوْ عَنِ الْعَيَّاشِ بْنِ أَبِي رَبِيعَةَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Al Husain bin Muhammad] Telah menceritakan kepada kami [Syarik] dan [Yazid bin Atah`] dari [Yazid bin Abu Ziyad] dari [Abdurrahman bin Sabith] dari [Ayyasy bin Abu Rabi'ah] ia berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Umat ini akan senantiasa berada dalam kebaikan, selama mereka memuliakan Hurmah (kesucian) ini dengan sebaik-baik pengagungan. Dan jika mereka telah meninggalkan dan meremehkannya, niscaya mereka akan binasa.\" Dan ia berkata dalam haditsnya Yazid bin Atha` dari Nabi shallallahu 'alaihi wasallam. Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Syarik] dari [Yazid bin Tsabith] dari [Al Muthallib] atau [Al Ayyas bin Abu Rabi'ah] ia berkata; Saya mendengar. Lalu ia pun menyebutkan hadits semisalnya."},"2343":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ أَبِي نَوْفَلِ بْنِ أَبِي عَقْرَبٍ عَنْ أَبِيهِ قَالَسَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الصَّوْمِ فَقَالَ صُمْ مِنْ الشَّهْرِ يَوْمًا قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي أَقْوَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي أَقْوَى إِنِّي أَقْوَى صُمْ يَوْمَيْنِ مِنْ كُلِّ شَهْرٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ زِدْنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زِدْنِي زِدْنِي ثَلَاثَةَ أَيَّامٍ مِنْ كُلِّ شَهْرٍ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al Aswad bin Syaiban] dari [Abu Naufal bin Abu 'Aqrab] dari [bapaknya] ia berkata; Saya bertanya kepada Nabi shallallahu 'alaihi wasallam tentang shaum (puasa). Beliau menjawab: \"Berpuasalah satu hari dari setiap bulan.\" Saya berkata, \"Wahai Rasulullah, saya lebih kuat dari itu.\" beliau bersabda: \"Saya kuat, saya kuat, berpuasalah dua hari dari setiap bulan.\" Saya berkata, \"Wahai Rasulullah, tambahkanlah lagi.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tambahkan lagi, tambahkan lagi, berpuasalah tiga hari dari setiap bulannya.\""},"2344":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْجَعْدُ عَنِ الْحَسَنِ بْنِ عَبْدِ اللَّهِ أَنَّ عَمْرَو بْنَ عُبَيْدِ اللَّهِ حَدَّثَهُ أَنَّهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَلَ كَتِفًا ثُمَّ قَامَ فَمَضْمَضَ فَصَلَّى وَلَمْ يَتَوَضَّأْ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] Telah menceritakan kepada kami [Al Ja'd] dari [Al Hasan bin Abdullah] bahwa [Amru bin Ubaid] telah menceritakan kepadanya, bahwa ia berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam makan bahu kambing, kemudian beliau berdiri dan berkumur-kumur lalu shalat dengan tidak berwudlu lagi."},"2345":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا زَمْعَةُ عَنْ عِيسَى بْنِ يَزْدَادَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَالَ أَحَدُكُمْ فَلْيَنْتُرْ ذَكَرَهُ ثَلَاثًا قَالَ زَمْعَةُ مَرَّةً فَإِنَّ ذَلِكَ يُجْزِئُ عَنْهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Zam'ah] dari [Isa bin Yazdad] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian kencing, hendaklah ia menarik zakarnya tiga kali.\" Zam'ah berkata; \"Sekali (saja), karena hal itu telah mencukupinya.\""},"2346":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَاقَ عَنْ عِيسَى بْنِ يَزْدَادَ بْنِ فَسَاءَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَالَ أَحَدُكُمْ فَلْيَنْتُرْ ذَكَرَهُ ثَلَاثَ مَرَّاتٍ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Zakariya bin Ishaq] dari [Isa bin Yazdad bin Fasa`ah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian kencing, hendaklah ia menarik zakarnya tiga kali.\""},"2347":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ ثَابِتٍ الْبُنَ��نِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي لَيْلَى قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةٍ لَيْسَتْ بِفَرِيضَةٍ فَمَرَّ بِذِكْرِ الْجَنَّةِ وَالنَّارِ فَقَالَ أَعُوذُ بِاللَّهِ مِنْ النَّارِ وَيْحٌ أَوْ وَيْلٌ لِأَهْلِ النَّارِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Ibnu Abu Laila] dari [Tsabit Al Banani] dari [Abdurrahman bin Abu Laila] dari [Abu Laila] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam membaca ayat di dalam shalat, namun bukan shalat wajib. Kemudian beliau melewati penyebutan Surga dan neraka, maka beliau pun membaca: \"Aku berlindung kepada Allah dari api neraka -atau- kecelakaanlah bagi penghuni neraka.\""},"2348":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي لَيْلَى عَنْ أَخِيهِ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ الْحَسَنُ بْنُ عَلِيٍّ يَحْبُو حَتَّى صَعِدَ عَلَى صَدْرِهِ فَبَالَ عَلَيْهِ قَالَ فَابْتَدَرْنَاهُ لِنَأْخُذَهُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْنِي ابْنِي قَالَ ثُمَّ دَعَا بِمَاءٍ فَصَبَّهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Ibnu Abu Laila] dari [saudaranya, Isa bin Abdurrahman], dari [bapaknya] dari [kakeknya], ia berkata; Kami berada di sisi Rasulullah shallallahu 'alaihi wasallam, kemudian datanglah Hasan bin Ali, ia merayap hingga menaiki dada beliau dan kencing. Maka kami pun segera beranjak hendak mengambilnya, namun Nabi shallallahu 'alaihi wasallam bersabda: \"Anakku.., anakku.\" Kemudian beliau meminta air dan menuangkan ke atasnya."},"2349":{"ar":"حَدَّثَنَا أَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِي لَيْلَى أَنَّهُكَانَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى بَطْنِهِ الْحَسَنُ أَوْ الْحُسَيْنُ شَكَّ زُهَيْرٌ قَالَ فَبَالَ حَتَّى رَأَيْتُ بَوْلَهُ عَلَى بَطْنِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَسَارِيعَ قَالَ فَوَثَبْنَا إِلَيْهِ قَالَ فَقَالَ عَلَيْهِ الصَّلَاة وَالسَّلَامُ دَعُوا ابْنِي أَوْ لَا تُفْزِعُوا ابْنِي قَالَ ثُمَّ دَعَا بِمَاءٍ فَصَبَّهُ عَلَيْهِ قَالَ فَأَخَذَ تَمْرَةً مِنْ تَمْرِ الصَّدَقَةِ قَالَ فَأَدْخَلَهَا فِي فِيهِ قَالَ فَانْتَزَعَهَا رَسُولُ اللَّهِ مِنْ فِيهِ","id":"Telah menceritakan kepada kami [Aswad bin Amir] Telah menceritakan kepada kami [Zuhair] dari [Abdullah bin Isa] dari [Isa bin Abdurrahman bin Abu Laila] dari [Abu Laila] bahwa ia pernah berada di sisi Rasulullah shallallahu 'alaihi wasallam. Saat itu, beliau sedang menggendong Hasan atau Husain -Zuhari ragu-, lalu anak itu kencing hingga saya melihat air kencingnya mengalir di perut Rasulullah shallallahu 'alaihi wasallam dan membasahi kainnya. Kami pun segera melompat hendak mengambilnya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Biarkan anakku -atau- janganlah kalian mengagetkannya.\" Kemudian beliau meminta air, lalu menuangkan ke atasnya. Kemudian anak itu mengambil satu biji dari kurma sedekah dan memasukkan ke dalam mulutnya, namun Rasulullah shallallahu 'alaihi wasallam segera menariknya kembali dari mulutnya."},"2350":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ قَيْسِ بْنِ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتْحَ خَيْبَرَ فَلَمَّا انْهَزَمُوا وَقَعْنَا فِي رِحَالِهِمْ فَأَخَذَ النَّاسُ مَا وَجَدُوا مِنْ خُرْثِيٍّ فَلَمْ يَكُنْ أَسْرَعَ مِنْ أَنْ فَارَتْ الْقُدُورُ قَالَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْقُدُورِ فَأُكْفِئَتْ وَقَسَمَ بَيْنَنَا فَجَعَلَ لِكُلِّ عَشَرَةٍ شَاةً","id":"Telah menceritakan kepada kami [Zakariya bin Adi] Telah menceritakan kepada kami [Ubaidullah bin Amru] dari [Zaid bin Abu Unaisah] dari [Qais bin Muslim] dari [Abdurrahman bin Abu Laila] dari [bapaknya] ia berkata; Saya ikut serta dalam penaklukan Khaibar bersama Rasulullah shallallahu 'alaihi wasallam. Ketika mereka kalah dan terpukul mundur, kami pun memasuki kediaman mereka, sehingga orang-orang pun mengambil apa yang mereka dapatkan dari berbagai perabot rumah dan perhiasannya. Dengan tidak secepat kuali yang mendidih, Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk (menumpahkan kuali itu), maka kuali itu pun ditumpahkan. Kemudian Rasulullah shallallahu 'alaihi wasallam membagikan untuk setiap orangnya sepuluh ekor kambing."},"2351":{"ar":"حَدَّثَنَا حَسَنُ بْنُ مُوسَى حَدَّثَنَا زُهَيْرٌ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ أَبِيهِ عَنْ جَدِّهِ عَنْ أَبِي لَيْلَى قَالَكُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى صَدْرِهِ أَوْ بَطْنِهِ الْحَسَنُ أَوْ الْحُسَيْنُ قَالَ فَرَأَيْتُ بَوْلَهُ أَسَارِيعَ فَقُمْنَا إِلَيْهِ فَقَالَ دَعُوا ابْنِي لَا تُفْزِعُوهُ حَتَّى يَقْضِيَ بَوْلَهُ ثُمَّ أَتْبَعَهُ الْمَاءَ ثُمَّ قَامَ فَدَخَلَ بَيْتَ تَمْرِ الصَّدَقَةِ وَدَخَلَ مَعَهُ الْغُلَامُ فَأَخَذَ تَمْرَةً فَجَعَلَهَا فِي فِيهِ فَاسْتَخْرَجَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ إِنَّ الصَّدَقَةَ لَا تَحِلُّ لَنَا","id":"Telah menceritakan kepada kami [Hasan bin Musa] Telah menceritakan kepada kami [Zuhair] dari [Abdullah bin Isa] dari [bapaknya] dari [kakeknya] dari [Abu Laila] ia berkata; Saya berada di sisi Rasulullah shallallahu 'alaihi wasallam yang sedang menggendong Hasan atau Husain, lalu saya melihat air kencingnya mengalir, maka saya segera berdiri ke arahnya, Maka beliau pun bersabda: \"Biarkan anakku, janganlah kalian mengagetkannya hingga ia selesai kencing.\" Setelah itu, beliau mengikutinya dengar siraman air, kemudian beliau berdiri dan masuk bersama anak itu ke dalam rumah penyimpanan kurma sedekah. Lalu anak itu mengambil satu biji kurma dan meletakkan di mulutnya, maka Nabi shallallahu 'alaihi wasallam pun mengeluarkannya dan bersabda: \"Sesungguhnya harta sedekah tidak halal bagi kami.\""},"2352":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ وَسَمِعْتُهُ أَنَا مِنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ عَنِ ابْنِ أَبِي لَيْلَى عَنْ ثَابِتٍ قَالَكُنْتُ جَالِسًا مَعَ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى فِي الْمَسْجِدِ فَأُتِيَ بِرَجُلٍ ضَخْمٍ فَقَالَ يَا أَبَا عِيسَى قَالَ نَعَمْ قَالَ حَدِّثْنَا مَا سَمِعْتَ فِي الْفِرَاءِ فَقَالَ سَمِعْتُ أَبِي يَقُولُ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَى رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أُصَلِّي فِي الْفِرَاءِ قَالَ فَأَيْنَ الدِّبَاغُفَلَمَّا وَلَّى قُلْتُ مَنْ هَذَا قَالَ هَذَا سُوَيْدُ بْنُ غَفَلَةَ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] dan -saya mendengarnya dari Abdullah bin Muhammad bin Abu Syaibah- Telah menceritakan kepada kami [Ali bin Hasyim] dari [Ibnu Abu Laila] dari [Tsabit] ia berkata; saya pernah duduk bersama [Abdurrahman bin Abu Laila] di dalam masjid. Lalu didatangkanlah seorang laki-laki yang besar badannya dan berkata, \"Wahai Abu Isa.\" Ia menjawab, \"Ya.\" Laki-laki berkata lagi, \"Ceritakanlah kepada kami apa yang telah Anda dengar tentang Al Firaa` (kulit).\" Maka ia berkata; Saya mendengar [bapakku] berkata; Saya pernah duduk di sisi Nabi shallallahu 'alaihi wasallam, lalu datanglah seorang laki-laki dan berkata, \"Wahai Rasulullah, apakah saya boleh shalat di atas kulit?\" beliau bersabda: \"Kalau begitu, di manakah Ad Dibaagh (proses penyamakan kulit)?\" ketika orang itu berlalu, saya bertanya, \"Siapakah orang ini?\" beliau menjawab: \"Ini adalah Suwaid bin Ghafalah.\""},"2353":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ حَدَّثَنَا عَلِيُّ بْنُ عَابِسٍ عَنْ أَبِي فَزَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ فِيمَا أَعْلَمُ شَكَّ مُوسَىأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَكَفَ فِي قُبَّةٍ مِنْ خُوصٍ","id":"Telah menceritakan kepada kami Abdullah Telah menceritakan kepada kami [Musa bin Dawud] Telah menceritakan kepada kami [Ali bin Abis] dari [Abu Fazarah] dari [Abdurrahman bin Abu Laila] dari [bapaknya] menurut apa yang saya ketahui -Musa ragu-ragu- bahwa Nabi shallallahu 'alaihi wasallam melakukan i'tikaf di dalam Kubah yang terbuat dari daun kurma."},"2354":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَأَبُو مَعْمَرٍ وَمُحَمَّدُ بْنُ حَسَّانَ السَّمْتِيُّ قَالُوا ثَنَا عَلِيُّ بْنُ عَابِسٍ عَنْ أَبِي فَزَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْتَكَفَ فِي قُبَّةٍ مِنْ خُوصٍ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Abu Ma'mar] dan [Muhammad bin Hassan As Samti] mereka berkata, Telah menceritakan kepada kami [Ali bin Abis] dari [Abu Fazarah] dari [Abdurrahman bin Abu Laila] dari [bapaknya] ia berkata; Saya melihat Nabi shallallahu 'alaihi wasallam melakukan i'tikaf di dalam Qubah yang terbuat dari daun kurma."},"2355":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ فَإِذَا ارْتَفَعَتْ فَارَقَهَا فَإِذَا كَانَتْ فِي وَسَطِ السَّمَاءِ قَارَنَهَا فَإِذَا دَلَكَتْ أَوْ قَالَ زَالَتْ فَارَقَهَا فَإِذَا دَنَتْ لِلْغُرُوبِ قَارَنَهَا فَإِذَا غَرُبَتْ فَارَقَهَا فَلَا تُصَلُّوا هَذِهِ الثَّلَاثَ سَاعَاتٍ","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abdullah Ash Shunabihi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari itu terbit di antara dua tanduk dari dua syetan. Jika ia meninggi, maka ia pun meninggalkannya. Jika matahari telah berada di tengah-tengah langit, syetan itu kembali menyertainya. Dan saat matahari menyingsing/condong ke arah barat, maka syetan itu meninggalkannya. kemudian, saat matahari mulai akan terbenam, syetan kembali menyertainya. Dan setelah terbenam, ia pun meninggalkannya. karena itu, janganlah kalian shalat pada tiga waktu ini.\""},"2356":{"ar":"حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ أَبُو غَسَّانَ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ مَضْمَضَ وَاسْتَنْشَقَ خَرَّتْ خَطَايَاهُ مِنْ فِيهِ وَأَنْفِهِ وَمَنْ غَسَلَ وَجْهَهُ خَرَجَتْ خَطَايَاهُ مِنْ أَشْفَارِ عَيْنَيْهِ وَمَنْ غَسَلَ يَدَيْهِ خَرَجَتْ مِنْ أَظْفَارِهِ أَوْ مِنْ تَحْتِ أَظْفَارِهِ وَمَنْ مَسَحَ رَأْسَهُ وَأُذُنَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ رَأْسِهِ أَوْ شَعَرِ أُذُنَيْهِ وَمَنْ غَسَلَ رِجْلَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ أَظْفَارِهِ أَوْ تَحْتَ أَظْفَارِهِ ثُمَّ كَانَتْ خُطَاهُ إِلَى الْمَسْجِدِ نَافِلَةًحَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي عَبْدِ اللَّهِ الصُّنَابِحِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَمَضْمَضَ وَاسْتَنْثَرَ خَرَجَتْ خَطَايَاهُ مِنْ أَنْفِهِ وَفَمِهِ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Sa'id] bekas budak Bani Hasyim, Telah menceritakan kepada kami [Muhammad bin Mutharrif Abu Ghassan] Telah menceritakan kepada kami [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abu Abdullah Ash Shunabihi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berkumur-kumur dan istinsyaaq (memasukkan air ke hidung lalu mengeluarkannya kembali), maka dosa-dosanya akan berjatuhan dari mulut dan hidungnya. Dan barangsiapa yang membasuh wajahnya, maka dosa-dosanya akan keluar dari bulu matanya. Dan siapa yang membasuh kedua tangannya, maka dosa-dosanya akan keluar dari kuku-kukunya atau dari bawah kuku-kukunya. Dan siapa yang mengusap kepala dan kedua telinganya, maka dosa-dosanya akan keluar dari kepala atau dari rambut kedua telinganya. Dan barangsiapa yang mencuci kedua kakinya, maka dosa-dosanya akan keluar dari kuku-kuku kakinya, atau dari bawah kukunya. kemudian langkah kaki yang ia ayunkan akan terhitung sebagai amalan sunnah.\" Telah menceritakan kepada kami [Husain bin Muhammad] Telah menceritakan kepada kami [Muhammad bin Mutharrif] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abu Abdullah Ash Shunabihi] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang berkumur-kumur dan intitsar (memasukkan air ke hidung lalu mengeluarkannya kembali), maka dosa-dosanya akan berjatuhan dari hidung dan mulutnya.\" Lalu ia pun menyebutkan maknanya."},"2357":{"ar":"حَدَّثَنَا عَتَّابُ بْنُ زِيَادٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُبَارَكٍ أَخْبَرَنَا خَالِدُ بْنُ سَعِيدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنِ الصُّنَابِحِيِّ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِبِلِ الصَّدَقَةِ نَاقَةً مُسِنَّةً فَغَضِبَ وَقَالَ مَا هَذِهِ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي ارْتَجَعْتُهَا بِبَعِيرَيْنِ مِنْ حَاشِيَةِ الصَّدَقَةِ فَسَكَتَ","id":"Telah menceritakan kepada kami ['Attab Bin Ziyad] Telah menceritakan kepada kami [Abdullah bin Mubarak] telah mengabarkan kepada kami [Khalid Bin Sa'id] dari [Qais Bin Abi Hazim] dari [Ash Sunabihi], ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat unta yang berumur satu tahun di segerombolan unta zakat, maka beliau marah dan bersabda; \"Apa ini?\" dia menjawab; \"Wahai Rasulullah, aku akan mengembalikannya dengan ganti dengan dua ekor unta dari hewan zakat.\" maka beliau pun diam."},"2358":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا الصَّلْتُ يَعْنِي ابْنَ الْعَوَّامِ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ وَهْبٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الصُّنَابِحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَنْ تَزَالَ أُمَّتِي فِي مَسَكَةٍ مَا لَمْ يَعْمَلُوا بِثَلَاثٍ مَا لَمْ يُؤَخِّرُوا الْمَغْرِبَ بِانْتِظَارِ الْإِظْلَامِ مُضَاهَاةَ الْيَهُودِ وَمَا لَمْ يُؤَخِّرُوا الْفَجْرَ إِمْحَاقَ النُّجُومِ مُضَاهَاةَ النَّصْرَانِيَّةِ وَمَا لَمْ يَكِلُوا الْجَنَائِزَ إِلَى أَهْلِهَا","id":"Telah menceritakan kepada kami [Ibnu Numair] Telah menceritakan kepada kami [Ash Shalt Bin al 'Awwam] ia berkata, telah menceritakan kepadaku [Al HArits Bin Wahb] dari [Abu Abdurrahman Ash Shunabihi], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ummatku akan tetap berada dalam keteguhan beragama selagi mereka tidak melakukan tiga perkara; selagi mereka tidak mengakhirkan waktu maghrib dengan menanti waktu gelap untuk menyelisihi orang-orang Yahudi, selagi mereka tidak mengakhirkan waktu fajar sampai hilangnya bintang untuk menyelisihi orang-orang Nashrani, dan selagi mereka tidak menelantarkan perkara jenazah kepada keluarganya.\""},"2359":{"ar":"قَالَ قَرَأْتُ عَلَى عَبْدِ الرَّحْمَنِ : مَالِكٌ قَالَ وَحَدَّثَنَا إِسْحَاقُ أَخْبَرَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ الصُّنَابِحِيِّ قَالَإِذَا تَوَضَّأَ الْعَبْدُ فَمَضْمَضَ خَرَجَتْ الْخَطَايَا مِنْ أَنْفِهِ فَإِذَا غَسَلَ وَجْهَهُ خَرَجَتْ الْخَطَايَا مِنْ وَجْهِهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَشْفَارِ عَيْنَيْهِ فَإِذَا غَسَلَ يَدَيْهِ خَرَجَتْ خَطَايَاهُ مِنْ يَدَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ يَدَيْهِ فَإِذَا مَسَحَ رَأْسَهُ خَرَجَتْ الْخَطَايَا مِنْ رَأْسِهِ حَتَّى تَخْرُجَ مِنْ أُذُنَيْهِ وَإِذَا غَسَلَ رِجْلَيْهِ خَرَجَتْ الْخَطَايَا مِنْ رِجْلَيْهِ حَتَّى تَخْرُجَ مِنْ تَحْتِ أَظْفَارِ رِجْلَيْهِ ثُمَّ كَانَ مَشْيُهُ إِلَى الْمَسْجِدِ وَصَلَاتُهُ نَافِلَةً لَهُ","id":"(Imam Ahmad) Berkata; Aku telah membacakan kepada [Abdurrahman]; [Malik], ia berkata, Telah menceritakan kepada kami [Ishaq] telah mengabarkan kepadaku [Malik] dari [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Abdullah Ash Shunabihi] ia berkata; \"Apabila seorang hamba berwudlu, kemudian dia berkumur-kumur, maka kesalahan-kesalahannya keluar dari hidungnya, apabila dia membasuh mukanya maka kesalahan-kesalahannya keluar dari mukanya sampai keluar dari bawah tepi pelupuk matanya, apabila dia membasuh kedua tangannya maka kesalahan-kesalahannya akan keluar dari kedua tangannya sampai keluar dari ujung jari-jari kedua tangannya, apabila ia mengusap kepalanya, maka kesalahan-kesalahannya akan keluar dari kepalanya sehingga keluar dari kedua telinganya. Dan apabila ia membasuh kedua kakinya maka kesalahan-kesalahannya akan keluar dari kedua kakinya sehingga keluar dari ujung jari-jari kakinya, kemudian berjalannya menuju masjid serta shalatnya adalah terhitung sunnah baginya.\""},"2360":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ أَنَّهُ سَمِعَ قَيْسًا يَقُولُ سَمِعْتُ الصُّنَابِحِيَّ الْأَحْمَسِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَلَا إِنِّي فَرَطُكُمْ عَلَى الْحَوْضِ وَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تَقْتَتِلُنَّ بَعْدِي","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Isma'il] bahwa mendengar [Qais] berkata, saya mendengar [Ash Shunabihi al Ahmasi] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketahuilah bahwa sayalah yang akan mendahului dan menyambut kalian di telaga, dan sesungguhnya aku berbangga dengan banyaknya jumlah kalian di banding dengan umat yang lain, maka janganlah kalian saling berbunuhan sepeninggalku.\""},"2361":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ وَزُهَيْرُ بْنُ مُحَمَّدٍ قَالَا ثَنَا زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ الصُّنَابِحِيَّ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ الشَّمْسَ تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ فَإِذَا طَلَعَتْ قَارَنَهَا فَإِذَا ارْتَفَعَتْ فَارَقَهَا وَيُقَارِنُهَا حِينَ تَسْتَوِي فَإِذَا زَالَتْ فَارَقَهَا فَصَلُّوا غَيْرَ هَذِهِ السَّاعَاتِ الثَّلَاثِحَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ أَبِي عَبْدِ اللَّهِ بِحَدِيثِ الشَّمْسِ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Malik] dan [Zuhair Bin Muhammad] keduanya berkata, Telah menceritakan kepada kami [Zaid Bin Aslam] dari ['Atha` Bin Yasar] dia berkata, saya mendengar [Abdullah Ash Shunabihi] berkata; Saya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya matahari terbit diantara dua tanduk syaitan, maka apabila dia terbit dia mengiringinya dan apabila dia meninggi dia meninggalkannya, dan mengiringinya tatkala tegak dan apabila tergelincir dia meninggalkannya. Maka lakukanlah shalat di selain pada tiga waktu ini.\" Telah menceritakan kepada kami [Abdurrazzaq] Telah menceritakan kepada kami [Ma'mar] dari [Abu Abdillah], dengan hadis matahari diatas."},"2362":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ أَخْبَرَنِي ابْنُ أَخِي أَبِي رُهْمٍ أَنَّهُ سَمِعَ أَبَا رُهْمٍ الْغِفَارِيَّ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِينَ بَايَعُوا تَحْتَ الشَّجَرَةِ يَقُولُغَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ تَبُوكَ فَلَمَّا فَصَلَ سَرَى لَيْلَةً فَسِرْتُ قَرِيبًا مِنْهُ وَأُلْقِيَ عَلَيَّ النُّعَاسُ فَطَفِقْتُ أَسْتَيْقِظُ وَقَدْ دَنَتْ رَاحِلَتِي مِنْ رَاحِلَتِهِ فَيُفْزِعُنِي دُنُوُّهَا خَشْيَةَ أَنْ أُصِيبَ رِجْلَهُ فِي الْغَرْزِ فَأُؤَخِّرُ رَاحِلَتِي حَتَّى غَلَبَتْنِي عَيْنِي فِي نِصْفِ اللَّيْلِ فَرَكِبَتْ رَاحِلَتِي رَاحِلَتَهُ وَرِجْلُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَرْزِ فَأَصَابَتْ رِجْلَهُ فَلَمْ أَسْتَيْقِظْ إِلَّا بِقَوْلِهِ حَسِّ فَرَفَعْتُ رَأْسِي فَقُلْتُ اسْتَغْفِرْ لِي يَا رَسُولَ اللَّهِ فَقَالَ سَلْ فَقَالَ فَطَفِقَ يَسْأَلُنِي عَمَّنْ تَخَلَّفَ مِنْ بَنِي غِفَارٍ فَأُخْبِرُهُ فَإِذَا هُوَ يَسْأَلُنِي مَا فَعَلَ النَّفَرُ الْحُمْرُ الطُّوَالُ الْقِطَاطُ أَوْ قَالَ الْقِصَارُ عَبْدُ الرَّزَّاقِ يَشُكُّ الَّذِينَ لَهُمْ نَعَمٌ بِشَظِيَّةِ شَرْخٍ قَالَ فَذَكَرْتُهُمْ فِي بَنِي غِفَارٍ فَلَمْ أَذْكُرْهُمْ حَتَّى ذَكَرْتُ رَهْطًا مِنْ أَسْلَمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا يَمْنَعُ أَحَدُ أُولَئِكَ حِينَ تَخَلَّفَ أَنْ يَحْمِلَ عَلَى بَعِيرٍ مِنْ إِبِلِهِ امْرَأً نَشِيطًا فِي سَبِيلِ اللَّهِ فَادْعُوا هَلْ أَنْ يَتَخَلَّفَ عَنْ الْمُهَاجِرِينَ مِنْ قُرَيْشٍ وَالْأَنْصَارِ وَأَسْلَمَ وَغِفَارٍحَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ صَالِحٍ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي ابْنُ أَخِي أَبِي رُهْمٍ الْغِفَارِيِّ أَنَّهُ سَمِعَ أَبَا رُهْمٍ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِينَ بَايَعُوا تَحْتَ الشَّجَرَةِ يَقُولُ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ تَبُوكَ فَنِمْتُ لَيْلَةً بِالْأَخْصَرِ فَسِرْتُ قَرِيبًا مِنْهُ فَذَكَرَ مَعْنَى حَدِيثِ مَعْمَرٍ إِلَّا أَنَّهُ قَالَ فَطَفِقْتُ أُؤَخِّرُ رَاحِلَتِي حَتَّى غَلَبَتْنِي عَيْنِي بَعْضَ اللَّيْلِ وَقَالَ مَا فَعَلَ النَّفَرُ السُّودُ الْجِعَادُ الْقِصَارُ الَّذِينَ لَهُمْ نَعَمٌ بِشَظِيَّةِ شَرْخٍ فَيَرَى أَنَّهُمْ مِنْ بَنِي غِفَارٍ حَدَّثَنَا يَعْقُوبُ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَاقَ وَذَكَرَ ابْنُ شِهَابٍ عَنِ ابْنِ أُكَيْمَةَ اللَّيْثِيِّ عَنِ ابْنِ أَخِي أَبِي رُهْمٍ الْغِفَارِيِّ أَنَّهُ سَمِعَ أَبَا رُهْمٍ كُلْثُومَ بْنَ حُصَيْنٍ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّذِينَ بَايَعُوا تَحْتَ الشَّجَرَةِ يَقُولُ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ تَبُوكَ فَذَكَرَ الْحَدِيثَ إِلَّا أَنَّهُ قَالَ فَطَفِقْتُ أُؤَخِّرُ رَاحِلَتِي عَنْهُ حَتَّى غَلَبَتْنِي عَيْنِي وَقَالَ مَا فَعَلَ النَّفَرُ السُّودُ الْجِعَادُ الْقِصَارُ قَالَ قُلْتُ وَاللَّهِ مَا أَعْرِفُ هَؤُلَاءِ مِنَّا حَتَّى قَالَ بَلَى الَّذِينَ لَهُمْ نَعَمٌ بِشَبَكَةِ شَرْخٍ قَالَ فَتَذَكَّرْتُهُمْ فِي بَنِي غِفَارٍ فَلَمْ أَذْكُرْهُمْ حَتَّى ذَكَرْتُ أَنَّهُمْ رَهْطٌ مِنْ أَسْلَمَ كَانُوا حِلْفًا فِينَا فَقُلْتُ يَا رَسُولَ اللَّهِ أُولَئِكَ رَهْطٌ مِنْ أَسْلَمَ كَانُوا حُلَفَاءَنَا","id":"Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] telah mengkhabarkan kepadaku [keponakan Abu Ruhm] bahwa ia mendengar [Abu Ruhm Al Ghifari] -dan ia termasuk salah seorang dari sahabat Nabi shallallahu 'alaihi wasallam yang ikut berbai'at dibawah pohon (Bai'atu Ridlwan) - berkata; Saya pernah bersama Rasulullah shallallahu 'alaihi wasallam pada perang Tabuk. Tatkala perjalanan membelah malam, aku berjalan dekat dengan beliau, tiba-tiba rasa kantuk menyerangku, maka aku bersegera bangun dan ternyata hewan tungganganku sudah mendekati hewan tunggangannya dan kedekatannya membuat aku terkejut. Karena khawatir kaki beliau yang ada di pelana terserempet maka aku mengakhirkan hewan tunggangankku sampai akhirnya mataku terkatup selama setengah malam. Dan ternyata hewan tungganganku menabrak hewan tunggangan beliau dan kaki beliau yang ada di pelana terserempet, dan aku tidak terbangun kecuali karena suara beliau yang merintih. Maka aku mengangkat kepalaku dan berkata, \"Mintalah ampun untukku wahai Rasulullah.\" Beliau bersabda: \"Mintalah.\" Kemudian beliau pun segera menanyakan orang-orang yang tidak ikut berperang dari Bani Ghifar, akupun memberitahukan kepada beliau dan ternyata beliau menanyakan kepadaku apa yang diperbuat oleh sekelompok orang hitam yang tinggi lagi berambut keriting, atau dia berkata: yang pendek -Abdurrazzaq ragu- yang mereka itu memiliki unta-unta di Syadziyatu Syarkhi. Dia melanjutkan; ' maka aku menyebutkan mereka dari Bani Ghifar, dan tidaklah aku menyebutkan mereka sehingga aku menyebutkan sekelompok orang dari Bani Aslam, dan aku berkata; \"Wahai Rasulullah apa yang mencegah salah seorang dari mereka ketika mereka tidak ikut berperang, untuk memberikan tunggangan diatas unta-unta mereka kepada seseorang yang sigap berada dijalan Allah sehingga mereka menyeru, apakah mereka hendak meninggalkan kaum Muhajirin dari Quraisy, kaum Anshar, Aslam dan Ghifar?\" Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Shalih] [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Ibnu Akhi Abu Ruhm Al Ghifari]  aku mendengar [Abu Ruhm] dan ia termasuk salah satu dari sahabat Nabi shallallahu 'alaihi wasallam yang ikut berbai'at dibawah pohon (Bai'atu Ridlwan) - berkata; Aku berperang bersama dengan Rasulullah shallallahu 'alaihi wasallam pada saat perang Tabuk. Suatu malam aku tidur di Akhsar, dan aku berjalan dekat beliau, lantas ia sebutkan makna hadis Ma'mar, hanya ia mengatakan dengan redaksi \"Maka aku lambatkan untaku hingga aku ketiduran sebagian malam, dan ia bertanya \"Apa yang dilakukan orang-orang hitam yang keriting dan cebol, yang mereka mempunyai unta di Syazhiyah Syarkh?, lantas ia lihat mereka dari bani ghifar. Telah menceritakan kepada kami [Ya'qub] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] dan [Ibnu Syihab] menyebutkan dari [Ibnu Ukaimah Al Laitsi] dari [keponakan Abu Ruhm Al Ghifari] bahwasanya dia telah mendengar [Abu Ruhm] -dan ia termasuk salah satu dari sahabat Nabi shallallahu 'alaihi wasallam yang ikut berbai'at dibawah pohon (Bai'atu Ridlwan) - berkata; Aku berperang bersama dengan Rasulullah shallallahu 'alaihi wasallam pada saat perang Tabuk. Ia pun menyebutkan hadits. Hanya saja ia mengatakan; \"Maka aku bersegera melambatkan hewan tungganganku sampai akhirnya mataku tak kuat menahan kantuk di pertengahan malam.\" Dan dia juga mengatakan; \"Apa yang diperbuat sekelompok orang hitam yang berambut kriting dan pendek?\" dan dia berkata, \"Demi Allah, aku tidak tahu, kalau mereka dari kelompok kami.\" sampai dia berkata; \"Betul, mereka adalah orang-orang yang memiliki unta-unta di Syabakati Syarkhi.\" Ia berkata; Maka aku pun mengingat-ingat Bani Ghifar, namun saya tidak mengingat mereka. Namun akhirnya saya pun ingat, bahwa mereka adalah orang-orang yang mempunyai perjanjian dengan kami. Maka saya berkata, \"Wahai Rasulullah, mereka adalah sekelompok orang dari Bani Aslam dan mereka adalah para sekutu kami.\""},"2363":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ثَوْرٍ قَالَ حَدَّثَنِي رَاشِدُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ لُحَيٍّ عَنْ عَبْدِ اللَّهِ بْنِ قُرْطٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَعْظَمُ الْأَيَّامِ عِنْدَ اللَّهِ يَوْمُ النَّحْرِ ثُمَّ يَوْمُ النَّفْرِ وَقُرِّبَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَمْسُ بَدَنَاتٍ أَوْ سِتٌّ يَنْحَرُهُنَّ فَطَفِقْنَ يَزْدَلِفْنَ إِلَيْهِ أَيَّتُهُنَّ يَبْدَأُ بِهَا فَلَمَّا وَجَبَتْ جُنُوبُهَا قَالَ كَلِمَةً خَفِيَّةً لَمْ أَفْهَمْهَا فَسَأَلْتُ بَعْضَ مَنْ يَلِينِي مَا قَالَ قَالُوا قَالَ مَنْ شَاءَ اقْتَطَعَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Tsaur] ia berkata; telah menceritakan kepadaku [Rasyid Bin Sa'd] dari [Abdullah bin Luhay] dari [Abdullah bin Qurth] bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hari-hari yang paling agung disisi Allah adalah hari Nahr (hari-hari penyembelihan hewan kurban), kemudian hari An Nafr (yakni saat-saat kembali dari Mina ke Madinah).\" Kemudian didekatlan kepada Rasulullah shallallahu 'alaihi wasallam lima atau enam Badanaat (Unta atau sapi yang disembelih di Mekah) untuk beliau sembelih, "},"2364":{"ar":"حَدَّثَنَا أَبُو الْيَمَانِ حَدَّثَنَا إِسْمَاعِيلُ بْنُ عَيَّاشٍ عَنْ بَكْرِ بْنِ زُرْعَةَ الْخَوْلَانِيِّ عَنْ مُسْلِمِ بْنِ عَبْدِ اللَّهِ الْأَزْدِيِّ قَالَجَاءَ عَبْدُ اللَّهِ بْنُ قُرْطٍ الْأَزْدِيُّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْتَ عَبْدُ اللَّهِ بْنُ قُرْطٍ","id":"Telah menceritakan kepada kami [Abul Yaman] Telah menceritakan kepada kami [Isma'il bin Ayyasy] dari [Bakr bin Zur'ah Al Khaulani] dari [Muslim bin Abdullah Al Azdi] ia berkata; Abdulah bin Qurth Al Azdi datang menghadap Rasulullah shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Kamu adalah Abdulah bin Qurth.\""},"2365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو أَخْبَرَنَا أَبُو كَثِيرٍ مَوْلَى اللَّيْثِيِّينَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍأَنَّ رَجُلًا جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا لِي يَا رَسُولَ اللَّهِ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ قَالَ الْجَنَّةُ قَالَ فَلَمَّا وَلَّى قَالَ إِلَّا الدَّيْنَ سَارَّنِي بِهِ جِبْرِيلُ عَلَيْهِ السَّلَام آنِفًا","id":"Telah menceritakan kepada kami [Muhammad bin Bisyr] Telah menceritakan kepada kami [Muhammad bin Amr] telah mengabarkan kepada kami [Abu Katsir] bekas budak Al Laitsiyyin, dari [Muhammad bin Abdullah bin Jahsy] bahwa seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan bertanya, \"Ganjaran apakah bagiku wahai Rasululah, jika aku terbunuh di jalan Allah?\" beliau menjawab, \"Yaitu surga.\" Ketika laki-laki itu berpaling beliau melanjutkan: \"Kecuali (kamu masih memiliki) hutang. Jibril telah membisikiku tadi.\""},"2366":{"ar":"حَدَّثَنَا خَلَفُ بْنُ الْوَلِيدِ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي كَثِيرٍ مَوْلَى الْهِلَالِيِّينَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ جَحْشٍ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ مَاذَا لِي إِنْ قَاتَلْتُ فِي سَبِيلِ اللَّهِ حَتَّى أُقْتَلَ قَالَ الْجَنَّةُ قَالَ فَلَمَّا وَلَّى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا الدَّيْنَ سَارَّنِي بِهِ جِبْرِيلُ عَلَيْهِ السَّلَام","id":"Telah menceritakan kepada kami [Khalaf bin Al Walid] Telah menceritakan kepada kami [Abbad bin Abbad] Telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Katsir] bekas budak Al Hilaliyyin, dari [Muhammad bin Abdullah bin Jahsy] dari [bapaknya] ia berkata; Seorang laki-laki menemui Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, ganjaran apakah untukku, jika aku berperang di jalan Allah hingga terbunuh?\" beliau menjawab: \"Yaitu surga.\" Ketika laki-laki itu berpaling, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kecuali (jika kamu masih memiliki tanggungan) hutang. Jibril 'Alaihis Salam telah membisikkannya padaku.\""},"2367":{"ar":"حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُ النَّاسَ يَوْمَ حُنَيْنٍ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِسَكْرَانَ فَأَمَرَ مَنْ كَانَ مَعَهُ أَنْ يَضْرِبُوهُ بِمَا كَانَ فِي أَيْدِيهِمْ","id":"Telah menceritakan kepada kami [Zaid bin Al Hubbab] Telah menceritakan kepada kami [Usamah bin Zaid] ia berkata, telah menceritakan kepadaku [Az Zuhri] dari [Abdurrahman bin Azhar] ia berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam berjalan di tengah-tengah manusia pada hari Hunain seraya menanyakan kediaman Khalid bin Al Walid. Kemudian didatangkanlah seorang peminum khamer (pemabuk), maka beliau pun memerintahkan orang-orang yang bersamanya untuk memukulinya dengan benda apa saja yang ada di tangan mereka.\""},"2368":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ عَنِ الزُّهْرِيِّ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَاةَ الْفَتْحِ وَأَنَا غُلَامٌ شَابٌّ يَتَخَلَّلُ النَّاسَ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِشَارِبٍ فَأَمَرَ بِهِ فَضَرَبُوهُ بِمَا فِي أَيْدِيهِمْ فَمِنْهُمْ مَنْ ضَرَبَهُ بِنَعْلِهِ وَمِنْهُمْ مَنْ ضَرَبَهُ بِعَصًا وَمِنْهُمْ مَنْ ضَرَبَهُ بِسَوْطٍ وَحَثَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التُّرَابَ","id":"Telah menceritakan kepada kami [Utsman bin Umar] Telah menceritakan kepada kami [Usamah bin Zaid] dari [Az Zuhri] bahwa ia mendengar [Abdurrahman bin Azhar] berkata; Saya melihat Rasulullah shallallahu 'alaihi wasallam pada saat perang Fathu Makkah. Dan saat itu saya masih anak muda belia. Beliau berjalan di tengah-tengah manusia seraya menanyakan kediaman Khalid bin Al Walid. Kemudian didatangkanlah seorang peminum khamer, dan beliau pun memerintahkannya (untuk menghukumnya). Maka mereka pun memukulinya dengan benda-benda yang ada pada tangan mereka. di antara mereka ada yang memukul dengan sendalnya, ada yang memukul dengan tongkat dan ada juga yang memukul dengan cambuk. Dan Rasulullah shallallahu 'alaihi wasallam melemparinya dengan pasir."},"2369":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ عَنْ مَعْمَرٍ عَنِ الزُّهْرِيِّ قَالَ وَكَانَ عَبْدُ الرَّحْمَنِ بْنُ أَزْهَرَ يُحَدِّثُعَنْ خَالِدِ بْنِ الْوَلِيدِ بْنِ الْمُغِيرَةِ خَرَجَ يَوْمَئِذٍ وَكَانَ عَلَى الْخَيْلِ خَيْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ أَزْهَرَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَمَا هَزَمَ اللَّهُ الْكُفَّارَ وَرَجَعَ الْمُسْلِمُونَ إِلَى رِحَالِهِمْ يَمْشِي فِي الْمُسْلِمِينَ وَيَقُولُ مَنْ يَدُلُّ عَلَى رَحْلِ خَالِدِ بْنِ الْوَلِيدِ قَالَ فَمَشَيْتُ أَوْ فَسَعَيْتُ بَيْنَ يَدَيْهِ وَأَنَا مُحْتَلِمٌ أَقُولُ مَنْ يَدُلُّ عَلَى رَحْلِ خَالِدِ بْنِ الْوَلِيدِ حَتَّى تَخَلَّلْنَا عَلَى رَحْلِهِ فَإِذَا خَالِدٌ مُسْتَنِدٌ إِلَى مُؤْخِرَةِ رَحْلِهِ فَأَتَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرَ إِلَى جُرْحِهِ قَالَ الزُّهْرِيُّ وَحَسِبْتُ أَنَّهُ قَالَ وَنَفَثَ فِيهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdurrazaq] dari [Ma'mar] dari [Az Zuhri] ia berkata, bahwa [Abdurrahman bin Azhar] menceritakan dari Khalid bin Al Warid bin Al Mughirah bahwa suatu ia keluar dan saat itu, ia berada di atas kuda, yakni kuda milik Rasulullah shallallahu 'alaihi wasallam. Ibnu Azhar berkata; Kemudian saya melihat Rasulullah shallallahu 'alaihi wasallam setelah Allah menghancurkan kaum kuffar dan kaum muslimin pun telah kembali ke rumah-rumah mereka, beliau berjalan di tengah-tengah kaum muslimin seraya bertanya: \"Siapa yang dapat menunjukkan kediaman Khalid bin Al Walid?\" Maka saya pun berjalan dan berjalan agak cepat di depannya -saat itu, saya sudah muhtalim (aqil balig) - seraya berkata, \"Siapa yang dapat menunjukkan kediaman Khalid bin Al Walid?\" hingga kami pun sampai di kediamannya, sementara Khalid sedang bersandar di belakang rumahnya. Maka Rasulullah shallallahu 'alaihi wasallam pun mendatanginya dan melihat lukanya. Az Zuhri berkata; Dan saya menduga bahwa ia mengatakan; \"Dan Rasulullah shallallahu 'alaihi wasallam meniup ke dalam (lukanya).\""},"2370":{"ar":"حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ وَحَدَّثَ ابْنُ شِهَابٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ كَانَ يُحَدِّثُأَنَّهُ حَضَرَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ كَانَ يَحْثِي فِي وُجُوهِهِمْ التُّرَابَقَالَ أَبِي وَهَذَا يَتْلُو حَدِيثَ الزُّهْرِيِّ عَنْ قَبِيصَةَ فِي شَارِبِ الْخَمْرِ","id":"Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [bapakku] dari [Shalih] Dan -dalam riwayat lain- Telah menceritakan kepada kami [Ibnu Syihab] bahwa [Abdurrahman bin Azhar] menceritakan bahwasanya; \"Ia pernah menghadiri Rasulullah shallallahu 'alaihi wasallam, saat beliau menaburkan pasir pada wajah-wajah mereka.\" Bapakku berkata; Dan orang ini telah membaca hadits Zuhri dari Qabishah mengenai minum khamer."},"2371":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ وَوَكِيعٌ قَالَا ثَنَا إِسْمَاعِيلُ قَالَ حَدَّثَنِي قَيْسٌ عَنِ الصُّنَابِحِيِّ الْأَحْمَسِيِّ قَالَ وَكِيعٌ فِي حَدِيثِهِ الصُّنَابِحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ وَإِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تَقْتَتِلُنَّ بَعْدِي","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dan [Waki'] keduanya berkata, Telah menceritakan kepada kami [Isma'il] ia berkata, telah menceritakan kepadaku [Qais] dari [Ash Shunabihi Al Ahmasi] -Waki' berkata dalam haditsnya- Ash Shunabihi, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sayalah yang akan mendahului kalian untuk memasuki Haudl (telaga), dan saya adalah Nabi yang membanggakan banyaknya jumlah kalian. maka janganlah kalian saling berbunuh-bunuhan setelahku.\""},"2372":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ إِسْمَاعِيلَ بْنِ أَبِي خَالِدٍ قَالَ سَمِعْتُ قَيْسَ بْنَ أَبِي حَازِمٍ قَالَ سَمِعْتُ الصُّنَابِحِيَّ الْبَجَلِيَّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَنَا فَرَطُكُمْ عَلَى الْحَوْضِ وَمُكَاثِرٌ بِكُمْ الْأُمَمَ قَالَ شُعْبَةُ أَوْ قَالَ النَّاسَ فَلَا تَقْتَتِلُنَّ بَعْدِيحَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ إِسْمَاعِيلَ عَنْ قَيْسٍ عَنِ الصُّنَابِحِيِّ الْأَحْمَسِيِّ مِثْلَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Isma'il bin Abu Khalid] ia berkata, saya mendengar [Qais bin Abu Hazim] ia berkata, saya mendengar [Ash Shunabihi Al Bajali] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akulah yang akan mendahului dan menjemput kalian di Telaga, dan saya berbangga dengan banyaknya jumlah kalian terhadap umat yang lain.\" Syu'bah berkata; Atau beliau mengatakan, \"(Terhadap) manusia yang lain. Karena itu, janganlah kalian saling berbunuhan sepeninggalku.\" Telah menceritakan kepada kami [Ibnu Numair] dari [Isma'il] dari [Qais] dari [Ash Shunabihi Al Ahmasi] semisalnya."},"2373":{"ar":"حَدَّثَنَا عَبَّادُ بْنُ عَبَّادِ بْنِ حَبِيبِ بْنِ الْمُهَلَّبِ بْنِ أَبِي صُفْرَةَ الْمُهَلَّبِيِّ أَبُو مُعَاوِيَةَ عَنْ مُجَالِدِ بْنِ سَعِيدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنِ الصُّنَابِحِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي مُكَاثِرٌ بِكُمْ الْأُمَمَ فَلَا تَرْجِعُنَّ بَعْدِي كُفَّارًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍحَدَّثَنَا يُونُسُ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنِ الصُّنَابِحِيِّ وَرُبَّمَا قَالَ الصُّنَابِحِ","id":"Telah menceritakan kepada kami [Abbad bin Abbad bin Habib bin Al Muhallab bin Shufrah Al Muhallabi Abu Mu'awiyah] dari [Mujalid bin Sa'id] dari [Qais bin Abu Hazim] dari [Ash Shunabihi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya berbangga dengan banyaknya jumlah kalian terhadap umat-umat yang lain. Karena itu, janganlah sekali-kali kalian kembali kepada kekafiran sepeninggalku, yaitu sebagian kalian menebas leher sebagian yang lain.\" Telah menceritakan kepada kami [Yunus] dari [Hammad bin Zaid] dari [Ash Shunabihi] dan terkadang ia mengatakan, Ash Shunabih."},"2374":{"ar":"قَالَ قُرِئَ عَلَى سُفْيَانَ وَأَنَا شَاهِدٌ سَمِعْتُ مَعْمَرًا يُحَدِّثُ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَزْهَرَ قَالَجُرِحَ خَالِدُ بْنُ الْوَلِيدِ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُ عَنْ رَحْلِهِ قُلْتُ وَأَنَا غُلَامٌ مَنْ يَدُلُّ عَلَى رَحْلِ خَالِدٍ فَأَتَاهُ وَهُوَ مَجْرُوحٌ فَجَلَسَ عِنْدَهُ","id":"(Imam Ahmad) Berkata; Telah dibacakan kepada [Sufyan] sementara saya menyaksikannya, saya mendengar [Ma'mar] menceritakan dari [Zuhri] dari [Abdurrahman bin Azhar] ia berkata; Khalid bin Walid terluka dan saya melihat Rasulullah shallallahu 'alaihi wasallam menanyakan kediamannya. Saya berkata - dan saat itu saya adalah seorang anak muda--, \"Siapa yang bisa menunjukkan tempat kediaman Khalid?\" kemudian beliau pun mendatanginya, sedangkan Khalid bin Walid dalam keadaan terluka, maka beliau pun duduk di sisinya."},"2375":{"ar":"حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى أَخْبَرَنَا أُسَامَةُ بْنُ زَيْدٍ عَنِ الزُّهْرِيِّ قَالَ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ أَزْهَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ حُنَيْنٍ وَهُوَ يَتَخَلَّلُ النَّاسَ يَسْأَلُ عَنْ رَحْلِ خَالِدِ بْنِ الْوَلِيدِ فَأُتِيَ بِسَكْرَانَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ عِنْدَهُ أَنْ يَضْرِبُوهُ بِمَا كَانَ فِي أَيْدِيهِمْ وَحَثَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التُّرَابَحَدَّثَنَا رَوْحٌ حَدَّثَنَا أُسَامَةُ بْنُ زَيْدٍ حَدَّثَنَا الزُّهْرِيُّ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ أَزْهَرَ الزُّهْرِيُّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَتَخَلَّلُ النَّاسَ يَسْأَلُ عَنْ مَنْزِلِ خَالِدِ بْنِ الْوَلِيدِ فَذَكَرَهُ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنِ ابْنِ إِسْحَاقَ وَثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ أَخْبَرَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنِ الصُّنَابِحِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فَذَكَرَهُ قَالَ يَزِيدُ بْنُ هَارُونَ الصُّنَابِحِيُّ رَجُلٌ مِنْ بَجِيلَةَ مِنْ أَحْمَسَ","id":"Telah menceritakan kepada kami [Shafwan bin 'Isa] Telah mengabarkan kepada kami [Usamah bin Zaid] dari [Az Zuhri] mengatakan, Telah mengabarkan kepada kami [Abdurrahman bin Azhar] mengatakan, Pernah kulihat Rasulullah Shallallahu'alaihiwasallam pada perang Hunain menerobos kerumunan para sahabat, rupanya beliau bertanya kemah Khalid bin alwalid. Lantas seorang pemabuk dikeler. Kemudian Rasulullah Shallallahu'alaihiwasallam menyuruh siapa saja yang disisinya untuk memukulinya dengan benda apa saja yang mereka punyai, dan beliau menaburinya dengan tanah. Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Usamah bin Zaid] Telah menceritakan kepada kami [Az Zuhri] telah menceritakan kepadaku [Abdurrahman bin Azhar Azzuhri] mengatakan, pernah aku melihat Rasulullah shallallahu 'alaihi wasallam menerobos kerumunan para shabaat bertanya persinggahan Khalid bin alwalid, lantas ia mengishakan. Telah menceritakan kepada kami Ya'qub mengatakan, telah menceritakan kepadaku Ayahku dari Ibn Ishaq, dan Telah menceritakan kepada kami Abdullah, maksudnya Ibnul Mubarak Telah mengabarkan kepada kami Ismail bin Abi Khalid dari Qais bin Abi hazim dari Ashshunabihi mengatakan, kudengar Rasulullah shallallahu 'alaihi wasallam bersabda: \" bersabda, lantas ia sebutkan. Sedang Yazid bin harun Assunabihi mengatakan dengan redaksi seorang dari Bajilah dari Ahmas."},"2376":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ قَالَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ يَا رَسُولَ اللَّهِ أَلَا تَسْتَعْمِلُنِي كَمَا اسْتَعْمَلْتَ فُلَانًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَتَلْقَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي غَدًا عَلَى الْحَوْضِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] Telah mengabarkan kepada kami [Syu'bah] dari [Qatadah] dari [Anas bin Malik] dari [Usaid bin Hudlair] Radliallahu Ta'ala 'Anhu, ia berkata, seorang laki-laki dari Anshar bertanya, \"Wahai Rasulullah, tidakkah tuan mempekerjakanku, sebagai tuan telah mempekerjakan si Fulan?\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sepeninggalku, kalian akan menemui sikap-sikap keegoisan, maka bersabarlah hingga kalian menemuiku kelak di telaga (Al Haudl).\""},"2377":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ إِسْحَاقَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ أَخْبَرَنَا يَحْيَى بْنُ أَيُّوبَ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أُمِّهِ فَاطِمَةَ ابْنَةِ حُسَيْنٍ عَنْ عَائِشَةَ أَنَّهَا كَانَتْ تَقُولُكَانَ أُسَيْدُ بْنُ حُضَيْرٍ مِنْ أَفَاضِلِ النَّاسِ وَكَانَ يَقُولُ لَوْ أَنِّي أَكُونُ كَمَا أَكُونُ عَلَى أَحْوَالٍ ثَلَاثٍ مِنْ أَحْوَالِي لَكُنْتُ حِينَ أَقْرَأُ الْقُرْآنَ وَحِينَ أَسْمَعُهُ يُقْرَأُ وَإِذَا سَمِعْتُ خُطْبَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِذَا شَهِدْتُ جِنَازَةً وَمَا شَهِدْتُ جِنَازَةً قَطُّ فَحَدَّثْتُ نَفْسِي بِسِوَى مَا هُوَ مَفْعُولٌ بِهَا وَمَا هِيَ صَائِرَةٌ إِلَيْهِ","id":"Telah menceritakan kepada kami [Ali bin Ishaq] Telah menceritakan kepada kami [Abdullah bin Mubarak] Telah mengabarkan kepada kami [Yahya bin Ayyub] dari [Umarah bin Ghaziyyah] dari [Muhammad bin Abdullah bin Amr] dari [Ibunya yakni Fathimah binti Husain], dari [Aisyah] bahwa ia berkata, \" [Usaid bin Khudair] adalah diantara sahabat yang hebat. Pernah ia katakan; Seandainya aku menghimpun tiga keadaan sekaligus, aku pun bisa melakukannya. Keadaan ketika aku membaca alquran dan saat aku mendengar alquran itu dibaca, ketika aku mendengar khutbah Rasulullah Shallallahu'alaihiwasallam, dan ketika aku menghadiri jenazah. Tidak pernah aku menghadiri jenazah, lantas kubayangkan hatiku dengan selain bagaimana jenazah itu diperlakukan dan apa yang bakalan ditemuinya."},"2378":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُسَيْدِ بْنِ حُضَيْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ قَالَإِنَّ رَجُلًا مِنْ الْأَنْصَارِ تَخَلَّى بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَا تَسْتَعْمِلُنِي كَمَا اسْتَعْمَلْتَ فُلَانًا قَالَ إِنَّكُمْ سَتَلْقَوْنَ بَعْدِي أَثَرَةً فَاصْبِرُوا حَتَّى تَلْقَوْنِي عَلَى الْحَوْضِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Qatadah] menceritakan dari [Anas bin Malik] dari [Usaid bin Hudlair] radliallahu 'anhu, ia berkata; Seorang laki-laki dari Anshar menyendiri bersama Rasulullah shallallahu 'alaihi wasallam, maka ia berkata, \"Tidakkah tuan mempekerjakanku, sebagaimana tuan telah memperkejakan si Fulan?\" beliau bersabda: \"Sesungguhnya akan kalian temui sikap-sikap keegoisan. Karena itu, bersabarlah, hingga kalian menjumpaiku di telaga (Al Haudl).\""},"2379":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِيهِ عَنْ جَدِّهِ عَلْقَمَةَ عَنْ عَائِشَةَ قَالَتْقَدِمْنَا مِنْ حَجٍّ أَوْ عُمْرَةٍ فَتُلُقِّينَا بِذِي الْحُلَيْفَةِ وَكَانَ غِلْمَانٌ مِنْ الْأَنْصَارِ تَلَقَّوْا أَهْلِيهِمْ فَلَقُوا أُسَيْدَ بْنَ حُضَيْرٍ فَنَعَوْا لَهُ امْرَأَتَهُ فَتَقَنَّعَ وَجَعَلَ يَبْكِي قَالَتْ فَقُلْتُ لَهُ غَفَرَ اللَّهُ لَكَ أَنْتَ صَاحِبُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَكَ مِنْ السَّابِقَةِ وَالْقِدَمِ مَا لَكَ تَبْكِي عَلَى امْرَأَةٍ فَكَشَفَ عَنْ رَأْسِهِ وَقَالَ صَدَقْتِ لَعَمْرِي حَقِّي أَنْ لَا أَبْكِي عَلَى أَحَدٍ بَعْدَ سَعْدِ بْنِ مُعَاذٍ وَقَدْ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَالَ قَالَتْ قُلْتُ لَهُ مَا قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ اهْتَزَّ الْعَرْشُ لِوَفَاةِ سَعْدِ بْنِ مُعَاذٍ قَالَتْ وَهُوَ يَسِيرُ بَيْنِي وَبَيْنَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yazid bin Harun] Telah mengabarkan kepada kami [Muhammad bin Amru] dari [bapaknya] dari [kakeknya, Alqamah], dari [Aisyah] ia berkata; Kami kembali dari perjalanan menunaikan haji atau umrah. Kemudian kami dijemput di Dzul Hulaifah. Dan para pemuda dari kalangan Anshar menemui keluarganya, dan mereka pun menjumpai [Usaid bin Hudlair] dan mengabarkan kematian isterinya. Ia pun menutupi kepalanya dan menangis. Aisyah berkata; Saya berkata padanya, \"Semoga Allah mengampunimu. Anda adalah sahabat Rasulullah shallallahu 'alaihi wasallam, Anda juga termasuk mereka yang pertama kali memeluk Islam, lalu kenapa Anda menangis lantaran seorang wanita?\" ia menyingkap kembali penutup kepalanya dan berkata, \"Anda telah berkata benar. Sesungguhnya, hidupku adalah hakku, saya tidak akan menangisi seorang pun setelah Sa'adz bin Mua'dz, dan Rasulullah shallallahu 'alaihi wasallam telah bersabda tentangnya. Aisyah berkata; Saya bertanya kepadanya, \"Apa yang disabdakan Rasulullah shallallahu 'alaihi wasallam tentangnya?\" beliau bersabda: \"Sunggu, Arsy telah bergoncang karena kewafatan Sa'd bin Mu'adz.\" Aisyah berkata, \"Dan ia berjalan di antara aku dan Rasulullah shallallahu 'alaihi wasallam.\""},"2380":{"ar":"حَدَّثَنَا عَفَّانُ قَالَ ثَنَا حَمَّادُ بْنُ سَلَمَةَ أَنْبَأَنَا الْحَجَّاجُ بْنُ أَرْطَأَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُسَيْدِ بْنِ حُضَيْرٍ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَوَضَّئُوا مِنْ لُحُومِ الْإِبِلِ وَلَا تَوَضَّئُوا مِنْ لُحُومِ الْغَنَمِ وَصَلُّوا فِي مَرَابِضِ الْغَنَمِ وَلَا تُصَلُّوا فِي مَبَارِكِ الْإِبِلِ","id":"Telah menceritakan kepada kami [Affan] ia berkata, Telah menceritakan kepada kami [Hammad bin Salamah] Telah memberitakan kepada kami [Al Hajjaj bin Artha`ah] dari [Abdullah bin Abdullah] dari [Abdurrahman bin Abu Laila] dari [Usaid bin Hudlair] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berwudlulah kalian setelah memakan daging Unta, dan janganlah berwudlu setelah mengomsumsi daging kambing. Dan shalatlah di kandang kambing, akan tetapi janganlah kalian shalat di kandang Unta.\" "},"2381":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ الْمَرْوَزِيُّ أَخْبَرَنَا عَبَّادُ بْنُ الْعَوَّامِ حَدَّثَنَا الْحَجَّاجُ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ قَالَ وَكَانَ ثِقَةً قَالَ وَكَانَ الْحَكَمُ يَأْخُذُ عَنْهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُسَيْدِ بْنِ حُضَيْرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ سُئِلَ عَنْ أَلْبَانِ الْإِبِلِ قَالَ تَوَضَّئُوا مِنْ أَلْبَانِهَا وَسُئِلَ عَنْ أَلْبَانِ الْغَنَمِ فَقَالَ لَا تَوَضَّئُوا مِنْ أَلْبَانِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Al Marwazi] Telah mengabarkan kepada kami [Abbad bin Awwam] Telah menceritakan kepada kami [Al Hajjaj] dari [Abdullah bin Abdullah] bekas budak Bani Hasyim, ia berkata -dan ia adalah seorang yang Tsiqqah dan Al Hakam juga mengambil hadits darinya-, dari [Abdurrahman bin Abu Laila] dari [Usaid bin Hudlair] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau pernah ditanya tentang susu Unta. Maka beliau bersabda: \"Berwudlulah kalian setelah meminum susunya.\" Kemudian beliau ditanya tentang susu kambing, maka beliau menjawab: \"Janganlah kalian berwudlu lagi setelah meminumnya.\""},"2382":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ قَالَجَلَبْتُ أَنَا وَمَخْرَمَةُ الْعَبْدِيُّ ثِيَابًا مِنْ هَجَرَ قَالَ فَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَاوَمَنَا فِي سَرَاوِيلَ وَعِنْدَنَا وَزَّانُونَ يَزِنُونَ بِالْأَجْرِ فَقَالَ لِلْوَزَّانِ زِنْ وَأَرْجِحْ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Suwaid bin Qais] ia berkata; Saya dan Makhramah Al Abdi membawa pakaian dari Hajar, kemudian Rasulullah shallallahu 'alaihi wasallam mendatangi kami, lalu beliau melakukan penawaran celana pada kami. Saat itu, kami memiliki tukang timbang yang menimbang dengan mengambil upah. Maka beliau bersabda kepada seorang penimbang: \"Timbanglah dan berilah kelebihan.\""},"2383":{"ar":"حَدَّثَنَا حَجَّاجٌ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ مَالِكٍ أَبِي صَفْوَانَ بْنِ عَمِيرَةَ قَالَبِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رِجْلَ سَرَاوِيلَ قَبْلَ الْهِجْرَةِ فَأَرْجَحَ لِي","id":"Telah menceritakan kepada kami [Hajjaj] Telah menceritakan kepada kami [Syu'bah] dari [Simak] dari [Malik Abu Safwan bin Amirah] ia berkata; \"Saya pernah menjual celana kepada Rasulullah shallallahu 'alaihi wasallam sebelum hijrah, maka beliau pun melebihkannya.\""},"2384":{"ar":"حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ إِسْمَاعِيلَ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ حَكِيمِ بْنِ جَابِرٍ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ الدُّبَّاءُ فَقُلْتُ مَا هَذَا قَالَ نُكَثِّرُ بِهِ طَعَامَنَا","id":"Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Isma'il] yakni Ibnu Abu Khalid, dari [Hakim bin Jabir] dari [bapaknya] ia berkata; Saya pernah menemui Rasulullah shallallahu 'alaihi wasallam dan saat itu, beliau mempunyai Ad Dubaa` (benaja yang terbuat dari labu). Maka saya pun bertanya, \"Apakah ini?\" beliau menjawab: \"Dengan itu, kami memperbanyak makanan kami.\""},"2385":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْمَاعِيلُ بْنُ أَبِي خَالِدٍ عَنْ حَكِيمِ بْنِ جَابِرٍ عَنْ أَبِيهِ قَالَدَخَلْتُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ فَرَأَيْتُ عِنْدَهُ قَرْعًا فَقُلْتُ يَا رَسُولَ اللَّهِ مَا هَذَا قَالَ هَذَا قَرْعٌ نُكَثِّرُ بِهِ طَعَامَنَا","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Hakim bin Jabir] dari [bapaknya] ia berkata; Saya pernah menemui Nabi shallallahu 'alaihi wasallam di dalam rumahnya, lalu saya melihat buah labu berada di sisinya, maka saya pun bertanya, \"Wahai Rasulullah, apakah ini?\" beliau menjawab: \"Buah labu, untuk memperbanyak makanan kami.\""},"2386":{"ar":"حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ عَنْ فِرَاسٍ عَنْ مُدْرِكِ بْنِ عُمَارَةَ عَنِ ابْنِ أَبِي أَوْفَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ وَلَا يَزْنِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ أَوْ سَرَفٍ وَهُوَ مُؤْمِنٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] Telah menceritakan kepada kami [Syu'bah] dari [Firas] dari [Mudrik bin Imarah] dari [Ibnu Abu Aufa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang yang meminum khamar tidak sempurna imannya saat ia meminumnya. Dan seorang pezina tidak sempurna imannya saat ia berzina. Dan seorang yang merampas harta tidak sempurna imannya ketika merampas.\""},"2387":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ عَنْ عُبَيْدِ بْنِ الْحَسَنِ الْمُزَنِيِّ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَاوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُحَدَّثَنَا وَكِيعٌ حَدَّثَنَا مِسْعَرٌ حَدَّثَنَا عُبَيْدُ بْنُ حَسَنٍ عَنِ ابْنِ أَبِي أَوْفَى أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ ذَلِكَ وَلَمْ يَقُلْ فِي الصَّلَاةِ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al A'masy] dari [Ubaid bin Al Hasan Al Mazani] ia berkata, saya mendengar [Ibnu Abu Aufa] berkata; Jika Rasulullah shallallahu 'alaihi wasallam mengangkat kepalanya dari posisi ruku', maka beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH, ALLAHUMMA RABBANAA LAKAL HAMDU MIL`AS SAMAAWAATI WA MIL`AL ARDLI, WA MIL`A MAA SYI`TA MIN SYAI`IN BA'DU (Ya Allah, bagi-Mu pujian seluas langit dan bumi, serta bagi-Mu pujian seluas apa yang Engkau kehendaki setelah itu).\" Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Mis'ar] Telah menceritakan kepada kami [Ubaid bin Hasan] dari [Ibnu Abu Aufa] bahwa Nabi shallallahu 'alaihi wasallam mengucapkan bacaan itu, namun beliau tidak membacanya di dalam shalat."},"2388":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا الْأَعْمَشُ حَدَّثَنِي الشَّيْبَانِيُّ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نَبِيذِ الْجَرِّ الْأَخْضَرِقَالَ قُلْتُ فَالْأَبْيَضُ قَالَ لَا أَدْرِي","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Al A'masy] telah menceritakan kepadaku [Asy Syaiban] ia berkata, me [Ibnu Abu Aufa] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang Nabidz Al Jarr Al Akhdlar (sejenis rendaman anggur yang kemudian disimpan dalam bejana yang terbuat dari tanah liat) yakni yang masih berwana hijau. Asy Syaibani berkata; Saya bertanya, \"Bagaimana dengan Nabidz yang telah berwarna putih?\" Ibnu Abu Aufa menjawab: \"Saya tidak tahu.\""},"2389":{"ar":"حَدَّثَنَا وَكِيعٌ وَيَعْلَى هُوَ ابْنُ عُبَيْدٍ قَالَا ثَنَا ابْنُ أَبِي خَالِدٍ وَهُوَ إِسْمَاعِيلُ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْأَحْزَابِ فَقَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ اهْزِمْ الْأَحْزَابِ اهْزِمْهُمْ وَزَلْزِلْهُمْ","id":"Telah menceritakan kepada kami [Waki'] dan [Ya'la] ia adalah Ibnu Ubaid, keduanya berkata, Telah menceritakan kepada kami [Ibnu Abu Khalid] ia adalah Isma'il, ia berkata, saya mendengar [Ibnu Abu Aufa] berkata; Rasulullah shallallahu 'alaihi wasallam mendo'akan kehancuran atas pasukan Ahzab, maka beliau membaca: \"ALLAHUMMA MUNZILAL KITAAB SARII'AL HISAAB, AHZIMIL AHZAAB, AHZIMHUM, WA ZALZILHUM (Ya Allah, Yang telah menurunkan kitab, yang maha cepat hisab-Nya, hancur-leburkanlah pasukan Ahzab, hancurkan dan goncanglah mereka).\""},"2390":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا ابْنُ أَبِي خَالِدٍ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُلَوْ كَانَ بَعْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَبِيٌّ مَا مَاتَ ابْنُهُ إِبْرَاهِيمُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Ibnu Abu Khalid] ia berkata, saya mendengar [Ibnu Abu Aufa] berkata; Sekiranya sepeninggal Nabi shallallahu 'alaihi wasallam akan ada lagi seorang Nabi, niscaya putranya, yaitu Ibrahim tidaklah meninggal."},"2391":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ أَبِي خَالِدٍ الدَّالَانِيِّ عَنْ إِبْرَاهِيمَ السَّكْسَكِيِّ عَنِ ابْنِ أَبِي أَوْفَى قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي لَا أَسْتَطِيعُ أَخْذَ شَيْءٍ مِنْ الْقُرْآنِ فَعَلِّمْنِي مَا يُجْزِئُنِي قَالَ قُلْ سُبْحَانَ اللَّهِ وَالْحَمْدُ لِلَّهِ وَلَا إِلَهَ إِلَّا اللَّهُ وَاللَّهُ أَكْبَرُ وَلَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ قَالَ يَا رَسُولَ اللَّهِ هَذَا لِلَّهِ عَزَّ وَجَلَّ فَمَا لِي قَالَ قُلْ اللَّهُمَّ اغْفِرْ لِي وَارْحَمْنِي وَعَافِنِي وَاهْدِنِي وَارْزُقْنِي ثُمَّ أَدْبَرَ وَهُوَ مُمْسِكُ كَفَّيْهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا هَذَا فَقَدْ مَلَأَ يَدَيْهِ مِنْ الْخَيْرِقَالَ مِسْعَرٌ فَسَمِعْتُ هَذَا الْحَدِيثَ مِنْ إِبْرَاهِيمَ السَّكْسَكِيِّ عَنِ ابْنِ أَبِي أَوْفَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَثَبَّتَنِي فِيهِ غَيْرِي","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Yazid bin Abu Khalid Ad Dalani] dari [Ibrahim As Saksaki] dari [Ibnu Abu Aufa] ia berkata; Seorang laki-laki mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya saya tidak bisa membaca sedikit pun dari Al Qur`an, karena itu, ajarilah aku sesuatu yang dapat menggantikannya.\" Beliau bersabdas: \"Bacalah, 'SUBHAANALLAH WAL HAMDULILLAH, WA LAA ILAAHA ILLALLAH, WALLAHU AKBAR, WALAA HAULA WALAA QUWWATA ILLAA BILLAH (Maha Suci Allah dan Segala puji bagi Allah, Tidak ada Ilah yang berhak disembah selain Allah, Allah Maha Besar. Tidak ada daya dan upaya kecuali atas izin Allah).'\" Laki-laki itu berkata, \"Wahai Rasulullah, ini semua hanya untuk Allah 'azza wajalla, maka apakah bagiku?\" beliau menjawab: \"Bacalah, 'ALLAHUMMAGHFIR LII, WAR HAMNII, WA 'AAFINI, WAHDINII, WARZUQNII (Ya Allah ampunilah aku, kasihanilah aku, dan maafkanlah aku. Berilah petunjuk dan curahkanlah rizki untukku).'\" Kemudian laki-laki itu berpaling sambil menggenggam kedua telapak tangannya, maka Nabi shallallahu 'alaihi wasallam bersabda: \"Adapun orang ini, maka sungguh, ia telah memenuhi kedua tangannya dengan kebaikan.\" [Mis'ar] bekata; Saya mendengar hadits ini dari [Ibrahim As Saksaki], dari [Ibnu Abu Aufa] dari Nabi shallallahu 'alaihi wasallam."},"2392":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي يَعْفُورٍ الْعَبْدِيِّ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ فَكُنَّا نَأْكُلُ فِيهَا الْجَرَادَ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Sufyan] dari [Abu Ya'fur Al Abdi] ia berkata, saya mendengar [Ibnu Abu Aufa] berkata; Kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali peperangan. Dan dalam peperangan itu kami sempat makan belalang."},"2393":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ شَيْخٍ مِنْ بَجِيلَةَ قَالَ سَمِعْتُ ابْنَ أَبِي أَوْفَى يَقُولُاسْتَأْذَنَ أَبُو بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ جَارِيَةٌ تَضْرِبُ بِالدُّفِّ ثُمَّ اسْتَأْذَنَ عُمَرُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَدَخَلَ ثُمَّ اسْتَأْذَنَ عُثْمَانُ رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَأَمْسَكَتْ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عُثْمَانَ رَجُلٌ حَيِيٌّ","id":"Telah menceritakan kepada kami [Abdurrahman] ia adalah Ibnu Mahdi Telah menceritakan kepada kami [Syu'bah] dari [seoran Syaikh] dari Bakhilah, ia berkata, saya mendengar [Ibnu Abu Aufa] berkata; Abu Bakar radliallahu 'anhu meminta izin kepada Nabi shallallahu 'alaihi wasallam, sementara di sisi beliau terdapat seorang budak wanita yang sedang memukul rebana. Kemudian Umar radliallahu 'anhum meminta izin, lalu ia pun masuk. Setelah itu, Utsman radliallahu 'anhu juga meminta izin, dan tiba-tiba budak wanita itu berhenti memukul rebana. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Utsman adalah seorang laki-laki yang sangat pemalu.\""},"2394":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ هُوَ ابْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبُو حَيَّانَ قَالَسَمِعْتُ شَيْخًا بِالْمَدِينَةِ يُحَدِّثُ أَنَّ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى كَتَبَ إِلَى عُبَيْدِ اللَّهِ إِذْ أَرَادَ أَنْ يَغْزُوَ الْحَرُورِيَّةَ فَقُلْتُ لِكَاتِبِهِ وَكَانَ لِي صَدِيقًا انْسَخْهُ لِي فَفَعَلَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا تَمَنَّوْا لِقَاءَ الْعَدُوِّ وَسَلُوا اللَّهَ عَزَّ وَجَلَّ الْعَافِيَةَ فَإِذَا لَقِيتُمُوهُمْ فَاصْبِرُوا وَاعْلَمُوا أَنَّ الْجَنَّةَ تَحْتَ ظِلَالِ السُّيُوفِ قَالَ فَيَنْظُرُ إِذَا زَالَتْ الشَّمْسُ نَهَدَ إِلَى عَدُوِّهِ ثُمَّ قَالَ اللَّهُمَّ مُنْزِلَ الْكِتَابِ وَمُجْرِيَ السَّحَابِ وَهَازِمَ الْأَحْزَابِ اهْزِمْهُمْ وَانْصُرْنَا عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Isma'il] ia adalah Ibnu Ibrahim, Telah menceritakan kepada kami [Ibnu Hayyan] ia berkata, saya mendengar [seorang Syaikh] di Madinah yang menceritakan bahwa [Abdullah bin Abu Aufa] menulis surat kepada Ubaidullah ketika ia akan memerangi Al Haruriyyah. Maka saya pun berkata kepada juru tulisnya -yang ia juga temanku-, \"Tuliskanlah untukku.\" Maka ia pun melakukannya. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Janganlah kalian berangan-angan untuk bertemu dengan musuh, dan mohon keselamatanlah kepada Allah. Jika kalian menghadapi mereka, maka bersabarlah. Dan ketahuilah, bahwa surga itu berada di bawah naungan pedang.\" Kemudian Beliau mencermati, jika matahari telah terbenam, maka beliau pun menyongsong untuk melawan musuh. Kemudian beliau membaca: \"ALLAHUMMA MUNZILAL KITAAB, WA MUJRIYAS SAHAAB, WA HAAZIMAL AHZAAB, IHZIMHUM WAN SHURNAA 'ALAIHIM (Ya Allah, Yang telah menurunkan kitab, Yang menggerakkan awan, pemusnah Ahzab, binasakanlah mereka dan menangkanlah kami atas mereka).\""},"2395":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ وَبَهْزٌ قَالَا ثَنَا شُعْبَةُ عَنْ عَدِيٍّ قَالَ بَهْزٌ أَخْبَرَنِي عَدِيُّ بْنُ ثَابِتٍ قَالَ ابْنُ جَعْفَرٍ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ وَابْنَ أَبِي أَوْفَى قَالَاأَصَابُوا حُمُرًا يَوْمَ خَيْبَرَ فَنَادَى مُنَادِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُكْفِئُوا الْقُدُورَ وَقَالَ بَهْزٌ عَنْ عَدِيٍّ عَنِ الْبَرَاءِ وَابْنِ أَبِي أوْفَى","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] dan [Bahz] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] dari [Adi] -dalam riwayat lain Bahz- berkata, telah mengabarakan kepadaku Adi bin Tsabit -Ibnu Ja'far berkata- saya mendengar [Al Baraa` bin Azib] dan [Ibnu Abu Aufa] keduanya berkata; Pada hari Khaibar, pada sahabat mendapat harta ghanimah berupa Himar (keledai), maka sang Munadi (penyeru) Rasulullah shallallahu 'alaihi wasallam pun menyerukan agar menumpahkan periuk. Bahz berkata; Dari Adi dari Al Baraa` dan Ibnu Abu Aufa."},"2396":{"ar":"حَدَّثَنَا عَفَّانُ عَنْ أَبِي عَوَانَةَ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ قَالَسَمِعْتُ جَرِيرَ بْنَ عَبْدِ اللَّهِ قَامَ يَخْطُبُ يَوْمَ تُوُفِّيَ الْمُغِيرَةُ بْنُ شُعْبَةَ فَقَالَ عَلَيْكُمْ بِاتِّقَاءِ اللَّهِ عَزَّ وَجَلَّ وَالْوَقَارِ وَالسَّكِينَةِ حَتَّى يَأْتِيَكُمْ أَمِيرٌ فَإِنَّمَا يَأْتِيكُمْ الْآنَ ثُمَّ قَالَ اشْفَعُوا لِأَمِيرِكُمْ فَإِنَّهُ كَانَ يُحِبُّ الْعَفْوَ وَقَالَ أَمَّا بَعْدُ فَإِنِّي أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أُبَايِعُكَ عَلَى الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَشْتَرِطُ عَلَى النُّصْحِ لِكُلِّ مُسْلِمٍ فَبَايَعْتُهُ عَلَى هَذَا وَرَبِّ هَذَا الْمَسْجِدِ إِنِّي لَكُمْ لَنَاصِحٌ جَمِيعًا ثُمَّ اسْتَغْفَرَ وَنَزَلَ","id":"Telah menceritakan kepada kami ['Affan] dari [Abu 'Awanah] Telah menceritakan kepada kami [Ziyad bin Ilaqah] ia berkata, saya mendengar [Jarir bin Abdullah] berkhutbah pada hari wafatnya Al Mughirah bin Syu'bah, ia berkata, \"Hendaklah kalian bertakwa kepada Allah 'azza wajalla, bersikap tenang, bersahaja, sampai pemimpin kalian datang, karena ia akan datang sekarang.\" Kemudian ia berkata lagi, \"Minta maaflah kalian kepada Amir kalian, karena ia menyukai untuk memaafkan.\" Ia berkata lagi, \"Amma Ba'du, sesungguhnya saya pernah mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, 'Saya berbai'at kepadamu atas dasar Islam.' Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya memberi syarat 'Untuk berbakti kepada setiap muslim.\" Kemudian saya pun berbai'at kepada beliau atas dasar ini, dan Rabb masjid ini. Sesungguhnya saya adalah seorang pemberi nasehat kepada kalian semua.\" Ia pun meminta ampun kepada Allah dan turun."},"2397":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّ قَالَقُلْتُ يَا رَسُولَ اللَّهِ اشْتَرِطْ عَلَيَّ فَقَالَ تَعْبُدُ اللَّهَ وَلَا تُشْرِكُ بِهِ شَيْئًا وَتُصَلِّي الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّي الزَّكَاةَ الْمَفْرُوضَةَ وَتَنْصَحُ لِلْمُسْلِمِ وَتَبْرَأُ مِنْ الْكَافِرِ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Ashim bin Bahdalah] dari [Abu Wa`il] dari [Jarir bin Abdullah Al Bajali] ia berkata, saya berkata, \"Wahai Rasulullah, tetapkanlah syarat atasku.\" Maka beliau bersabda: \"Kamu beribadah kepada Allah, janganlah kamu menyekutukan-Nya dengan sesuatu apa pun, hendaklah kamu menunaikan shalat wajib, membayar zakat wajib, dan selalu berbakti kepada setiap muslim serta berlepas diri dari orang kafir.\""},"2398":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ حَبِيبٍ عَنِ الْمُغِيرَةِ بْنِ شُبَيْلٍ أَوْ شِبْلٍ قَالَ أَبُو نُعَيْمٍ الْمُغِيرَةُ بْنُ شُبَيْلٍ يَعْنِي ابْنَ عَوْفٍ فِي هَذَا الْحَدِيثِ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا عَبْدٍ أَبَقَ فَقَدْ بَرِئَتْ مِنْهُ الذِّمَّةُ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Habib] dari [Al Mughirah bin Syubail] atau Syibl telah berkata [Abu Nu'aim]; [Al Mughirah bin Syubail] yakni Ibnu 'Auf dalam hadits ini, dari [Jarir bin Abdullah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang budak yang melarikan diri, maka telah terlepas darinya Adz Dzimmah (jaminan keamanan dan tanggungan).\""},"2399":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ عَوْنِ بْنِ أَبِي جُحَيْفَةَ عَنِ الْمُنْذِرِ بْنِ جَرِيرٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً حَسَنَةً كَانَ لَهُ أَجْرُهَا وَأَجْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ يُنْتَقَصَ مِنْ أُجُورِهِمْ شَيْءٌ وَمَنْ سَنَّ فِي الْإِسْلَامِ سُنَّةً سَيِّئَةً كَانَ عَلَيْهِ وِزْرُهَا وَوِزْرُ مَنْ عَمِلَ بِهَا مِنْ بَعْدِهِ مِنْ غَيْرِ أَنْ يُنْتَقَصَ مِنْ أَوْزَارِهِمْ شَيْءٌحَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَوْنَ بْنَ أَبِي جَحْفَةَ عَنِ الْمُنْذِرِ بْنِ جَرِيرٍ الْبَجَلِيِّ عَنْ أَبِيهِ قَالَ كُنَّا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَدْرِ النَّهَارِ فَذَكَرَهُ إِلَّا أَنَّهُ قَالَ فَأَمَرَ بِلَالًا فَأَذَّنَ ثُمَّ دَخَلَ ثُمَّ خَرَجَ يُصَلِّي وَقَالَ كَأَنَّهُ مُذْهَبَةٌ","id":"Telah menceritakan kepada kami [Abdurrahman bin Mahdi] Telah menceritakan kepada kami [Syu'bah] dari [Aun bin Abu Juhaifah] dari [Al Mundzir bin Jarir] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa memulai kebaikan dalam Islam, ia memperoleh pahala dan pahala siapa saja yang emnirunya sesudahnya dnegan tidak mengurangi pahala mereka sama seklai. Sebaliknya barangsiapa memulai kebiasaan buruk dalam Islam, ia mendapat dosanya dan dosa yang menirunya dengan tidak mengurangi dosa mereka sedikitpun. Telah menceritakan kepada kami [Hasyim bin Al Qasim] Telah menceritakan kepada kami [Syu'bah] mengatakan, aku mendengar ['Aun bin Abi Jahafah] dari [Almundzir bin Jarir Al Bajali] dari [ayahnya] mengatakan, kami berada di sisi Rasulullah Shallallahu'alaihiwasallam di awal siang, lantas ia sebut redaksinya. Hanya ia mengatakan, lantas beliau menyuruh Bilal mengumandangkan adzan, kemudian beliau masuk kamar dan keluar kamarnya dan mendirikan shalat. Kata ayah Jarir, seolah-olah beliau disepuh emas (maksudnya beliau bersinar-sinar wajahnya karena gembira melihat kesegeraan sahabat taat kepada Allah)."},"2400":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنِ الْحَجَّاجِ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ زَاذَانَ عَنْ جَرِيرِ بْنِ عَبْدِ اللَّهِ الْبَجَلِيِّأَنَّ رَجُلًا جَاءَ فَدَخَلَ فِي الْإِسْلَامِ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُهُ الْإِسْلَامَ وَهُوَ فِي مَسِيرِهِ فَدَخَلَ خُفُّ بَعِيرِهِ فِي جُحْرِ يَرْبُوعٍ فَوَقَصَهُ بَعِيرُهُ فَمَاتَ فَأَتَى عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَمِلَ قَلِيلًا وَأُجِرَ كَثِيرًا قَالَهَا حَمَّادٌ ثَلَاثًا اللَّحْدُ لَنَا وَالشَّقُّ لِغَيْرِنَاحَدَّثَنَا عَفَّانُ حَدَّثَنَا عَبْدُ الْوَاحِدِ حَدَّثَنَا حَجَّاجُ بْنُ أَرْطَاةَ حَدَّثَنَا عُثْمَانُ الْبَجَلِيُّ عَنْ زَاذَانَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Al Hajjaj] dari [Amru bin Murrah] dari [Zadzan] dari [Jarir bin Abdullah Al Bajali] bahwa seorang laki-laki datang dan menyatakan masuk Islam. Maka Rasulullah shallallahu 'alaihi wasallam pun mengajarkan Islam kepadanya, saat itu ia masih berada dalam perjalanan. Tiba-tiba telapak kaki Unta miliknya masuk ke dalam sarang Yarbu' (sejenis hewan yang menyerupai tikus dan berekor panjang lagi berbulu), sehingga Untanya itu mematahkan lehernya dan ia pun meninggal. Kemudian Rasulullah shallallahu 'alaihi wasallam mendatanginya dan bersabda: \"Ia beramal sedikit, namun diberi ganjaran pahala yang banyak.\" Hammad mengatakannya sebanyak tiga kali, \"Lahad adalah untuk kita, sedakang Asy Syaq adalah untuk selain kita.\" Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Abdul Wahid] Telah menceritakan kepada kami [Hajjaj bin Arthah] Telah menceritakan kepada kami [Utsman Al Bajali] dari [Zadzan] ia pun menyebutkan hadits. "},"2401":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سِمَاكِ بْنِ حَرْبٍ عَنْ عُبَيْدِ اللَّهِ بْنِ جَرِيرٍ عَنْ جَرِيرٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أُبَايِعُكَ عَلَى الْإِسْلَامِ فَقَبَضَ يَدَهُ وَقَالَ النُّصْحُ لِكُلِّ مُسْلِمٍ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُ مَنْ لَمْ يَرْحَمْ النَّاسَ لَمْ يَرْحَمْهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Simak bin Harb] dari [Ubaidullah bin Jarir] dari [Jarir] ia berkata; Saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Saya berbaiat kepada Anda di atas Islam.\" Beliau pun menjabat tangannya dan bersabda: \"Untuk berbakti kepada setiap muslim.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang tidak mengasihi manusia, maka ia tidak akan dikasihi Allah 'azza wajalla.\""},"2402":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ قَالَ سَمِعْتُ أَبَا وَائِلٍ يُحَدِّثُ عَنْ رَجُلٍ عَنْ جَرِيرٍ أَنَّهُ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى إِقَامِ الصَّلَاةِ وَإِيتَاءِ الزَّكَاةِ وَالنُّصْحِ لِلْمُسْلِمِ وَعَلَى فِرَاقِ الْمُشْرِكِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Manshur] ia berkata, saya mendengar [Abu Wa`il] menceritakan dari [seorang laki-laki] dari [Jarir] bahwa ia berkata; \"Saya telah berbai'at kepada Rasulullah shallallahu 'alaihi wasallam untuk (senantiasa) mendirikan shalat, mengeluarkan zakat, berbakti kepada setiap muslim dan berlepas diri dari orang musyrik.\""},"2403":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا ظَبْيَانَ يُحَدِّثُ عَنْ جَرِيرٍ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ لَمْ يَرْحَمْ النَّاسَ لَمْ يَرْحَمْهُ اللَّهُ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] ia berkata, saya mendengar [Abu Zhabyan] menceritakan dari [Jarir] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang tidak mengasihi manusia, maka Allah 'azza wajalla tidak akan mengasihinya.\""},"2404":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنْ أَبِي وَائِلٍ أَنَّ جَرِيرًا قَالَيَا رَسُولَ اللَّهِ اشْتَرِطْ عَلَيَّ قَالَ تَعْبُدُ اللَّهَ لَا تُشْرِكُ بِهِ شَيْئًا وَتُصَلِّي الصَّلَاةَ الْمَكْتُوبَةَ وَتُؤَدِّي الزَّكَاةَ الْمَفْرُوضَةَ وَتَنْصَحُ الْمُسْلِمَ وَتَبْرَأُ مِنْ الْكَافِرِ","id":"Telah menceritakan kepada kami [Bahz] Telah menceritakan kepada kami [Hammad bin Salamah] Telah menceritakan kepada kami [Ashim bin Bahdalah] dari [Abu Wa`il] bahwa [Jarir] berkata, \"Wahai Rasulullah, tetapkan syarat atasku.\" Beliau bersabda: \"Kamu beribadah kepada Allah, janganlah kamu menyekutukan-Nya dengan sesuatu apa pun, hendaklah kamu menunaikan shalat wajib, membayar zakat wajib, dan selalu berbakti kepada setiap muslim serta berlepas diri dari orang kafir.\""},"2405":{"ar":"حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ جَرِيرٍ عَنْ أَبِيهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَا يَرْحَمُ مَنْ لَا يَرْحَمُ النَّاسَ","id":"Telah menceritakan kepada kami [Bahz] Telah menceritakan kepada kami [Hammad bin Salamah] dari [Abdul Malik bin Umair] dari [Ubaidullah bin Jarir] dari [bapaknya] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla tidak akan mengasihi seorang yang tidak mengasihi manusia.\""},"2406":{"ar":"حَدَّثَنَا يَحْيَى عَنْ يُوسُفَ بْنِ صُهَيْبٍ وَوَكِيعٌ حَدَّثَنَا يُوسُفُ عَنْ حَبِيبِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ أَرْقَمَ رَضِيَ اللَّهُ تَعَالَى عَنْهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَأْخُذْ مِنْ شَارِبِهِ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Yahya] dari [Yusuf bin Suhaib] dan [Waki'] Telah menceritakan kepada kami [Yusuf] dari [Habib bin Yasar] dari [Zaid bin Arqam] radliallahu 'anhu dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa yang tidak dapat mengambil minuman dari Al Haudl (telaga Nabi di surga), maka ia bukanlah golongan kami.\""},"2407":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا هِشَامٌ الدَّسْتُوَائِيُّ عَنِ الْقَاسِمِ بْنِ عَوْفٍ الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ قُبَاءَ وَهُمْ يُصَلُّونَ الضُّحَى فَقَالَ صَلَاةُ الْأَوَّابِينَ إِذَا رَمِضَتْ الْفِصَالُ مِنْ الضُّحَى","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Hisyam Ad Dastuwa`i] dari [Al Qasim bin Auf Asy Syaibani] dari [Zaid bin Arqam] ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar menemui penghuni Quba` yang saat itu mereka sedang shalat. maka beliau bersabda: \"Shalat orang-orang yang bertaubat adalah ketika anak-anak unta telah menderum (karena panas).\""},"2408":{"ar":"قَالَ يَزِيدُ بْنُ حَيَّانَ حَدَّثَنَا زَيْدُ بْنُ أَرْقَمَ فِي مَجْلِسِهِ ذَلِكَ قَالَبَعَثَ إِلَيَّ عُبَيْدُ اللَّهِ بْنُ زِيَادٍ فَأَتَيْتُهُ فَقَالَ مَا أَحَادِيثُ تُحَدِّثُهَا وَتَرْوِيهَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَجِدُهَا فِي كِتَابِ اللَّهِ تُحَدِّثُ أَنَّ لَهُ حَوْضًا فِي الْجَنَّةِ قَالَ قَدْ حَدَّثَنَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَوَعَدَنَاهُ قَالَ كَذَبْتَ وَلَكِنَّكَ شَيْخٌ قَدْ خَرِفْتَ قَالَ إِنِّي قَدْ سَمِعَتْهُ أُذُنَايَ وَوَعَاهُ قَلْبِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنْ جَهَنَّمَ وَمَا كَذَبْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yazid bin Hayyan] Telah menceritakan kepada kami [Zaid bin Arqam] di dalam majelisnya, ia berkata; Ubaidullah bin Ziyad mengutus seseorang kepadaku, lalu saya pun mendatanginya. Kemudian ia bertanya; \"Hadits apa saja yang kamu ceritakan dan riwayatkan dari Rasulullah shallallahu 'alaihi wasallam yang tidak kami dapatkan di dalam Kitabullah, kamu menceritakan bahwa beliau memiliki Haudl (telaga) di surge?.\" Ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menceritakan dan menjanjikannya kepada kami.\" Ubaid berkata, \"Kamu telah berdusta, kamu adalah seorang yang telah tua dan pikun.\" Zaid berkata, \"Sesungguhnya kedua telingaku telah mendengarnya dan hatiku telah menghafalnya dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: 'Barangsiapa yang berdusta atas namaku, maka hendaklah ia mempersiapkan tempat duduknya di neraka jahannam.' Tidaklah saya berdusta atas nama Rasulullah shallallahu 'alaihi wasallam.\""},"2409":{"ar":"وَحَدَّثَنَا زَيْدٌ فِي مَجْلِسِهِ قَالَإِنَّ الرَّجُلَ مِنْ أَهْلِ النَّارِ لَيَعْظُمُ لِلنَّارِ حَتَّى يَكُونَ الضِّرْسُ مِنْ أَضْرَاسِهِ كَأُحُدٍ","id":"Dan Telah menceritakan kepada kami [Zaid] di dalam majelisnya, ia berkata; Sesungguhnya seorang laki-laki penghuni neraka, benar-benar akan dibesarkan di neraka hingga besar gigi gerahamnya seperti gunung Uhud."},"2410":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ يَزِيدَ بْنِ حَيَّانَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَسَحَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ الْيَهُودِ قَالَ فَاشْتَكَى لِذَلِكَ أَيَّامًا قَالَ فَجَاءَهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ رَجُلًا مِنْ الْيَهُودِ سَحَرَكَ عَقَدَ لَكَ عُقَدًا عُقَدًا فِي بِئْرِ كَذَا وَكَذَا فَأَرْسَلَ إِلَيْهَا مَنْ يَجِيءُ بِهَا فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا رَضِيَ اللَّهُ تَعَالَى عَنْهُ فَاسْتَخْرَجَهَا فَجَاءَ بِهَا فَحَلَّلَهَا قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنَّمَا نُشِطَ مِنْ عِقَالٍ فَمَا ذَكَرَ لِذَلِكَ الْيَهُودِيِّ وَلَا رَآهُ فِي وَجْهِهِ قَطُّ حَتَّى مَاتَ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Yazid bin Hayyan] dari [Zaid bin Arqam] ia berkata; Seorang laki-laki menyihir Nabi shallallahu 'alaihi wasallam, sebab itu beliau pun jatuh sakit berhari-hari. Kemudian Jibril 'Alaihis Salam mendatangi beliau dan berkata, \" Sesungguhnya seorang laki-laki dari kalangan Yahudi telah meyihirmu. Ia telah membuat beberapa buhul untukmu di sumur. Utuslah seorang yang akan mengambilnya.\" Maka Rasulullah shallallahu 'alaihi wasallam mengutus Ali radliallahu 'anhu. Ia pun mengeluarkannya kemudian membawanya dan mengurainya. Setelah itu, Rasulullah shallallahu 'alaihi wasallam pun berdiri seolah beliau baru saja terbebaskan dari belenggu. Beliau tidak lagi menyebut orang Yahudi itu, dan beliau pun tidak pernah melihatnya hingga meninggal."},"2411":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ ثُمَامَةَ بْنِ عُقْبَةَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ مِنْ الْيَهُودِ فَقَالَ يَا أَبَا الْقَاسِمِ أَلَسْتَ تَزْعُمُ أَنَّ أَهْلَ الْجَنَّةِ يَأْكُلُونِ فِيهَا وَيَشْرَبُونَ وَقَالَ لِأَصْحَابِهِ إِنْ أَقَرَّ لِي بِهَذِهِ خَصَمْتُهُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَلَى وَالَّذِي نَفْسِي بِيَدِهِ إِنَّ أَحَدَهُمْ لَيُعْطَى قُوَّةَ مِائَةِ رَجُلٍ فِي الْمَطْعَمِ وَالْمَشْرَبِ وَالشَّهْوَةِ وَالْجِمَاعِ قَالَ فَقَالَ لَهُ الْيَهُودِيُّ فَإِنَّ الَّذِي يَأْكُلُ وَيَشْرَبُ تَكُونُ لَهُ الْحَاجَةُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاجَةُ أَحَدِهِمْ عَرَقٌ يَفِيضُ مِنْ جُلُودِهِمْ مِثْلُ رِيحِ الْمِسْكِ فَإِذَا الْبَطْنُ قَدْ ضَمُرَ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Tsumamah bin Uqbah] dari [Zaid bin Arqam] ia berkata; Seorang Yahudi mendatangi Nabi shallallahu 'alaihi wasallam dan bertanya, \"Wahai Abu Qasim, bukankah Anda telah berdalih bahwa penghuni surga makan dan minum di dalamnya?\" Kemudian laki-laki itu berkata kepada temannya, \"Jika ia menetapkan hal ini, maka saya akan membantahnya.\" Maka Nabi shallallahu 'alaihi wasallam menjawab: \"Ya, demi Dzat yang jiwaku berada di Tangan-Nya, salah seorang dari mereka benar-benar akan diberi kekuatan seratus laki-laki, yakni dalam makanan, minuman, syahwat dan jima'.\" Orang Yahudi itu bertanya, \"Maka yang makan dan minum, mestinya akan memiliki hajat (buang air).\" maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hajat salah seorang dari mereka adalah keringat yang keluar dari kulit-kulit mereka yang wanginya seharum Misk, dan perut pun mengecil kembali.\""},"2412":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنِ الْقَاسِمِ الشَّيْبَانِيِّأَنَّ زَيْدَ بْنَ أَرْقَمَ رَأَى قَوْمًا يُصَلُّونَ فِي مَسْجِدِ قُبَاءَ مِنْ الضُّحَى فَقَالَ أَمَا لَقَدْ عَلِمُوا أَنَّ الصَّلَاةَ فِي غَيْرِ هَذِهِ السَّاعَةِ أَفْضَلُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ صَلَاةَ الْأَوَّابِينَ حِينَ تَرْمَضُ الْفِصَالُ وَقَالَ مَرَّةً وَأُنَاسٌ يُصَلُّونَ","id":"Telah menceritakan kepada kami [Isma'il bin Ulyah] telah mengabarkan kepada kami [Ayyub] dari [Al Qasim Asy Syaibani] bahwa [Zaid bin Arqam] melihat suatu kaum yang sedang shalat di Masjid Quba` pada waktu Dluha, maka ia pun berkata; \"Bukankah mereka tahu, bahwa shalat yang dilakukan di luar waktu ini adalah lebih utama?, Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Shalat orang-orang yang bertaubat adalah saat anak-anak Unta menderum (karena panasnya matahari).\" Dan sekali waktu Zaid berkata; \"Sementara orang-orang sedang shalat.\""},"2413":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ حَدَّثَنِي عَمْرُو بْنُ مُرَّةَ عَنِ ابْنِ أَبِي لَيْلَىأَنَّ زَيْدَ بْنَ أَرْقَمَ كَانَ يُكَبِّرُ عَلَى جَنَائِزِنَا أَرْبَعًا وَأَنَّهُ كَبَّرَ عَلَى جِنَازَةٍ خَمْسًا فَسَأَلُوهُ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُهَا أَوْ كَبَّرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] telah menceritakan kepadaku [Amru bin Murrah] dari [Ibnu Abu Laila] bahwa [Zaid bin Arqam] bertakbir (menshalati jenazah) sebanyak empat kali takbir, kemudian ia bertakbir lagi hingga (takbirnya menjadi) lima kali. Maka orang-orang pun bertanya. Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melakukan takbir yang kelima. Atau Nabi shallallahu 'alaihi wasallam telah mengucapkan takbir itu."},"2414":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يُوسُفَ بْنِ صُهَيْبٍ عَنْ حَبِيبِ بْنِ يَسَارٍ عَنْ زَيْدِ بْنِ أَرْقَمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَأْخُذْ مِنْ شَارِبِهِ فَلَيْسَ مِنَّا","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yusuf bin Shuhaib] dari [Habib bin Yasar] dari [Zaid bin Arqam] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Siapa yang tidak dapat mengamil minuman dari (telaga Al Haudl) maka ia bukanlah termasuk dari golongan kami.\""},"2415":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ حَبِيبٍ يَعْنِي ابْنَ أَبِي ثَابِتٍ عَنْ أَبِي الْمِنْهَالِ قَالَ سَمِعْتُ زَيْدَ بْنَ أَرْقَمَ وَالْبَرَاءَ بْنَ عَازِبٍ يَقُولَانِنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَيْعِ الذَّهَبِ بِالْوَرِقِ دَيْنًاحَدَّثَنَا بَهْزٌ وَعَفَّانُ قَالَا ثَنَا شُعْبَةُ قَالَ بَهْزٌ فِي حَدِيثِهِ حَدَّثَنِي حَبِيبُ بْنُ أَبِي ثَابِتٍ قَالَ سَمِعْتُ أَبَا الْمِنْهَالِ رَجُلًا مِنْ بَنِي كِنَانَةَ قَالَ سَأَلْتُ الْبَرَاءَ عَنْ الصَّرْفِ فَقَالَ سَلْ زَيْدَ بْنَ أَرْقَمَ فَإِنَّهُ خَيْرٌ مِنِّي وَأَعْلَمُ قَالَ سَأَلْتُ زَيْدًا فَذَكَرَ الْحَدِيثَ حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ وَعَامِرُ بْنُ مُصْعَبٍ سَمِعَا أَبَا الْمِنْهَالِ قَالَ سَأَلْتُ الْبَرَاءَ وَزَيْدَ بْنَ أَرْقَمَ فَذَكَرَ نَحْوَهُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي حَسَنُ بْنُ مُسْلِمٍ عَنْ أَبِي الْمِنْهَالِ وَلَمْ يَسْمَعْهُ مِنْهُ أَنَّهُ سَمِعَ زَيْدًا وَالْبَرَاءَ فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Habib] yakni Ibnu Abu Tsabit, dari [Abul Minhal] ia berkata, saya mendengar [Zaid bin Arqam] dan [Al Baraa` bin Azib] berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang jual beli emas dengan Wariq (uang dirham) secara hutang.\" Telah menceritakan kepada kami [Bahz] dan ['Affan] keduanya berkata, Telah menceritakan kepada kami [Syu'bah] -Bahz berkata dalam haditsnya- telah menceritakan kepadaku [Habib bin Abu Tsabit] ia berkata, saya mendengar [Abu Minhal] yakni seorang laki-laki dari Bani Kinanah, ia berkata; Saya bertanya kepada Al Baraa` tentang Ash Sharf (jual beli emas dengan perask dan semisal). Ia pun berkata, \"Tanyakanlah kepada Zaid bin Arqam, karena ia adalah lebih baik dan lebih tahu dariku.\" Maka saya pun bertanya kepada [Zaid]. Ia pun menyebutkan hadits itu. Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Amru bin Dinar] dan [Amir bin Mush'ab] keduanya mendengar [Abu Minhal] berkata; Saya bertanya kepada [Al Bara`] dan [Zaid bin Arqam]. Maka ia pun menyebutkan hadits semisalnya. Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Hasan bin Muslim] dari [Abu Minhal] namun ia belum mendengar darinya, bahwa ia mendengar Zaid dan Al Baraa`, kemudian ia pun menyebutkan hadits."},"2416":{"ar":"حَدَّثَنَا مُعَاوِيَةُ بْنُ عَبْدِ اللَّهِ بْنِ مُعَاوِيَةَ بْنِ عَاصِمِ بْنِ الْمُنْذِرِ بْنِ الزُّبَيْرِ حَدَّثَنَا سَلَّامٌ أَبُو الْمُنْذِرِ الْقَارِئُ حَدَّثَنَا عَاصِمُ بْنُ بَهْدَلَةَ عَنِ الشَّعْبِيِّ أَوْ خَيْثَمَةَ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا مَثَلُ الْمُسْلِمِينَ كَالرَّجُلِ الْوَاحِدِ إِذَا وَجِعَ مِنْهُ شَيْءٌ تَدَاعَى لَهُ سَائِرُ جَسَدِهِ","id":"Telah menceritakan kepada kami [Mu'awiyah bin Abdullah bin Mu'awiyah bin Ashim bin Mundzir bin Az Zubair] Telah menceritakan kepada kami [Sallam Abu Mundzir Al Qori'] Telah menceritakan kepada kami [Ashim bin Bahdalah] dari [Asy Sya'bi] atau [Khaitsamah] dari [An Nu'man bin Basyir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya perumpamaan kaum muslimin, adalah seperti satu tubuh, jika ada bagian tubuhnya yang sakit, maka seluruh jasadnya turut merasakan.\""},"2417":{"ar":"حَدَّثَنَا مَنْصُورُ بْنُ أَبِي مُزَاحِمٍ قَالَ حَدَّثَنَا أَبُو وَكِيعٍ الْجَرَّاحُ بْنُ مَلِيحٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنِ الشَّعْبِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ مَنْ لَمْ يَشْكُرْ الْقَلِيلَ لَمْ يَشْكُرْ الْكَثِيرَ وَمَنْ لَمْ يَشْكُرْ النَّاسَ لَمْ يَشْكُرْ اللَّهَ عَزَّ وَجَلَّ وَالتَّحَدُّثُ بِنِعْمَةِ اللَّهِ شُكْرٌ وَتَرْكُهَا كُفْرٌ وَالْجَمَاعَةُ رَحْمَةٌ وَالْفُرْقَةُ عَذَابٌ","id":"Telah menceritakan kepada kami [Manshur bin Abu Muzahim] ia berkata, Telah menceritakan kepada kami [Abu Waki' Al Jarrah bin Malih] dari [Abu Abdurrahman] dari [Asy Sya'bi] dari [An Nu'aman bin Basyir] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda di mimbar ini: \"Siapa yang tidak mampu mensyukuri nikmat yang sedikit, maka ia tidak akan mampu mensyukuri nikmat yang banyak. Dan siapa yang tidak mampu berterimah kasih kepada manusia, maka ia tidak akan mampu bersyukur kepada Allah 'azza wajalla. Membicarakan nikmat Allah adalah syukur, sedangkan meninggalkannya adalah kufur. Hidup berjama'ah adalah rahmat, sedangkan perpecahan adalah adzab.\""},"2418":{"ar":"قَالَ عَبْد اللَّهِ حَدَّثَنِي يَحْيَى بْنُ عَبْدِ رَبِّهِ مَوْلَى بَنِي هَاشِمٍ حَدَّثَنَا أَبُو وَكِيعٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنِ الشَّعْبِيِّ عَنِ النُّعْمَانِ بْنِ بَشِيرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى هَذِهِ الْأَعْوَادِ أَوْ عَلَى هَذَا الْمِنْبَرِ مَنْ لَمْ يَشْكُرْ الْقَلِيلَ لَمْ يَشْكُرْ الْكَثِيرَ وَمَنْ لَمْ يَشْكُرْ النَّاسَ لَمْ يَشْكُرْ اللَّهَ عَزَّ وَجَلَّ وَالتَّحَدُّثُ بِنِعْمَةِ اللَّهِ شُكْرٌ وَتَرْكُهَا كُفْرٌ وَالْجَمَاعَةُ رَحْمَةٌ وَالْفُرْقَةُ عَذَابٌقَالَ فَقَالَ أَبُو أُمَامَةَ الْبَاهِلِيُّ عَلَيْكُمْ بِالسَّوَادِ الْأَعْظَمِ قَالَ فَقَالَ رَجُلٌ مَا السَّوَادُ الْأَعْظَمُ فَنَادَى أَبُو أُمَامَةَ هَذِهِ الْآيَةَ الَّتِي فِي سُورَةِ النُّورِ{ فَإِنْ تَوَلَّوْا فَإِنَّمَا عَلَيْهِ مَا حُمِّلَ وَعَلَيْكُمْ مَا حُمِّلْتُمْ }","id":"Telah berkata Abdullah telah menceritakan kepadaku [Yahya bin Abdu Rabbih] bekas budak Bani Hasyim, Telah menceritakan kepada kami [Abu Waki'] dari [Abu Abdurrahman] dari [Asy Sya'bi] dari [An Nu'man bin Basyir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar ini: \"Siapa yang tidak mampu mensyukuri yang sedikit, maka ia tidak akan mampu mensyukuri sesuatu yang banyak. Dan siapa yang bisa berterima kasih kepada manusia, maka ia tidak akan bersyukur kepada Allah 'azza wajalla. Membicarakan nikmat Allah adalah syukur, sedangkan meninggalkannya adalah kufur. Berjama'ah adalah rahmat, sedangkan perpecahan adalah adzab.\" [Abu Umamah Al Bahili] berkata; \"Hendaklah kalian bersama golongan mayoritas muslimin.\" Kemudian Abu Umamah membacakan ayat ini, yang terdapat dalam surat An Nur: \"Dan jika kamu berpaling, Maka Sesungguhnya kewajiban Rasul itu adalah apa yang dibebankan kepadanya, dan kewajiban kamu sekalian adalah semata-mata apa yang dibebankan kepadamu.\" (QS. Annur 54)."},"2419":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ هُوَ الْقَوَارِيرِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا حَاجِبُ بْنُ الْمُفَضَّلِ يَعْنِي ابْنَ الْمُهَلَّبِ عَنْ أَبِيهِ عَنِ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَارِبُوا بَيْنَ أَبْنَائِكُمْ يَعْنِي سَوُّوا بَيْنَهُمْ","id":"Telah menceritakan kepada kami [Abdullah bin Umar Al Qawariri] Telah menceritakan kepada kami [Hammad] yakni Ibnu Zaid, Telah menceritakan kepada kami [Hajib bin Al Mufadldlal] yakni Ibnul Muhallab, dari [bapaknya] dari [An Nu'man bin Basyir], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Berlaku adillah di antara anak-anak kalian.\""},"2420":{"ar":"حَدَّثَنَا عَبْد اللَّهِ حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ الْبَاهِلِيُّ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَمُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالُوا ثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ حَاجِبِ بْنِ الْمُفَضَّلِ بْنِ الْمُهَلَّبِ عَنْ أَبِيهِ أَنَّهُ سَمِعَ النُّعْمَانَ بْنَ بَشِيرٍ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْدِلُوا بَيْنَ أَبْنَائِكُمْ اعْدِلُوا بَيْنَ أَبْنَائِكُمْ","id":"Telah menceritakan kepada kami Abdullah Telah menceritakan kepada kami [Ibrahim bin Al Hasan Al Bahili] dan [Ubaidullah bin Umar Al Fawariri] dan [Muhammad bin Abu Bakr Al Muqaddami] mereka berkata, Telah menceritakan kepada kami [Hammad bin Zaid] dsari [Hajib bin Al Mufadldlal bin Al Muhallab] dari [bapaknya] bahwa mendengar [An Nu'man bin Basyir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berlaku adillah terhadap anak-anak kalian. Berlaku adillah terhadap anak-anak kalian.\""},"2421":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنِ الشَّعْبِيِّ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ بِنَوَاصِيهَا الْخَيْرُ وَالْأَجْرُ وَالْمَغْنَمُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Asy Sya'bi] dari [Urwah Al Bariqi] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terikat kebaikan, pahala dan harta ghanimah hingga hari kiamat.\""},"2422":{"ar":"حَدَّثَنَا سُفْيَانُ أَخْبَرَنَا الْبَارِقِيُّ شَبِيبٌ أَنَّهُ سَمِعَ عُرْوَةَ الْبَارِقِيَّ يَقُولُسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُوَرَأَيْتُ فِي دَارِهِ سَبْعِينَ فَرَسًا","id":"Telah menceritakan kepada kami [Sufyan] telah mengabarkan kepada kami [Al Bariqi Syabib] bahwa ia mendengar [Urwah Al Bariqi] berkata, saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terikat kebaikan, pahala dan harta ghanimah hingga hari kiamat.\" Dan di rumahnya, saya melihat tujuh puluh ekor kuda."},"2423":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ بِنَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu Safar] dari [Asy Sya'bi] dari [Urwah bin Abul Ja'dari] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terdapat kebaikan, pahala dan harta ghanimah hingga hari kiamat tiba.\""},"2424":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ زَكَرِيَّا وَوَكِيعٌ قَالَ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنْ عُرْوَةَ قَالَ يَحْيَى ابْنِ أَبِي الْجَعْدِ الْبَارِقِيُّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ وَكِيعٌ فِي حَدِيثِهِ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Zakariya] dan [Waki'] ia berkata, Telah menceritakan kepada kami [Zakariya] dari [Amir] dari [Urwah] telah berkata [Yahya] [Ibnu Abul Ja'dari Al Bariqi] dari Nabi shallallahu 'alaihi wasallam. Dan [Waki'] berkata dalam haditsnya; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terdapat kebaikan, pahala dan harta ghanimah hingga hari kiamat tiba.\""},"2425":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَاقَ عَنِ الْعَيْزَارِ عَنْ عُرْوَةَ بْنِ جَعْدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al 'Aizar] dari [Amru bin Ja'd] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada ubun-ubun kuda, selalu terdapat kebaikan.\""},"2426":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا الزُّبَيْرُ بْنُ الْخِرِّيتِ حَدَّثَنَا أَبُو لَبِيدٍ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ الْبَارِقِيِّ قَالَعَرَضَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَبٌ فَأَعْطَانِي دِينَارًا وَقَالَ أَيْ عُرْوَةُ ائْتِ الْجَلَبَ فَاشْتَرِ لَنَا شَاةً فَأَتَيْتُ الْجَلَبَ فَسَاوَمْتُ صَاحِبَهُ فَاشْتَرَيْتُ مِنْهُ شَاتَيْنِ بِدِينَارٍ فَجِئْتُ أَسُوقُهُمَا أَوْ قَالَ أَقُودُهُمَا فَلَقِيَنِي رَجُلٌ فَسَاوَمَنِي فَأَبِيعُهُ شَاةً بِدِينَارٍ فَجِئْتُ بِالدِّينَارِ وَجِئْتُ بِالشَّاةِ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا دِينَارُكُمْ وَهَذِهِ شَاتُكُمْ قَالَ وَصَنَعْتَ كَيْفَ قَالَ فَحَدَّثْتُهُ الْحَدِيثَ فَقَالَ اللَّهُمَّ بَارِكْ لَهُ فِي صَفْقَةِ يَمِينِهِفَلَقَدْ رَأَيْتُنِي أَقِفُ بِكُنَاسَةِ الْكُوفَةِ فَأَرْبَحُ أَرْبَعِينَ أَلْفًا قَبْلَ أَنْ أَصِلَ إِلَى أَهْلِي وَكَانَ يَشْتَرِي الْجَوَارِيَ وَيَبِيعُ حَدَّثَنَا إِبْرَاهِيمُ بْنُ الْحَجَّاجِ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا الزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ أَبِي لَبِيدٍ وَهُوَ لُمَازَةُ بْنُ زَبَّارٍ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ الْبَارِقِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Kamil] Telah menceritakan kepada kami [Sa'id bin Zaid] Telah menceritakan kepada kami [Az Zubair bin Al Khirrit] Telah menceritakan kepada kami [Abu Labid] dari [Urwah bin Abul Ja'd Al Bariqi] ia berkata; Suatu ketika Nabi shallallahu 'alaihi wasallam melihat barang-barang impor, maka beliau pun memberiku satu Dinar seraya bersabda: \"Wahai Urwah, datangilah barang impor itu, dan belilah untuk kami satu ekor kambing.\" Saya pun mendatangi barang-barang impor itu, dan melakukan tawar menawar dengan pemiliknya hingga saya dapat membeli dua ekor kambing darinya dengan harga satu Dinar. Akhirnya saya segera menuntunnya, lalu seorang laki-laki menjumpaiku dan menawar kambing itu, maka saya pun menjual satu ekor kambing dengan harga satu Dinar. Akhirnya saya kembali dengan membawa kembali satu Dinar dan satu ekor kambing. Saya berkata, \"Wahai Rasulullah, ini uang Dinar kalian, dan ini kambing kalian.\" beliau bertanya: \"Apa yang kamu lakukan?\" Maka saya pun menceritakan alur kejadiannya. Beliau berdo'a: \"ALLAHUMMA BAARIK LAHU FI SHAFQATI YAMIINIH (Ya Allah, berilah keberkahan dalam ikrar dan janjinya).\" Maka kalian telah melihatku saat berada di TPS (Tempat pembuangan Sampah) di Kufah, saya telah meraih keuntungan empat puluh ribu sebelum sampai ke keluargaku. Saat itu, Urwah membeli budak-budak wanita dan menjualnya. Telah menceritakan kepada kami [Ibrahim bin Hajjaj] Telah menceritakan kepada kami [Sa'id bin Zaid] Telah menceritakan kepada kami [Az Zubair bin Hirrit] dari [Abu Labid] ia adalah Lumazah bin Zabbar dari [Urwah bin Abul Ja'd Al Bariqi] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"2427":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا أَبُو إِسْحَاقَ قَالَ سَمِعْتُ الْعَيْزَارَ بْنَ حُرَيْثٍ يُحَدِّثُ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ الْأَزْدِيِّ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Abu Ishaq] ia berkata, saya mendengar [Al 'Aizar bin Huraits] menceritakan dari [Urwah bin Abul Ja'd Al Azdi] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terdapat kebaikan.\""},"2428":{"ar":"حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنِ الشَّعْبِيِّ حَدَّثَنِي عُرْوَةُ الْبَارِقِيُّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] Telah menceritakan kepada kami [Zakariya] dari [Asy Sya'bi] telah menceritakan kepadaku [Urwah Al Bariqi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terdapat kebaikan, yaitu berupa pahala dan harta ghanimah hingga hari kiamat.\""},"2429":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنَا الزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ أَبِي لَبِيدٍ قَالَ كَانَ عُرْوَةُ بْنُ أَبِي الْجَعْدِ الْبَارِقِيُّ نَازِلًا بَيْنَ أَظْهُرِنَا فَحَدَّثَ عَنْهُ أَبُو لَبِيدٍ لُمَازَةُ بْنُ زَبَّارٍ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِ قَالَعَرَضَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَبٌ فَأَعْطَانِي دِينَارًا فَقَالَ أَيْ عُرْوَةُ ائْتِ الْجَلَبَ فَاشْتَرِ لَنَا شَاةً قَالَ فَأَتَيْتُ الْجَلَبَ فَسَاوَمْتُ صَاحِ��َهُ فَاشْتَرَيْتُ مِنْهُ شَاتَيْنِ بِدِينَارٍ فَجِئْتُ أَسُوقُهُمَا أَوْ قَالَ أَقُودُهُمَا فَلَقِيَنِي رَجُلٌ فَسَاوَمَنِي فَأَبِيعُهُ شَاةً بِدِينَارٍ فَجِئْتُ بِالدِّينَارِ وَجِئْتُ بِالشَّاةِ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا دِينَارُكُمْ وَهَذِهِ شَاتُكُمْ قَالَ وَصَنَعْتَ كَيْفَ فَحَدَّثْتُهُ الْحَدِيثَ فَقَالَ اللَّهُمَّ بَارِكْ لَهُ فِي صَفْقَةِ يَمِينِهِفَلَقَدْ رَأَيْتُنِي أَقِفُ بِكُنَاسَةِ الْكُوفَةِ فَأَرْبَحُ أَرْبَعِينَ أَلْفًا قَبْلَ أَنْ أَصِلَ إِلَى أَهْلِي وَكَانَ يَشْتَرِي الْجَوَارِيَ وَيَبِيعُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Sa'id bin Zaid] Telah menceritakan kepada kami [Az Zubair bin Khirrit] dari [Abu Labid] ia berkata; Urwah bin Abul Ja'd singgah di tengah-tengah kami. Lantas Abu Labid Lumazah bin Zabbar menceritakan (hadits) dari [Urwah bin Abul Ja'd Albariqi], ia berkata; Rasulullah shallallahu 'alaihi wasallam mendapatkan barang-barang imporan, kemudian beliau memberiku sedinar seraya beliau katakana kepada pembaginya; \" Tolong si Urwah berilah barang imporan itu dan belilah kambing untuk kita-kita. Kata 'Urwah, lantas kubeli seekor kambing dan kutawar penjualnya, sehingga kubeli dua ekor kambing seharga sedinar. Aku giring keduanya -atau dengan redaksi 'aku menuntunnya, bukan menggiring--, kemudian seseorang menemuiku dan menawarku dan kujual satu ekor daripadanya dengan harga sedinar. Maka aku bawa satu dinar dan seekor kambing, lantas kukatakan 'Ya Rasulullah, ini dinarmu dan ini kambingmu. Kata Nabi, tadi kamu lakukan bagaimana kok bisa seperti ini? Maka kuceritakan kisahnya. Maka beliau memanjatkan doa \"alloohumma baarik lahu fi shofqoti yamiinihi\" (ya Allah, berilah barakah dalam ikrar atau akad jual belinya), hingga di kemudian hari aku melihatku berdiri di tempat pembuangan sampah di Kufah dan aku dapatkan laba sebanyak empat puluh ribu sebelum aku sampai ke kelurgaku. Dengan uang itu ia membeli hamba sahaya dan berbisnis."},"2430":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ عَنِ الشَّعْبِيِّ قَالَ سَمِعْتُ عُرْوَةَ بْنَ أَبِي الْجَعْدِ الْبَارِقِيَّ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Hushain] dari [Asy Sya'bi] ia berkata, saya mendengar [Urwah bin Abul Ja'd Al Bariqi] berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu, terdapat kebaikan, yaitu berupa pahala dan harta ghanimah hingga hari kiamat.\""},"2431":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنِ الشَّعْبِيِّ أَخْبَرَنَا عَدِيُّ بْنُ حَاتِمٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَكُلُوا وَاشْرَبُوا حَتَّى يَتَبَيَّنَ لَكُمْ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ }قَالَ عَمَدْتُ إِلَى عِقَالَيْنِ أَحَدُهُمَا أَسْوَدُ وَالْآخَرُ أَبْيَضُ فَجَعَلْتُهُمَا تَحْتَ وِسَادِي قَالَ ثُمَّ جَعَلْتُ أَنْظُرُ إِلَيْهِمَا فَلَا تُبِينُ لِي الْأَسْوَدَ مِنْ الْأَبْيَضِ وَلَا الْأَبْيَضَ مِنْ الْأَسْوَدِ فَلَمَّا أَصْبَحْتُ غَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ بِالَّذِي صَنَعْتُ فَقَالَ إِنْ كَانَ وِسَادُكَ إِذًا لَعَرِيضٌ إِنَّمَا ذَلِكَ بَيَاضُ النَّهَارِ مِنْ سَوَادِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushain] dari [Asy Sya'bi] telah mengabarkan kepada kami [Adi bin Hatim] ia berkata; Ketika ayat ini turun: \"Dan makan minumlah hingga terang bagimu benang putih dari benang hitam, yaitu fajar.\" (QS. Albaqarah 187), Saya pun pergi mengambil dua benang yang satu berwarna putih sedang yang satunya lagi berwarna hitam. Lalu saya meletakkan di bawah bantalku, kemudian saya mencoba melihatnya, namun bagiku tidak tampak jelas antara yang putih dan hitam atau pun sebaliknya. Pada pagi harinya, saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan mengabarkan hal apa yang telah saya perbuat. Maka beliau bersabda: \"Kalau begitu, bantalmu panjang sekali. Hanyasanya maksudnya adalah putihnya siang daripada kegelapan malam.\""},"2432":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مُجَالِدٌ وَزَكَرِيَّا وَغَيْرُهُمَا عَنِ الشَّعْبِيِّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَقَالَ مَا أَصَابَ بِحَدِّهِ فَخَرَقَ فَكُلْ وَمَا أَصَابَ بِعَرْضِهِ فَقَتَلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Mujalid] dan [Zakariya] dan selain keduanya, dari [Asy Sya'bi] dari [Adi bin Hatim] ia berkata; Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam tentang Shaidul Mi'radl (hewan buruan yang terkena lemparan tombak, namun yang mengenai sasaran bukan bagian tajamnya). Maka beliau menjawab: \"Hewan buruan yang terkena oleh bagian ujung (mata) tombak, kemudian mati, maka makanlah. Dan hewan yang terkena oleh bagian tombak yang lain sehingga mati, maka ia adalah Waqidz (hewan yang dibunuh dengan menggunakan alat yang tidak tajam alais tumpul), karena itu, janganlah kamu memakannya.\""},"2433":{"ar":"حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ خَيْثَمَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْكُمْ مِنْ أَحَدٍ إِلَّا سَيُكَلِّمُهُ اللَّهُ عَزَّ وَجَلَّ لَيْسَ بَيْنَهُ وَبَيْنَهُ تَرْجُمَانٌ ثُمَّ يَنْظُرُ أَيْمَنَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ أَشْأَمَ مِنْهُ فَلَا يَرَى إِلَّا شَيْئًا قَدَّمَهُ ثُمَّ يَنْظُرُ تِلْقَاءَ وَجْهِهِ فَتَسْتَقْبِلُهُ النَّارُ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَطَاعَ مِنْكُمْ أَنْ يَقِيَ وَجْهَهُ النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَلْيَفْعَلْ","id":"Telah menceritakan kepada kami [Abu Mu'awiyah] Telah menceritakan kepada kami [Al A'masy] dari [Khaitsamah] dari [Adi bin Hatim] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak seorang pun dari kalian, kecuali Allah 'azza wajalla akan mengajaknya berbicara, sementara tidak ada perantara antara dia dan Allah. Kemudian ia melihat ke sebelah kirinya, maka ia pun tidak melihat, kecuali sesuatu yang telah ia perbuatnya. Dan ia melihat ke sebelah kanannya, maka ia pun tidak melihat kecuali sesuatu yang telah diperbuatnya. Kemudian ia melihat ke arah depan, dan ternyata neraka telah berada di depannya.\" kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian yang mampu menyelamatkan wajahnya dari api neraka meskipun hanya dengan satu biji kurma, maka lakukanlah.\""},"2434":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سِمَاكٌ عَنْ مُرَيِّ بْنِ قَطَرِىٍّ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبِي كَانَ يَصِلُ الرَّحِمَ وَيَقْرِي الضَّيْفَ وَيَفْعَلُ كَذَا قَالَ إِنَّ أَبَاكَ أَرَادَ شَيْئًا فَأَدْرَكَهُ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَرْمِي الصَّيْدَ وَلَا أَجِدُ مَا أُذَكِّيهِ بِهِ إِلَّا الْمَرْوَةَ وَالْعَصَا قَالَ أَمَرَّ الدَّمَ بِمَا شِئْتَ ثُمَّ اذْكُرْ اسْمَ اللَّهِ عَزَّ وَجَلَّ قُلْتُ طَعَامٌ مَا أَدَعُهُ إِلَّا تَحَرُّجًا قَالَ مَا ضَارَعْتَ فِيهِ نَصْرَانِيَّةً فَلَا فَدَعْهُ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Simak] dari [Muray bin Qathari] dari [Adi bin Hatim] ia berkata; Saya berkata, \"Wahai Rasulullah, sesungguhnya, bapakku telah menyambung shilaturahim, ia juga memuliakan tamu dan juga berbuat ini dan itu.\" beliau bersabda: \"Sesungguhya bapakmu menginginkan sesuatu, dan ia pun mendapatkannya.\" Saya berkata lagi, \"Wahai Rasulullah, jika saya melempar hewan buruan, namun saya tidak mendapatkan sesuatu yang dapat saya gunakan untuk menyembelihnya kecuali batu runcing dan sebatang kayu, bagaimana tanggapan baginda?.\" Beliau bersabda: \"Alirkanlah darahnya dengan menggunakan alat apa saja, kemudian bacalah nama Allah 'azza wajalla.\" Saya berkata, \"Bagaimana tanggapan anda tentang makanan yang saya tidak bisa meninggalkannya, selain karena terpaksa?.\" Beliau bersabda; \"Sesuatu yang kamu lakukan dan menyerupai orang Nasrani, itu jangan, tinggalkanlah itu semua.\""},"2435":{"ar":"حَدَّثَنَا يَحْيَى عَنْ مُجَالِدٍ أَخْبَرَنِي عَامِرٌ حَدَّثَنِي عَدِيُّ بْنُ حَاتِمٍ قَالَعَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ وَالصِّيَامَ قَالَ صَلِّ كَذَا وَكَذَا وَصُمْ فَإِذَا غَابَتْ الشَّمْسُ فَكُلْ وَاشْرَبْ حَتَّى يَتَبَيَّنَ لَكَ الْخَيْطُ الْأَبْيَضُ مِنْ الْخَيْطِ الْأَسْوَدِ وَصُمْ ثَلَاثِينَ يَوْمًا إِلَّا أَنْ تَرَى الْهِلَالَ قَبْلَ ذَلِكَ فَأَخَذْتُ خَيْطَيْنِ مِنْ شَعْرٍ أَسْوَدَ وَأَبْيَضَ فَكُنْتُ أَنْظُرُ فِيهِمَا فَلَا يَتَبَيَّنُ لِي فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ وَقَالَ يَا ابْنَ حَاتِمٍ إِنَّمَا ذَاكَ بَيَاضُ النَّهَارِ مِنْ سَوَادِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Yahya] dari [Majalid] telah mengabarkan kepadaku [Amir] telah menceritakan kepadaku [Adi bin Hatim] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajariku shalat dan puasa. Beliau bersabda: \"Tunaikanlah shalat pada saat begini dan begitu. Kemudian berpuasalah, dan ketika matahari telah terbenam, maka makan dan minumlah kamu hingga tampak bagimu benang putih daripada benang hitam. Berpuasalah selama tiga puluh hari, kecuali sebelum itu, kamu telah melihat Hilal.\" Akhirnya saya pun mengambil dua helai rambut yang hitam dan yang putih, lalu saya pun melihat kepada keduanya, namun belum juga tampak bagiku. Maka saya mengungkapkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau pu tertawa dan bersabda: \"Wahai ibnu Hatim, maksud sebenarnya adalah putihnya siang daripada kegelapan malam.\""},"2436":{"ar":"حَدَّثَنَا يَحْيَى حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْحَاقَ عَنْ عَبْدِ اللَّهِ بْنِ مَعْقِلٍ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ","id":"Telah menceritakan kepada kami [Yahya] Telah menceritakan kepada kami [Syu'bah] Telah menceritakan kepada kami [Abu Ishaq] dari [Abdullah bin Ma'qil] ia berkata, saya mendengar [Adi bin Hatim] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhkanlah diri kalian dari api neraka, meskipun hanya dengan sebiji kurma.\""},"2437":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ ابْنِ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ ابْنِ حُذَيْفَةَ قَالَ كُنْتُ أُحَدَّثُ حَدِيثًا عَنْ عَدِيِّ بْنِ حَاتِمٍ فَقُلْتُ هَذَا عَدِيٌّ فِي نَاحِيَةِ الْكُوفَةِ فَلَوْ أَتَيْتُهُ فَكُنْتُ أَنَا الَّذِي أَسْمَعُهُ مِنْهُ فَأَتَيْتُهُ فَقُلْتُ إِنِّي كُنْتُ أُحَدَّثُ عَنْكَ حَدِيثًا فَأَرَدْتُ أَنْ أَكُونَ أَنَا الَّذِي أَسْمَعُهُ مِنْكَ قَالَلَمَّا بَعَثَ اللَّهُ عَزَّ وَجَلَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَرْتُ مِنْهُ حَتَّى كُنْتُ فِي أَقْصَى أَرْضِ الْمُسْلِمِينَ مِمَّا يَلِي الرُّومَ قَالَ فَكَرِهْتُ مَكَانِي الَّذِي أَنَا فِيهِ حَتَّى كُنْتُ لَهُ أَشَدَّ كَرَاهِيَةً لَهُ مِنِّي مِنْ حَيْثُ جِئْتُ قَالَ قُلْتُ لَآتِيَنَّ هَذَا الرَّجُلَ فَوَاللَّهِ إِنْ كَانَ صَادِقًا فَلَأَسْمَعَنَّ مِنْهُ وَإِنْ كَانَ كَاذِبًا مَا هُوَ بِضَائِرِي قَالَ فَأَتَيْتُهُ وَاسْتَشْرَفَنِي النَّاسُ وَقَالُوا عَدِيُّ بْنُ حَاتِمٍ عَدِيُّ بْنُ حَاتِمٍ قَالَ أَظُنُّهُ قَالَ ثَلَاثَ مِرَارٍ قَالَ فَقَالَ لِي يَا عَدِيُّ بْنَ حَاتِمٍ أَسْلِمْ تَسْلَمْ قَالَ قُلْتُ إِنِّي مِنْ أَهْلِ دِينٍ قَالَ يَا عَدِيُّ بْنَ حَاتِمٍ أَسْلِمْ تَسْلَمْ قَالَ قُلْتُ إِنِّي مِنْ أَهْلِ دِينٍ قَالَهَا ثَلَاثًا قَالَ أَنَا أَعْلَمُ بِدِينِكَ مِنْكَ قَالَ قُلْتُ أَنْتَ أَعْلَمُ بِدِينِي مِنِّي قَالَ نَعَمْ قَالَ أَلَيْسَ تَرْأَسُ قَوْمَكَ قَالَ قُلْتُ بَلَى قَالَ فَذَكَرَ مُحَمَّدٌ الرَّكُوسِيَّةَ قَالَ كَلِمَةً الْتَمَسَهَا يُقِيمُهَا فَتَرَكَهَا قَالَ فَإِنَّهُ لَا يَحِلُّ فِي دِينِكَ الْمِرْبَاعُ قَالَ فَلَمَّا قَالَهَا تَوَاضَعَتْ مِنِّي هُنَيَّةٌ قَالَ وَإِنِّي قَدْ أَرَى أَنَّ مِمَّا يَمْنَعُكَ خَصَاصَةٌ تَرَاهَا مِمَّنْ حَوْلِي وَإِنَّ النَّاسَ عَلَيْنَا أَلْبًا وَاحِدًا هَلْ تَعْلَمُ مَكَانَ الْحِيرَةِ قَالَ قُلْتُ قَدْ سَمِعْتُ بِهَا وَلَمْ آتِهَا قَالَ لَتُوشِكَنَّ الظَّعِينَةُ أَنْ تَخْرُجَ مِنْهَا بِغَيْرِ جِوَارٍ حَتَّى تَطُوفَ قَالَ يَزِيدُ بْنُ هَارُونَ جَوْرٍ وَقَالَ يُونُسُ عَنْ حَمَّادٍ جَوَازٍ ثُمَّ رَجَعَ إِلَى حَدِيثِ عَدِيِّ بْنِ حَاتِمٍ حَتَّى تَطُوفَ بِالْكَعْبَةِ وَلَتُوشِكَنَّ كُنُوزُ كِسْرَى بْنِ هُرْمُزَ أَنْ تُفْتَحَ قَالَ قُلْتُ كِسْرَى بْنُ هُرْمُزَ قَالَ كِسْرَى بْنُ هُرْمُزَ قَالَ قُلْتُ كِسْرَى بْنُ هُرْمُزَ قَالَ كِسْرَى بْنُ هُرْمُزَ ثَلَاثَ مَرَّاتٍ وَلَيُوشِكَنَّ أَنْ يَبْتَغِيَ مَنْ يَقْبَلُ مَالَهُ مِنْهُ صَدَقَةً فَلَا يَجِدُ قَالَ فَلَقَدْ رَأَيْتُ ثِنْتَيْنِ قَدْ رَأَيْتُ الظَّعِينَةَ تَخْرُجُ مِنْ الْحِيرَةِ بِغَيْرِ جِوَارٍ حَتَّى تَطُوفَ بِالْكَعْبَةِ وَكُنْتُ فِي الْخَيْلِ الَّتِي غَارَتْ وَقَالَ يُونُسُ عَنْ حَمَّادٍ أَغَارَتْ عَلَى الْمَدَائِنِ وَايْمُ اللَّهِ لَتَكُونَنَّ الثَّالِثَةُ إِنَّهُ لَحَدِيثُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَنِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Ibnu 'Aun] dari [Muhammad bin Sirin] dari [Ibnu Hudzaifah] ia berkata, saya menceritakan suatu hadits dari [Adi bin Hatim]. Saya berkata; \"Akulah Adi yang berada di ujung Kufah, sekiranya saya mendatanginya, maka sayalah yang akan mendengar langsung darinya.\" Maka saya pun mendatanginya dan berkata, \"Sesungguhnya saya menceritakan suatu hadits darimu, dan saya ingin mendengarnya langsung darimu.\" Ia berkata; Ketika Allah 'azza wajalla mengutus Nabi shallallahu 'alaihi wasallam, saya lari darinya hingga saya berada di penghujung tanah kaum muslimin mendekati Romawi. Lalu saya merasa benci berada di tempat yang aku tempati, hingga kebencianku terhadapnya melebihi kebencianku terhadap tempatku dahulu. Akhirnya saya berkata, \"Saya akan benar-benar mendatangi laki-laki ini. Demi Allah, jika ia adalah seorang yang Shadiq (benar), saya benar-benar akan mendengarnya. Namun, jika ia adalah seorang pendusta, maka ia tidak akan mampu melukaiku.\" Maka saya mendatanginya dan orang -orang pun mengawasiku. Mereka berkata, \"Tolong awasi si Adi bin Hatim, Tolong awasi si Adi bin Hatim.\" Saya menduga mereka mengatakannya hingga tiga kali. Kemudian beliau bersabda padaku: \"Wahai Adi, masuk Islamlah, niscaya kamu akan selamat.\" Saya berkata, \"Sesungguhnya saya adalah seorang yang telah beragama.\" Beliau bersabda lagi: \"Wahai Adi, masuk Islamlah, niscaya kamu akan selamat.\" Saya berkata, \"Sesungguhnya saya adalah seorang yang telah beragama.\" Beliau mengatakannya hingga tiga kali. Kemudian beliau bersabda: \"Sesungguhnya saya lebih tahu tentang agamamu daripada kamu.\" Saya bertanya, \"Anda lebih tahu tentang agamaku daripada aku?\" beliau menjawab: \"Ya.\" Beliau bertanya lagi: \"Bukankah kamu memimpin kaummu?\" saya menjawab, \"Ya, benar.\" Kata Adi, lantas nabi Muhammad menyebut-nyebut agama Rakusiyah, yaitu sebuah agama campuran antara majusi dan Kristen. Kata Adi, itulah sebuah istilah yang beliau ambil, beliau luruskan, lantas beliau tinggalkan. Kemudian beliau bersabda: \"Sesungguhnya di dalam agamamu tidak dihalalkan seperempat dari harta ghanimah.\" Saat beliau mengatakannya, saya pun diam beberapa saat. Beliau bersabda lagi: \"Dan sungguh, saya melihat bahwa salah satu yang menghalangimu (untuk memeluk Islam) adalah kesusahan yang dialami oleh orang di sekelilingku. Dan sesungguhnya orang-orang merupakan satu koalisi yang bersatu padu memusuhi kami. Apakah kamu tahu daerah Al Hirah?\" saya menjawab, \"Saya pernah mendengarnya, namun saya belum ke sana.\" Beliau bersabda: \"Nyaris aka nada seorang wanita berangkat darinya dengan tanpa perlindungan, hingga kamu melakukan thawaf -Yazid bin Harun berkata dengan redaksi; 'dengan tanpa penganiayaan'. Sedang Yunus berkata, dari Hammad dengan redaksi; 'dengan tanpa dibolehkan'. Kemudian ia kembali pada hadits Adi bin Hatim, yakni; Hingga kamu melakukan thawaf- di Ka'bah. Dan diprediksikan Istana Kisra bin Hurmus akan ditaklukkan.\" Saya balik bertanya, \"Kisra bin Hurmuz?\" beliau menjawab: \"Ya, benar, Kisra bin Hurmuz.\" Saya balik bertanya lagi, \"Kisra bin Hurmuz?\" beliau menjawab: \"Ya, benar, Kisra bin Hurmuz.\" Saya mengulanginya hingga tiga kali. Beliau bersabda lagi: \"Dan diprediksikan akan datang sebuah masa yang ketika itu seseorang berangan-angan agar ada yang mau menerima sedekah darinya, namun ia tidak mendapatkannya.\" Adi bin Hatim berkata; Sungguh, saya telah melihat dua hal (dari apa yang beliau sabdakan). Saya telah melihat seorang wanita yang melakukan perjalanan, ia berangkat dari Hirah tanpa seorang pengawal pun hingga ia melakukan thawaf di Ka'bah, sementara saya berada di atas kuda yang sedang menyerbu pasukan musuh. -Yunus berkata, dari Hammad- (Kuda) yang menyerbu Mada'in. Demi Allah, yang ketiga benar-benar akan terjadi. Sungguh, itu adalah hadits Rasulullah shallallahu 'alaihi wasallam yang telah beliau ceritakan kepadaku."},"2438":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يُحَدِّثُ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ رَجُلًا جَاءَهُ يَسْأَلُهُ عَنْ شَيْءٍ اسْتَقَلَّهُ فَحَلَفَ ثُمَّ قَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرًا خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْ عَنْ يَمِينِهِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا حَدِيثٌ مَا سَمِعْتُهُ قَطُّ مِنْ أَحَدٍ إِلَّا مِنْ أَبِي","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] ia berkata, saya mendengar [Abdullah bin Amr] menceritakan dari [Adi bin Hatim] bahwa seorang laki-laki mendatanginya dan meminta sesuatu yang ia anggap hanya sedikit. Lalu ia bersumpah (untuk tidak memberikannya). Lantas ia berkata; \"Duh sekiranya aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang bersumpah, kemudian ia melihat sesuatu yang lebih baik darinya, maka hendaklah ia lakukan yang lebih baik dan membayar kaffarat sumpahnya.\" Abu Abdurrahman berkata; Saya tidak pernah mendengar hadits ini dari seorang pun, kecuali dari bapakku."},"2439":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ سِمَاكَ بْنَ حَرْبٍ قَالَ سَمِعْتُ عَبَّادَ بْنَ حُبَيْشٍ يُحَدِّثُ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَجَاءَتْ خَيْلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ قَالَ رُسُلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِعَقْرَبٍ فَأَخَذُوا عَمَّتِي وَنَاسًا قَالَ فَلَمَّا أَتَوْا بِهِمْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَصَفُّوا لَهُ قُلْتُ يَا رَسُولَ اللَّهِ نَأَى الْوَافِدُ وَانْقَطَعَ الْوَلَدُ وَأَنَا عَجُوزٌ كَبِيرَةٌ مَا بِي مِنْ خِدْمَةٍ فَمُنَّ عَلَيَّ مَنَّ اللَّهُ عَلَيْكَ قَالَ مَنْ وَافِدُكِ قَالَتْ عَدِيُّ بْنُ حَاتِمٍ قَالَ الَّذِي فَرَّ مِنْ اللَّهِ وَرَسُولِهِ قَالَتْ فَمَنَّ عَلَيَّ قَالَتْ فَلَمَّا رَجَعَ وَرَجُلٌ إِلَى جَنْبِهِ نَرَى أَنَّهُ عَلِىٌّ قَالَ سَلِيهِ حِمْلَانًا قَالَ فَسَأَلَتْهُ فَأَمَرَ لَهَا قَالَتْ فَأَتَتْنِي فَقَالَتْ لَقَدْ فَعَلْتَ فَعْلَةً مَا كَانَ أَبُوكَ يَفْعَلُهَا قَالَتْ ائْتِهِ رَاغِبًا أَوْ رَاهِبًا فَقَدْ أَتَاهُ فُلَانٌ فَأَصَابَ مِنْهُ وَأَتَاهُ فُلَانٌ فَأَصَابَ مِنْهُ قَالَ فَأَتَيْتُهُ فَإِذَا عِنْدَهُ امْرَأَةٌ وَصِبْيَانٌ أَوْ صَبِيٌّ فَذَكَرَ قُرْبَهُمْ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَفْتُ أَنَّهُ لَيْسَ مُلْكُ كِسْرَى وَلَا قَيْصَرَ فَقَالَ لَهُ يَا عَدِيُّ بْنَ حَاتِمٍ مَا أَفَرَّكَ أَنْ يُقَالَ لَا إِلَهَ إِلَّا اللَّهُ فَهَلْ مِنْ إِلَهٍ إِلَّا اللَّهُ مَا أَفَرَّكَ أَنْ يُقَالَ اللَّهُ أَكْبَرُ فَهَلْ شَيْءٌ هُوَ أَكْبَرُ مِنْ اللَّهِ عَزَّ وَجَلَّ قَالَ فَأَسْلَمْتُ فَرَأَيْتُ وَجْهَهُ اسْتَبْشَرَ وَقَالَ إِنَّ الْمَغْضُوبَ عَلَيْهِمْ الْيَهُودُ وَ الضَّالِّينَ النَّصَارَي ثُمَّ سَأَلُوهُ فَحَمِدَ اللَّهَ تَعَالَى وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ فَلَكُمْ أَيُّهَا النَّاسُ أَنْ تَرْضَخُوا مِنْ الْفَضْلِ ارْتَضَخَ امْرُؤٌ بِصَاعٍ بِبَعْضِ صَاعٍ بِقَبْضَةٍ بِبَعْضِ قَبْضَةٍ قَالَ شُعْبَةُ وَأَكْثَرُ عِلْمِي أَنَّهُ قَالَ بِتَمْرَةٍ بِشِقِّ تَمْرَةٍ إِنَّ أَحَدَكُمْ لَاقِي اللَّهَ عَزَّ وَجَلَّ فَقَائِلٌ مَا أَقُولُ أَلَمْ أَجْعَلْكَ سَمِيعًا بَصِيرًا أَلَمْ أَجْعَلْ لَكَ مَالًا وَوَلَدًا فَمَاذَا قَدَّمْتَ فَيَنْظُرُ مِنْ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِ وَعَنْ يَمِينِهِ وَعَنْ شِمَالِهِ فَلَا يَجِدُ شَيْئًا فَمَا يَتَّقِي النَّارَ إِلَّا بِوَجْهِهِ فَاتَّقُوا النَّارَ وَلَوْ بِشِقِّ تَمْرَةٍ فَإِنْ لَمْ تَجِدُوهُ فَبِكَلِمَةٍ لَيِّنَةٍ إِنِّي لَا أَخْشَى عَلَيْكُمْ الْفَاقَةَ لَيَنْصُرَنَّكُمْ اللَّهُ تَعَالَى وَلَيُعْطِيَنَّكُمْ أَوْ لَيَفْتَحَنَّ لَكُمْ حَتَّى تَسِيرَ الظَّعِينَةُ بَيْنَ الْحِيرَةِ ويَثْرِبَ أَوْ أَكْثَرَ مَا تَخَافُ السَّرَقَ عَلَى ظَعِينَتِهَاقَالَ مُحَمَّدُ بْنُ جَعْفَرٍ ثَنَاهُ شُعْبَةُ مَا لَا أُحْصِيهِ وَقَرَأْتُهُ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Simak bin Harb] berkata, saya mendengar [Abbad bin Khubaisy] menceritakan dari [Adi bin Hatim] ia berkata; Suatu ketika datanglah pasukan berkuda milik Rasulullah shallallahu 'alaihi wasallam atau ia mengatakan; para utusan Rasulullah shallallahu 'alaihi wasallam, yang ketika itu saya berada di 'Aqrab. Mereka kemudian menangkap (dan menawan) bibiku dan beberapa orang. Ketika mereka (pasukan berkuda muslimin) membawa para tawanan kepada Rasulullah shallallahu 'alaihi wasallam, mereka pun dibariskan di hadapan beliau. Saya berkata, \"Wahai Rasulullah, utusan kami telah pergi jauh, dan anak-anak pun terputus dari keluarganya, sementara saya adalah seorang wanita tua yang lemah. Tak bisa melayani apa-apa. Berbuat baiklah padaku, semoga Allah berbuat baik pada Anda.\" Beliau bertanya: \"Siapakah utusanmu?\" wanita itu menjawab, \" Itu si 'Adi bin Hatim.\" Beliau bersabda: \"Orang yang telah lari dari Allah dan Rasul-Nya?\" wanita itu berkata, \"Berbuat baiklah padaku.\" Ketika seorang laki-laki kembali ke sisinya -kami lihat laki-laki itu adalah Ali-, ia berkata, \"Mintalah biaya kepada beliau.\" (Adi bin Hatim) Berkata; kemudian wanita itu pun meminta kepada beliau dan beliau pun memerintahkan untuk memberinya. Kemudian wanita itu mendatangiku dan berkata, \"Kamu telah berbuat sesuatu yang sebelumnya tidak pernah dilakukan oleh bapakmu. Datangilah ia denga perasaan suka atau benci. Dan sungguh, si Fulan telah mendatanginya dan ia pun mendapatkan bagian darinya. Dan si Fulan juga telah mendatanginya dan ia pun mendapatkan bagian darinya.\" (Adi) Berkata; Akhirnya aku pun mendatangi beliau dan ternyata di sisi beliau ada wanita dan anak-anak kecil. Ia menyebutkan kedekatan mereka dengan Nabi shallallahu 'alaihi wasallam, akhirnya aku tahu, bahwa watak beliau bukan seperti raja Kisra dan bukan pula Kaisar. Kemudian beliau bertanya kepadanya: \"Wahai Adi bin Hatim, apa yang menyebabkanmu enggan untuk diikrarkan bahwa, tidak ada Tuhan yang berhak disembah selain Allah? Apakah ada Tuhan lain selain Allah? Apakah yang menyebabkanmu enggan untuk dikatakan, 'ALLAHU AKBAR (Allah Maha Besar)? Adakah yang lebih besar dari Allah 'azza wajalla?\" Akhirnya (Adi bin Hatim) Berkata; Maka saya pun memeluk Islam. Dan saya pun melihat wajah beliau dipenuhi kegembiraan. Kemudian beliau bersabda: \"Sesungguhnya yang dimaksud mereka yang dimurkai adalah kaum Yahudi, dan yang dimaksud mereka yang tersesat adalah kaum Nasrani.\" Mereka (orang-orang yang berada di sekeliling beliau) pun meminta sesuatu kepada beliau. Maka beliau memuji Allah, dan membaca puji-pujian atas-Nya. Setelah itu beliau bersabda: \"Wahai sekalian manusia, hendaklah kalian memberi dari kelebihan harta (yang dikaruniakan kepada kalian). Seorang yang mempunyai satu sha' memberi setengah sha', yang mempunyai satu genggam memberi setengah gengam, -Syu'bah berkata; sejauh apa aku ketahui, beliau berkata- (bahkan) yang memiliki satu biji kurma, memberi dengan setengah biji kurma. Sesungguhnya salah seorang dari kalian akan menjumpai Allah 'azza wajalla, sehingga Dia pun akan bertanya, 'Bukankah Aku telah menjadikanmu mendengar dan melihat? Bukankah Aku telah mengaruniakanmu harta dan anak? Lalu apa yang telah kamu persembahkan? ' Ia pun melihat ke depannya, ke belakang, ke samping kanannya dan ke samping kirinya, namun ia tidak mendapatkan sesuatu pun. Dan tidak ada yang bisa menjaga dari api neraka selain beramal karena mencari wajah-Nya. Karena itu, jauhkanlah diri kalian dari neraka meskipun hanya dengan setengah biji kurma. Dan jika kalian tidak mendapati, maka hendaklah berkata-kata dengan kalimat yang baik. Sesungguhnya saya tidak khawatir kefakiran akan menimpa kalian, Allah benar-benar akan menolong dan memberi kalian atau benar-benar akan membuka rezeki untuk kalian hingga seorang wanita melakukan safar dengan hewan tunggangannya antara Hirat dan Yatsrib -atau dengan redaksi- Yang banyak kalian khawatirkan yaitu pencurian terhadap wanita penggangnya.\" Muhammad bin Ja'far berkata; Syu'bah menceritakannya kepada kami hingga saya tidak lagi menghitungnya (seberapa kali ia menceritakannya), dan saya telah membacakan hadits itu kepadanya."},"2440":{"ar":"حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَجَاءَ رَجُلَانِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَشَهَّدَ أَحَدُهُمَا فَقَالَ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ الْخَطِيبُ أَنْتَ قُمْ","id":"Telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Abdul Aziz bin Rufai'] dari [Tamim bin Tharafah] dari [Adi bin Hatim] ia berkata; Dua orang laki-laki mendatangi Rasulullah shallallahu 'alaihi wasallam. Kemudian salah seorang dari bertasyahadat lantas berkata, \"Barangsiapa yang mentaati Allah dan Rasul-Nya, maka sungguh ia telah mendapat petunjuk. Dan siapa yang bermaksiat kepada keduanya...\" maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Seburuk-buruk khatib adalah kamu, berdirilah.\""},"2441":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا الشَّيْبَانِيُّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فِي شَهْرِ رَمَضَانَ فَلَمَّا غَابَتْ الشَّمْسُ قَالَ انْزِلْ يَا فُلَانُ فَاجْدَحْ لَنَا قَالَ يَا رَسُولَ اللَّهِ عَلَيْكَ نَهَارٌ قَالَ انْزِلْ فَاجْدَحْ قَالَ فَفَعَلَ فَنَاوَلَهُ فَشَرِبَ فَلَمَّا شَرِبَ أَوْمَأَ بِيَدِهِ إِلَى الْمَغْرِبِ فَقَالَ إِذَا غَرَبَتْ الشَّمْسُ هَاهُنَا جَاءَ اللَّيْلُ مِنْ هَاهُنَا فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Asy Syaibani] dari [Abdullah bin Abu Aufa] ia berkata; Kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan pada bulan Ramadlan. Ketika matahari terbenam beliau bersabda: \"Wahai Fulan, sediakanlah minuman untuk kami.\" Ia berkata, \"Wahai Rasulullah, hari masih terang.\" Beliau bersabda: \"Sediakanlah minuman untuk kami.\" Maka ia pun menyiapkannya dan beliau minum. Setelah itu, beliau memberi isyarat dengan tangannya ke arah barat seraya bersabda: \"Jika matahari telah terbenam di sebelah ini, maka malam telah tiba dari sini dan orang yang berpuasa pun telah berbuka.\""},"2442":{"ar":"حَدَّثَنَا هُشَيْمٌ أَنْبَأَنَا الشَّيْبَانِيُّ عَنْ مُحَمَّدِ بْنِ أَبِي الْمُجَالِدِ مَوْلَى بَنِي هَاشِمٍ قَالَأَرْسَلَنِي ابْنُ شَدَّادٍ وَأَبُو بُرْدَةَ فَقَالَا انْطَلِقْ إِلَى ابْنِ أَبِي أَوْفَى فَقُلْ لَهُ إِنَّ عَبْدَ اللَّهِ بْنَ شَدَّادٍ وَأَبَا بُرْدَةَ يُقْرِئَانِكَ السَّلَامَ وَيَقُولَانِ هَلْ كُنْتُمْ تُسَلِّفُونَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْبُرِّ وَالشَّعِيرِ وَالزَّبِيبِ قَالَ نَعَمْ كُنَّا نُصِيبُ غَنَائِمَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُسَلِّفُهَا فِي الْبُرِّ وَالشَّعِيرِ وَالتَّمْرِ وَالزَّبِيبِ فَقُلْتُ عِنْدَ مَنْ كَانَ لَهُ زَرْعٌ أَوْ عِنْدَ مَنْ لَيْسَ لَهُ زَرْعٌ فَقَالَ مَا كُنَّا نَسْأَلُهُمْ عَنْ ذَلِكَ قَالَ وَقَالَا لِي انْطَلِقْ إِلَى عَبْدِ الرَّحْمَنِ بْنِ أَبْزَى فَاسْأَلْهُ قَالَ فَانْطَلَقَ فَسَأَلَهُ فَقَالَ مِثْلَ مَا قَالَ ابْنُ أَبِي أَوْفَىقَالَ وَكَذَا حَدَّثَنَاهُ أَبُو مُعَاوِيَةَ عَنْ زَائِدَةَ عَنِ الشَّيْبَانِيِّ قَالَ وَالزَّيْتِ","id":"Telah menceritakan kepada kami [Husyaim] telah memberitakan kepada kami [Asy Syaibani] dari [Muhammad bin Abul Mujalid] bekas budak Bani Mujalid, ia berkata; Ibnu Syaddad dan Abu Burdah mengutusku, mereka berdua berkata, \"Pergi dan temuilah [Ibnu Abu Aufa] kemudian katakan bahwa, Abdullah bin Syaddad dan Abu Burdah menyampaikan salam atasmu, dan keduanya bertanya, 'Apakah pada masa Rasulullah shallallahu 'alaihi wasallam, kalian memberi pinjaman harta pada pertanian gandum, dan anggur?\" ia menjawab, \"Ya. Kami pernah mendapatkan harta ghanimah pada masa Rasulullah shallallahu 'alaihi wasallam lalu kami menjadikannya sebagai pinjaman pada usaha gandum, kurma dan anggur.\" Saya bertanya, \"Kepada siapa?\" ia menjawab, \"Bagi yang memiliki lahan pertanian atau juga bagi yang tidak memiliki lahan.\" Ia berkata, \"Kami tidak menanyakan yang itu.\" Ibnu Abu Aufa berkata, \"Temuilah [Abdurrahman bin Abza] dan bertanyalah padanya.\" ia pun pergi dan bertanya kepadanya, maka Abdurrahman pun memberikan jawaban sebagai jawaban Ibnu Abu Aufa. Ia pun berkata; Seperti inilah yang telah diceritakan oleh [Abu Mu'awiyah] dari [Za`idah] dari [Asy Syaibani]; Ia berkata; \"Dan (juga) minyak Zaitun.\""},"2443":{"ar":"حَدَّثَنَا سُفْيَانُ حَدَّثَنَا أَبُو يَعْفُورٍ عَبْدِيٌّ مَوْلًى لَهُمْ قَالَذَهَبْتُ إِلَى ابْنِ أَبِي أَوْفَى أَسْأَلُهُ عَنْ الْجَرَادِ قَالَ غَزَوْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سِتَّ غَزَوَاتٍ نَأْكُلُ الْجَرَادَ","id":"Telah menceritakan kepada kami [Sufyan] Telah menceritakan kepada kami [Abu Ya'fur] bekas budak mereka, ia berkata; saya menemui [Ibnu Abu Aufa] untuk menanyakan tentang belalang. Ia menjawab, \"Saya telah ikut berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak enam kali peperangan, dan kami makan belalang.\""},"2444":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَاقَ الشَّيْبَانِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَقَالَ لِرَجُلٍ انْزِلْ فَاجْدَحْ لَنَا وَقَالَ سُفْيَانُ مَرَّةً يَا رَسُولَ اللَّهِ قَالَ اجْدَحْ قَالَ يَا رَسُولَ اللَّهِ قَالَ اجْدَحْ فَجَدَحَ فَشَرِبَ فَلَمَّا شَرِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْمَأَ بِيَدِهِ نَحْوَ اللَّيْلِ إِذَا رَأَيْتُمْ اللَّيْلَ قَدْ أَقْبَلَ مِنْ هَاهُنَا فَقَدْ أَفْطَرَ الصَّائِمُ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq Asy Syaibani] ia berkata, saya mendengar [Abdullah bin Abu Aufa] berkata; Kami pernah bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan. Kemudian beliau berkata kepada seseorang: \"Singgah dan siapkanlah minuman untuk kami.\" Dan sekali waktu Sufyan berkata; \"Wahai Rasulullah.\" Beliau bersabda: \"Siapkanlah minuman.\" Ia berkata, \"Wahai Rasulullah.\" Beliau bersabda: \"Siapkanlah minuman.\" Maka ia pun menyediakan minuman. Beliau kemudian minum. Dan setelah Rasulullah shallallahu 'alaihi wasallam minum, beliau menunjuk dengan tangannya ke arah datangnya malam, \"Jika kalian telah melihat malam masuk dari sini, maka orang yang berpuasa sudah mulai berbuka.\""},"2445":{"ar":"حَدَّثَنَا سُفْيَانُ عَنِ الشَّيْبَانِيِّ عَنِ ابْنِ أَبِي أَوْفَى قَالَأَصَبْنَا حُمُرًا خَارِجًا مِنْ الْقَرْيَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْفِئُوا الْقُدُورَ بِمَا فِيهَافَذَكَرْتُ ذَلِكَ لِسَعِيدِ بْنِ جُبَيْرٍ فَقَالَ إِنَّمَا نَهَى عَنْهَا أَنَّهَا كَانَتْ تَأْكُلُ الْعَذِرَةَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Asy Syaibani] dari [Ibnu Abu Aufa] ia berkata; Kami mendapatkan harta ghanimah berupa Himar yang muncul dari pedesaan. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Tumpahkanlah bejana dan beserta isinya.\" Saya pun menuturkan hal itu kepada Sa'id bin Jubair, ia berkata, \"Beliau melarangnya, karena himar itu selalu makan sisa makanan manusia.\""},"2446":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ أَخْبَرَنَا لَيْثٌ عَنْ مُدْرِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فَيَقُولُ اللَّهُمَّ طَهِّرْنِي بِالثَّلْجِ وَالْبَرَدِ وَالْمَاءِ الْبَارِدِ اللَّهُمَّ طَهِّرْ قَلْبِي مِنْ الْخَطَايَا كَمَا طَهَّرْتَ الثَّوْبَ الْأَبْيَضَ مِنْ الدَّنَسِ وَبَاعِدْ بَيْنِي وَبَيْنَ ذُنُوبِي كَمَا بَاعَدْتَ بَيْنَ الْمَشْرِقِ وَالْمَغْرِبِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ قَلْبٍ لَا يَخْشَعُ وَمِنْ نَفْسٍ لَا تَشْبَعُ وَدُعَاءٍ لَا يُسْمَعُ وَعِلْمٍ لَا يَنْفَعُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ هَؤُلَاءِ الْأَرْبَعِ اللَّهُمَّ إِنِّي أَسْأَلُكَ عِيشَةً تَقِيَّةً وَمِيتَةً سَوِيَّةً وَمَرَدًّا غَيْرَ مُخْزٍ","id":"Telah menceritakan kepada kami [Isma'il] telah mengabarkan kepada kami [Laits] dari [Mudrik] dari [Abdullah bin Abu Aufa] bahwa Rasulullah shallallahu 'alaihi wasallam berdo'a: \"ALLAHUMMA THAHHIRNII BITS TSALJI WAL BARADI WAL MAA`IL BAARID, ALLAHUMMA THAHHIR QALBI, MINAL KHATHAAYAA KAMAA THAHHARTATS TSAUBAL ABYADLA MINAD DANASI WA BAA'ID BAINII WA BAINA DZUNUUBI KAMAA BAA'ADTA BAINAL MASYRIQI WAL MAGHRIBI, ALLAHUMMA INNI `A'UUDZU BIKA MIN QALBIN LAA YAKHSYA' WA MIN NAFSIN LAA TASYBA' WA DU'AA`IN LAA YUSMA' WA 'ILMIN LAA YANFA'. ALLAHUMMA INNII A'UUDZU BIKA MIN HAA`ULAA`IL ARBA', ALLAHUMMA INNII AS`ALUKA 'IISYATAN TAQIYYAH WA MIITATAN SAWIYYAH WA MARADDAN GHAIRA MUKHZIN (Ya Allah, sucikanlah aku dengan salju dan (air) yang sejuk. Ya Allah sucikanlah hatiku dari segala dosa, sebagaimana Engkau membersihkan kain putih dari kotoran. Dan jauhkanlah antara diriku dengan dosa-dosaku, sebagaimana Engkau telah menjauhkan antara timur dan barat. Ya Allah, aku berlindung kepada-Mu, dari hati yang tak pernah khyusu', nafsu yang tak pernah puas, do'a yang tidak pernah terkabul dan ilmu tidak bermanfaat. Ya Allah, aku berlindung kepada-Mu dari keempat hal itu. Ya Allah, aku meminta pada-Mu kehidupan yang penuh dengan ketakwaan, kematian yang penuh kedamaian dan tempat kembali tanpa ada kehinaan di dalamnya).\""},"2447":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ حَدَّثَنَا أَيُّوبُ عَنِ القَاسِمِ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَقَدِمَ مُعَاذٌ الْيَمَنَ أَوْ قَالَ الشَّامَ فَرَأَى النَّصَارَى تَسْجُدُ لِبَطَارِقَتِهَا وَأَسَاقِفَتِهَا فَرَوَّأَ فِي نَفْسِهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَقُّ أَنْ يُعَظَّمَ فَلَمَّا قَدِمَ قَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ النَّصَارَى تَسْجُدُ لِبَطَارِقَتِهَا وَأَسَاقِفَتِهَا فَرَوَّأْتُ فِي نَفْسِي أَنَّكَ أَحَقُّ أَنْ تُعَظَّمَ فَقَالَ لَوْ كُنْتُ آمِرًا أَحَدًا أَنْ يَسْجُدَ لِأَحَدٍ لَأَمَرْتُ الْمَرْأَةَ أَنْ تَسْجُدَ لِزَوْجِهَا وَلَا تُؤَدِّي الْمَرْأَةُ حَقَّ اللَّهِ عَزَّ وَجَلَّ عَلَيْهَا كُلَّهُ حَتَّى تُؤَدِّيَ حَقَّ زَوْجِهَا عَلَيْهَا كُلَّهُ حَتَّى لَوْ سَأَلَهَا نَفْسَهَا وَهِيَ عَلَى ظَهْرِ قَتَبٍ لَأَعْطَتْهُ إِيَّاهُحَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنِ الْقَاسِمِ بْنِ عَوْفٍ رَجُلٍ مِنْ أَهْلِ الْكُوفَةِ أَحَدِ بَنِي مُرَّةَ بْنِ هَمَّامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أَبِيهِ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ إِنَّهُ أَتَى الشَّامَ فَرَأَى النَّصَارَى فَذَكَرَ مَعْنَاهُ إِلَّا أَنَّهُ قَالَ فَقُلْتُ لِأَيِّ شَيْءٍ تَصْنَعُونَ هَذَا قَالُوا هَذَا كَانَ تَحِيَّةَ الْأَنْبِيَاءِ قَبْلَنَا فَقُلْتُ نَحْنُ أَحَقُّ أَنْ نَصْنَعَ هَذَا بِنَبِيِّنَا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهُمْ كَذَبُوا عَلَى أَنْبِيَائِهِمْ كَمَا حَرَّفُوا كِتَابَهُمْ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَبْدَلَنَا خَيْرًا مِنْ ذَلِكَ السَّلَامَ تَحِيَّةَ أَهْلِ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Isma'il] Telah menceritakan kepada kami [Ayub] dari [Al Qasim Asy Syaibani] dari [Abdullah bin Abu Aufa] ia berkata; Ketika Mu'adz sampai di negeri Yaman atau Syam, ia melihat orang-orang Nasrani sujud kepada para komandan dan ulamanya. Lalu terpikirkanlah di dalam hatinya bahwa Rasulullah shallallahu 'alaihi wasallam adalah lebih berhak. Maka ketika ia kembali, ia berkata, \"Wahai Rasulullah, saya telah melihat orang-orang sujud kepada para komandan dan para ulama mereka, lalu terpikirkanlah di dalam hatiku bahwa Anda adalah lebih berhak untuk dimuliakan.\" Maka beliau bersabda: \"Sekiranya saya boleh memerintahkan seseorang untuk sujud kepada orang lain, niscaya saya akan memerintahkan wanita untuk sujud kepada suaminya. Dan seorang wanita tidak akan memenuhi hak Allah 'azza wajalla atas dirinya sepenuhnya, kecuali ia memenuhi hak suaminya atas dirinya. Bahkan sekiranya suaminya meminta dirinya, sementara ia saat itu berada di atas pelana kendaraan, maka ia harus mentaatinya.\" Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qasim bin Auf] seorang laki-laki dari Kufah, yaitu Bani Murrah bin Hammam, dari [Abdurrahman bin Abu Laila] dari [bapaknya] dari [Mu'adz bin Jabal] ia berkata; ia mendatangi negeri Syam, lalu ia melihat orang-orang Nasrani. Ia pun menyebutkan maknanya. Hanya saja ia mengatakan; Saya berkata, \"Untuk apa kalian berbuat seperti ini?\" mereka menjawab, \"Ini adalah bentuk penghormatan kepada para Nabi pada masa sebelum kami.\" Maka saya pun berkata, \"Sesungguhnya kami lebih berhak untuk berbuat seperti ini kepada Nabi kami.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mereka telah berdusta kepada Nabi-Nabi mereka, sebagaimana mereka telah merubah Kitab-Kitab mereka. sesungguhnya Allah 'azza wajalla telah menggantikan untuk kita sesuatu yang lebih baik dari itu, yaitu Salam, ucapan selamat bagi penghuni surga.\""},"2448":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَاعِيلَ يَعْنِي ابْنَ أَبِي خَالِدٍ قَالَقُلْتُ لِعَبْدِ اللَّهِ بنِ أَبِي أَوْفَى هَلْ بَشَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَدِيجَةَ قَالَ نَعَمْ بَشَّرَهَا بِبَيْتٍ مِنْ قَصَبٍ لَا صَخَبٌ فِيهِ وَلَا نَصَبٌ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il] yakni Ibnu Abu Khalid, ia berkata, saya bertanya kepada [Abdullah bin Abu Aufa], \"Apakah Nabi shallallahu 'alaihi wasallam pernah memberi kabar gembira kepada Khadijah?\" ia menjawab, \"Ya, beliau telah menyampaikan berita gembira padanya berupa rumah yang terbuat dari mutiara, yang tiada kebisingan di dalamnya dan tidak pula kepenatan.\""},"2449":{"ar":"حَدَّثَنَا يَحْيَى عَنْ إِسْمَاعِيلَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ أَبِي أَوْفَى قَالَاعْتَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَافَ بِالْبَيْتِ ثُمَّ خَرَجَ فَطَافَ بَيْنَ الصَّفَا وَالْمَرْوَةِ وَجَعَلْنَا نَسْتُرُهُ مِنْ أَهْلِ مَكَّةَ أَنْ يَرْمِيَهُ أَحَدٌ أَوْ يُصِيبَهُ بِشَيْءٍ فَسَمِعْتُهُ يَدْعُو عَلَى الْأَحْزَابِ يَقُولُ اللَّهُمَّ مُنْزِلَ الْكِتَابِ سَرِيعَ الْحِسَابِ هَازِمَ الْأَحْزَابِ اللَّهُمَّ اهْزِمْهُمْ وَزَلْزِلْهُمْ","id":"Telah menceritakan kepada kami [Yahya] dari [Isma'il] Telah menceritakan kepada kami [Abdullah bin Abu Aufa] ia berkata; Rasulullah shallallahu 'alaihi wasallam melakukan Umrah, lalu beliau thawaf di Baitullah. Kemudian beliau keluar dan melakukan thawaf antara Shafa dan Marwah, maka kami pun melindungi beliau daripada lemparan kaum musyrikin, atau mencelakainya dengan sesuatu. Kemudian saya mendengar beliau mendo'akan kecelakaan atas pasukan Ahzab: \"ALLAHUMMA MUNZILAL KITAABI SARII'UL HISAABI HAAZIMAL AHZAAB ALLAHUMMAH ZIMHUM WA ZALZILHUM (Ya Allah, yang telah menurunkan kitab, Yang maha cepat hisab-Nya, Ya Allah, binasakan dan goyahkanlah kekuatan mereka).\""},"2450":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ قَالَقُلْتُ لِعَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى أَوْصَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ قَالَ لَا قُلْتُ فَكَيْفَ أَمْرَ الْمُسْلِمِينَ بِالْوَصِيَّةِ قَالَ أَوْصَى بِكِتَابِ اللَّهِ عَزَّ وَجَلَّقَالَ مَالِكُ بْنُ مِغْوَلٍ قَالَ طَلْحَةُ وَقَالَ الْهُزَيْلُ بْنُ شُرَحْبِيلَ أَبُو بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ كَانَ يَتَأَمَّرُ عَلَى وَصِيِّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَدَّ أَبُو بَكْرٍ رَضِيَ اللَّهُ تَعَالَى عَنْهُ أَنَّهُ وَجَدَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَهْدًا فَخُزِمَ أَنْفُهُ بِخِزَامٍ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Malik bin Mighwal] dari [Thalhah bin Musharrif] ia berkata, saya bertanya kepada [Abdullah bin Abu Aufa], \"Apakah Nabi shallallahu 'alaihi wasallam pernah berwasiat?\" Ia menjawab, \"Tidak.\" Saya bertanya lagi, \"lalu mengapa beliau memerintahkan wasiat kepada kaum muslimin?\" ia menjawab, \"Beliau telah berwasiat dengan Kitabullah 'azza wajalla.\" Malik bin Mighwal berkata, Thalhah berkata, Al Huzail bin Syurahbil berkata; Dan Abu Bakar radliallahu 'anhu memerintah dengan menunaikan wasiat Rasulullah shallallahu 'alaihi wasallam. Juga Abu Bakar Rasulullah shallallahu 'alaihi wasallam merasa senang memperoleh janji dibersamakan dengan Rasulullah shallallahu 'alaihi wasallam, maka hidung untanya ia kalungi dengan gelang dari rambut (sebagai pertanda kegembiraannya)."},"2451":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ الْحَجَّاجِ يَعْنِي الصَّوَّافَ بْنَ أَبِي عُثْمَانَ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ وَأَبِي سَلَمَةَ عَنْ أَبِي قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بِنَا فَيَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ فِي الرَّكْعَتَيْنِ الْأُولَيَيْنِ بِفَاتِحَةِ الْكِتَابِ وَسُورَتَيْنِ وَيُسْمِعُنَا الْآيَةَ أَحْيَانًا وَكَانَ يُطَوِّلُ فِي الرَّكْعَةِ الْأُولَى مِنْ الظُّهْرِ وَيُقَصِّرُ فِي الثَّانِيَةِ وَكَذَا فِي الصُّبْحِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Al Hajjaj] yakni Ash Shawwaf bin Abu Utsman, dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dan [Abu Salamah] dari [Abu Qatadah] ia berkata; Rasulullah shallallahu 'alaihi wasallam shalat Zhuhur dan Ashar bersama kami, maka pada dua raka'at pertama beliau membaca Fatihatul Kitab (surat Al Fatihah) dan dua surat. Dan terkadang beliau memperdengarkan bacaan ayatnya pada kami. Kemudian beliau memanjangkan raka'at pertama shalat Zhuhur, dan memendekkan raka'at kedua, seperti inilah yang beliau lakukan pada shalat Subuh."},"2452":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنِ الْحَجَّاجِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ��َالَ إِذَا شَرِبَ أَحَدُكُمْ فَلَا يَتَنَفَّسْ فِي الْإِنَاءِ وَإِذَا دَخَلَ الْخَلَاءَ فَلَا يَتَمَسَّحْ بِيَمِينِهِ وَإِذَا بَالَ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Adi] dari [Al Hajjaj] dari [Yahya bin Abu Katsir] dari [Abdullah bin Abu Qatadah] dari [bapaknya] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian minum, maka janganlah ia bernafas dalam benjana. Dan jika ia hendak memasuki Kakus, maka janganlah ia membasuh (bersuci) dengan menggunakan tangan kanannya. Jika ia kencing, maka janganlah ia memegang zakarnya dengan tangan kanan.\""},"2453":{"ar":"قَالَ يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي طَلْحَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلَا يَأْكُلْ بِشِمَالِهِ وَإِذَا شَرِبَ فَلَا يَشْرَبْ بِشِمَالِهِ وَإِذَا أَخَذَ فَلَا يَأْخُذْ بِشِمَالِهِ وَإِذَا أَعْطَى فَلَا يُعْطِي بِشِمَالِهِ","id":"Telah berkata [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abullah bin Abu Thalhah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian makan, janganlah makan dengan tangan kirinya, dan apabila meminum maka jangan pula dengan tangan kirinya, dan apa bila mengambil sesuatu juga jangan dengan tangan kirinya, dan begitu pula apabila memberikan kepada seseorang, juga jangan dengan tangan kirinya.\""},"2454":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ عَطِيَّةَ الْقُرَظِيِّ قَالَعُرِضْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَشَكُّوا فِيَّ فَأَمَرَ بِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَنْظُرُوا إِلَيَّ هَلْ أَنْبَتُّ بَعْدُ فَنَظَرُوا فَلَمْ يَجِدُونِي أَنْبَتُّ فَخَلَّى عَنِّي وَأَلْحَقَنِي بِالسَّبْيِ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abdul Malik bin Umari] dari ['Athiyah Al Qurazhi] ia berkata; \"Saya dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam pada hari Quraizhah, dan mereka (para sahabat) meragukanku (apakah aku sudah baligh ataukah belum). Maka Nabi shallallahu 'alaihi wasallam memerintahkan mereka untuk melihat tubuhku, apakah bulu kemaluanku telah tumbuh. Mereka pun melihatnya, tapi bulu kemaluanku ternyata belum tumbuh. Akhirnya mereka melepaskan dan menggabungkanku bersama anak kecil.\""},"2455":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ أَنَّهُ سَمِعَ عَطِيَّةَ يَقُولُكُنْتُ يَوْمَ حَكَمَ سَعْدٌ فِيهِمْ غُلَامًا فَلَمْ يَجِدُونِي أَنْبَتُّ فَهَا أَنَا ذَا بَيْنَ أَظْهُرِكُمْ","id":"Telah menceritakan kepada kami [Sufyan] dari [Abdul Malik] bahwa ia mendengar ['Athiyyah] berkata; \"Ketika Sa'd menghukumi (Bani Quraizhah) saya masih kecil, sehingga mereka tidak mendapati bulu kemaluanku tumbuh. Karena itulah, saya bisa hadir di hadapan kalian.\""},"2456":{"ar":"حَدَّثَنَا إِسْمَاعِيلُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُبَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَ وَقَدْ سَمِعْتُهُ مِنْ عُقْبَةَ وَلَكِنِّي لِحَدِيثِ عُبَيْدٍ أَحْفَظُ قَالَتَزَوَّجْتُ امْرَأَةً فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي تَزَوَّجْتُ فُلَانَةَ ابْنَةَ فُلَانٍ فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا وَهِيَ كَاذِبَةٌ فَأَعْرَضَ عَنِّي فَأَتَيْتُهُ مِنْ قِبَلِ وَجْهِهِ فَقُلْتُ إِنَّهَا كَاذِبَةٌ فَقَالَ فَكَيْفَ بِهَا وَقَدْ زَعَمَتْ أَنَّهَا قَدْ أَرْضَعَتْكُمَا دَعْهَا عَنْكَ","id":"Telah menceritakan kepada kami [Isma'il bin Ibrahim] telah mengabarkan kepada kami [Ayyub] dari [Abdullah bin Abu Mulaikah] ia berkata, telah menceritakan kepadaku [Ubaid bin Abu Maryam] dari [Uqbah bin Harits] -Abdullah berkata; saya telah mendengarnya dari Uqbah, tapi saya lebih menghafal hadits Ubaid- ia berkata; \"Aku menikahi seorang wanita. Lalu datanglah seorang wanita hitam dan berkata, \"Sesungguhnya aku telah menyusui kalian berdua.\" Maka aku segera menemui Nabi shallallahu 'alaihi wasallam dan menuturkan kepadanya bahwa, \"Aku telah menikahi fulanah binti fulan lalu datanglah seorang wanita hitam dan mengatakan, 'Sesungguhnya aku telah menyusui kalian berdua.'\" Wanita itu adalah pendusta. Namun beliau berpaling dariku, maka saya mendatangi beliau dari arah depannya seraya berkata, \"Wanita adalah pendusta.\" Akhirnya beliau bersabda: \"Bagaimana lagi dengan wanita itu, padahal ia telah mengaku bahwa ia telah menyusui kalian berdua. Tinggalkanlah perempuan yang telah engkau nikahi itu.\""},"2457":{"ar":"حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَاعِيلَ بْنِ أُمَيَّةَ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَتَزَوَّجْتُ ابْنَةَ أَبِي إِهَابٍ فَجَاءَتْ امْرَأَةٌ سَوْدَاءُ فَذَكَرَتْ أَنَّهَا أَرْضَعَتْنَا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ بَيْنَ يَدَيْهِ فَكَلَّمْتُهُ فَأَعْرَضَ عَنِّي فَقُمْتُ عَنْ يَمِينِهِ فَأَعْرَضَ عَنِّي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا هِيَ سَوْدَاءُ قَالَ وَكَيْفَ وَقَدْ قِيلَ","id":"Telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah] dari [Ibnu Abu Mulaikah] dari [Uqbah bin Harits] ia berkata; Saya menikahi anak wanita Abu Ihab. Lalu datanglah seorang wanita berkulit hitam dan menuturkan bahwa ia telah menyusui kami. Saya pun segera menemui Rasulullah shallallahu 'alaihi wasallam, saya berdiri di hadapannya dan berbicara kepadanya, namun beliau berpaling dariku. Saya berdiri lagi di sebelah kanannya, namun beliau tetap berpaling dariku. Akhirnya saya berkata, \"Wahai Rasulullah, ia hanyalah seorang wanita hitam.\" Beliau bersabda: \"Lalu bagaimana lagi, sedangkan wanita telah mengatakannya?\""},"2458":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا أَبِي حَدَّثَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ قَالَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنُّعَيْمَانِ قَدْ شَرِبَ الْخَمْرَ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ فِي الْبَيْتِ فَضَرَبُوهُ بِالْأَيْدِي وَالْجَرِيدِ وَالنِّعَالِ قَالَ وَكُنْتُ فِيمَنْ ضَرَبَهُ","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [bapakku] Telah menceritakan kepada kami [Ayyub] dari [Ibnu Abu Mulaikah] ia berkata, telah menceritakan kepadaku [Uqbah bin Harits] ia berkata; An Nu'aiman dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam setelah ia minum khamar. Maka Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada semua yang berada di rumah untuk memukulnya. Dan mereka pun memukulnya dengan tangan, pelepah kurma, dan terompah. Dan waktu itu, saya termasuk orang yang memukulnya."},"2459":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ فَلَمَّا سَلَّمَ قَامَ سَرِيعًا فَدَخَلَ عَلَى بَعْضِ نِسَائِهِ ثُمَّ خَرَجَ وَرَأَى مَا فِي وُجُوهِ الْقَوْمِ مِنْ تَعَاجُبِهِمْ لِسُرْعَتِهِ قَالَ ذَكَرْتُ وَأَنَا فِي الصَّلَاةِ تِبْرًا عِنْدَنَا فَكَرِهْتُ أَنْ يُمْسِيَ أَوْ يَبِيتَ عِنْدَنَا فَأَمَرْتُ بِقَسْمِهِحَدَّثَنَا أَبُو أَحْمَدَ حَدَّثَنَا عُمَرُ بْنُ سَعِيدٍ عَنِ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَ انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ صَلَّى الْعَصْرَ فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Umar bin Sa'id bin Abu Husain] ia berkata, telah mengabarkan kepadaku [Abdullah bin Abu Mulaikah] dari [Uqbah bin Harits] ia berkata; Saya pernah shalat Ashar bersama Rasulullah shallallahu 'alaihi wasallam. Setelah beliau salam, beliau segera berdiri dan masuk ke dalam rumah salah seorang dari isteri-isterinya. Kemudian beliau keluar dan melihat keheranan pada wajah-wajah sahabatnya. Beliau bersabda: \"Pada saat shalat tadi, saya teringat akan Tibr (batangan emas/perak) yang ada pada kami, dan saya tidak suka kalau benda itu bersore atau bermalam hari pada kami, sehingga saya memerintahkan untuk membagi-bagikannya.\" Telah menceritakan kepada kami [Abu Ahmad] Telah menceritakan kepada kami [Umar bin Sa'id] dari [Ibnu Abu Mulaikah] dari [Uqbah bin Harits] ia berkata; Rasulullah shallallahu 'alaihi wasallam langsung beranjak setelah beliau menunaikan shalat Ashar. Ia pun menyebutkan maknanya."},"2460":{"ar":"حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ حَدَّثَنَا قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي نَجِيحٍ السُّلَمِيِّ قَالَحَاصَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِصْنَ الطَّائِفِ أَوْ قَصْرَ الطَّائِفِ فَقَالَ مَنْ بَلَغَ بِسَهْمٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَلَهُ دَرَجَةٌ فِي الْجَنَّةِ فَبَلَغْتُ يَوْمَئِذٍ سِتَّةَ عَشَرَ سَهْمًا وَمَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَهُوَ لَهُ عِدْلُ مُحَرَّرٍ وَمَنْ أَصَابَهُ شَيْبٌ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَهُوَ لَهُ نُورٌ يَوْمَ الْقِيَامَةِ وَأَيُّمَا رَجُلٍ أَعْتَقَ رَجُلًا مُسْلِمًا جَعَلَ اللَّهُ عَزَّ وَجَلَّ وِقَاءَ كُلِّ عَظْمٍ مِنْ عِظَامِهِ عَظْمًا مِنْ عِظَامِ مُحَرِّرِهِ مِنْ النَّارِ وَأَيُّمَا امْرَأَةٍ مُسْلِمَةٍ أَعْتَقَتْ امْرَأَةً مُسْلِمَةً فَإِنَّ اللَّهَ عَزَّ وَجَلَّ جَاعِلٌ وِقَاءَ كُلِّ عَظْمٍ مِنْ عِظَامِهَا عَظْمًا مِنْ عِظَامِ مُحَرِّرِهَا مِنْ النَّارِحَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَن سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمُرِيِّ عَنْ أَبِي نَجِيحٍ السُّلَمِيِّ قَالَ حَاصَرْنَا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِصْنَ الطَّائِفِ فَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ فَبَلَغَهُ فَلَهُ دَرَجَةٌ فِي الْجَنَّةِ فَقَالَ رَجُلٌ يَا نَبِيَّ اللَّهِ إِنْ رَمَيْتُ فَبَلَغْتُ فَلِي دَرَجَةٌ فِي الْجَنَّةِ قَالَ فَرَمَى فَبَلَغَ قَالَ فَبَلَغْتُ يَوْمَئِذٍ سِتَّةَ عَشَرَ سَهْمًا فَذَكَرَ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] Telah menceritakan kepada kami [Qatadah] dari [Salim bin Abul Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Abu Najih As Sulami] ia berkata; Kami bersama Rasulullah shallallahu 'alaihi wasallam mengepung benteng dan istana Tha`if. Kemudian beliau bersabda: \"Barangsiapa yang meluncurkan satu anak panah di dalan Allah 'azza wajalla, maka baginya satu derajat di dalam surga.\" Maka pada hari itu, saya dapat meluncurkan enam belas anak panah. Beliau bersabda lagi: \"Barangsiapa yang meluncurkan satu anak panah di jalan Allah 'azza wajalla, maka baginya adalah seperti pahala orang yang membebaskan budak. Dan siapa yang sehelai rambutnya menjadi uban di jalan Allah 'azza wajalla, maka hal itu akan menjadi cahaya baginya kelak pada hari kiamat. Dan siapa saja yang membebaskan satu orang budak muslim, maka Allah 'azza wajalla akan menjadikan setiap bagian tubuh budak itu sebagai pembebas dirinya dari api neraka. Dan wanita muslimah mana saja yang membebaskan satu orang budak wanita muslimah, maka Allah 'azza wajalla akan menjadikan dari setiap bagian tubuh budak wanita itu sebagi tebusan dirinya dari neraka.\" Telah menceritakan kepada kami [Abdul Wahhab] dari [Sa'id] dari [Qatadah] dari [Salim bin Abul Ja'd Al Ghathafani] dari [Ma'dan bin Abu Thalhah Al Ya'muri] dari [Abu Najih As Sulami] ia bekata; Kami bersama Nabi shallallahu 'alaihi wasallam mengepung benteng Tha`if, lalu saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meluncurkan satu anak panah di dalan Allah 'azza wajalla, maka baginya satu derajat di dalam surga.\" Maka seorang laki-laki kemudian berkata, \"Wahai Nabiyullah, jika saya melempar satu anak panah, lalu mengenai sasaran maka saya akan mendapatkan satu derajat di surge?.\" Maka laki-laki itu pun melempar dan mengenai sasaran. Dan pada hari itu, saya pun melempar dan mengenai sasaran sebanyak enam belas anak panah. Kemudian ia pun menyebut makna semisal."},"2461":{"ar":"��َدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ الْبَجَلِيِّ عَنْ صَخْرٍ الْغَامِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهَا أَوَّلَ النَّهَارِوَكَانَ صَخْرٌ رَجُلًا تَاجِرًا فَكَانَ لَا يَبْعَثُ غِلْمَانَهُ إِلَّا مِنْ أَوَّلِ النَّهَارِ فَكَثُرَ مَالُهُ حَتَّى لَا يَدْرِيَ أَيْنَ يَضَعُ مَالَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin Atha`] dari [Umarah bin Hadid Al Bajali] dari [Shakhr Al Ghamidi] dari Nabi shallallahu 'alaihi wasallam, beliau berdo'a: \"ALLAHUMMA BAARIK LIUMMATII FI BUKUURIHAA (Ya Allah, berilah keberkahan pada untuk ummatku di waktu pagi mereka).\" Dan jika Nabi shallallahu 'alaihi wasallam mengirim Sariyyah (ekspedisi militer yang dikirim untuk operasi tertentu), maka beliau mengirimnya pada pagi hari. Kemudian Shakhr adalah seorang penjual, dan ia juga tidak pernah mengirim para pelayannya kecuali pada permulaan hari (pagi hari), sehingga hartanya pun semakin berkembang dan banyak, sampai ia tidak tahu lagi di mana ia letakkan hartanya."},"2462":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ سُفْيَانَ الثَّقَفِيِّ عَنْ أَبِيهِأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ وَقَدْ قَالَ هُشَيْمٌ قُلْتُ يَا رَسُولَ اللَّهِ مُرْنِي فِي الْإِسْلَامِ بِأَمْرٍ لَا أَسْأَلُ عَنْهُ أَحَدًا بَعْدَكَ قَالَ قُلْ آمَنْتُ بِاللَّهِ ثُمَّ اسْتَقِمْ قَالَ قُلْتُ فَمَا أَتَّقِي فَأَوْمَأَ إِلَى لِسَانِهِ","id":"Telah menceritakan kepada kami [Husyaim] dari [Ya'la bin Atha`] dari [Abdullah bin Sufyan Ats Tsaqafi] dari [bapaknya] bahwa seorang laki-laki berkata; \"Wahai Rasulullah..\" dan Husyaim berkata; Saya berkata, \"Wahai Rasulullah, perintahkanlah padaku suatu syariat dalam Islam ini, yang tidak akan aku tanyakan kepada seorang pun setelah Anda.\" Beliau bersabda: \"Katakanlah, 'Aku beriman kepada Allah' lalu istiqamahlah (dalam ucapanmu).\" Saya bertanya lagi, \"Lalu apakah yang harus aku waspadai?\" Maka beliau pun memberi isyarat dengan menunjuk ke arah lidahnya."},"2463":{"ar":"حَدَّثَنَا سُرَيْجُ بْنُ النُّعْمَانِ حَدَّثَنَا نُوحُ بْنُ قَيْسٍ عَنْ أَشْعَثَ بْنِ جَابِرٍ الْحُدَّانِيِّ عَنْ مَكْحُولٍ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْخٌ كَبِيرٌ يَدَّعِمُ عَلَى عَصًا لَهُ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ لِي غَدَرَاتٍ وَفَجَرَاتٍ فَهَلْ يُغْفَرُ لِي قَالَ أَلَسْتَ تَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ بَلَى وَأَشْهَدُ أَنَّكَ رَسُولُ اللَّهِ قَالَ قَدْ غُفِرَ لَكَ غَدَرَاتُكَ وَفَجَرَاتُكَ","id":"Telah menceritakan kepada kami [Suraij bin Nu'man] Telah menceritakan kepada kami [Nuh bin Qais] dari [Asy'ats bin Jabir Al Huddani] dari [Makhul] dari [Amru bin 'Abasah] ia berkata; Bahwasanya seorang lelaki tua (lansia) datang kepada Nabi shallallahu 'alaihi wasallam sambil bersandar pada tongkatnya dan bertanya, \"Wahai Rasulallah, sesungguhnya aku adalah seorang yang mempunyai dosa karena sering menipu dan berbuat aniaya, apakah aku bisa diampuni?\" Beliau menjawab: \"Bukankah kamu bersaksi bahwa tiada tuhan yang berhak disembah selain Allah?\" Orang tua itu menjawab, \"Ya, dan saya juga bersaksi bahwa Anda adalah utusan Allah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, dosa lantaran penipuan dan aniayamu telah diampuni.\""},"2464":{"ar":"حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا حَرِيزُ بْنُ عُثْمَانَ وَهُوَ الرَّحَبِيُّ حَدَّثَنَا سُلَيْمُ بْنُ عَامِرٍ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ بِعُكَاظٍ فَقُلْتُ مَنْ تَبِعَكَ عَلَى هَذَا الْأَمْرِ فَقَالَ حُرٌّ وَعَبْدٌ وَمَعَهُ أَبُو بَكْرٍ وَبِلَالٌ رَضِيَ اللَّهُ تَعَالَى عَنْهُمَا فَقَالَ لِي ارْجِعْ حَتَّى يُمَكِّنَ اللَّهُ عَزَّ وَجَلَّ لِرَسُولِهِ فَأَتَيْتُهُ بَعْدُ فَقُلْتُ يَا رَسُولَ اللَّهِ جَعَلَنِي اللَّهُ فِدَاءَكَ شَيْئًا تَعْلَمُهُ وَأَجْهَلُهُ لَا يَضُرُّكَ وَيَنْفَعُنِي اللَّهُ عَزَّ وَجَلَّ بِهِ هَلْ مِنْ سَاعَةٍ أَفْضَلُ مِنْ سَاعَةٍ وَهَلْ مِنْ سَاعَةٍ يُتَّقَى فِيهَا فَقَالَ لَقَدْ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ قَبْلَكَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَتَدَلَّى فِي جَوْفِ اللَّيْلِ فَيَغْفِرُ إِلَّا مَا كَانَ مِنْ الشِّرْكِ وَالْبَغْيِ فَالصَّلَاةُ مَشْهُودَةٌ مَحْضُورَةٌ فَصَلِّ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ فَأَقْصِرْ عَنْ الصَّلَاةِ فَإِنَّهَا تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَهِيَ صَلَاةُ الْكُفَّارِ حَتَّى تَرْتَفِعَ فَإِذَا اسْتَقَلَّتْ الشَّمْسُ فَصَلِّ فَإِنَّ الصَّلَاةَ مَحْضُورَةٌ مَشْهُودَةٌ حَتَّى يَعْتَدِلَ النَّهَارُ فَإِذَا اعْتَدَلَ النَّهَارُ فَأَقْصِرْ عَنْ الصَّلَاةِ فَإِنَّهَا سَاعَةٌ تُسَجَّرُ فِيهَا جَهَنَّمُ حَتَّى يَفِيءَ الْفَيْءُ فَإِذَا فَاءَ الْفَيْءُ فَصَلِّ فَإِنَّ الصَّلَاةَ مَحْضُورَةٌ مَشْهُودَةٌ حَتَّى تَدَلَّى الشَّمْسُ لِلْغُرُوبِ فَإِذَا تَدَلَّتْ فَأَقْصِرْ عَنْ الصَّلَاةِ حَتَّى تَغِيبَ الشَّمْسُ فَإِنَّهَا تَغِيبُ عَلَى قَرْنَيْ شَيْطَانٍ وَهِيَ صَلَاةُ الْكُفَّارِ","id":"Telah menceritakan kepada kami [Yazid bin Harun] Telah menceritakan kepada kami [Harits bin Utsman] ia adalah Ar Rahabi, Telah menceritakan kepada kami [Sulaim bin Amir] dari [Amru bin Abasah] ia berkata; Saya mendatangi Rasulullah shallallahu 'alaihi wasallam ketika beliau di 'Ukadz, lalu aku bertanya, \"Siapakah orang yang menjadi pengikut Anda dalam perkara ini (Din Islam)?\" Beliau menjawab: \"Seorang yang merdeka dan juga sorang budak.\" Saat itu beliau bersama Abu Bakar dan Bilal radliallahu 'anhuma. Kemudian beliau bersabda kepadaku: \"Pulanglah kamu hingga Allah menguatkan Rasul-Nya.\" Setelah itu, saya mendatangi beliau dan berkata, \"Semoga Allah menjadikanku sebagai tebusanmu. Ajarkanlah aku sesuatu yang Anda ketahui sementara aku tidak mengetahuinya, yaitu sesuatu yang tidak membahayakanmu dan Allah juga memberiku manfaat dengannya. Apakah ada suatu waktu yang lebih utama dari waktu yang lain, dan adakah suatu waktu yang harus kita waspadai?\" Beliau menjawab: \"Sungguh, kamu telah bertanya kepadaku tentang sesuatu yang belum pernah ditanyakan oleh seorang pun sebelummu. Sesungguhnya Allah 'azza wajalla turun pada sepertiga akhir malam, dan Dia mengampuni dosa apa saja kecuali syirik dan perbuatan yang melampaui batas. Shalat adalah suatu ibadah yang disaksikan dan dihadiri (oleh para malaikat) maka hendaklah kamu shalat hingga matahari terbit. Dan apabila matahari telah terbit, maka janganlah kamu shalat hingga matahari meninggi, karena matahari terbit diantara dua tanduk syetan, dan shalat pada waktu itu adalah shalatnya orang-orang kafir. Kemudian, jika matahari sudah meninggi, maka shalatlah, karena shalat pada waktu itu disaksikan dan dihadiri (oleh para malaikat) hingga pertengahan siang. Saat matahari berada di pertengahan langit, maka janganlah kamu shalat, karena pada waktu itu api neraka sedang dinyalakan hingga bayangan kembali muncul. Dan apabila bayangan sudah kembali maka shalatlah kamu, karena shalat pada waktu itu disaksikan dan dihadiri (oleh para malaikat) hingga matahari turun untuk terbenam. Ketika matahari hari hendak terbenam, maka janganlah kamu shalat hingga benar-benar terbenam, Karena matahari terbenam diantara dua tanduk syetan dan pada waktu itulah orang-orang kafir beribadah.\""},"2465":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا حَجَّاجٌ يَعْنِي ابْنَ دِينَارٍ عَنْ مُحَمَّدِ بْنِ ذَكْوَانَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ مَنْ تَبِعَكَ عَلَى هَذَا الْأَمْرِ قَالَ حُرٌّ وَعَبْدٌ قُلْتُ مَا الْإِسْلَامُ قَالَ طِيبُ الْكَلَامِ وَإِطْعَامُ الطَّعَامِ قُلْتُ مَا الْإِيمَانُ قَالَ الصَّبْرُ وَالسَّمَاحَةُ قَالَ قُلْتُ أَيُّ الْإِسْلَامِ أَفْضَلُ قَالَ مَنْ سَلِمَ الْمُسْلِمُونَ مِنْ لِسَانِهِ وَيَدِهِ قَالَ قُلْتُ أَيُّ الْإِيمَانِ أَفْضَلُ قَالَ خُلُقٌ حَسَنٌ قَالَ قُلْتُ أَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِ قَالَ قُلْتُ أَيُّ الْهِجْرَةِ أَفْضَلُ قَالَ أَنْ تَهْجُرَ مَا كَرِهَ رَبُّكَ عَزَّ وَجَلَّ قَالَ قُلْتُ فَأَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ عُقِرَ جَوَادُهُ وَأُهْرِيقَ دَمُهُ قَالَ قُلْتُ أَيُّ السَّاعَاتِ أَفْضَلُ قَالَ جَوْفُ اللَّيْلِ الْآخِرُ ثُمَّ الصَّلَاةُ مَكْتُوبَةٌ مَشْهُودَةٌ حَتَّى يَطْلُعَ الْفَجْرُ فَإِذَا طَلَعَ الْفَجْرُ فَلَا صَلَاةَ إِلَّا الرَّكْعَتَيْنِ حَتَّى تُصَلِّيَ الْفَجْرَ فَإِذَا صَلَّيْتَ صَلَاةَ الصُّبْحِ فَأَمْسِكْ عَنْ الصَّلَاةِ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ الشَّمْسُ فَإِنَّهَا تَطْلُعُ فِي قَرْنَيْ شَيْطَانٍ وَإِنَّ الْكُفَّارَ يُصَلُّونَ لَهَا فَأَمْسِكْ عَنْ الصَّلَاةِ حَتَّى تَرْتَفِعَ فَإِذَا ارْتَفَعَتْ فَالصَّلَاةُ مَكْتُوبَةٌ مَشْهُودَةٌ حَتَّى يَقُومَ الظِّلُّ قِيَامَ الرُّمْحِ فَإِذَا كَانَ كَذَلِكَ فَأَمْسِكْ عَنْ الصَّلَاةِ حَتَّى تَمِيلَ فَإِذَا مَالَتْ فَالصَّلَاةُ مَكْتُوبَةٌ مَشْهُودَةٌ حَتَّى تَغْرُبَ الشَّمْسُ فَإِذَا كَانَ عِنْدَ غُرُوبِهَا فَأَمْسِكْ عَنْ الصَّلَاةِ فَإِنَّهَا تَغْرُبُ أَوْ تَغِيبُ فِي قَرْنَيْ شَيْطَانٍ وَإِنَّ الْكُفَّارَ يُصَلُّونَ لَهَا","id":"Telah menceritakan kepada kami [Ibnu Numair] Telah menceritakan kepada kami [Hajjaj] yakni Ibnu Dinar, dari [Muhammad bin Dzakwan] dari [Syahr bin Hausyab] dari [Amru bin 'Asabah] ia berkata; Saya mendatangi Rasulullah shallallahu 'alaihi wasallam dan bertanya, \"Wahai Rasulullah, siapa saja yang mengikuti Anda di atas perkara (Din Islam) ini?\" beliau menjawab: \"Yaitu seorang yang merdeka dan seorang budak.\" Saya bertanya lagi, \"Apakah Islam itu?\" beliau menjawab: \"Yaitu berkata-kata yang baik dan memberi makanan.\" Saya bertanya lagi, \"Apakah iman itu?\" beliau menjawab: \"Yaitu sabar dan As Samaahah (murah hati).\" Saya bertanya kembali, \"Islam seperti apakah yang paling utama?\" beliau menjawab: \"Yaitu seseorang yang kaum muslimin selamat dari lisan dan tangannya.\" aku bertanya lagi, \"Iman seperti apakah yang paling utama?\" beliau menjawab: \"Yaitu akhlak yang baik.\" Saya berta lagi, \"Shalat apakah yang paling utama?\" beliau menjawab: \"Yaitu shalat dengan berdiri lama.\" Saya bertanya lagi, \"Hijrah yang manakah yang paling utama?\" beliau menjawab: \"Yaitu kamu berhijrah dari apa-apa yang dibenci oleh Rabb-mu Azza wa Jalla.\" Saya bertanya kembali, \"Jihad yang manakah yang paling utama?\" beliau menjawab: \"Yaitu siapa yang kuda perang miliknya terluka dan darahnya mencucur.\" Saya bertanya lagi, \"Waktu manakah yang paling utama?\" beliau menjawab: \"Yaitu sepertiga akhir malam. Kemudian shalat wajib adalah disaksikan oleh para malaikat hingga waktu fajar menyingsing. Jika fajar telah terbit, maka tidak ada shalat kecuali dua raka'at sampai kamu menunaikan shalat Fajar. Setelah kamu menunaikan shalat Shubuh, maka janganlah kamu shalat hingga matahari terbit. Saat matahari terbit, maka sesungguhnya ia terbit di antara dua tanduk syetan, dan pada waktu itu orang-orang kafir sedang beribadah, karena itu, janganlah kamu shalat hingga matahari meninggi. Ketika Matahari telah meninggi, maka shalatlah, dan shalat di waktu itu adalah berpahala, dan disaksikan oleh para malaikat sampai bayangan seseorang menyerupai panjang tombak, maka pada waktu ini janganlah kamu menunaikan shalat hingga matahari condong. Dan ketika matahari telah condong, maka shalat pada waktu itu akan ditulis pahalanya dan akan disaksikan oleh para malaikat hingga matahari terbenam. Dan saat matahari akan terbenam, maka janganlah kamu shalat, karena ia terbenam di antara dua tanduk syetan dan saat itu, orang-orang kafir sedang beribadah.\""},"2466":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْفَيْضِ عَنْ سُلَيْمِ بْنِ عَامِرٍ قَالَكَانَ بَيْنَ مُعَاوِيَةَ وَبَيْنَ قَوْمٍ مِنْ الرُّومِ عَهْدٌ فَخَرَجَ مُعَاوِيَةُ قَالَ فَجَعَلَ يَسِيرُ فِي أَرْضِهِمْ حَتَّى يَنْقُضُوا فَيُغِيرَ عَلَيْهِمْ فَإِذَا رَجُلٌ يُنَادِي فِي نَاحِيَةِ النَّاسِ وَفَاءٌ لَا غَدْرٌ فَإِذَا هُوَ عَمْرُو بْنُ عَبَسَةَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ بَيْنَهُ وَبَيْنَ قَوْمٍ عَهْدٌ فَلَا يَشِدَّ عُقْدَةً وَلَا يَحُلَّ حَتَّى يَمْضِيَ أَمَدُهَا أَوْ يَنْبِذَ إِلَيْهِمْ عَلَى سَوَاءٍ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Syu'bah] dari [Abu Al Faidl] dari [Sulaim bin Amir] ia berkata; Antara Mu'awiyah dan orang-orang Romawi terdapat suatu perjanjian. Mu'awiyah pun keluar dan berjalan menelusuri perkampungan mereka, hingga jika mereka sampai melanggar perjanjian, maka mereka diserang. Tiba-tiba seorang laki-laki yang berada di kerumunan manusia menyerukan, \"Penuhilah janji dan hendaklah tidak ada pengkhianatan.\" Dan ternyata ia adalah [Amru bin Abasah]. Lalu ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang antara ia dan suatu kaum terdapat suatu perjanjian, maka janganlah ia memperberat perjanjian itu (dengan menambah syarat-syaratnya) atau mencederai ikatannya, hingga batas waktunya berakhir atau hingga mereka sama-sama membatalkannya.\""},"2467":{"ar":"حَدَّثَنَا هَاشِمٌ حَدَّثَنِي عَبْدُ الْحَمِيدِ حَدَّثَنِي شَهْرٌ حَدَّثَنِي أَبُو ظَبْيَةَ قَالَإِنَّ شُرَحْبِيلَ بْنَ السِّمْطِ دَعَا عَمْرَو بْنَ عَبَسَةَ السُّلَمِيَّ فَقَالَ يَا ابْنَ عَبَسَةَ هَلْ أَنْتَ مُحَدِّثِي حَدِيثًا سَمِعْتَهُ أَنْتَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيهِ تَزَيُّدٌ وَلَا كَذِبٌ وَلَا تُحَدِّثْنِيهِ عَنْ آخَرَ سَمِعَهُ مِنْهُ غَيْرِكَ قَالَ نَعَمْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَقُولُ قَدْ حَقَّتْ مَحَبَّتِي لِلَّذِينَ يَتَحَابُّونَ مِنْ أَجْلِي وَحَقَّتْ مَحَبَّتِي لِلَّذِينَ يَتَصَافُّونَ مِنْ أَجْلِي وَحَقَّتْ مَحَبَّتِي لِلَّذِينَ يَتَزَاوَرُونَ مِنْ أَجْلِي وَحَقَّتْ مَحَبَّتِي لِلَّذِينَ يَتَبَاذَلُونَ مِنْ أَجْلِي وَحَقَّتْ مَحَبَّتِي لِلَّذِينَ يَتَنَاصَرُونَ مِنْ أَجْلِي","id":"Telah menceritakan kepada kami [Hasyim] telah menceritakan kepadaku [Abdul Hamid] telah menceritakan kepadaku [Syahr] telah menceritakan kepadaku [Abu Dzabyah] ia berkata; Bahwasanya Syurahbil bin As Simth memanggil Amru bin Abasah As Sulami dan bertanya, \"Wahai Ibnu Abasah, apakah Anda mau menceritakan kepadaku suatu hadits yang telah Anda dengar dari Rasulullah shallallahu 'alaihi wasallam tanpa ada tambahan ataupun kedustaan? Dan janganlah Anda ceritakan kepadaku suatu hadits dari sahabat lain yang ia mendengarnya dari beliau selain Anda. [Amru bin Abasah] berkata; Baiklah, aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah Ta'ala telah berfirman: 'Sungguh telah berhak mendapatkan kecintaan-Ku orang-orang yang saling mencintai karena Aku, dan sungguh telah berhak mendapatkan kecintaan-Ku orang-orang yang saling merapatkan barisan karena Aku, dan sungguh telah berhak mendapatkan kecintaan-Ku orang-orang yang saling mengunjungi karena Aku, dan sungguh telah berhak mendapatkan kecintaan-Ku orang-orang yang saling berkorban (untuk membantu yang lain) karena Aku, dan sungguh telah berhak mendapatkan kecintaan-Ku orang-orang yang saling menolong karena Aku.'\""},"2468":{"ar":"و قَالَ عَمْرُو بْنُ عَبَسَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا رَجُلٍ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ فَبَلَغَ مُخْطِئًا أَوْ مُصِيبًا فَلَهُ مِنْ الْأَجْرِ كَرَقَبَةٍ يُعْتِقُهَا مِنْ وَلَدِ إِسْمَاعِيلَ وَأَيُّمَا رَجُلٍ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ فَهِيَ لَهُ نُورٌ وَأَيُّمَا رَجُلٍ مُسْلِمٍ أَعْتَقَ رَجُلًا مُسْلِمًا فَكُلُّ عُضْوٍ مِنْ الْمُعْتَقِ بِعُضْوٍ مِنْ الْمُعْتِقِ فِدَاءٌ لَهُ مِنْ النَّارِ وَأَيُّمَا امْرَأَةٍ مُسْلِمَةٍ أَعْتَقَتْ امْرَأَةً مُسْلِمَةً فَكُلُّ عُضْوٍ مِنْ الْمُعْتَقَةِ بِعُضْوٍ مِنْ الْمُعْتِقَةِ فِدَاءٌ لَهَا مِنْ النَّارِ وَأَيُّمَا رَجُلٍ مُسْلِمٍ قَدَّمَ لِلَّهِ عَزَّ وَجَلَّ مِنْ صُلْبِهِ ثَلَاثَةً لَمْ يَبْلُغُوا الْحِنْثَ أَوْ امْرَأَةٍ فَهُمْ لَهُ سُتْرَةٌ مِنْ النَّارِ وَأَيُّمَا رَجُلٍ قَامَ إِلَى وَضُوءٍ يُرِيدُ الصَّلَاةَ فَأَحْصَى الْوَضُوءَ إِلَى أَمَاكِنِهِ سَلِمَ مِنْ كُلِّ ذَنْبٍ أَوْ خَطِيئَةٍ لَهُ فَإِنْ قَامَ إِلَى الصَّلَاةِ رَفَعَهُ اللَّهُ عَزَّ وَجَلَّ بِهَا دَرَجَةً وَإِنْ قَعَدَ قَعَدَ سَالِمًا فَقَالَ شُرَحْبِيلُ بْنُ السِّمْطِ آنْتَ سَمِعْتَ هَذَا الْحَدِيثَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا ابْنَ عَبَسَةَ قَالَ نَعَمْ وَالَّذِي لَا إِلَهَ إِلَّا هُوَ لَوْ أَنِّي لَمْ أَسْمَعْ هَذَا الْحَدِيثَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ مَرَّةٍ أَوْ مَرَّتَيْنِ أَوْ ثَلَاثٍ أَوْ أَرْبَعٍ أَوْ خَمْسٍ أَوْ سِتٍّ أَوْ سَبْعٍ فَانْتَهَى عِنْدَ سَبْعٍ مَا حَلَفْتُ يَعْنِي مَا بَالَيْتُ أَنْ لَا أُحَدِّثَ بِهِ أَحَدًا مِنْ النَّاسِ وَلَكِنِّي وَاللَّهِ مَا أَدْرِي عَدَدَ مَا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan [Amru bin Abasah] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meluncurkan satu anak panah di jalan Allah dengan tepat mengenai sasaran atau tidak, maka baginya pahala seperti orang yang memerdekakan satu budak dari anaknya Isma'il. Dan siapa pun yang miliki sehelai rambut yang beruban di jalan Allah, maka hal itu akan menjadi cahaya baginya. Laki-laki musli m mana pun yang memerdekakan satu orang budak muslim, maka setiap anggota tubuh dari budak itu (yang dimerdekakan itu) akan menjadi tebusan untuk setiap anggota tubuh yang memerdekakan dari api neraka. Dan wanita muslimah mana pun yang membebaskan satu orang budak wanita muslimah, maka setiap organ tubuh dari budak wanita itu akan menjadi tebusan bagi Mu'tiqah (wanita yang membebaskan) dari api nerakan. Dan laki-laki muslim atau wanita muslimah mana pun yang merelakan (kematian tiga orang anaknya yang belum baligh) kepada Allah, maka ketiganya itu akan menjadi penghalang baginya dari api neraka. Dan barangsiapa yang beranjak ke tempat wudlu untuk menunaikan shalat, lalu ia meratakan air wudlu ke anggota wudlunya, maka seolah telah terbebas dari setiap dosa atau kesalahannya. Dan jika ia beranjak untuk menunaikan shalat, maka Allah akan menjadikan (dari setiap langkahnya) satu derajat (kedudukan di akhirat), dan jika ia duduk, maka ia telah duduk dalam keadaan selamat.\" Syurahbil bin Ash Shimth berkata, \"Apakah Anda mendengar hadits ini langsung dari Rasulullah shallallahu 'alaihi wasallam wahai Ibnu 'Abasah?\" ia menjawab, \"Ya, dan demi Dzat yang tidak ada Tuhan yang berhak disembah selain Dia, sekiranya saya belum mendengar hadits ini dari Rasulullah shallallahu 'alaihi wasallam lebih dari sekali, atau dua, tiga, empat, lima, enam, atau tujuh kali, maka saya tidak akan bersumpah, yang kumaksudkan saya tidak peduli untuk tidak menceritakannya kepada seorang pun dari manusia, akan tetapi demi Allah, saya tidak ingat lagi berapa kali saya mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"2469":{"ar":"حَدَّثَنَا حَيْوَةُ بْنُ شُرَيْحٍ حَدَّثَنَا بَقِيَّةُ حَدَّثَنَا بَحِيرُ بْنُ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ كَثِيرِ بْنِ مُرَّةَ عَنْ عَمْرِو بْنِ عَبَسَةَ أَنَّهُ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ بَنَى لِلَّهِ مَسْجِدًا لِيُذْكَرَ اللَّهُ عَزَّ وَجَلَّ فِيهِ بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ وَمَنْ أَعْتَقَ نَفْسًا مُسْلِمَةً كَانَتْ فِدْيَتَهُ مِنْ جَهَنَّمَ وَمَنْ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Haiwah bin Syuraih] Telah menceritakan kepada kami [Baqiyyah] Telah menceritakan kepada kami [Bahirah bin Sa'd] dari [Khalid bin Ma'dan] dari [Katsir bin Murrah] dari [Amru bin 'Abasah] bahwa ia telah menceritakan kepada mereka, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membangun Masjid karena Allah, dengan tujuan agar Allah senantiasa disebut nama-Nya, maka Allah akan membangunkan baginya rumah di surga. Dan barangsiapa yang memerdekakan satu orang budak wanita muslimah, maka wanita itu akan menjadi tebusannya dari api neraka. Dan siapa yang sehelai rambutnya beruban di jalan Allah 'azza wajalla, maka sehelai rambut itu akan menjadi cahaya baginya kelak pada hari kiamat.\""},"2470":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا عُثْمَانُ بْنُ عُبَيْدٍ أَبُو دَوْسٍ الْيَحْصَبِيُّ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَائِذٍ الثُّمَالِيُّ عَنْ عَمْرِو بْنِ عَبَسَةَ السُّلَمِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرُّ قَبِيلَتَيْنِ فِي الْعَرَبِ نَجْرَانُ وَبَنُو تَغْلِبَ","id":"Telah menceritakan kepada kami [Abul Mughirah] Telah menceritakan kepada kami [Utsman bin Ubaid Abu Idris Al Yahshabi] Telah menceritakan kepada kami [Abdurrahman bin A`idz Ats Tsumali] dari [Amru bin Abasah As Sulami] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua kabilah dari bangsa Arab yang paling jelek adalah Najran dan Banu Taghlib.\""},"2471":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا ابْنُ عَيَّاشٍ حَدَّثَنِي شُرَحْبِيلُ بْنُ مُسْلِمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ مَوْهَبٍ الْأَمْلُوكِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ السُّلَمِيِّ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى السَّكُونِ وَالسَّكَاسِكِ وَعَلَى خَوْلَانَ الْعَالِيَةِ وَعَلَى الْأَمْلُوكِ أَمْلُوكِ رَدْمَانِ","id":"Telah menceritakan kepada kami [Abul Mughirah] Telah menceritakan kepada kami [Ibnu Ayyasy] telah menceritakan kepadaku [Syurahbil bin Muslim] dari [Abdurrahman bin Yazid bin Mauhab Al Amluki] dari [Amru bin 'Abasah As Sulami] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat dengan penuh ketenangan, ketundukan, perhatian yang tinggi, dan penuh penghambaan.\""},"2472":{"ar":"حَدَّثَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو حَدَّثَنِي شُرَيْحُ بْنُ عُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَائِذٍ الْأَزْدِيِّ عَنْ عَمْرِو بْنِ عَبَسَةَ السُّلَمِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْرِضُ يَوْمًا خَيْلًا وَعِنْدَهُ عُيَيْنَةُ بْنُ حِصْنِ بْنِ بَدْرٍ الْفَزَارِيُّ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا أَفْرَسُ بِالْخَيْلِ مِنْكَ فَقَالَ عُيَيْنَةُ وَأَنَا أَفْرَسُ بِالرِّجَالِ مِنْكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَيْفَ ذَاكَ قَالَ خَيْرُ الرِّجَالِ رِجَالٌ يَحْمِلُونَ سُيُوفَهُمْ عَلَى عَوَاتِقِهِمْ جَاعِلِينَ رِمَاحَهُمْ عَلَى مَنَاسِجِ خُيُولِهِمْ لَابِسُو الْبُرُودِ مِنْ أَهْلِ نَجْدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبْتَ بَلْ خَيْرُ الرِّجَالِ رِجَالُ أَهْلِ الْيَمَنِ وَالْإِيمَانُ يَمَانٍ إِلَى لَخْمٍ وَجُذَامَ وَعَامِلَةَ وَمَأْكُولُ حِمْيَرَ خَيْرٌ مِنْ آكِلِهَا وَحَضْرَمَوْتُ خَيْرٌ مِنْ بَنِي الْحَارِثِ وَقَبِيلَةٌ خَيْرٌ مِنْ قَبِيلَةٍ وَقَبِيلَةٌ شَرٌّ مِنْ قَبِيلَةٍ وَاللَّهِ مَا أُبَالِي أَنْ يَهْلِكَ الْحَارِثَانِ كِلَاهُمَا لَعَنَ اللَّهُ الْمُلُوكَ الْأَرْبَعَةَ جَمَدَاءَ وَمِخْوَسَاءَ وَمِشْرَخَاءَ وَأَبْضَعَةَ وَأُخْتَهُمْ الْعَمَرَّدَةَ ثُمَّ قَالَ أَمَرَنِي رَبِّي عَزَّ وَجَلَّ أَنْ أَلْعَنَ قُرَيْشًا مَرَّتَيْنِ فَلَعَنْتُهُمْ وَأَمَرَنِي أَنْ أُصَلِّيَ عَلَيْهِمْ فَصَلَّيْتُ عَلَيْهِمْ مَرَّتَيْنِ ثُمَّ قَالَ عُصَيَّةُ عَصَتْ اللَّهَ وَرَسُولَهُ غَيْرَ قَيْسٍ وَجَعْدَةَ وَعُصَيَّةَ ثُمَّ قَالَ لَأَسْلَمُ وَغِفَارُ وَمُزَيْنَةُ وَأَخْلَاطُهُمْ مِنْ جُهَيْنَةَ خَيْرٌ مِنْ بَنِي أَسَدٍ وَتَمِيمٍ وَغَطَفَانَ وَهَوَازِنَ عِنْدَ اللَّهِ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ ثُمَّ قَالَ شَرُّ قَبِيلَتَيْنِ فِي الْعَرَبِ نَجْرَانُ وَبَنُو تَغْلِبَ وَأَكْثَرُ الْقَبَائِلِ فِي الْجَنَّةِ مَذْحِجٌ وَمَأْكُولُقَالَ قَالَ ��َبُو الْمُغِيرَةِ قَالَ صَفْوَانُ حِمْيَرَ حِمْيَرَ خَيْرٌ مِنْ آكِلِهَا قَالَ مَنْ مَضَى خَيْرٌ مِمَّنْ بَقِيَ","id":"Telah menceritakan kepada kami [Abu Al Mughirah] Telah menceritakan kepada kami [Shafwan bin Amru] telah menceritakan kepadaku [Syuraih bin Ubaid] dari [Abdurrahman bin A'idz Al Azdi] dari [Amru bin Abasah As Sulami] ia berkata; Pada suatu hari Rasulullah shallallahu 'alaihi wasallam menampakkan seekor kuda, dan di sisi beliau terdapat Uyainah bin Hishn bin Badr Al Fazari. Maka Rasulullah shallallahu 'alaihi wasallam bersabda padanya: \"Aku lebih pandai dan lihai bermain kuda darimu.\" Maka Uyainah berkata, \"Dan saya lebih lihai berperang daripada Anda.\" Kemudian Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya, \"Kenapa bisa begitu?\" Ia menjawab, \"Sebaik-baiki pasukan adalah mereka yang membawa pedangnya di atas pundaknya, meletakkan tombaknya di atas pundak kudanya, dan mereka mengenakan Burud (sejenis pakaian luar), dan mereka berasal dari penduduk Najed.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kamu telah berdusta, bahkan sebaik-baik kstaria adalah para ksatria penduduk Yaman. Iman merupakan penisbatan ke negeri Yaman hingga suku Lakhm, Judzam, dan 'Amilah. Ma`kul dari Himyar lebih baik daripada `Akilnya. Khadramaut lebih baik daripada Bani Harits. Ada kabilah yang lebih baik dari kabilah yang lain dan ada juga kabilah yang lebih buruk dari kabilah yang lain. Demi Allah, saya tidak peduli lagi sekiranya dua kabilah Harits binasa. Semoga Allah melaknati Al Muluk Al Arba'ah (raja yang empat) yaitu, Jamada`, Mikhwasa`, Misyrakha` dan Abdla'ah, serta saudara perempuan mereka Al 'Amarradah.\" Kemudian beliau juga bersabda: \"Allah telah memerintahkanku untuk melaknati suku Quraisy sebanyak dua kali, maka aku pun melaknati mereka. Dan Allah juga memerintahkanku untuk bershalawat atas mereka, maka saya pun bershalawat atas mereka sebanyak dua kali. Suku 'Ushayyah telah durhaka kepada Allah dan Rasul-Nya, selain Qais, Ja'dah dan 'Ushayyah.\" Beliau bersabda lagi: \"Bani Aslam, Ghifar, dan Muzainah serta suku yang bergabung bersama mereka dari Juhainah adalah lebih baik daripada Bani Asad, Tamim, Ghathafan dan Hawazin di sisi Allah pada hari kiamat.\" Beliau bersabda lagi: \"Dua kabilah yang paling buruk di negeri Arab adalah Najran dan Bani Taghlib. Dan kabilah yang paling banyak di surga adalah Majhij dan Ma`kul.\" Abul Mughrah berkata; \"Shafwan adalah Himyar, Himyar lebih baik dari `Akilnya. Mereka yang telah berlalu adalah lebih baik dari mereka yang tersisa.\""},"2473":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنِ الشَّعْبِيِّ عَنْ مُحَمَّدِ بْنِ صَيْفِيٍّ الْأَنْصَارىِّ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ عَاشُورَاءَ فَقَالَ أَصُمْتُمْ يَوْمَكُمْ هَذَا فَقَالَ بَعْضُهُمْ نَعَمْ وَقَالَ بَعْضُهُمْ لَا قَالَ فَأَتِمُّوا بَقِيَّةَ يَوْمِكُمْ هَذَا وَأَمَرَهُمْ أَنْ يُؤْذِنُوا أَهْلَ الْعَرُوضِ أَنْ يُتِمُّوا يَوْمَهُمْ ذَلِكَ","id":"Telah menceritakan kepada kami [Husyain] telah mengabarkan kepada kami [Hushain] dari [Asy Sya'bi] dari [Muhammad bin Shaifi Al Anshari] ia berkata; Pada hari 'Asyuraa` Rasulullah shallallahu 'alaihi wasallam menemui kami, kemudian beliau bertanya: \"Apakah kalian berpuasa pada hari ini?\" Sebagian mereka menjawab: \"Ya.\" Dan sebagian yang lain menjawab, \"Tidak.\" Beliau bersabda: \"Sempurnakanlah puasa dari sisa hari kalian ini.\" Lalu beliau memerintahkan mereka untuk mngumumkan kepada penduduk 'Arudh (penduduk Makkah dan Madinah) agar mereka menyempurnakan puasa pada hari itu."},"2474":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عُثْمَانُ بْنُ حَكِيمٍ الْأَنْصَارِيُّ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ عَمِّهِ يَزِيدَ بْنِ ثَابِتٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا وَرَدْنَا الْبَقِيعَ إِذَا هُوَ بِقَبْرٍ جَدِيدٍ فَسَأَلَ عَنْهُ فَقِيلَ فُلَانَةُ فَعَرَفَهَا فَقَالَ أَلَا آذَنْتُمُونِي بِهَا قَالُوا يَا رَسُولَ اللَّهِ كُنْتَ قَائِلًا صَائِمًا فَكَرِهْنَا أَنْ نُؤْذِنَكَ فَقَالَ لَا تَفْعَلُوا لَا يَمُوتَنَّ فِيكُمْ مَيِّتٌ مَا كُنْتُ بَيْنَ أَظْهُرِكُمْ أَلَا آذَنْتُمُونِي بِهِ فَإِنَّ صَلَاتِي عَلَيْهِ لَهُ رَحْمَةٌ قَالَ ثُمَّ أَتَى الْقَبْرَ فَصَفَّنَا خَلْفَهُ وَكَبَّرَ عَلَيْهِ أَرْبَعًا","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Utsman bin Hakim Al Anshari] dari [Kharijah bin Zaid] dari [pamannya] yakni Yazid bin Tsabit, ia berkata; Kami pernah keluar bersama Rasulullah shallallahu 'alaihi wasallam, ketika kami melewati Baqi' beliau melihat ada sebuah kuburan baru, maka beliau menanyakannya. Kemudian disampaikan bahwa itu si Fulanah, dan beliau ternyata mengenalnya. Maka beliau bersabda: \"Mengapa kalian tidak memberitahukan aku (tentang kematiannya)?\" para sahabat menjawab, \"Ya Rasulallah, ketika itu Anda sedang sedang Qailulah (tidur siang) dan berpuasa, sehingga kami enggan untuk memberitahukanmu.\" Beliau bersabda: \"Jangan demikian. Dan janganlah sekali-kali salah seorang di antara ada yang mati sedang saya masih berada ditengah-tengah kalian, kemudian kalian tidak memberitahukanku. Sebab shalat-ku atasnya adalah rahmat.\" Akhirnya beliau mendatangi kubur tadi dan membariskan kami dibelakangnya lalu beliau takbir dengan empat kali takbir."},"2475":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ عَنْ عُثْمَانَ يَعْنِي ابْنَ حَكِيمٍ عَنْ خَارِجَةَ بْنِ زَيْدٍ عَنْ عَمِّهِ يَزِيدَ بْنِ ثَابِتٍ أَنَّهُكَانَ جَالِسًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أَصْحَابِهِ فَطَلَعَتْ جِنَازَةٌ فَلَمَّا رَآهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَارَ وَثَارَ أَصْحَابُهُ مَعَهُ فَلَمْ يَزَالُوا قِيَامًا حَتَّى نَفَذَتْ قَالَ وَاللَّهِ مَا أَدْرِي مِنْ تَأَذٍّ بِهَا أَوْ مِنْ تَضَايُقِ الْمَكَانِ وَلَا أَحْسِبُهَا إِلَّا يَهُودِيًّا أَوْ يَهُودِيَّةً وَمَا سَأَلْنَا عَنْ قِيَامِهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Numair] dari [Utsman] yakni Ibnu Hakim, dari [Kharijah bin Zaid] dari [pamannya] yakni Yazid bin Tsabit, bahwa ia pernah duduk bersama Rasulullah shallallahu 'alaihi wasallam beserta para sahabatnya. Kemudian muncullah sekelompok orang yang sedang mengusung jenazah. Ketika Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau minggir seraya berdiri yang diikuti oleh para sahabat, mereka tetap dalam keadaan berdiri hingga para pengusung janazah tersebut berlalu. Yazid bin Tsabit berkata; \"Aku tidak tahu (sebab Rasul berdiri), apakah karena khawatir kami menyakiti jenazah, ataukah karena sempitnya tempat itu. Dan saya duga, beliau lakukan demikian tidak lain kecuali itu adalah jenazah seorang wanita Yahudi. Dan kami tidak bertanya sebab berdirinya Rasulullah shallallahu 'alaihi wasallam."},"2476":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ بَحْرٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ إِبْرَاهِيمَ بْنِ مَيْسَرَةَ عَنْ عَمْرِو بْنِ شَرِيدٍ عَنْ أَبِيهِ الشَّرِيدِ بْنِ سُوَيْدٍ قَالَمَرَّ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا جَالِسٌ هَكَذَا وَقَدْ وَضَعْتُ يَدِي الْيُسْرَى خَلْفَ ظَهْرِي وَاتَّكَأْتُ عَلَى أَلْيَةِ يَدِي فَقَالَ أَتَقْعُدُ قَعْدَةَ الْمَغْضُوبِ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Ali bin Bahr] Telah menceritakan kepada kami [Isa bin Yunus] telah mengabarkan kepada kami [Ibnu Juraij] dari [Ibrahim bin Maisarah] dari [Amru bin Syarid] dari [bapaknya, Asy Syarid] bin Suwaid, ia berkata; Rasulullah shallallahu 'alaihi wasallam melintas didepanku sementara aku sedang duduk dengan posisi tangan kiri dibelakang punggungku dan aku bersandar kepada jempol tanganku, lalu beliau berkata kepadaku: \"Apakah kamu duduk dengan cara duduknya AL MAGDHUUBI 'ALAIHIM (orang yang dimurkai Allah)?\""},"2477":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنِ الشَّرِيدِأَنَّ أُمَّهُ أَوْصَتْ أَنْ يُعْتِقُوا عَنْهَا رَقَبَةً مُؤْمِنَةً فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ عِنْدِي جَارِيَةٌ سَوْدَاءُ نُوبِيَّةٌ فَأُعْتِقُهَا عَنْهَا فَقَالَ ائْتِ بِهَا فَدَعَوْتُهَا فَجَاءَتْ فَقَالَ لَهَا مَنْ رَبُّكِ قَالَتْ اللَّهُ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Hammad bin Salamah] Telah menceritakan kepada kami [Muhammad bin Amru] dari [Abu Salamah] dari [Asy Syarid] bahwa ibunya telah berwasiat agar mereka memerdekakan untuknya seorang budak wanita mukminah. Maka ia pun menanyakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, dan ia berkata, \"Saya memiliki seorang budak wanita hitam Nubiyyah, apakah dia yang saya bebaskan?\" beliau bersabda: \"Datangkanlah ia kemari.\" Budak wanita itu pun datang dan beliau langsung bertanya: \"Siapakah Rabb-mu?\" ia menjawab, \"Allah.\" Beliau bertanya lagi: \"Siapakah saya?\" ia menjawab: \"Anda adalah Rasulullah.\" Beliau bersabda: \"Merdekakanlah wanita itu, karena ia adalah seorang wanita mukminah.\""},"2478":{"ar":"حَدَّثَنَا وَكِيعٌ حَدَّثَنَا وَبْرُ بْنُ أَبِي دُلَيْلَةَ شَيْخٌ مِنْ أَهْلِ الطَّائِفِ عَنِ مُحَمَّدِ بْنِ مَيْمُونِ بْنِ مُسَيْكَةَ وَأَثْنَى عَلَيْهِ خَيْرًا عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُقَالَ وَكِيعٌ عِرْضُهُ شِكَايَتُهُ وَعُقُوبَتُهُ حَبْسُهُ","id":"Telah menceritakan kepada kami [Waki'] Telah menceritakan kepada kami [Wabr bin Abu Dulailah] yakni seorang syaikh dari Tha`if, dari [Muhammad bin Maimun bin Musaikah] -ia pun memujinya dengan kebaikan- dari [Amru bin Syarid] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penangguhan (hutang) seorang yang mampu, menghalalkan kehormatan dan hukumannya.\" Waki' berkata; Kehormatannya adalah diadukan (kepada hakim) sedangkan hukumannya adalah dipenjara."},"2479":{"ar":"حَدَّثَنَا مَكِّيُّ بْنُ إِبْرَاهِيمَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ عَمْرٍو عَنِ الشَّرِيدِ أَنَّهُ سَمِعَهُ يُخْبِرُهُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا وَجَدَ الرَّجُلَ رَاقِدًا عَلَى وَجْهِهِ لَيْسَ عَلَى عَجُزِهِ شَيْءٌ رَكَضَهُ بِرِجْلِهِ وَقَالَ هِيَ أَبْغَضُ الرِّقْدَةِ إِلَى اللَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Makki bin Ibrahim] Telah menceritakan kepada kami [Ibnu Juraij] ia berkata, telah mengabarkan kepadaku [Ibrahim bin Maisarah] dari [Amru bin Asy Syarid] dari [Asy Syarid] bahwa ia mendengarnya mengabarkan kepadanya dari Nabi shallallahu 'alaihi wasallam bahwasanya; Bila beliau mendapatkan seseorang yang sedang tidur dengan menelungkupkan wajahnya, dengan pantat tidak diselimuti kain yang bisa disepaknya dengan kaki, beliau bersabda: \"Itu adalah posisi tidur yang paling dibenci Allah 'azza wajalla.\""},"2480":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ أَخْبَرَنَا قَتَادَةُ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنِ الشَّرِيدِ بْنِ سُوَيْدٍ الثَّقَفِيِّأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَارُ الدَّارِ أَحَقُّ بِالدَّارِ مِنْ غَيْرِهِ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Hammam] telah mengabarkan kepada kami [Qatadah] dari [Amru bin Syu'aib] dari [Asy Syarid bin Suwaid Ats Tsaqafi] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tetangga rumah lebih berhak untuk ditawari membeli rumah (hak syuf'ah) dari pada yang lainnya.\""},"2481":{"ar":"حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَطَاءٍ أَخْبَرَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ عَمْرِو بْنِ شُعَيْبٍ حَدَّثَنِي عَمْرُو بْنُ الشَّرِيدِ عَنْ أَبِيهِ الشَّرِيدِ بْنِ سُوَيْدٍ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَرْضٌ لَيْسَ لِأَحَدٍ فِيهَا شِرْكٌ وَلَا قَسْمٌ إِلَّا الْجِوَارُ قَالَ الْجَارُ أَحَقُّ بِسَقَبِهِ مَا كَانَ","id":"Telah menceritakan kepada kami [Abdul Wahhab bin Atha`] telah mengabarkan kepada kami [Husain Al Mu'allim] dari [Amru bin Syu'aib] telah menceritakan kepadaku [Amru bin Asy Syarid] dari [bapaknya] yakni Syarid bin Suwaid, ia berkata; Saya bertanya, \"Wahai Rasulullah, bagaimana dengan tanah (pribadi) yang padanya tidak ada persekutuan dan tidak pula pembagian kecuali tetangga?\" berliau menjawab: \"Tetangga itu lebih berhak ditawari untuk membeli tanah itu daripada yang lain.\""},"2482":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ وَالْخَفَّافُ أَخْبَرَنَا حُسَيْنٌ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ الشَّرِيدِ بْنِ سُوَيْدٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ قَالَ الْخَفَّافُ قُلْتُ يَا رَسُولَ اللَّهِ أَرْضٌ لَيْسَ لِأَحَدٍ فِيهَا شِرْكٌ وَلَا قَسْمٌ إِلَّا الْجِوَارُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجَارُ أَحَقُّ بِسَقَبِهِ مَا كَانَ","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Husain Al Mu'allim] dan [Al Khaffaf] telah mengabarkan kepada kami [Husain] dari [Amru bin Syu'aib] dari [Amru bin Syarid] dari [bapaknya] yakni Syarid bin Suwaid, bahwa seorang laki-laki berkata; \"Wahai Rasulullah, itu Al Khaffaf.\" Saya bertanya, \"Wahai Rasulullah, bagaimana dengan tanah (milik priadi) yang padanya tidak ada persekutuan dan tidak pula pembagian kecuali tetangga?\" beliau menjawab: \"Tetangga itu lebih berhak untuk ditawari membeli tanah itu daripada yang lain.\""},"2483":{"ar":"حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ أَخْبَرَنِي وَبْرُ بْنُ أَبِي دُلَيْلَةَ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ مَيْمُونِ بْنِ مُسَيْكَةَ قَالَ حَدَّثَنِي عَمْرُو بْنُ الشَّرِيدِ قَالَ حَدَّثَنِي أَبِي قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيُّ الْوَاجِدِ يُحِلُّ عِرْضَهُ وَعُقُوبَتَهُ","id":"Telah menceritakan kepada kami [Adl Dlahak bin Makhlad] telah mengabarkan kepadaku [Wabr bin Abu Dulailah] ia berkata, telah mengabarkan kepadaku [Muhammad bin Abdullah bin Maimun bin Musaikah] ia berkata, telah menceritakan kepadaku [Amru bin Syarid] ia berkata, telah menceritakan kepadaku [bapakku] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penangguhan (hutang) seorang yang mampu, menghalalkan kehormatan dan hukumannya.\" "},"2484":{"ar":"حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَاقَ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مَيْسَرَةَ أَنَّهُ سَمِعَ يَعْقُوبَ بْنَ عَاصِمِ بْنِ عُرْوَةَ يَقُولُ سَمِعْتُ الشَّرِيدَ يَقُولُأَشْهَدُ لَوَقَفْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِعَرَفَاتٍ قَالَ فَمَا مَسَّتْ قَدَمَاهُ الْأَرْضَ حَتَّى أَتَى جَمْعًا","id":"Telah menceritakan kepada kami [Rauh] Telah menceritakan kepada kami [Zakariya bin Ishaq] telah mengabarkan kepada kami [Ibrahim bin Maisarah] bahwa ia mendengar [Ya'qub bin Ashim bin Urwah] berkata, saya mendengar [Asy Syarid] berkata; \"Saya bersaksi bahwa saya benar-benar telah wukuf bersama Rasulullah shallallahu 'alaihi wasallam di Arafah. Kaki beliau sama sekali tidak menyentuh tanah hingga beliau datang ke Jam' (Muzdalifah).\""},"2485":{"ar":"حَدَّثَنَا مُهَنَّأُ بْنُ عَبْدِ الْحَمِيدِ قَالَ أَبِي كُنْيَتُهُ أَبُو شِبْلٍ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنِ الشَّرِيدِأَنَّ أُمَّهُ أَوْصَتْ أَنْ يُعْتَقَ عَنْهَا رَقَبَةٌ مُؤْمِنَةٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمِّي أَوْصَتْ أَنْ يُعْتَقَ عَنْهَا رَقَبَةٌ مُؤْمِنَةٌ وَعِنْدِي جَارِيَةٌ نُوبِيَّةٌ سَوْدَاءُ فَقَالَ ادْعُ بِهَا فَجَاءَ بِهَا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَبُّكِ قَالَتْ اللَّهُ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah menceritakan kepada kami [Muhammad bin Abdul Hamid] telah berkata bapakku kunyahnya adalah Abu Syibl, Telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin Amru] dari [Abu Salamah] dari [Asy Syarid] bahwa ibunya telah berwasiat agar kemudian hari satu orang budak wanita mukminah dimerdekakn baginya, maka ia pun berkata, \"Wahai Rasulullah, Ibuku telah berwasiat, agar dimerdekakan baginya seorang budak wanita mukminah. Sementara saya hanya memiliki budak wanita Nubiyyah berkulit hitam. Beliau bersabda: \"Panggillah ia.\" Maka ia pun membawanya. Nabi shallallahu 'alaihi wasallam bertanya pada budak wanita itu, \"Siapa Rabb-mu.\" Budak Wanita itu menjawab, \"Allah.\" Beliau bertanya lagi: \"Siapakah aku?\" wanita itu pun menjawab, \"Anda adalah Rasulullah.\" Maka beliau bersabda: \"Merdekakanlah ia, karena wanita itu adalah wanita mukminah.\""},"2486":{"ar":"حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنِ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ ثَعْلَبَةَ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَنْصَارِيِّ عَنْ مُجَمِّعِ بْنِ جَارِيَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَيَقْتُلَنَّ ابْنُ مَرْيَمَ الدَّجَّالَ بِبَاب لُدٍّ أَوْ إِلَى جَانِبِ لُدٍّ","id":"Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abdullah bin Ubaidullah bin Tsa'labah Al Anshari] dari [Abdullah bin Zaid Al Anshari] dari [Mujammi' bin Jariyah] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ibnu Maryam benar-benar akan membunuh Dajjal di Bab ludd atau dengan redaksi \"di Janibb Ludd\".\" "},"2487":{"ar":"حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا يَعْلَى بْنُ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ إِذَا بَعَثَ سَرِيَّةً أَوْ جَيْشًا بَعَثَهُمْ مِنْ أَوَّلِ النَّهَارِقَالَ وَكَانَ صَخْرٌ رَجُلًا تَاجِرًا فَكَانَ يَبْعَثُ تِجَارَتَهُ مِنْ أَوَّلِ النَّهَارِ قَالَ فَأَثْرَى وَكَثُرَ مَالُهُ","id":"Telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Ya'la bin Atha`] dari [Umarah bin Hadid] dari [Shakhr Al Ghamidi] berkata; Rasulullah shallallahu 'alaihi wasallam berdo'a: \"ALLAHUMMA BAARIK LUMMATII FI BUKUURIHAA (Ya Allah, berilah keberkahan pada umatku di waktu padi harinya).\" Dan jika beliau hendak mengutus Sariyyah (pasukan khusus untuk operasi tertentu), maka beliau akan mengutusnya pada permulaan hari (waktu pagi). Shakhr adalah seorang pedagang dan dia selalu mengirim barang dagangannya sejak pagi hari. Karenanya ia kaya dan hartanya berlimpah."},"2488":{"ar":"حَدَّثَنَا عَفَّانُ حَدَّثَنَا شُعْبَةُ قَالَ يَعْلَى بْنُ عَطَاءٍ أَنْبَأَنِي قَالَ سَمِعْتُ عُمَارَةَ بْنَ حَدِيدٍ رَجُلًا مِنْ بَجِيلَةَ قَالَ سَمِعْتُ صَخْرًا الْغَامِدِيَّ رَجُلًا مِنْ الْأَزْدِ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهُمْ مِنْ أَوَّلِ النَّهَارِوَكَانَ صَخْرٌ رَجُلًا تَاجِرًا وَكَانَ لَهُ غِلْمَانٌ فَكَانَ يَبْعَثُ غِلْمَانَهُ مِنْ أَوَّلِ النَّهَارِ قَالَ فَكَثُرَ مَالُهُ حَتَّى كَانَ لَا يَدْرِي أَيْنَ يَضَعُهُ","id":"Telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Syu'bah] ia berkata, telah memberitakan kepadaku [Ya'la bin Atha`] ia berkata, saya mendengar [Umarah bin Hadid] seorang dari Bajilah, ia berkata, saya mendengar [Shakhr Al Ghamidi] seorang laki-laki dari Al Azd, berkata; Bahwa Nabi shallallahu 'alaihi wasallam berdo'a: \"ALLAHUMMA BAARIK LIUMMATII FI BUKUURIHAA (Ya Allah, berilah keberkahan pada untuk ummatku di waktu pagi mereka).\" Dan jika Nabi shallallahu 'alaihi wasallam mengirim Sariyyah (pasukan khusus yang dikirim untuk operasi tertentu), maka belia mengirimnya pada pagi hari. Kemudian Shakhr adalah seorang penjual, dan ia juga tidak pernah mengirim para pelayannya kecuali pada permulaan hari (pagi hari), sehingga hartanya pun semakin berkembang dan banyak, sampai ia tidak tahu lagi di mana ia letakkan hartanya."},"2489":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ الْبَجَلِيِّ عَنْ صَخْرٍ الْغَامِدِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا قَالَ وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهَا أَوَّلَ النَّهَارِوَكَانَ صَخْرٌ تَاجِرًا فَكَانَ لَا يَبْعَثُ غِلْمَانَهُ إِلَّا مِنْ أَوَّلِ النَّهَارِ فَكَثُرَ مَالُهُ حَتَّى كَانَ لَا يَدْرِي أَيْنَ يَضَعُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin Atha`] dari [Umarah bin Hadid Al Bajali] dari [Shakhr Al Ghamidi] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau pernah berdo'a: \"ALLAHUMMA BAARIK LIUMMATII FI BUKUURIHAA (Ya Allah, berilah keberkahan pada untuk ummatku di waktu pagi mereka).\" Dan jika Nabi shallallahu 'alaihi wasallam mengirim Sariyyah (pasukan khusus yang dikirim untuk operasi tertentu), maka belia mengirimnya pada pagi hari. Kemudian Shakhr adalah seorang penjual, dan ia juga tidak pernah mengirim para pelayannya kecuali pada permulaan hari (pagi hari), sehingga hartanya pun semakin berkembang dan banyak, sampai ia tidak tahu lagi di mana ia letakkan hartanya."},"2490":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا يُوسُفُ بْنُ يَعْقُوبَ الْمَاجِشُونُ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ الْمُنْكَدِرِ قَالَدَخَلْتُ عَلَى جَابِرِ بْنِ عَبْدِ اللَّهِ وَهُوَ يَمُوتُ فَقُلْتُ أَقْرِئْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنِّي السَّلَامَ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil Al Marwazi] ia berkata, Telah menceritakan kepada kami [Yusuf bin Ya'qub Al Majisyun] ia berkata, telah mengabarkan kepadaku [Muhammad bin Al Munkadir] ia berkata; Aku menemui [Jabir bin Abdullah] yang saat itu telah meninggal. Aku pun berkata, \"Sampaikanlah salam dariku kepada Rasulullah shallallahu 'alaihi wasallam.\""},"2491":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ أَخْبَرَنَا عَبَّادُ بْنُ الْعَوَّامِ حَدَّثَنَا الْحَجَّاجُ عَنْ عَبْدِ اللَّهِ مَوْلَى بَنِي هَاشِمٍ قَالَ وَكَانَ ثِقَةً قَالَ وَكَانَ الْحَكَمُ يَأْخُذُ عَنْهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ أُسَيْدِ بْنِ حُضَيْرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ أَلْبَانِ الْإِبِلِ فَقَالَ تَوَضَّئُوا مِنْ أَلْبَانِهَا وَسُئِلَ عَنْ أَلْبَانِ الْغَنَمِ فَقَالَ لَا تَوَضَّئُوا مِنْ أَلْبَانِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] telah mengabarkan kepada kami [Abbad bin Al Awwam] Telah menceritakan kepada kami [Al Hajjaj] dari [Abdullah] bekas budak Bani Hasyim, ia berkata; ia adalah seorang yang Tsiqqah, ia berkata, Al Hakam meriwayatkan darinya, dari [Abdurrahman bin Abu Laila] dari [Usaid bin Hudlair] dari Nabi shallallahu 'alaihi wasallam, beliau ditanya tentang air susu Unta, maka beliau bersabda: \"Berwudlulah kalian setelah meminum susu Unta.\" Kemudian beliau ditanya tentang susu kambing, maka beliau bersabda: \"Janganlah kalian berwudlu setelah meminumnya.\""},"2492":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مُقَاتِلٍ حَدَّثَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا مِسْعَرٌ عَنْ حَمَّادٍ قَالَالْبَوْلُ عِنْدَنَا بِمَنْزِلَةِ الدَّمِ مَا لَمْ يَكُنْ قَدْرَ الدِّرْهَمِ فَلَا بَأْسَ بِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Muqatil] Telah menceritakan kepada kami [Ibnul Mubarak] telah mengabarkan kepada kami [Mis'ar] dari [Hammad] ia berkata; \"Air kencing menurut kami sama dengan darah, apabila tidak sampai ukuran uang dirham maka tidaklah mengapa.\""},"2493":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنِ الْحَسَنِ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ إِنَّ الْمَعْرُوفَ وَالْمُنْكَرَ خَلِيقَتَانِ يُنْصَبَانِ لِلنَّاسِ يَوْمَ الْقِيَامَةِ فَأَمَّا الْمَعْرُوفُ فَيُبَشِّرُ أَصْحَابَهُ وَيُوعِدُهُمْ الْخَيْرَ وَأَمَّا الْمُنْكَرُ فَيَقُولُ إِلَيْكُمْ إِلَيْكُمْ وَمَا يَسْتَطِيعُونَ لَهُ إِلَّا لُزُومًا","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Hasan] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwa muhammad berada ditangan-Nya, sesungguhnya sesuatu yang ma'ruf dan yang munkar pada hari kiamat nanti akan menjadi makhluk seperti manusia, adapun suatu yang ma'ruf, maka dia akan memberikan kabar gembira kepada para pelakunya dan memberikan janji-janji berupa kebaikan, sementara suatu yang munkar maka dia akan berkata, 'Pergilah kalian-pergilah kalian.' namun mereka tidak mampu kecuali mereka akan menetapinya.\""},"2494":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ إِبْرَاهِيمَ أَخْبَرَنَا لَيْثٌ عَنْ أَبِي بُرْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ قَيْسٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً ثُمَّ قَالَ عَلَى مَكَانِكُمْ اثْبُتُوا ثُمَّ أَتَى الرِّجَالَ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُنِي أَنْ آمُرَكُمْ أَنْ تَتَّقُوا اللَّهَ تَعَالَى وَأَنْ تَقُولُوا قَوْلًا سَدِيدًا ثُمَّ تَخَلَّلَ إِلَى النِّسَاءِ فَقَالَ لَهُنَّ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَأْمُرُنِي أَنْ آمُرَكُنَّ أَنْ تَتَّقُوا اللَّهَ وَأَنْ تَقُولُوا قَوْلًا سَدِيدًا قَالَ ثُمَّ رَجَعَ حَتَّى أَتَى الرِّجَالَ فَقَالَ إِذَا دَخَلْتُمْ مَسَاجِدَ الْمُسْلِمِينَ وَأَسْوَاقَهُمْ وَمَعَكُمْ النَّبْلُ فَخُذُوا بِنُصُولِهَا لَا تُصِيبُوا بِهَا أَحَدًا فَتُؤْذُوهُ أَوْ تَجْرَحُوهُ","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Yazid] yakni Ibnu Ibrahim, telah mengabarkan kepada kami [Laits] dari [Abu Burdah] dari [Abdullah bin Qais] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam shalat mengimami kami, kemudian beliau bersabda: \"Kalian tetaplah berada di tempat.\" Beliau kemudian mendatangi tempat kaum laki-laki dan bersabda: \"Sesungguhnya Allah 'azza wajalla telah memerintahkan aku untuk memerintahkan kalian agar kalian selalu betakwa kepada Allah dan selalu berkata dengan kata-kata yang baik.\" Setelah itu, beliau berjalan menuju kaum wanita, kemudian beliau bersabda: \"Sesungguhnya Allah 'azza wajalla telah memerintahkan aku untuk memerintahkan kalian agar kalian selalu bertakwa kepada Allah dan selalu berkata dengan kata-kata yang baik.\" kemudian beliau kembali lagi ketempat kaum laki-laki dan bersabda: \"Apabila kalian masuk ke dalam masjid atau pasar kaum muslimin sementara kalian membawa tombak, maka peganglah ujungnya (matanya), janganlah sampai kalian mencelakai atau melukai seseorang.\""},"2495":{"ar":"حَدَّثَنَا هُشَيْمٌ عَنْ مُجَالِدٍ عَنِ الشَّعْبِيِّ قَالَكَتَبَ عُمَرُ فِي وَصِيَّت��هِ أَنْ لَا يُقَرَّ لِي عَامِلٌ أَكْثَرَ مِنْ سَنَةٍ وَأَقِرُّوا الْأَشْعَرِيَّ يَعْنِي أَبَا مُوسَى أَرْبَعَ سِنِينَ","id":"Telah menceritakan kepada kami [Husyaim] dari [Mujalid] dari [Asy Sya'bi] ia berkata; [Umar] menulis dalam wasiatnya: \"Pejabat-pejabatku untuk tidak dilantik menjabat melebihi setahun.\" Sementara mereka melantik al- Alasy'ari yakni Abu Musa untuk masa jabatan empat tahun."},"2496":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا لَيْثٌ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَرَّتْ بِكُمْ جِنَازَةُ يَهُودِيٍّ أَوْ نَصْرَانِيٍّ أَوْ مُسْلِمٍ فَقُومُوا لَهَا فَلَسْتُمْ لَهَا تَقُومُونَ إِنَّمَا تَقُومُونَ لِمَنْ مَعَهَا مِنْ الْمَلَائِكَةِ","id":"Telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Laits] dari [Abu Burdah] dari [Abu Musa] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila dihadapan kalian lewat jenazah orang yahudi atau nasrani atau muslim, maka hendaklah kalian berdiri! Berdiri tersebut bukan untuk menghormati jenazah itu, akan tetapi untuk yang bersamanya yaitu para malaikat.\""},"2497":{"ar":"حَدَّثَنَا عَبْدُ الصَّمَدِ وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا عَلِيُّ بْنُ زَيْدٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ الرَّقَاشِيِّ عَنِ الْأَشْعَرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ بَيْنَ يَدَيْ السَّاعَةِ الْهَرْجَ قَالُوا وَمَا الْهَرْجُ قَالَ الْقَتْلُ قَالُوا أَكْثَرُ مِمَّا نَقْتُلُ إِنَّا لَنَقْتُلُ كُلَّ عَامٍ أَكْثَرَ مِنْ سَبْعِينَ أَلْفًا قَالَ إِنَّهُ لَيْسَ بِقَتْلِكُمْ الْمُشْرِكِينَ وَلَكِنْ قَتْلُ بَعْضِكُمْ بَعْضًا قَالُوا وَمَعَنَا عُقُولُنَا يَوْمَئِذٍ قَالَ إِنَّهُ لَتُنْزَعُ عُقُولُ أَهْلِ ذَلِكَ الزَّمَانِ وَيُخَلَّفُ لَهُ هَبَاءٌ مِنْ النَّاسِ يَحْسِبُ أَكْثَرُهُمْ أَنَّهُمْ عَلَى شَيْءٍ وَلَيْسُوا عَلَى شَيْءٍقَالَ عَفَّانُ فِي حَدِيثِهِ قَالَ أَبُو مُوسَى وَالَّذِي نَفْسِي بِيَدِهِ مَا أَجِدُ لِي وَلَكُمْ مِنْهَا مَخْرَجًا إِنْ أَدْرَكَتْنِي وَإِيَّاكُمْ إِلَّا أَنْ نَخْرُجَ مِنْهَا كَمَا دَخَلْنَا فِيهَا لَمْ نُصِبْ مِنْهَا دَمًا وَلَا مَالًا","id":"Telah menceritakan kepada kami [Abdush Shamad] dan [Affan] ia berkata, Telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Ali bin Zaid] dari [Hiththan bin Abdullah Ar Raqasyi] dari [Al Asy'ari] bahwasanya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya menjelang datangnya hari kiamat, akan terjadi banyak sekali Al Haraj.\" Mereka (para sahabat) bertanya, \"Apa maksud istilah Al Haraj?\" Beliau menjawab: \"(Yaitu) pembunuhan.\" Mereka bertanya: \"Apakah lebih banyak dari yang kami lakukan, karena kami setiap tahun membunuh lebih dari tujuh puluh ribu orang?.\" Beliau bersabda: \"Bukan seperti yang kalian lakukan yaitu (memerangi) kaum musyrikin. Akan tetapi (pembunuhan yang terjadi) antara sebagian kalian dengan sebagian yang lain (peperangan sesama muslimin).\" Mereka bertanya lagi, \"Apakah pada hari itu, kami masih bersama dengan orang-orang yang berakal?\" Beliau menjawab: \"Sesungguhnya orang-orang yang berakal pada masa itu telah banyak yang meninggal, lalu digantikan dengan orang yang tidak memiliki kemampuan apa-apa dari manusia, kelompok yang banyak menyangka mereka mempunyai dasar yang kuat, padahal mereka tidak mempunyai pegangan apa-apa.\" Affan berkata dalam haditsnya; Abu musa berkata: \"Demi Dzat yang jiwaku berada ditangan-Nya, aku tidak mendapatkan jalan keluar untukku dan juga untuk kalian jika aku dan kalian menemuinya kecuali kita harus keluar darinya sebagaimana kita masuk didalamnya dan jangan sampai kita menumpahkan darah ataupun menjarah harta (orang lain).\""},"2498":{"ar":"حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَاقَ عَنِ الْأَسْوَدِ قَالَ قَالَ أَبُو مُوسَىلَقَدْ ذَكَّرَنَا عَلِيُّ بْنُ أَبِي طَالِبٍ صَلَاةً كُنَّا نُصَلِّيهَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِمَّا نَسِينَاهَا وَإِمَّا تَرَكْنَاهَا عَمْدًا يُكَبِّرُ كُلَّمَا رَكَعَ وَكُلَّمَا رَفَعَ وَكُلَّمَا سَجَدَ","id":"Telah menceritakan kepada kami [Yahya bin Adam] Telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Al Aswad] ia berkata, [Abu Musa] berkata; \"Ali bin Abi Thalib telah mengingatkan kami tentang shalat yang pernah kami tunaikan bersama Rasulullah shallallahu 'alaihi wasallam. Bisa jadi karena kami lupa atau karena kami meninggalkannya dengan sengaja. Beliau selalu bertakbir setiap hendak ruku' dan setiap kali bangkit dari ruku' dan setiap kali beliau sujud.\""},"2499":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ قَالَ سَمِعْتُ رَجُلًا مِنْ قُرَيْشٍ يُقَالُ لَهُ أَبُو عَبْدِ اللَّهِ كَانَ يُجَالِسُ جَعْفَرَ بْنَ رَبِيعَةَ قَالَ سَمِعْتُ أَبَا بُرْدَةَ الْأَشْعَرِيَّ يُحَدِّثُ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَعْظَمَ الذُّنُوبِ عِنْدَ اللَّهِ عَزَّ وَجَلَّ أَنْ يَلْقَاهُ عَبْدٌ بِهَا بَعْدَ الْكَبَائِرِ الَّتِي نَهَى عَنْهَا أَنْ يَمُوتَ الرَّجُلُ وَعَلَيْهِ دَيْنٌ لَا يَدَعُ قَضَاءً","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] Telah menceritakan kepada kami [Sa'id bin Abu Ayyub] ia berkata; Saya mendengar seorang laki-laki Quraisy yang biasa dipanggil [Abu Abdullah] yang selalu bermajelis bersama Ja'far bin Rabi'ah, ia berkata, saya mendengar [Abu Burdah Al Asy'ari] menceritakan dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya dosa yang paling besar disisi Allah 'azza wajalla yang didapatkan seorang hamba setelah Al Kabaa`ir (dosa-dosa besar) yang dilarang untuk melakukannya, adalah seorang meninggal, sementara ia masih memiliki hutang dan tidak meninggalkan sesuatu untuk membayarnya.\""},"2500":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ قَالَكَانَ عَبْدُ اللَّهِ وَأَبُو مُوسَى جَالِسَيْنِ وَهُمَا يَتَذَاكَرَانِ الْحَدِيثَ فَقَالَ أَبُو مُوسَى قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ يَدَيْ السَّاعَةِ أَيَّامٌ يُرْفَعُ فِيهَا الْعِلْمُ وَيَنْزِلُ فِيهَا الْجَهْلُ وَيَكْثُرُ فِيهَا الْهَرْجُ وَالْهَرْجُ الْقَتْلُ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid] Telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] ia berkata; Abdullah dan Abu Musa duduk-duduk saling mengingatkan hadits. [Abu Musa] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Menjelang kiamat tiba, terdapat hari-hari yang pada hari itu ilmu diangkat, dan kebodohan merajalela. Serta akan banyak terjadi Al Haraj, yaitu pembunuhan.\""}};
